def default_data_dir():
    root = os.getenv("BOT_DATA_DIR", "").strip()
    candidate = root or str(user_data_root() / "runtime" / INSTANCE_SAFE)
    return validate_external_storage_directory(candidate, repository_root=Path(BASE_DIR), label="BOT_DATA_DIR")

DATA_DIR = default_data_dir()
# State and exports are deliberately kept outside the repository so they cannot
# be committed with source code or included in a release by accident.
def default_export_dir():
    root = os.getenv("BOT_EXPORT_DIR", "").strip()
    candidate = root or str(user_data_root() / "exports" / INSTANCE_SAFE)
    return validate_external_storage_directory(candidate, repository_root=Path(BASE_DIR), label="BOT_EXPORT_DIR")

