# Auth timestamp guard. Kalshi signed requests require the access timestamp in
# current epoch milliseconds. If Windows time drifts or wakes from sleep stale,
# Kalshi can reject an otherwise-valid signature with header_timestamp_expired.
# This guard estimates the HTTPS server Date offset from public responses and
# retries exactly once for that specific error without loosening auth security.
AUTH_TIMESTAMP_SYNC_ENABLED = os.getenv("AUTH_TIMESTAMP_SYNC_ENABLED", "1").lower() not in {"0", "false", "no"}
AUTH_TIMESTAMP_EXPIRED_RETRY_ENABLED = os.getenv("AUTH_TIMESTAMP_EXPIRED_RETRY_ENABLED", "1").lower() not in {"0", "false", "no"}
