def kalshi_environment_from_base_url(base_url: str = None) -> str:
    host = urlparse(str(base_url or BASE_URL or "")).netloc.lower()
    if "demo" in host:
        return "demo"
    if "kalshi" in host or "elections" in host:
        return "live"
    return "unknown"

