# Target-tranche sell mode: the intended 10-contract entry loop sells 40% at 2c (4 contracts).
# The general min order-profit gate remains higher (10 contracts / 5c total) for new entries
# and larger orders. This narrow sell-side rescue permits the core 10 -> 4 exit only when
# the strict 2c trade still clears both net-profit and net-to-fee-ratio requirements.
# Buy/miner action plans still use MIN_PROFITABLE_ORDER_QTY_FP=10.00 so the buy side does
# not start creating tiny entries.
TARGET_TRANCHE_SELL_ENABLED = os.getenv("TARGET_TRANCHE_SELL_ENABLED", "1").lower() not in {"0", "false", "no"}
TARGET_TRANCHE_SELL_MIN_QTY_FP = Decimal(os.getenv("TARGET_TRANCHE_SELL_MIN_QTY_FP", "4.00"))
TARGET_TRANCHE_SELL_MAX_QTY_FP = Decimal(os.getenv("TARGET_TRANCHE_SELL_MAX_QTY_FP", "10.00"))
TARGET_TRANCHE_SELL_MIN_NET_CENTS = Decimal(os.getenv("TARGET_TRANCHE_SELL_MIN_NET_CENTS", "2.50"))
TARGET_TRANCHE_SELL_MIN_PER_CONTRACT_CENTS = Decimal(os.getenv("TARGET_TRANCHE_SELL_MIN_PER_CONTRACT_CENTS", str(MIN_NET_EDGE_PER_CONTRACT_CENTS)))
TARGET_TRANCHE_SELL_MIN_NET_TO_TOTAL_FEES_RATIO = Decimal(os.getenv("TARGET_TRANCHE_SELL_MIN_NET_TO_TOTAL_FEES_RATIO", "1.95"))
TARGET_TRANCHE_SELL_REQUIRE_2C = os.getenv("TARGET_TRANCHE_SELL_REQUIRE_2C", "1").lower() not in {"0", "false", "no"}

# Realized fee/fill reconciliation. This uses live portfolio fills to compare
# expected fees against actual exchange fees and writes a fill-level audit trail.
FILL_SYNC_ENABLED = os.getenv("FILL_SYNC_ENABLED", "1").lower() not in {"0", "false", "no"}
FILL_SYNC_INTERVAL_SECONDS = int(os.getenv("FILL_SYNC_INTERVAL_SECONDS", "5"))
FILL_SYNC_LOOKBACK_SECONDS = int(os.getenv("FILL_SYNC_LOOKBACK_SECONDS", "21600"))
FILL_SYNC_REPLAY_SECONDS = int(os.getenv("FILL_SYNC_REPLAY_SECONDS", "60"))
FILL_SYNC_MAX_PAGES = int(os.getenv("FILL_SYNC_MAX_PAGES", "3"))
FILL_LEDGER_CSV_PATH = os.getenv("FILL_LEDGER_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_fill_ledger.csv")).strip()

# Settlement reconciliation. Unsold residual inventory can settle instead of exit;
# this ledger captures actual settlement fees/revenue and feeds market/series quality.
SETTLEMENT_SYNC_ENABLED = os.getenv("SETTLEMENT_SYNC_ENABLED", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_SYNC_INTERVAL_SECONDS = int(os.getenv("SETTLEMENT_SYNC_INTERVAL_SECONDS", "30"))
SETTLEMENT_SYNC_LOOKBACK_SECONDS = int(os.getenv("SETTLEMENT_SYNC_LOOKBACK_SECONDS", "86400"))
SETTLEMENT_SYNC_REPLAY_SECONDS = int(os.getenv("SETTLEMENT_SYNC_REPLAY_SECONDS", "300"))
SETTLEMENT_SYNC_MAX_PAGES = int(os.getenv("SETTLEMENT_SYNC_MAX_PAGES", "3"))
SETTLEMENT_LEDGER_CSV_PATH = os.getenv("SETTLEMENT_LEDGER_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_settlement_ledger.csv")).strip()
SETTLEMENT_BAD_FEE_CENTS = Decimal(os.getenv("SETTLEMENT_BAD_FEE_CENTS", "0.50"))
# Settlement integrity. The bot now keeps a global settlement de-dupe index and
# dedupes settlement-derived analytics so replayed settlement rows cannot inflate
# daily-goal/P&L numbers. Existing duplicate ledgers are compacted with a backup.
SETTLEMENT_DEDUPE_ENABLED = os.getenv("SETTLEMENT_DEDUPE_ENABLED", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_USE_TOTAL_COST_FIELDS = os.getenv("SETTLEMENT_USE_TOTAL_COST_FIELDS", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_LEDGER_COMPACT_ON_START = os.getenv("SETTLEMENT_LEDGER_COMPACT_ON_START", "1").lower() not in {"0", "false", "no"}
# Sell-first startup/cycle policy: settlement replay can be expensive on busy days and is
# not needed to place or repair protective 2c sell orders. Keep it enabled, but run it
# after the first sell-management path so option 2 reaches sell coverage faster.
SETTLEMENT_SYNC_DEFER_UNTIL_AFTER_SELL = os.getenv("SETTLEMENT_SYNC_DEFER_UNTIL_AFTER_SELL", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_DEDUPE_FOR_DAILY_GOAL = os.getenv("SETTLEMENT_DEDUPE_FOR_DAILY_GOAL", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_GLOBAL_DEDUPE_LIMIT = int(os.getenv("SETTLEMENT_GLOBAL_DEDUPE_LIMIT", "20000"))
SETTLEMENT_INTEGRITY_ENABLED = os.getenv("SETTLEMENT_INTEGRITY_ENABLED", "1").lower() not in {"0", "false", "no"}
SETTLEMENT_INTEGRITY_LATEST_JSON_PATH = os.getenv("SETTLEMENT_INTEGRITY_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_settlement_integrity_latest.json")).strip()
SETTLEMENT_INTEGRITY_LATEST_CSV_PATH = os.getenv("SETTLEMENT_INTEGRITY_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_settlement_integrity_latest.csv")).strip()
SETTLEMENT_INTEGRITY_HISTORY_CSV_PATH = os.getenv("SETTLEMENT_INTEGRITY_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_settlement_integrity_history.csv")).strip()

# Balance precision / fee-rounding ledger. Kalshi is adding balance_dollars with
# centi-cent precision for direct members; keep using the legacy integer cents
# field when that is all the API returns, but preserve the higher precision field
# for realized EV, fee-rounding, and account-movement reconciliation when present.
BALANCE_PRECISION_LEDGER_ENABLED = os.getenv("BALANCE_PRECISION_LEDGER_ENABLED", "1").lower() not in {"0", "false", "no"}
BALANCE_PRECISION_LEDGER_INTERVAL_SECONDS = int(os.getenv("BALANCE_PRECISION_LEDGER_INTERVAL_SECONDS", "60"))
# Conservative default remains cent precision because Kalshi's legacy balance field is integer cents.
# Direct-member accounts can expose balance_dollars at $0.0001 precision; set
# FEE_GUARD_BALANCE_PRECISION_DOLLARS=0.0001 once your account consistently returns balance_dollars.
FEE_GUARD_BALANCE_PRECISION_MODE = os.getenv("FEE_GUARD_BALANCE_PRECISION_MODE", "conservative_cent").strip().lower()
FEE_GUARD_BALANCE_PRECISION_DOLLARS = Decimal(os.getenv("FEE_GUARD_BALANCE_PRECISION_DOLLARS", "0.01"))
BALANCE_PRECISION_LEDGER_MAX_ROWS = int(os.getenv("BALANCE_PRECISION_LEDGER_MAX_ROWS", "50000"))
BALANCE_PRECISION_LATEST_JSON_PATH = os.getenv("BALANCE_PRECISION_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_balance_precision_ledger_latest.json")).strip()
BALANCE_PRECISION_LATEST_CSV_PATH = os.getenv("BALANCE_PRECISION_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_balance_precision_ledger_latest.csv")).strip()
BALANCE_PRECISION_LATEST_TXT_PATH = os.getenv("BALANCE_PRECISION_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_balance_precision_ledger_latest.txt")).strip()
BALANCE_PRECISION_HISTORY_CSV_PATH = os.getenv("BALANCE_PRECISION_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_balance_precision_ledger_history.csv")).strip()

DAILY_LEDGER_CSV_PATH = os.getenv("DAILY_LEDGER_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_daily_risk_ledger.csv")).strip()
DAILY_LEDGER_INTERVAL_SECONDS = int(os.getenv("DAILY_LEDGER_INTERVAL_SECONDS", "60"))
MIN_REALIZED_NET_FILL_CENTS = Decimal(os.getenv("MIN_REALIZED_NET_FILL_CENTS", "0.01"))
FEE_GUARD_USE_REALIZED_CUSHION = os.getenv("FEE_GUARD_USE_REALIZED_CUSHION", "1").lower() not in {"0", "false", "no"}
FEE_GUARD_MAX_REALIZED_CUSHION_PER_CONTRACT_CENTS = Decimal(os.getenv("FEE_GUARD_MAX_REALIZED_CUSHION_PER_CONTRACT_CENTS", "0.25"))

# Adaptive recovery tuning. It never lowers the configured RECOVERY_BUFFER unless
# ADAPTIVE_RECOVERY_RELAX_ENABLED=1; by default it only tightens recovery when
# actual fees/partial fills are worse than the pre-trade model.
ADAPTIVE_RECOVERY_ENABLED = os.getenv("ADAPTIVE_RECOVERY_ENABLED", "1").lower() not in {"0", "false", "no"}
ADAPTIVE_RECOVERY_MIN = Decimal(os.getenv("ADAPTIVE_RECOVERY_MIN", str(RECOVERY_BUFFER)))
ADAPTIVE_RECOVERY_MAX = Decimal(os.getenv("ADAPTIVE_RECOVERY_MAX", "2.00"))
ADAPTIVE_RECOVERY_STEP = Decimal(os.getenv("ADAPTIVE_RECOVERY_STEP", "0.05"))
ADAPTIVE_RECOVERY_COOLDOWN_SECONDS = int(os.getenv("ADAPTIVE_RECOVERY_COOLDOWN_SECONDS", "300"))
ADAPTIVE_FEE_DRIFT_TRIGGER_CENTS = Decimal(os.getenv("ADAPTIVE_FEE_DRIFT_TRIGGER_CENTS", "1.00"))
ADAPTIVE_RECOVERY_RELAX_ENABLED = os.getenv("ADAPTIVE_RECOVERY_RELAX_ENABLED", "0").lower() in {"1", "true", "yes"}

# Queue/throughput safety. Increasing a live order can forfeit price-time queue
# priority on some exchange interfaces, so the default preserves the existing
# queue instead of amending upward.
PRESERVE_QUEUE_ON_INCREASE = os.getenv("PRESERVE_QUEUE_ON_INCREASE", "1").lower() not in {"0", "false", "no"}
BATCH_CANCEL_ENABLED = os.getenv("BATCH_CANCEL_ENABLED", "1").lower() not in {"0", "false", "no"}
KNOWN_ORDER_ID_LIMIT = int(os.getenv("KNOWN_ORDER_ID_LIMIT", "500"))
PROCESSED_FILL_ID_LIMIT = int(os.getenv("PROCESSED_FILL_ID_LIMIT", "5000"))

# Optional live WebSocket listener. REST fill sync remains the source of truth
# for fee_cost; the stream is used for low-latency hints and order awareness.
WEBSOCKET_ENABLED = os.getenv("WEBSOCKET_ENABLED", "1").lower() not in {"0", "false", "no"}
# Private sell-critical channels retain a dedicated protected queue. The public
# market_lifecycle_v2 channel is now enabled by default so price-grid changes can
# be consumed directly from Kalshi without waiting for eventually-consistent REST.
# Lifecycle events do not wake the full cycle unless explicitly enabled.
WEBSOCKET_CHANNELS = tuple(ch.strip() for ch in os.getenv("WEBSOCKET_CHANNELS", "fill,user_orders,market_positions,order_group_updates,market_lifecycle_v2").split(",") if ch.strip())
WEBSOCKET_MAX_BACKLOG = int(os.getenv("WEBSOCKET_MAX_BACKLOG", "1000"))
WEBSOCKET_PRIVATE_MAX_BACKLOG = int(os.getenv("WEBSOCKET_PRIVATE_MAX_BACKLOG", "5000"))
WEBSOCKET_PUBLIC_MAX_DRAIN_PER_CYCLE = int(os.getenv("WEBSOCKET_PUBLIC_MAX_DRAIN_PER_CYCLE", "250"))
WEBSOCKET_PRIVATE_EVENT_TYPES = {"fill", "user_order", "market_position", "order_group_updates"}
WEBSOCKET_RECONNECT_BASE_SECONDS = int(os.getenv("WEBSOCKET_RECONNECT_BASE_SECONDS", "2"))
WEBSOCKET_RECONNECT_MAX_SECONDS = int(os.getenv("WEBSOCKET_RECONNECT_MAX_SECONDS", "30"))
WEBSOCKET_AUTH_FAILURE_STOP = os.getenv("WEBSOCKET_AUTH_FAILURE_STOP", "1").lower() not in {"0", "false", "no"}
# Dedicated WebSocket handshake 429 circuit.  A private-stream HTTP 429 should
# not create a tight reconnect loop or be misreported as a VPN/IP transition.
# REST sell-management remains active; this only spaces WebSocket handshakes and
# writes clearer diagnostic proof for Option C.
WEBSOCKET_429_BACKOFF_ENABLED = os.getenv("WEBSOCKET_429_BACKOFF_ENABLED", "1").lower() not in {"0", "false", "no"}
WEBSOCKET_429_BACKOFF_BASE_SECONDS = float(os.getenv("WEBSOCKET_429_BACKOFF_BASE_SECONDS", "10"))
WEBSOCKET_429_BACKOFF_MAX_SECONDS = float(os.getenv("WEBSOCKET_429_BACKOFF_MAX_SECONDS", "90"))
WEBSOCKET_429_BACKOFF_RESET_SECONDS = float(os.getenv("WEBSOCKET_429_BACKOFF_RESET_SECONDS", "300"))
# Explicit client keepalive and queue limits. Kalshi also sends heartbeat ping frames;
# these client settings let the bot detect broken VPN/router paths quickly without
# changing order placement rules. Set any timeout/interval to -1 to pass None.
WEBSOCKET_PING_INTERVAL_SECONDS = float(os.getenv("WEBSOCKET_PING_INTERVAL_SECONDS", "20"))
WEBSOCKET_PING_TIMEOUT_SECONDS = float(os.getenv("WEBSOCKET_PING_TIMEOUT_SECONDS", "20"))
WEBSOCKET_OPEN_TIMEOUT_SECONDS = float(os.getenv("WEBSOCKET_OPEN_TIMEOUT_SECONDS", "10"))
WEBSOCKET_CLOSE_TIMEOUT_SECONDS = float(os.getenv("WEBSOCKET_CLOSE_TIMEOUT_SECONDS", "5"))
WEBSOCKET_MAX_QUEUE_MESSAGES = int(os.getenv("WEBSOCKET_MAX_QUEUE_MESSAGES", "64"))
# Dedicated Trade API websocket hosts are preferred for new integrations; keep a
# fallback env switch because the shared hosts remain supported by Kalshi.
WEBSOCKET_USE_DEDICATED_HOST = os.getenv("WEBSOCKET_USE_DEDICATED_HOST", "1").lower() not in {"0", "false", "no"}
# Only affects orderbook_delta subscriptions. Keeping yes/no book prices on a
# single yes-leg scale avoids no-side price-flip ambiguity in downstream logic.
WEBSOCKET_ORDERBOOK_USE_YES_PRICE = os.getenv("WEBSOCKET_ORDERBOOK_USE_YES_PRICE", "1").lower() not in {"0", "false", "no"}
WEBSOCKET_ORDERBOOK_INITIAL_TICKERS = tuple(x.strip() for x in os.getenv("WEBSOCKET_ORDERBOOK_INITIAL_TICKERS", "").split(",") if x.strip())
# WebSocket burst protection. Kalshi error code 25 means a subscription buffer overflowed.
# Keep private fill/order/position channels alive and temporarily drop heavy L2 deltas.
WEBSOCKET_BUFFER_OVERFLOW_GUARD_ENABLED = os.getenv("WEBSOCKET_BUFFER_OVERFLOW_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
WEBSOCKET_BUFFER_OVERFLOW_THROTTLE_SECONDS = int(os.getenv("WEBSOCKET_BUFFER_OVERFLOW_THROTTLE_SECONDS", "900"))
WEBSOCKET_BUFFER_OVERFLOW_UNSUBSCRIBE_ORDERBOOK_DELTA = os.getenv("WEBSOCKET_BUFFER_OVERFLOW_UNSUBSCRIBE_ORDERBOOK_DELTA", "1").lower() not in {"0", "false", "no"}
WEBSOCKET_BUFFER_OVERFLOW_PRUNE_ORDERBOOK_COMMANDS = os.getenv("WEBSOCKET_BUFFER_OVERFLOW_PRUNE_ORDERBOOK_COMMANDS", "1").lower() not in {"0", "false", "no"}

# Top-candidate orderbook snapshot refresh. REST batch orderbooks remain the
# deterministic fallback. When an orderbook_delta WebSocket sid is available,
# the bot can also request Kalshi's get_snapshot action without adding those
# tickers to the delta subscription.
ORDERBOOK_SNAPSHOT_REFRESH_ENABLED = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_ENABLED", "1").lower() not in {"0", "false", "no"}
ORDERBOOK_SNAPSHOT_REFRESH_TOP_N = int(os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_TOP_N", "12"))
ORDERBOOK_SNAPSHOT_REFRESH_INTERVAL_SECONDS = int(os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_INTERVAL_SECONDS", "30"))
ORDERBOOK_SNAPSHOT_REFRESH_FRESH_SECONDS = int(os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_FRESH_SECONDS", "45"))
ORDERBOOK_SNAPSHOT_REFRESH_USE_WS_GET_SNAPSHOT = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_USE_WS_GET_SNAPSHOT", "0").lower() not in {"0", "false", "no"}
ORDERBOOK_SNAPSHOT_REFRESH_WS_AUTO_SUBSCRIBE = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_WS_AUTO_SUBSCRIBE", "1").lower() not in {"0", "false", "no"}
ORDERBOOK_SNAPSHOT_REFRESH_WS_SEED_TOP_N = int(os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_WS_SEED_TOP_N", "3"))
ORDERBOOK_SNAPSHOT_REFRESH_REST_FALLBACK = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_REST_FALLBACK", "1").lower() not in {"0", "false", "no"}
ORDERBOOK_SNAPSHOT_REFRESH_MAX_REST_TICKERS = int(os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_MAX_REST_TICKERS", "12"))
ORDERBOOK_SNAPSHOT_CACHE_MAX_TICKERS = int(os.getenv("ORDERBOOK_SNAPSHOT_CACHE_MAX_TICKERS", "300"))
ORDERBOOK_SNAPSHOT_REFRESH_LATEST_JSON_PATH = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_orderbook_snapshot_refresh_latest.json")).strip()
ORDERBOOK_SNAPSHOT_REFRESH_LATEST_TXT_PATH = os.getenv("ORDERBOOK_SNAPSHOT_REFRESH_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_orderbook_snapshot_refresh_latest.txt")).strip()

# WebSocket health is advisory by default because REST reconciliation remains the
# source of truth. It exports staleness and lag so operators can see stream problems
# without freezing sell/recovery. Set BUY_ACTION_LIVE_SAFETY_BLOCK_ON_WS_STALE=1
# only after you see repeat stale-stream problems in health exports.
WEBSOCKET_HEALTH_ENABLED = os.getenv("WEBSOCKET_HEALTH_ENABLED", "1").lower() not in {"0", "false", "no"}
WEBSOCKET_HEALTH_INTERVAL_SECONDS = int(os.getenv("WEBSOCKET_HEALTH_INTERVAL_SECONDS", "60"))
WEBSOCKET_STALE_WARN_SECONDS = int(os.getenv("WEBSOCKET_STALE_WARN_SECONDS", "300"))
WEBSOCKET_STALE_BLOCK_SECONDS = int(os.getenv("WEBSOCKET_STALE_BLOCK_SECONDS", "900"))
WEBSOCKET_HEALTH_LATEST_JSON_PATH = os.getenv("WEBSOCKET_HEALTH_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_websocket_health_latest.json")).strip()
WEBSOCKET_HEALTH_LATEST_TXT_PATH = os.getenv("WEBSOCKET_HEALTH_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_websocket_health_latest.txt")).strip()
LIVE_SAFETY_GLOBAL_PAUSE_ON_WEBSOCKET_STALE = os.getenv("LIVE_SAFETY_GLOBAL_PAUSE_ON_WEBSOCKET_STALE", "0").lower() in {"1", "true", "yes"}


# VPN / sudden-IP-change resilience. A VPN toggle can invalidate pooled HTTP
# keep-alive sockets and the authenticated WebSocket stream even though the bot
# process is still healthy. This guard does not loosen trading gates. It only
# detects route/DNS transitions, rebuilds the REST session, refreshes auth time,
# clears stale local L2 hints, and asks the WebSocket listener to reconnect.
HTTP_SESSION_POOL_CONNECTIONS = max(1, int(os.getenv("HTTP_SESSION_POOL_CONNECTIONS", "10")))
HTTP_SESSION_POOL_MAXSIZE = max(1, int(os.getenv("HTTP_SESSION_POOL_MAXSIZE", "20")))
NETWORK_TRANSITION_GUARD_ENABLED = os.getenv("NETWORK_TRANSITION_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_PROBE_INTERVAL_SECONDS = max(2, int(os.getenv("NETWORK_TRANSITION_PROBE_INTERVAL_SECONDS", "15")))
NETWORK_TRANSITION_COOLDOWN_SECONDS = max(1, int(os.getenv("NETWORK_TRANSITION_COOLDOWN_SECONDS", "8")))
NETWORK_TRANSITION_LOCAL_ROUTE_PROBE_ENABLED = os.getenv("NETWORK_TRANSITION_LOCAL_ROUTE_PROBE_ENABLED", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_DNS_PROBE_ENABLED = os.getenv("NETWORK_TRANSITION_DNS_PROBE_ENABLED", "1").lower() not in {"0", "false", "no"}
# DNS answers can rotate on healthy CDNs without a VPN/IP transition. Keep DNS
# visible in reports, but do not make DNS part of the reconnect signature unless
# explicitly enabled by the operator. Route/proxy changes still trigger recovery.
NETWORK_TRANSITION_INCLUDE_DNS_IN_SIGNATURE = os.getenv("NETWORK_TRANSITION_INCLUDE_DNS_IN_SIGNATURE", "0").lower() in {"1", "true", "yes"}
NETWORK_TRANSITION_REBUILD_SESSION_ON_CHANGE = os.getenv("NETWORK_TRANSITION_REBUILD_SESSION_ON_CHANGE", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_REBUILD_SESSION_ON_TRANSPORT = os.getenv("NETWORK_TRANSITION_REBUILD_SESSION_ON_TRANSPORT", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_RECONNECT_WEBSOCKET_ON_CHANGE = os.getenv("NETWORK_TRANSITION_RECONNECT_WEBSOCKET_ON_CHANGE", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_RECONNECT_WEBSOCKET_ON_TRANSPORT = os.getenv("NETWORK_TRANSITION_RECONNECT_WEBSOCKET_ON_TRANSPORT", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_CLEAR_LOCAL_L2_ON_CHANGE = os.getenv("NETWORK_TRANSITION_CLEAR_LOCAL_L2_ON_CHANGE", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_FORCE_AUTH_RESYNC_ON_CHANGE = os.getenv("NETWORK_TRANSITION_FORCE_AUTH_RESYNC_ON_CHANGE", "1").lower() not in {"0", "false", "no"}
NETWORK_TRANSITION_REPORT_INTERVAL_SECONDS = max(5, int(os.getenv("NETWORK_TRANSITION_REPORT_INTERVAL_SECONDS", "30")))
NETWORK_TRANSITION_SOCKET_TIMEOUT_SECONDS = max(0.2, float(os.getenv("NETWORK_TRANSITION_SOCKET_TIMEOUT_SECONDS", "1.25")))
NETWORK_TRANSITION_MAX_DNS_ADDRS = max(1, int(os.getenv("NETWORK_TRANSITION_MAX_DNS_ADDRS", "8")))
NETWORK_TRANSITION_SIGNATURE_SCHEMA = "route_dns_v3_opt_in" if NETWORK_TRANSITION_INCLUDE_DNS_IN_SIGNATURE else "route_v3_dns_report_only"
NETWORK_TRANSITION_LATEST_JSON_PATH = os.getenv("NETWORK_TRANSITION_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_network_transition_guard_latest.json")).strip()
NETWORK_TRANSITION_LATEST_TXT_PATH = os.getenv("NETWORK_TRANSITION_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_network_transition_guard_latest.txt")).strip()
BUY_ACTION_LIVE_SAFETY_BLOCK_ON_WS_STALE = os.getenv("BUY_ACTION_LIVE_SAFETY_BLOCK_ON_WS_STALE", "0").lower() in {"1", "true", "yes"}

# Private Stream SLA + Buy Pause Watchdog. Private fill/order/position events are
# sell-critical; if they are delayed, backlogged, or had to be rescued right
# before the sell loop, pause NEW buy handoff while keeping sell placement/repair
# fully active. This avoids adding inventory when the bot is not receiving private
# stream state quickly enough to place fee-safe 2c exits.
PRIVATE_STREAM_SLA_ENABLED = os.getenv("PRIVATE_STREAM_SLA_ENABLED", "1").lower() not in {"0", "false", "no"}
PRIVATE_STREAM_SLA_BLOCK_BUY_ACTION = os.getenv("PRIVATE_STREAM_SLA_BLOCK_BUY_ACTION", "0" if BUY_PRIORITY_HEDGE_ADVISORY_MODE else "1").lower() not in {"0", "false", "no"}
PRIVATE_STREAM_SLA_REQUIRE_FILL_POSITION_CHANNELS = os.getenv("PRIVATE_STREAM_SLA_REQUIRE_FILL_POSITION_CHANNELS", "1").lower() not in {"0", "false", "no"}
PRIVATE_STREAM_SLA_BLOCK_IF_NO_PRIVATE_EVENTS = os.getenv("PRIVATE_STREAM_SLA_BLOCK_IF_NO_PRIVATE_EVENTS", "0").lower() in {"1", "true", "yes"}
PRIVATE_STREAM_SLA_NO_EVENT_GRACE_SECONDS = int(os.getenv("PRIVATE_STREAM_SLA_NO_EVENT_GRACE_SECONDS", "180"))
PRIVATE_STREAM_SLA_WARN_PRIVATE_QUEUE_DEPTH = int(os.getenv("PRIVATE_STREAM_SLA_WARN_PRIVATE_QUEUE_DEPTH", "10"))
PRIVATE_STREAM_SLA_MAX_PRIVATE_QUEUE_DEPTH = int(os.getenv("PRIVATE_STREAM_SLA_MAX_PRIVATE_QUEUE_DEPTH", "50"))
PRIVATE_STREAM_SLA_MAX_PRIVATE_EVENT_LAG_SECONDS = int(os.getenv("PRIVATE_STREAM_SLA_MAX_PRIVATE_EVENT_LAG_SECONDS", "60"))
