LOG_ACCOUNT_LIMITS = os.getenv("LOG_ACCOUNT_LIMITS", "1").lower() not in {"0", "false", "no"}

# Local token-bucket throttling. Kalshi rate limits are token-budget based, with
# separate read/write buckets. This keeps the bot from hammering into 429s when
# there are many positions or cleanup operations. Values are updated from
# /account/limits at startup when available.
API_SELF_THROTTLE_ENABLED = os.getenv("API_SELF_THROTTLE_ENABLED", "1").lower() not in {"0", "false", "no"}
API_READ_TOKEN_BUDGET_PER_SECOND = Decimal(os.getenv("API_READ_TOKEN_BUDGET_PER_SECOND", "200"))
API_WRITE_TOKEN_BUDGET_PER_SECOND = Decimal(os.getenv("API_WRITE_TOKEN_BUDGET_PER_SECOND", "100"))
API_TOKEN_BUCKET_SECONDS = Decimal(os.getenv("API_TOKEN_BUCKET_SECONDS", "2"))
ACCOUNT_LIMITS_ARE_REQUESTS_PER_SECOND = os.getenv("ACCOUNT_LIMITS_ARE_REQUESTS_PER_SECOND", "0").lower() not in {"0", "false", "no"}
API_429_ADAPTIVE_PENALTY_ENABLED = os.getenv("API_429_ADAPTIVE_PENALTY_ENABLED", "1").lower() not in {"0", "false", "no"}
API_429_PENALTY_COST_MULTIPLIER = Decimal(os.getenv("API_429_PENALTY_COST_MULTIPLIER", "3.00"))
# Rolling 429 circuit breaker. A burst of read 429s means public discovery is
# starving private/sell-critical reads; write 429s mean urgent order lifecycle
# writes may be at risk. The circuit pauses only NEW buy handoff and extends
# low-priority read cooldowns; it never disables sell repair, reduce-only, or
# cancel paths.
API_429_BURST_CIRCUIT_ENABLED = os.getenv("API_429_BURST_CIRCUIT_ENABLED", "1").lower() not in {"0", "false", "no"}
API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION = os.getenv("API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION", "1").lower() not in {"0", "false", "no"}
API_429_BURST_WINDOW_SECONDS = max(60, int(os.getenv("API_429_BURST_WINDOW_SECONDS", "600")))
API_429_BURST_MAX_READ_429 = max(1, int(os.getenv("API_429_BURST_MAX_READ_429", "24")))
API_429_BURST_MAX_WRITE_429 = max(1, int(os.getenv("API_429_BURST_MAX_WRITE_429", "4")))
API_429_BURST_BUY_PAUSE_SECONDS = max(30, int(os.getenv("API_429_BURST_BUY_PAUSE_SECONDS", "300")))
API_429_BURST_LOW_READ_COOLDOWN_SECONDS = max(60, int(os.getenv("API_429_BURST_LOW_READ_COOLDOWN_SECONDS", "600")))
API_429_BURST_MAX_EVENTS = max(50, int(os.getenv("API_429_BURST_MAX_EVENTS", "500")))
API_429_BURST_CIRCUIT_JSON_PATH = os.getenv("API_429_BURST_CIRCUIT_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_api_429_burst_circuit_latest.json")).strip()
API_429_BURST_CIRCUIT_TXT_PATH = os.getenv("API_429_BURST_CIRCUIT_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_api_429_burst_circuit_latest.txt")).strip()
API_429_BURST_CIRCUIT_HISTORY_CSV_PATH = os.getenv("API_429_BURST_CIRCUIT_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_api_429_burst_circuit_history.csv")).strip()
API_LIMITS_SNAPSHOT_JSON_PATH = os.getenv("API_LIMITS_SNAPSHOT_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_api_limits_latest.json")).strip()
ENDPOINT_COSTS_SNAPSHOT_JSON_PATH = os.getenv("ENDPOINT_COSTS_SNAPSHOT_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_endpoint_costs_latest.json")).strip()

# Write-burst reserve guard. Kalshi rate limits use separate read/write token
# buckets; this guard keeps normal discovery/batch writes from draining the
# write bucket needed for urgent sell repairs, IOC/FOK exits, decreases, and
# cancels. It never bypasses exchange/user-data/order-group/fee guards.
API_WRITE_BURST_GUARD_ENABLED = os.getenv("API_WRITE_BURST_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
API_WRITE_BURST_RESERVE_FRACTION = Decimal(os.getenv("API_WRITE_BURST_RESERVE_FRACTION", "0.35"))
API_WRITE_BURST_RESERVE_MIN_TOKENS = Decimal(os.getenv("API_WRITE_BURST_RESERVE_MIN_TOKENS", "30"))
API_WRITE_BURST_RESERVE_MAX_TOKENS = Decimal(os.getenv("API_WRITE_BURST_RESERVE_MAX_TOKENS", "120"))
API_WRITE_BURST_WAIT_LOG_SECONDS = int(os.getenv("API_WRITE_BURST_WAIT_LOG_SECONDS", "15"))
API_WRITE_BURST_LATEST_JSON_PATH = os.getenv("API_WRITE_BURST_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_write_burst_guard_latest.json")).strip()
API_WRITE_BURST_LATEST_TXT_PATH = os.getenv("API_WRITE_BURST_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_write_burst_guard_latest.txt")).strip()

# Read-priority reserve guard. Health bundles showed deep discovery reads hitting
# 429s while live reconciliation and sell-repair reads were also active. This
# reserves part of the read bucket for critical/high priority reads: fills,
# settlements, live positions/orders, balance, limits, exchange status, and
# active sell-repair orderbooks. Discovery/telemetry reads wait when they would
# spend that reserve. It does not block urgent sells or loosen strategy gates.
API_READ_PRIORITY_GUARD_ENABLED = os.getenv("API_READ_PRIORITY_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
API_READ_PRIORITY_RESERVE_FRACTION = Decimal(os.getenv("API_READ_PRIORITY_RESERVE_FRACTION", "0.30"))
API_READ_PRIORITY_RESERVE_MIN_TOKENS = Decimal(os.getenv("API_READ_PRIORITY_RESERVE_MIN_TOKENS", "40"))
API_READ_PRIORITY_RESERVE_MAX_TOKENS = Decimal(os.getenv("API_READ_PRIORITY_RESERVE_MAX_TOKENS", "120"))
API_READ_PRIORITY_WAIT_LOG_SECONDS = int(os.getenv("API_READ_PRIORITY_WAIT_LOG_SECONDS", "15"))
API_READ_PRIORITY_LATEST_JSON_PATH = os.getenv("API_READ_PRIORITY_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_read_priority_guard_latest.json")).strip()
API_READ_PRIORITY_LATEST_TXT_PATH = os.getenv("API_READ_PRIORITY_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_read_priority_guard_latest.txt")).strip()
# Low-priority read slow-lane. When a low-priority discovery/enrichment read hits
# a 429, pause only low-priority reads for a short cooldown while critical
# reconciliation, sell repair, fills, settlements, and account-limit reads continue.
API_LOW_PRIORITY_READ_COOLDOWN_ON_429_ENABLED = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_ON_429_ENABLED", "1").lower() not in {"0", "false", "no"}
# Fail fast instead of sleeping inside the live loop while a low-priority read
# family is cooling down. This preserves positions/orders/balance reconciliation
# and sell management; only discovery/enrichment reads are deferred.
API_LOW_PRIORITY_READ_COOLDOWN_FAIL_FAST_ENABLED = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_FAIL_FAST_ENABLED", "1").lower() not in {"0", "false", "no"}
API_LOW_PRIORITY_READ_DEFER_LOG_SECONDS = max(1, int(os.getenv("API_LOW_PRIORITY_READ_DEFER_LOG_SECONDS", "30")))
API_LOW_PRIORITY_READ_COOLDOWN_SECONDS = int(os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_SECONDS", "180"))
API_LOW_PRIORITY_READ_COOLDOWN_MAX_SECONDS = int(os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_MAX_SECONDS", "600"))
API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_ENABLED = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_ENABLED", "1").lower() not in {"0", "false", "no"}
API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR = Decimal(os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR", "1.75"))
API_LOW_PRIORITY_READ_COOLDOWN_STREAK_RESET_SECONDS = int(os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_STREAK_RESET_SECONDS", "900"))
API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_PATH = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_PATH", "1").lower() not in {"0", "false", "no"}
API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_FAMILY = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_FAMILY", "1").lower() not in {"0", "false", "no"}
API_LOW_PRIORITY_READ_COOLDOWN_REPORT_PATH = os.getenv("API_LOW_PRIORITY_READ_COOLDOWN_REPORT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_low_priority_read_cooldown_latest.json")).strip()


# Fee rounding model. Kalshi now documents trade fees rounded to centicents plus
# a per-order rounding accumulator. For pre-trade safety, the default models a
# conservative single-fill fee; realized fee_cost from fills remains source of truth.
FEE_GUARD_FEE_ROUNDING_MODE = os.getenv("FEE_GUARD_FEE_ROUNDING_MODE", "kalshi_single_fill").strip().lower()  # kalshi_single_fill, legacy_cent
FEE_GUARD_STRESS_PARTIAL_FILLS = int(os.getenv("FEE_GUARD_STRESS_PARTIAL_FILLS", "3"))
FEE_GUARD_STRESS_MIN_FILL_QTY_FP = Decimal(os.getenv("FEE_GUARD_STRESS_MIN_FILL_QTY_FP", "1.00"))

# Market-quality scoring exports a live allow/avoid signal for the buy side and
