MARKET_QUALITY_NO_HISTORY_SCORE = Decimal(os.getenv("MARKET_QUALITY_NO_HISTORY_SCORE", "60"))

# Orderbook batching cuts read load when managing many live positions.
BATCH_ORDERBOOK_ENABLED = os.getenv("BATCH_ORDERBOOK_ENABLED", "1").lower() not in {"0", "false", "no"}
