ORDER_GROUP_ENABLED = os.getenv("ORDER_GROUP_ENABLED", "0").lower() not in {"0", "false", "no"}
ORDER_GROUP_ID = os.getenv("ORDER_GROUP_ID", "").strip()
ORDER_GROUP_AUTO_CREATE = os.getenv("ORDER_GROUP_AUTO_CREATE", "0").lower() in {"1", "true", "yes"}
