ORDER_GROUP_CONTRACTS_LIMIT_FP = Decimal(os.getenv("ORDER_GROUP_CONTRACTS_LIMIT_FP", "100.00"))
ORDER_GROUP_VERIFY_ON_START = os.getenv("ORDER_GROUP_VERIFY_ON_START", "1").lower() not in {"0", "false", "no"}
ORDER_GROUP_UPDATE_LIMIT_ON_START = os.getenv("ORDER_GROUP_UPDATE_LIMIT_ON_START", "1").lower() not in {"0", "false", "no"}
