ORDER_GROUP_TRIGGERED_PAUSE_WRITES = os.getenv("ORDER_GROUP_TRIGGERED_PAUSE_WRITES", "1").lower() not in {"0", "false", "no"}
ORDER_GROUP_AUTO_RESET_ENABLED = os.getenv("ORDER_GROUP_AUTO_RESET_ENABLED", "0").lower() in {"1", "true", "yes"}
