ORDER_GROUP_STATUS_SYNC_ON_START = os.getenv("ORDER_GROUP_STATUS_SYNC_ON_START", "1").lower() not in {"0", "false", "no"}
ORDER_GROUP_STATUS_SYNC_INTERVAL_SECONDS = int(os.getenv("ORDER_GROUP_STATUS_SYNC_INTERVAL_SECONDS", "120"))
ORDER_GROUP_REQUIRE_FOR_BUY_ACTION_HANDOFF = os.getenv("ORDER_GROUP_REQUIRE_FOR_BUY_ACTION_HANDOFF", "1").lower() not in {"0", "false", "no"}
ORDER_GROUP_TRIPWIRE_LATEST_JSON_PATH = os.getenv("ORDER_GROUP_TRIPWIRE_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_order_group_tripwire_latest.json")).strip()
