ORDER_GROUP_LATEST_JSON_PATH = ORDER_GROUP_TRIPWIRE_LATEST_JSON_PATH

# Order API mode. Kalshi's event-market V2 order endpoint uses a single YES-side
# bid/ask book and the legacy /portfolio/orders shape is scheduled for future
# deprecation. Dedicated hedge lockdown therefore defaults to V2-only mutations.
ORDER_API_VERSION = os.getenv("ORDER_API_VERSION", "v2").strip().lower()  # v2, legacy, auto
ORDER_API_LEGACY_FALLBACK = os.getenv("ORDER_API_LEGACY_FALLBACK", "0").lower() not in {"0", "false", "no"}
SELF_TRADE_PREVENTION_TYPE = os.getenv("SELF_TRADE_PREVENTION_TYPE", "taker_at_cross").strip().lower()
# Kalshi V2 currently rejects reduce_only on resting/GTC orders. The sell bot
# still caps sell size from live position/bucket math before placing, but only
# includes reduce_only where the V2 endpoint accepts it. This fixes the observed
# live blocker: "reduce_only can only be used with IoC orders" on 2c resting exits.
V2_REDUCE_ONLY_MODE = os.getenv("V2_REDUCE_ONLY_MODE", "ioc_only").strip().lower()  # off, ioc_only, non_resting, always
V2_RETRY_WITHOUT_REDUCE_ONLY = os.getenv("V2_RETRY_WITHOUT_REDUCE_ONLY", "1").lower() not in {"0", "false", "no"}
SELL_PLACEMENT_AUDIT_ENABLED = os.getenv("SELL_PLACEMENT_AUDIT_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_PLACEMENT_AUDIT_LATEST_JSON_PATH = os.getenv("SELL_PLACEMENT_AUDIT_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_placement_audit_latest.json")).strip()
SELL_PLACEMENT_AUDIT_LATEST_CSV_PATH = os.getenv("SELL_PLACEMENT_AUDIT_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_placement_audit_latest.csv")).strip()
SELL_PLACEMENT_AUDIT_HISTORY_CSV_PATH = os.getenv("SELL_PLACEMENT_AUDIT_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_placement_audit_history.csv")).strip()
SELL_PLACEMENT_AUDIT_MAX_ROWS = int(os.getenv("SELL_PLACEMENT_AUDIT_MAX_ROWS", "200"))
SELL_ROUTE_VISIBILITY_HINTS_ENABLED = os.getenv("SELL_ROUTE_VISIBILITY_HINTS_ENABLED", "1").lower() not in {"0", "false", "no"}

# Resting sell coverage / queue-gap repair. Queue preservation is valuable, but
# the prior behavior could leave a 2c resting order permanently smaller than the
# 40% sell target. This watchdog preserves the old queue briefly, then amends
# upward when the uncovered target gap persists.
SELL_COVERAGE_AUDIT_ENABLED = os.getenv("SELL_COVERAGE_AUDIT_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_COVERAGE_AUDIT_LATEST_JSON_PATH = os.getenv("SELL_COVERAGE_AUDIT_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_coverage_audit_latest.json")).strip()
SELL_COVERAGE_AUDIT_LATEST_CSV_PATH = os.getenv("SELL_COVERAGE_AUDIT_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_coverage_audit_latest.csv")).strip()
SELL_COVERAGE_AUDIT_HISTORY_CSV_PATH = os.getenv("SELL_COVERAGE_AUDIT_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_coverage_audit_history.csv")).strip()
