QUEUE_GAP_REPAIR_ENABLED = os.getenv("QUEUE_GAP_REPAIR_ENABLED", "1").lower() not in {"0", "false", "no"}
QUEUE_GAP_REPAIR_AFTER_SECONDS = int(os.getenv("QUEUE_GAP_REPAIR_AFTER_SECONDS", "45"))
QUEUE_GAP_REPAIR_MIN_GAP_FP = Decimal(os.getenv("QUEUE_GAP_REPAIR_MIN_GAP_FP", "1.00"))
QUEUE_GAP_REPAIR_MIN_COVERAGE_PCT = Decimal(os.getenv("QUEUE_GAP_REPAIR_MIN_COVERAGE_PCT", "100.00"))
QUEUE_GAP_REPAIR_FORCE_IF_NO_ACTIVE_SELL = os.getenv("QUEUE_GAP_REPAIR_FORCE_IF_NO_ACTIVE_SELL", "1").lower() not in {"0", "false", "no"}

# 2c Sell Liveness Watchdog. Placement/coverage audits prove that orders were
# attempted and sized; this watchdog answers the next live question: is each
# resting 2c exit actually alive, covered, visible, and moving before close?
SELL_LIVENESS_ENABLED = os.getenv("SELL_LIVENESS_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_LIVENESS_LATEST_JSON_PATH = os.getenv("SELL_LIVENESS_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_liveness_latest.json")).strip()
SELL_LIVENESS_LATEST_CSV_PATH = os.getenv("SELL_LIVENESS_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_liveness_latest.csv")).strip()
SELL_LIVENESS_HISTORY_CSV_PATH = os.getenv("SELL_LIVENESS_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_sell_liveness_history.csv")).strip()
SELL_LIVENESS_MAX_ROWS = int(os.getenv("SELL_LIVENESS_MAX_ROWS", "300"))
SELL_LIVENESS_STALE_NO_FILL_SECONDS = int(os.getenv("SELL_LIVENESS_STALE_NO_FILL_SECONDS", "180"))
SELL_LIVENESS_STALLED_QUEUE_SECONDS = int(os.getenv("SELL_LIVENESS_STALLED_QUEUE_SECONDS", "300"))
SELL_LIVENESS_MIN_COVERAGE_PCT = Decimal(os.getenv("SELL_LIVENESS_MIN_COVERAGE_PCT", "100.00"))
SELL_LIVENESS_MIN_EXIT_DEPTH_COVERAGE_PCT = Decimal(os.getenv("SELL_LIVENESS_MIN_EXIT_DEPTH_COVERAGE_PCT", "50.00"))
SELL_LIVENESS_MIN_QUEUE_VELOCITY_FP_PER_MIN = Decimal(os.getenv("SELL_LIVENESS_MIN_QUEUE_VELOCITY_FP_PER_MIN", str(QUEUE_ETA_MIN_VELOCITY_FP_PER_MIN)))
POST_WRITE_SELL_VERIFY_ENABLED = os.getenv("POST_WRITE_SELL_VERIFY_ENABLED", "1").lower() not in {"0", "false", "no"}
POST_WRITE_SELL_VERIFY_INTERVAL_SECONDS = int(os.getenv("POST_WRITE_SELL_VERIFY_INTERVAL_SECONDS", "15"))

# Sell-first priority guard. When live inventory exists without covered resting
# exits, order management runs before heavy analytics/discovery. This prevents
# low-priority market scans from delaying the core 2c sell placement path.
SELL_FIRST_PRIORITY_ENABLED = os.getenv("SELL_FIRST_PRIORITY_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_FIRST_DEFER_ANALYTICS_WHEN_POSITIONS = os.getenv("SELL_FIRST_DEFER_ANALYTICS_WHEN_POSITIONS", "1").lower() not in {"0", "false", "no"}
SELL_FIRST_DEFER_ONLY_UNCOVERED = os.getenv("SELL_FIRST_DEFER_ONLY_UNCOVERED", "1").lower() not in {"0", "false", "no"}
SELL_FIRST_DEFER_ANALYTICS_ON_FIRST_CYCLE = os.getenv("SELL_FIRST_DEFER_ANALYTICS_ON_FIRST_CYCLE", "1").lower() not in {"0", "false", "no"}
SELL_FIRST_LOG_EVERY_SECONDS = int(os.getenv("SELL_FIRST_LOG_EVERY_SECONDS", "30"))

# WebSocket position hints are authoritative enough to rescue the sell path when
# REST /portfolio/positions is stale/empty or is queried before fresh WS events
# are drained. Hints are short-lived and only add missing non-zero tickers.
WS_POSITION_SELL_FALLBACK_ENABLED = os.getenv("WS_POSITION_SELL_FALLBACK_ENABLED", "1").lower() not in {"0", "false", "no"}
WS_POSITION_SELL_HINT_MAX_AGE_SECONDS = int(os.getenv("WS_POSITION_SELL_HINT_MAX_AGE_SECONDS", "120"))
WS_POSITION_SELL_HINT_LIMIT = int(os.getenv("WS_POSITION_SELL_HINT_LIMIT", "300"))
SELL_PATH_DOCTOR_ENABLED = os.getenv("SELL_PATH_DOCTOR_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_PATH_DOCTOR_LATEST_JSON_PATH = os.getenv("SELL_PATH_DOCTOR_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_path_doctor_latest.json")).strip()
SELL_PATH_DOCTOR_LATEST_TXT_PATH = os.getenv("SELL_PATH_DOCTOR_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_path_doctor_latest.txt")).strip()
# Sell-latency rescue: after any pre-sell analytics/reporting work, redrain private
# WS events and refresh positions/orders so newly filled buys cannot wait behind
# low-priority exports until the 15m market is already determined/settled.
SELL_RESCUE_AFTER_PREWORK_ENABLED = os.getenv("SELL_RESCUE_AFTER_PREWORK_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_RESCUE_FORCE_POSITION_REFRESH_AFTER_PREWORK = os.getenv("SELL_RESCUE_FORCE_POSITION_REFRESH_AFTER_PREWORK", "1").lower() not in {"0", "false", "no"}
SELL_RESCUE_REFRESH_ORDERBOOKS = os.getenv("SELL_RESCUE_REFRESH_ORDERBOOKS", "1").lower() not in {"0", "false", "no"}
SELL_RESCUE_LATEST_JSON_PATH = os.getenv("SELL_RESCUE_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_latency_rescue_latest.json")).strip()
SELL_RESCUE_LATEST_TXT_PATH = os.getenv("SELL_RESCUE_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_latency_rescue_latest.txt")).strip()

# Sell Path Watchdog Auto-Recovery. This is a hard sell-side safety layer: if
# active inventory exists without a live managed 2c exit for more than a few
# seconds, heavy analytics/buy-handoff work is paused and the next sell pass is
# treated as urgent. It never weakens FeeGuard; it only prevents naked inventory
# from being hidden behind discovery/analytics work.
SELL_PATH_WATCHDOG_ENABLED = os.getenv("SELL_PATH_WATCHDOG_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS = int(os.getenv("SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS", "8"))
SELL_PATH_WATCHDOG_BLOCK_BUY_ACTION = os.getenv("SELL_PATH_WATCHDOG_BLOCK_BUY_ACTION", "0" if BUY_PRIORITY_HEDGE_ADVISORY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_PATH_WATCHDOG_BYPASS_MARKET_QUALITY_BLOCKS = os.getenv("SELL_PATH_WATCHDOG_BYPASS_MARKET_QUALITY_BLOCKS", "1").lower() not in {"0", "false", "no"}
SELL_PATH_WATCHDOG_LATEST_JSON_PATH = os.getenv("SELL_PATH_WATCHDOG_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_path_watchdog_latest.json")).strip()
SELL_PATH_WATCHDOG_LATEST_TXT_PATH = os.getenv("SELL_PATH_WATCHDOG_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_path_watchdog_latest.txt")).strip()

# Partial-fill residual protection. Once a fee-approved 2c sell has partially
# filled, the leftover can be smaller than the original profitable-size gate.
# Canceling that residual leaves inventory naked. Preserve the already-resting
# residual, and when no order exists, only promote the replacement size upward
# if the larger replacement still clears FeeGuard.
SELL_RESIDUAL_KEEP_APPROVED_ORDER_ENABLED = os.getenv("SELL_RESIDUAL_KEEP_APPROVED_ORDER_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_RESIDUAL_PROMOTE_FEE_SAFE_REPLACEMENT_ENABLED = os.getenv("SELL_RESIDUAL_PROMOTE_FEE_SAFE_REPLACEMENT_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_RESIDUAL_PROMOTE_MIN_CUM_FILLED_FP = Decimal(os.getenv("SELL_RESIDUAL_PROMOTE_MIN_CUM_FILLED_FP", "0.01"))
SELL_RESIDUAL_PROMOTE_MAX_EXTRA_OVER_TARGET_FP = Decimal(os.getenv("SELL_RESIDUAL_PROMOTE_MAX_EXTRA_OVER_TARGET_FP", "4.00"))
# If the normal fractional recovery target is too small to clear FeeGuard, escalate
# to a full-position 2c sell only when that larger order passes the same strict
# after-fee rules. This preserves the "net well above fees" rule and fixes cases
# where 4-of-10 is fee-blocked but 10-of-10 is fee-safe.
SELL_FULL_POSITION_FEE_SAFE_ESCALATION_ENABLED = os.getenv("SELL_FULL_POSITION_FEE_SAFE_ESCALATION_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_FULL_POSITION_ESCALATION_REQUIRE_NO_ACTIVE_ORDER = os.getenv("SELL_FULL_POSITION_ESCALATION_REQUIRE_NO_ACTIVE_ORDER", "1").lower() not in {"0", "false", "no"}
# Full-position 2c coverage fixes the uncovered-residual pattern where a 10-contract
# buy received only a 4-contract recovery sell and then the leftover 6 contracts were
# treated as below-target/no_target. Default ON because it only sells existing live
# inventory at the same strict 2c target after FeeGuard passes.
SELL_FULL_POSITION_2C_COVERAGE_ENABLED = os.getenv("SELL_FULL_POSITION_2C_COVERAGE_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_FEE_GUARD = os.getenv("SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_FEE_GUARD", "1").lower() not in {"0", "false", "no"}
SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_NO_ACTIVE_ORDER = os.getenv("SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_NO_ACTIVE_ORDER", "1").lower() not in {"0", "false", "no"}
SELL_FULL_POSITION_2C_COVERAGE_MIN_DELTA_FP = Decimal(os.getenv("SELL_FULL_POSITION_2C_COVERAGE_MIN_DELTA_FP", "0.01"))

# Residual-after-recovery mode. The support bundle showed the bot sold the normal
# 40% recovery packet, then left the remaining 60% position open because it was
# already above the configured fractional target. This mode continues to cover
# live residual inventory at the same 2c target after the configured recovery
# packet has filled. It does not affect new buys, and the residual order must pass
# both an incremental after-fee edge floor and a combined recovered-position edge
# floor before it can bypass the standalone 10-contract FeeGuard gate.
SELL_REMAINDER_AFTER_RECOVERY_ENABLED = os.getenv("SELL_REMAINDER_AFTER_RECOVERY_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_REMAINDER_AFTER_RECOVERY_STRICT_2C = os.getenv("SELL_REMAINDER_AFTER_RECOVERY_STRICT_2C", "1").lower() not in {"0", "false", "no"}
SELL_REMAINDER_AFTER_RECOVERY_MIN_CUM_FILLED_FP = Decimal(os.getenv("SELL_REMAINDER_AFTER_RECOVERY_MIN_CUM_FILLED_FP", "0.01"))
SELL_REMAINDER_AFTER_RECOVERY_MIN_GROUP_NET_CENTS = Decimal(os.getenv("SELL_REMAINDER_AFTER_RECOVERY_MIN_GROUP_NET_CENTS", str(MIN_NET_EDGE_CENTS)))
SELL_REMAINDER_AFTER_RECOVERY_MIN_INCREMENTAL_NET_CENTS = Decimal(os.getenv("SELL_REMAINDER_AFTER_RECOVERY_MIN_INCREMENTAL_NET_CENTS", "2.00"))
SELL_REMAINDER_AFTER_RECOVERY_MIN_PER_CONTRACT_CENTS = Decimal(os.getenv("SELL_REMAINDER_AFTER_RECOVERY_MIN_PER_CONTRACT_CENTS", str(MIN_NET_EDGE_PER_CONTRACT_CENTS)))
SELL_REMAINDER_AFTER_RECOVERY_REQUIRE_BASE_TARGET_FILLED = os.getenv("SELL_REMAINDER_AFTER_RECOVERY_REQUIRE_BASE_TARGET_FILLED", "1").lower() not in {"0", "false", "no"}
SELL_REMAINDER_AFTER_RECOVERY_MAX_QTY_FP = Decimal(os.getenv("SELL_REMAINDER_AFTER_RECOVERY_MAX_QTY_FP", "1000.00"))

# Residual Sell Fill-Probability Tuner + optional 2c/3c residual ladder.
# The live default is intentionally conservative: always keep 2c coverage first.
# The 3c ladder is report/advisory-only unless explicitly enabled, so this
# upgrade cannot remove the working 2c sell path by default.
RESIDUAL_SELL_TUNER_ENABLED = os.getenv("RESIDUAL_SELL_TUNER_ENABLED", "1").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_TUNER_INTERVAL_SECONDS = int(os.getenv("RESIDUAL_SELL_TUNER_INTERVAL_SECONDS", "30"))
RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION = os.getenv("RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_TUNER_BUY_PAUSE_SECONDS = int(os.getenv("RESIDUAL_SELL_TUNER_BUY_PAUSE_SECONDS", "120"))
RESIDUAL_SELL_TUNER_MIN_HISTORY_ROWS = int(os.getenv("RESIDUAL_SELL_TUNER_MIN_HISTORY_ROWS", "4"))
