RESIDUAL_SELL_TUNER_NEAR_CLOSE_SECONDS = int(os.getenv("RESIDUAL_SELL_TUNER_NEAR_CLOSE_SECONDS", "120"))
RESIDUAL_SELL_TUNER_LATEST_JSON_PATH = os.getenv("RESIDUAL_SELL_TUNER_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_residual_sell_tuner_latest.json")).strip()
