RESIDUAL_SELL_TUNER_LATEST_TXT_PATH = os.getenv("RESIDUAL_SELL_TUNER_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_residual_sell_tuner_latest.txt")).strip()
RESIDUAL_SELL_TUNER_HISTORY_CSV_PATH = os.getenv("RESIDUAL_SELL_TUNER_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_residual_sell_tuner_history.csv")).strip()
RESIDUAL_SELL_TUNER_SUPPORT_ZIPS = os.getenv("RESIDUAL_SELL_TUNER_SUPPORT_ZIPS", "").strip()
RESIDUAL_SELL_LADDER_ENABLED = os.getenv("RESIDUAL_SELL_LADDER_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_LADDER_3C_ADVISORY_ENABLED = os.getenv("RESIDUAL_SELL_LADDER_3C_ADVISORY_ENABLED", "1").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_LADDER_3C_LIVE_ENABLED = os.getenv("RESIDUAL_SELL_LADDER_3C_LIVE_ENABLED", "0").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_LADDER_3C_PRICE = Decimal(os.getenv("RESIDUAL_SELL_LADDER_3C_PRICE", "0.03"))
RESIDUAL_SELL_LADDER_3C_MIN_SECONDS_TO_CLOSE = int(os.getenv("RESIDUAL_SELL_LADDER_3C_MIN_SECONDS_TO_CLOSE", "240"))
RESIDUAL_SELL_LADDER_3C_REQUIRE_STRONG_HISTORY = os.getenv("RESIDUAL_SELL_LADDER_3C_REQUIRE_STRONG_HISTORY", "1").lower() not in {"0", "false", "no"}
RESIDUAL_SELL_LADDER_3C_REQUIRE_NO_ACTIVE_2C = os.getenv("RESIDUAL_SELL_LADDER_3C_REQUIRE_NO_ACTIVE_2C", "1").lower() not in {"0", "false", "no"}


# Sell Queue Aging + Emergency Exit Optimizer. This is a sell-side execution
# layer only. It keeps the strict 2c target by default, uses queue age/position
# and visible same-side bids to decide when a resting 2c sell is unlikely to
# finish in time, and can take an immediate still-profitable bid only after
# FeeGuard confirms the net edge. Same-price refresh is report-only by default
# because refreshing forfeits price-time priority.
SELL_QUEUE_EXIT_OPTIMIZER_ENABLED = os.getenv("SELL_QUEUE_EXIT_OPTIMIZER_ENABLED", "1").lower() not in {"0", "false", "no"}
SELL_QUEUE_EXIT_TAKE_PROFITABLE_BID_ENABLED = os.getenv("SELL_QUEUE_EXIT_TAKE_PROFITABLE_BID_ENABLED", "0" if HEDGE_2C_ONLY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_QUEUE_EXIT_REFRESH_ENABLED = os.getenv("SELL_QUEUE_EXIT_REFRESH_ENABLED", "0").lower() not in {"0", "false", "no"}
SELL_QUEUE_EXIT_BLOCK_BUY_ACTION = os.getenv("SELL_QUEUE_EXIT_BLOCK_BUY_ACTION", "0" if BUY_PRIORITY_HEDGE_ADVISORY_MODE else "1").lower() not in {"0", "false", "no"}
SELL_QUEUE_EXIT_LATEST_JSON_PATH = os.getenv("SELL_QUEUE_EXIT_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_queue_exit_optimizer_latest.json")).strip()
SELL_QUEUE_EXIT_LATEST_CSV_PATH = os.getenv("SELL_QUEUE_EXIT_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_queue_exit_optimizer_latest.csv")).strip()
SELL_QUEUE_EXIT_LATEST_TXT_PATH = os.getenv("SELL_QUEUE_EXIT_LATEST_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_queue_exit_optimizer_latest.txt")).strip()
SELL_QUEUE_EXIT_HISTORY_CSV_PATH = os.getenv("SELL_QUEUE_EXIT_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_queue_exit_optimizer_history.csv")).strip()
SELL_QUEUE_EXIT_MAX_ROWS = int(os.getenv("SELL_QUEUE_EXIT_MAX_ROWS", "300"))
SELL_QUEUE_EXIT_MAX_REST_SECONDS = int(os.getenv("SELL_QUEUE_EXIT_MAX_REST_SECONDS", "75"))
SELL_QUEUE_EXIT_MAX_SECONDS_SINCE_FILL = int(os.getenv("SELL_QUEUE_EXIT_MAX_SECONDS_SINCE_FILL", "60"))
SELL_QUEUE_EXIT_STALLED_QUEUE_AHEAD_FP = Decimal(os.getenv("SELL_QUEUE_EXIT_STALLED_QUEUE_AHEAD_FP", "25.00"))
SELL_QUEUE_EXIT_STALLED_QUEUE_ETA_SECONDS = int(os.getenv("SELL_QUEUE_EXIT_STALLED_QUEUE_ETA_SECONDS", "120"))
SELL_QUEUE_EXIT_NEAR_CLOSE_SECONDS = int(os.getenv("SELL_QUEUE_EXIT_NEAR_CLOSE_SECONDS", "150"))
SELL_QUEUE_EXIT_MIN_VISIBLE_QTY_FP = Decimal(os.getenv("SELL_QUEUE_EXIT_MIN_VISIBLE_QTY_FP", "1.00"))
SELL_QUEUE_EXIT_CANCEL_RESTING_TO_TAKE_BID = os.getenv("SELL_QUEUE_EXIT_CANCEL_RESTING_TO_TAKE_BID", "1").lower() not in {"0", "false", "no"}
SELL_QUEUE_EXIT_TIF = os.getenv("SELL_QUEUE_EXIT_TIF", "immediate_or_cancel").strip().lower()
SELL_QUEUE_EXIT_REPORT_TOP_PROBLEMS = int(os.getenv("SELL_QUEUE_EXIT_REPORT_TOP_PROBLEMS", "80"))

# Recovery Cycle Audit. This measures whether the 4-of-10 2c recovery sale
# actually filled, only rested in queue, or missed before settlement. It is used
# as a buy-side no-new-exposure signal without changing the strict 2c target.
RECOVERY_CYCLE_AUDIT_ENABLED = os.getenv("RECOVERY_CYCLE_AUDIT_ENABLED", "1").lower() not in {"0", "false", "no"}
