ORDERBOOK_PRESSURE_MAX_SIZE_MULTIPLIER = Decimal(os.getenv("ORDERBOOK_PRESSURE_MAX_SIZE_MULTIPLIER", "1.20"))

# Buy Action Close-Risk Guard. A 1c entry needs enough runway for the 4-at-2c
# recovery leg to rest and fill before settlement. This prevents late-window
# entries from becoming unsold leftover exposure; sells themselves remain strict 2c.
BUY_ACTION_CLOSE_RISK_GUARD_ENABLED = os.getenv("BUY_ACTION_CLOSE_RISK_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
BUY_ACTION_MIN_SECONDS_TO_CLOSE = int(os.getenv("BUY_ACTION_MIN_SECONDS_TO_CLOSE", "180"))
BUY_ACTION_WARN_SECONDS_TO_CLOSE = int(os.getenv("BUY_ACTION_WARN_SECONDS_TO_CLOSE", "300"))


# Prospective Recovery Entry Projection. The action/miner side used to score a
# 10-contract candidate as if every contract would exit at 2c. The live strategy
# actually buys 10 and sells 6 at 2c, keeping 4 upside contracts. This layer
# projects that exact 10->6 packet before an action row is exported.
RECOVERY_ENTRY_PROJECTION_ENABLED = os.getenv("RECOVERY_ENTRY_PROJECTION_ENABLED", "1").lower() not in {"0", "false", "no"}
RECOVERY_ENTRY_PROJECTION_REQUIRE_FOR_ACTION_PLAN = os.getenv("RECOVERY_ENTRY_PROJECTION_REQUIRE_FOR_ACTION_PLAN", "0" if BUY_PRIORITY_HEDGE_ADVISORY_MODE else "1").lower() not in {"0", "false", "no"}
RECOVERY_ENTRY_PROJECTION_LATEST_JSON_PATH = os.getenv("RECOVERY_ENTRY_PROJECTION_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_recovery_entry_projection_latest.json")).strip()
