RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT = Decimal(os.getenv("RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT", "100.00"))
