MANAGED_ORDER_BACKFILL_INTERVAL_SECONDS = int(os.getenv("MANAGED_ORDER_BACKFILL_INTERVAL_SECONDS", "60"))
MANAGED_ORDER_BACKFILL_LOOKBACK_SECONDS = int(os.getenv("MANAGED_ORDER_BACKFILL_LOOKBACK_SECONDS", "7200"))
MANAGED_ORDER_BACKFILL_MAX_PAGES = int(os.getenv("MANAGED_ORDER_BACKFILL_MAX_PAGES", "3"))
MANAGED_ORDER_BACKFILL_LIMIT_PER_PAGE = int(os.getenv("MANAGED_ORDER_BACKFILL_LIMIT_PER_PAGE", "1000"))
MANAGED_ORDER_BACKFILL_STATUSES = tuple(x.strip() for x in os.getenv("MANAGED_ORDER_BACKFILL_STATUSES", "executed,canceled").split(",") if x.strip())
MANAGED_ORDER_BACKFILL_MAX_AUDIT_ROWS = int(os.getenv("MANAGED_ORDER_BACKFILL_MAX_AUDIT_ROWS", "500"))
MANAGED_ORDER_BACKFILL_LATEST_JSON_PATH = os.getenv("MANAGED_ORDER_BACKFILL_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_managed_order_backfill_latest.json")).strip()
MANAGED_ORDER_BACKFILL_LATEST_CSV_PATH = os.getenv("MANAGED_ORDER_BACKFILL_LATEST_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_managed_order_backfill_latest.csv")).strip()
MANAGED_ORDER_BACKFILL_HISTORY_CSV_PATH = os.getenv("MANAGED_ORDER_BACKFILL_HISTORY_CSV_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_sell_bot_managed_order_backfill_history.csv")).strip()

# Account endpoint-cost discovery. Kalshi exposes non-default endpoint token costs;
# enabling this lets the local self-throttle adapt instead of assuming all routes
# cost the default 10 tokens.
ENDPOINT_COSTS_ENABLED = os.getenv("ENDPOINT_COSTS_ENABLED", "1").lower() not in {"0", "false", "no"}
ENDPOINT_COSTS_REFRESH_SECONDS = int(os.getenv("ENDPOINT_COSTS_REFRESH_SECONDS", "3600"))

# Exchange/user-data freshness guards. They let the bot keep reading/reconciling,
# but pause live order writes when exchange trading is inactive or REST user data
# appears materially stale relative to recent write-sensitive decisions.
EXCHANGE_STATUS_CHECK_ENABLED = os.getenv("EXCHANGE_STATUS_CHECK_ENABLED", "1").lower() not in {"0", "false", "no"}
EXCHANGE_STATUS_CACHE_SECONDS = int(os.getenv("EXCHANGE_STATUS_CACHE_SECONDS", "15"))
EXCHANGE_STATUS_PAUSE_WRITES = os.getenv("EXCHANGE_STATUS_PAUSE_WRITES", "1").lower() not in {"0", "false", "no"}
# Kalshi V2 accepts cancel_order_on_pause on create. Scalping exits default to cancel-on-pause
# so a stale 2c order does not silently survive a pause/reopen cycle.
CANCEL_ORDER_ON_PAUSE = os.getenv("CANCEL_ORDER_ON_PAUSE", "1").lower() not in {"0", "false", "no"}
EXCHANGE_PAUSE_FAIL_CLOSED = os.getenv("EXCHANGE_PAUSE_FAIL_CLOSED", "1").lower() not in {"0", "false", "no"}
# Schedule/maintenance write guard. The exchange status endpoint is immediate;
# the schedule endpoint adds planned maintenance-window awareness so queued live
# writes are not flushed seconds before a scheduled pause.
EXCHANGE_SCHEDULE_GUARD_ENABLED = os.getenv("EXCHANGE_SCHEDULE_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
EXCHANGE_SCHEDULE_REFRESH_SECONDS = int(os.getenv("EXCHANGE_SCHEDULE_REFRESH_SECONDS", "300"))
EXCHANGE_MAINTENANCE_BUFFER_SECONDS = int(os.getenv("EXCHANGE_MAINTENANCE_BUFFER_SECONDS", "120"))
EXCHANGE_SCHEDULE_FAIL_OPEN = os.getenv("EXCHANGE_SCHEDULE_FAIL_OPEN", "1").lower() not in {"0", "false", "no"}
# Exchange-announcement guard. Kalshi removed GET /exchange/announcements from
# the Predictions REST API on 2026-07-04. Keep the old switch for local backward
# compatibility, but default the removed endpoint OFF and rely on exchange status,
# schedule, WebSocket lifecycle, and reconnect guards instead of spending a read
# token on a guaranteed 404 every process start.
EXCHANGE_ANNOUNCEMENTS_ENDPOINT_REMOVED = os.getenv("EXCHANGE_ANNOUNCEMENTS_ENDPOINT_REMOVED", "1").lower() not in {"0", "false", "no"}
