# Execution Quality Controller: ambiguous mutation reconciliation.
# A transport timeout or 5xx can happen after the exchange accepted a write. The
# old flow could then fall back with a fresh client_order_id, especially after a
# batch-create failure, creating duplicate protective sells. This controller keeps
# the original client identity, reconciles through private user_order evidence and
# bounded REST reads, validates cancel/amend/decrease response identity, and fails
# closed when the outcome cannot be proven. It never loosens FeeGuard or changes
# the 40% at 2c strategy.
MUTATION_OUTCOME_RECONCILE_ENABLED = os.getenv("MUTATION_OUTCOME_RECONCILE_ENABLED", "1").lower() not in {"0", "false", "no"}
MUTATION_RESPONSE_IDENTITY_GUARD_ENABLED = os.getenv("MUTATION_RESPONSE_IDENTITY_GUARD_ENABLED", "1").lower() not in {"0", "false", "no"}
MUTATION_AMBIGUOUS_FAIL_CLOSED = os.getenv("MUTATION_AMBIGUOUS_FAIL_CLOSED", "1").lower() not in {"0", "false", "no"}
# Create retries reuse the exact same client_order_id, as required for safe
# replay after an unconfirmed write. Other mutations get one wire attempt and
# then reconcile; this avoids repeating non-idempotent reduce_by calls.
MUTATION_CREATE_SAME_ID_MAX_ATTEMPTS = max(1, int(os.getenv("MUTATION_CREATE_SAME_ID_MAX_ATTEMPTS", "2")))
MUTATION_WRITE_MAX_ATTEMPTS = max(1, int(os.getenv("MUTATION_WRITE_MAX_ATTEMPTS", "1")))
MUTATION_RECONCILE_POLL_ATTEMPTS = max(1, int(os.getenv("MUTATION_RECONCILE_POLL_ATTEMPTS", "3")))
MUTATION_RECONCILE_WAIT_SECONDS = max(0.0, float(os.getenv("MUTATION_RECONCILE_WAIT_SECONDS", "0.50")))
MUTATION_RECONCILE_LOOKBACK_SECONDS = max(30, int(os.getenv("MUTATION_RECONCILE_LOOKBACK_SECONDS", "600")))
MUTATION_RECONCILE_MAX_PAGES = max(1, int(os.getenv("MUTATION_RECONCILE_MAX_PAGES", "2")))
MUTATION_RECONCILE_LIMIT_PER_PAGE = max(10, min(1000, int(os.getenv("MUTATION_RECONCILE_LIMIT_PER_PAGE", "200"))))
MUTATION_JOURNAL_MAX_EVENTS = max(20, int(os.getenv("MUTATION_JOURNAL_MAX_EVENTS", "200")))
MUTATION_WS_ORDER_CACHE_MAX_EVENTS = max(20, int(os.getenv("MUTATION_WS_ORDER_CACHE_MAX_EVENTS", "200")))
MUTATION_OUTCOME_JOURNAL_JSON_PATH = os.getenv("MUTATION_OUTCOME_JOURNAL_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_mutation_outcome_journal_latest.json")).strip()
MUTATION_OUTCOME_JOURNAL_TXT_PATH = os.getenv("MUTATION_OUTCOME_JOURNAL_TXT_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_mutation_outcome_journal_latest.txt")).strip()


# Rate-Limit-Aware Smart Amend Scheduler. Amend/decrease/write calls are locally
# token-budget aware; this scheduler avoids low-value same-price re-amends while
# preserving urgent 2c exit repairs, reductions, near-close exits, and large
# coverage gaps. It never loosens fee gates or places buys.
