SMART_AMEND_MIN_SECONDS_BETWEEN_PRICE_AMENDS = int(os.getenv("SMART_AMEND_MIN_SECONDS_BETWEEN_PRICE_AMENDS", "4"))
SMART_AMEND_MIN_GAP_QTY_FP = Decimal(os.getenv("SMART_AMEND_MIN_GAP_QTY_FP", "1.00"))
