SMART_AMEND_RECENT_EVENT_LIMIT = int(os.getenv("SMART_AMEND_RECENT_EVENT_LIMIT", "200"))
SMART_AMEND_REPORT_INTERVAL_SECONDS = int(os.getenv("SMART_AMEND_REPORT_INTERVAL_SECONDS", "30"))
SMART_AMEND_SCHEDULER_LATEST_JSON_PATH = os.getenv("SMART_AMEND_SCHEDULER_LATEST_JSON_PATH", os.path.join(EXPORT_DIR, "kalshi_15m_smart_amend_scheduler_latest.json")).strip()
