# Hedge lockdown is a hard safety overlay for this dedicated hedge bot. Local
# config may contain old experimental settings from prior builds; when enabled,
# live startup is forced back to the contract: sell 40% only, at contract-side
# 2c only, with no batch V2 NO-side inverse / IOC / residual / full-position /
# urgent-exit paths. Disable only if intentionally running a different strategy.
def _apply_hedge_lockdown_defaults() -> None:
    global HEDGE_2C_ONLY_MODE, HEDGE_TARGET_FRACTION, HEDGE_EXIT_PRICE, TARGET_FRACTION_OVERRIDE
    global SELL_PRICE, TARGET_2C_PRICE, TARGET_2C_STRICT_SELL_PRICE
    global HEDGE_NO_SIDE_USE_LEGACY_ORDER, HEDGE_BLOCK_NO_SIDE_V2_INVERSE, HEDGE_BLOCK_NON_2C_SELL_PAYLOAD, HEDGE_BLOCK_OVER_TARGET_SELL_QTY
    global ORDER_API_VERSION, ORDER_API_LEGACY_FALLBACK
    global IOC_ENABLED, BATCH_CREATE_V2_ENABLED, BATCH_CREATE_V2_SINGLE_FALLBACK
    global POST_ONLY_CROSS_FALLBACK_ENABLED, POST_ONLY_CROSS_FALLBACK_TIF, POST_ONLY_CROSS_FALLBACK_REQUIRE_FEE_GUARD, POST_ONLY_CROSS_FALLBACK_MIN_NET_TO_TOTAL_FEES_RATIO
    global SELL_FULL_POSITION_2C_COVERAGE_ENABLED, SELL_FULL_POSITION_FEE_SAFE_ESCALATION_ENABLED, SELL_REMAINDER_AFTER_RECOVERY_ENABLED
    global SELL_RESIDUAL_PROMOTE_FEE_SAFE_REPLACEMENT_ENABLED, SELL_QUEUE_EXIT_TAKE_PROFITABLE_BID_ENABLED, URGENT_EXIT_ENABLED
    global RESIDUAL_SELL_LADDER_ENABLED, RESIDUAL_SELL_LADDER_3C_LIVE_ENABLED, RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION
    global DYNAMIC_SELL_PRICE_ENABLED, AUTO_PRICE_SEARCH_ENABLED, DYNAMIC_SELL_PRICE_MAX
    global MARKET_DISCOVERY_TARGET_SELL_PRICE, OPPORTUNITY_MINER_MAX_SELL_PRICE, DAILY_GOAL_STRETCH_SELL_PRICE
    global ENTRY_LADDER_MAX_SELL_PRICE, ENTRY_LADDER_PILOT_SELL_PRICE, ENTRY_LADDER_NORMAL_SELL_PRICE, ENTRY_LADDER_AGGRESSIVE_SELL_PRICE
    global BUY_SIDE_NEGATIVE_PNL_RECOMMENDED_SELL_PRICE, BUY_FEEDBACK_BAD_RECOMMENDED_SELL_PRICE, BUY_FEEDBACK_STALE_RECOMMENDED_SELL_PRICE
    global BUY_ACTION_AUDIT_CAUTION_RECOMMENDED_SELL_PRICE, BUY_ACTION_AUDIT_BAD_RECOMMENDED_SELL_PRICE
    global BUY_SIDE_LOW_SCORE_RECOMMENDED_SELL_PRICE, BUY_SIDE_CRITICAL_RECOMMENDED_SELL_PRICE, BUY_SIDE_LOW_VELOCITY_RECOMMENDED_SELL_PRICE
    global DEAD_MARKET_ESCAPE_RECOMMENDED_SELL_PRICE, BUY_SIDE_LOW_TRADE_TAPE_RECOMMENDED_SELL_PRICE
    if not HEDGE_LOCKDOWN_ENFORCE:
        return
    HEDGE_2C_ONLY_MODE = True
    HEDGE_TARGET_FRACTION = Decimal("0.40")
    TARGET_FRACTION_OVERRIDE = "0.40"
    HEDGE_EXIT_PRICE = Decimal("0.02")
    SELL_PRICE = Decimal("0.02")
    TARGET_2C_PRICE = Decimal("0.02")
    TARGET_2C_STRICT_SELL_PRICE = True
    DYNAMIC_SELL_PRICE_ENABLED = False
    AUTO_PRICE_SEARCH_ENABLED = False
    DYNAMIC_SELL_PRICE_MAX = Decimal("0.02")
    MARKET_DISCOVERY_TARGET_SELL_PRICE = Decimal("0.02")
    OPPORTUNITY_MINER_MAX_SELL_PRICE = Decimal("0.02")
    DAILY_GOAL_STRETCH_SELL_PRICE = Decimal("0.02")
    ENTRY_LADDER_MAX_SELL_PRICE = Decimal("0.02")
    ENTRY_LADDER_PILOT_SELL_PRICE = Decimal("0.02")
    ENTRY_LADDER_NORMAL_SELL_PRICE = Decimal("0.02")
    ENTRY_LADDER_AGGRESSIVE_SELL_PRICE = Decimal("0.02")
    BUY_SIDE_NEGATIVE_PNL_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_FEEDBACK_BAD_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_FEEDBACK_STALE_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_ACTION_AUDIT_CAUTION_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_ACTION_AUDIT_BAD_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_SIDE_LOW_SCORE_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_SIDE_CRITICAL_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_SIDE_LOW_VELOCITY_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    DEAD_MARKET_ESCAPE_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    BUY_SIDE_LOW_TRADE_TAPE_RECOMMENDED_SELL_PRICE = Decimal("0.02")
    # Dedicated hedge mode stays on Kalshi Create Order V2. V2 quotes the YES
    # book only, so a contract-side NO exit at 2c is represented as a YES-book
    # bid near 98c. v41.19 keeps that official route and preserves explicit logs,
    # audits, and Export20 route decoding so it is not mistaken for "no sell".
    ORDER_API_VERSION = "v2"
    ORDER_API_LEGACY_FALLBACK = False
    HEDGE_NO_SIDE_USE_LEGACY_ORDER = False
    HEDGE_BLOCK_NO_SIDE_V2_INVERSE = False
    HEDGE_BLOCK_NON_2C_SELL_PAYLOAD = True
