    BATCH_CREATE_V2_ENABLED = False
    BATCH_CREATE_V2_SINGLE_FALLBACK = False
    SELL_FULL_POSITION_2C_COVERAGE_ENABLED = False
    SELL_FULL_POSITION_FEE_SAFE_ESCALATION_ENABLED = False
    SELL_REMAINDER_AFTER_RECOVERY_ENABLED = False
