def create_public_tls_context() -> ssl.SSLContext:
    context = ssl.create_default_context(cafile=PUBLIC_CA_BUNDLE)
    context.check_hostname = True
    context.verify_mode = ssl.CERT_REQUIRED
    if hasattr(ssl, "TLSVersion"):
        context.minimum_version = ssl.TLSVersion.TLSv1_2
    return context


def create_http_session() -> requests.Session:
    session = requests.Session()
    # requests otherwise inherits HTTP(S)_PROXY and netrc credentials. The public
    # launcher strips those variables and the engine independently opts out.
    session.trust_env = False
    try:
        adapter = requests.adapters.HTTPAdapter(
            pool_connections=HTTP_SESSION_POOL_CONNECTIONS,
            pool_maxsize=HTTP_SESSION_POOL_MAXSIZE,
            pool_block=False,
        )
        session.mount("https://", adapter)
    except Exception:
        pass
    try:
        session.headers.update({"User-Agent": f"Kalshi15mSellBotPublic/{BUILD_ID}"})
    except Exception:
        pass
    return session


SESSION = create_http_session()


def http_session_request(method: str, url: str, **kwargs):
    # Defense in depth: credentials are never sent to an arbitrary environment
    # variable, redirects cannot move them to another origin, and TLS validation
    # cannot be disabled by a caller.
    url = validate_outbound_rest_url(url)
    if "verify" in kwargs and kwargs.get("verify") not in {True, PUBLIC_CA_BUNDLE}:
        raise RuntimeError("The pinned public CA bundle cannot be replaced or disabled")
    if kwargs.get("allow_redirects") is True:
        raise RuntimeError("HTTP redirects are not permitted for Kalshi API requests")
    if kwargs.get("proxies"):
        raise RuntimeError("Proxies are not permitted for authenticated exchange traffic")
    if kwargs.get("cert"):
        raise RuntimeError("Unexpected client certificates are not permitted")
    kwargs["verify"] = PUBLIC_CA_BUNDLE
    kwargs["allow_redirects"] = False
    kwargs["proxies"] = {}
    with HTTP_SESSION_LOCK:
        response = SESSION.request(method=method, url=url, **kwargs)
    if 300 <= int(getattr(response, "status_code", 0) or 0) < 400:
        raise RuntimeError("Kalshi API redirect response refused")
    return response
