def configure_endpoint_costs(costs_payload: dict) -> None:
    if not isinstance(costs_payload, dict):
        return
    default_cost = parse_decimal(costs_payload.get("default_cost", "10"), "10")
    parsed = {}
    for row in costs_payload.get("endpoint_costs", []) or []:
        method = str(row.get("method") or "").upper()
        path = _normalize_endpoint_cost_path(row.get("path") or "")
        if not method or not path:
            continue
        parsed[(method, path)] = parse_decimal(row.get("cost", default_cost), str(default_cost))
    ENDPOINT_COSTS["default_cost"] = default_cost
    ENDPOINT_COSTS["costs"] = parsed
    ENDPOINT_COSTS["last_refresh_ts"] = now_ts()
    meta = STATE.setdefault("meta", {})
    meta["api_default_endpoint_cost"] = str(default_cost)
    meta["api_non_default_endpoint_costs"] = len(parsed)
    try:
        atomic_write_json(ENDPOINT_COSTS_SNAPSHOT_JSON_PATH, {
            "snapshot_ts": now_ts(),
            "utc_day": utc_day_from_ts(now_ts()),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "default_cost": str(default_cost),
            "non_default_count": len(parsed),
            "endpoint_costs": [
                {"method": method, "path": path, "cost": str(cost)}
                for (method, path), cost in sorted(parsed.items())
            ],
            "source": "GET /account/endpoint_costs",
            "documented_local_overrides_enabled": bool(DOCUMENTED_ENDPOINT_COST_OVERRIDES_ENABLED),
            "documented_local_overrides": [
                {"method": method, "path": path, "cost": str(cost)}
                for (method, path), cost in sorted(DOCUMENTED_ENDPOINT_COST_OVERRIDES.items())
            ],
        })
    except Exception as e:
        LOGGER.debug("Could not write endpoint cost snapshot: %s", e)


def maybe_refresh_endpoint_costs(force: bool = False) -> None:
    global ENDPOINT_COSTS_UNSUPPORTED
    if not ENDPOINT_COSTS_ENABLED or ENDPOINT_COSTS_UNSUPPORTED:
        return
    now = now_ts()
    if not force and now - int(ENDPOINT_COSTS.get("last_refresh_ts", 0) or 0) < ENDPOINT_COSTS_REFRESH_SECONDS:
        return
    try:
        # Docs publish this as an account endpoint, but the live environment may return 404
        # for some accounts/tiers. Treat it as optional and fall back to the documented default.
        payload = signed_request("GET", "/account/endpoint_costs", timeout=8, max_retries=1) if (API_KEY_ID and PRIVATE_KEY is not None) else public_get_json("/account/endpoint_costs", timeout=8, max_retries=1)
        configure_endpoint_costs(payload)
        LOGGER.info(
            "Account endpoint costs | default_cost=%s | non_default_count=%s",
            ENDPOINT_COSTS.get("default_cost"),
            len(ENDPOINT_COSTS.get("costs") or {}),
        )
    except KalshiEndpointUnsupported as e:
        ENDPOINT_COSTS_UNSUPPORTED = True
        ENDPOINT_COSTS["last_refresh_ts"] = now
        STATE.setdefault("meta", {})["api_endpoint_costs_unsupported"] = "1"
        LOGGER.warning("Account endpoint costs unavailable/unsupported; using default endpoint cost=%s | %s", ENDPOINT_COSTS.get("default_cost"), e)
    except Exception as e:
        ENDPOINT_COSTS["last_refresh_ts"] = now
        LOGGER.warning("Could not read account endpoint costs; using default endpoint cost=%s | %s", ENDPOINT_COSTS.get("default_cost"), e)


def _limit_bucket_value(limits: dict, side: str, *flat_names):
    if not isinstance(limits, dict):
        return None
    bucket = limits.get(side)
    if isinstance(bucket, dict):
        for name in ("refill_rate", "rate", "limit", "requests_per_second", "tokens_per_second"):
            if bucket.get(name) is not None:
                return bucket.get(name)
    for name in flat_names:
        if limits.get(name) is not None:
            return limits.get(name)
    return None


def _limit_bucket_capacity(limits: dict, side: str):
    bucket = limits.get(side) if isinstance(limits, dict) else None
    if isinstance(bucket, dict):
        for name in ("bucket_capacity", "capacity", "burst", "max_tokens"):
            if bucket.get(name) is not None:
                return bucket.get(name)
    return None


def configure_rate_limiter_from_limits(limits: dict) -> None:
    if not isinstance(limits, dict):
        return
    # Kalshi account limits have been observed as both documented flat
    # read_limit/write_limit request-per-second fields and nested token-bucket
    # objects. Support both shapes; only multiply flat request limits by the
    # default endpoint cost when ACCOUNT_LIMITS_ARE_REQUESTS_PER_SECOND=1.
    read_limit = _limit_bucket_value(limits, "read", "read_limit", "read_refill_rate", "read_requests_per_second")
    write_limit = _limit_bucket_value(limits, "write", "write_limit", "write_refill_rate", "write_requests_per_second")
    if read_limit is None and write_limit is None:
        STATE.setdefault("meta", {})["api_account_limits_unrecognized"] = json.dumps(limits, sort_keys=True)[:1000]
        return
    default_cost = parse_decimal(ENDPOINT_COSTS.get("default_cost", "10"), "10")
    read_rate = parse_decimal(read_limit, "0") if read_limit is not None else None
    write_rate = parse_decimal(write_limit, "0") if write_limit is not None else None
    # Nested bucket payloads are already token-rate-like; flat payloads are
    # request-per-second limits and need conversion to local token budgets.
    if ACCOUNT_LIMITS_ARE_REQUESTS_PER_SECOND and not (isinstance(limits.get("read"), dict) or isinstance(limits.get("write"), dict)):
        if read_rate is not None:
            read_rate *= default_cost
        if write_rate is not None:
            write_rate *= default_cost
    read_capacity = _limit_bucket_capacity(limits, "read")
    write_capacity = _limit_bucket_capacity(limits, "write")
    RATE_LIMITER.configure(read_rate=read_rate, write_rate=write_rate, read_capacity=read_capacity, write_capacity=write_capacity)
    meta = STATE.setdefault("meta", {})
    if read_limit is not None:
        meta["api_read_limit_raw"] = str(read_limit)
        meta["api_read_token_budget_per_second"] = str(read_rate)
        if read_capacity is not None:
            meta["api_read_bucket_capacity"] = str(read_capacity)
    if write_limit is not None:
        meta["api_write_limit_raw"] = str(write_limit)
        meta["api_write_token_budget_per_second"] = str(write_rate)
        if write_capacity is not None:
            meta["api_write_bucket_capacity"] = str(write_capacity)
    meta["api_account_limits_are_requests_per_second"] = bool(ACCOUNT_LIMITS_ARE_REQUESTS_PER_SECOND and not (isinstance(limits.get("read"), dict) or isinstance(limits.get("write"), dict)))
    meta["api_rate_limit_default_endpoint_cost"] = str(default_cost)
    try:
        atomic_write_json(API_LIMITS_SNAPSHOT_JSON_PATH, {
            "snapshot_ts": now_ts(),
            "utc_day": utc_day_from_ts(now_ts()),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "usage_tier": limits.get("usage_tier"),
            "read_raw": limits.get("read"),
            "write_raw": limits.get("write"),
            "effective_read_tokens_per_second": str(RATE_LIMITER.rates.get("read")),
            "effective_write_tokens_per_second": str(RATE_LIMITER.rates.get("write")),
            "default_endpoint_cost": str(default_cost),
            "flat_limits_treated_as_requests_per_second": bool(meta["api_account_limits_are_requests_per_second"]),
            "source": "GET /account/limits",
        })
    except Exception as e:
        LOGGER.debug("Could not write account API limits snapshot: %s", e)


def note_rate_limit_response(method: str, path: str, json_body=None, status_code: int = 429) -> None:
    if int(status_code or 0) != 429:
        return
    kind = endpoint_rate_kind(method, path)
    cost = endpoint_token_cost(method, path, json_body=json_body)
    meta = STATE.setdefault("meta", {})
    meta["api_429_count"] = int(meta.get("api_429_count", 0) or 0) + 1
    if kind == "read":
        meta["api_read_429_count"] = int(meta.get("api_read_429_count", 0) or 0) + 1
    else:
        meta["api_write_429_count"] = int(meta.get("api_write_429_count", 0) or 0) + 1
    meta["api_last_429_ts"] = now_ts()
    meta["api_last_429_method"] = str(method).upper()
    meta["api_last_429_path"] = path
    meta["api_last_429_kind"] = kind
    meta["api_last_429_cost"] = str(cost)
    try:
        record_api_429_burst_event(kind, method, path, cost)
        build_api_429_burst_circuit_payload(context="rate_limit_response", mutate=True)
    except Exception:
        pass
    if kind == "read" and API_LOW_PRIORITY_READ_COOLDOWN_ON_429_ENABLED:
        try:
            read_priority = endpoint_read_priority(method, path)
        except Exception:
            read_priority = "normal"
        if read_priority == "low":
            base_cooldown = max(0, int(API_LOW_PRIORITY_READ_COOLDOWN_SECONDS))
            max_cooldown = max(base_cooldown, int(API_LOW_PRIORITY_READ_COOLDOWN_MAX_SECONDS))
            now = now_ts()
            bucket_key = "global"
            if API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_PATH:
                try:
                    bucket_key = "path:" + (str(path or "").split("?")[0][:160] or "global")
                except Exception:
                    bucket_key = "path:global"
            family_key = ""
            if API_LOW_PRIORITY_READ_COOLDOWN_BUCKETS_BY_FAMILY:
                try:
                    family_key = "family:" + low_priority_read_cooldown_family_key(path)
                except Exception:
                    family_key = "family:global"
            buckets = meta.setdefault("api_low_priority_read_cooldown_buckets", {})
            if not isinstance(buckets, dict):
                buckets = {}
                meta["api_low_priority_read_cooldown_buckets"] = buckets
            def _bump_cooldown_bucket(key: str) -> tuple:
                if not key:
                    return {}, 0
                b = buckets.setdefault(key, {}) if isinstance(buckets, dict) else {}
                last = int(b.get("last_429_ts", 0) or 0)
                if API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_ENABLED and last and now - last <= max(1, API_LOW_PRIORITY_READ_COOLDOWN_STREAK_RESET_SECONDS):
                    st = int(b.get("streak", 0) or 0) + 1
                else:
                    st = 1
                b["last_429_ts"] = now
                b["streak"] = st
                b["path"] = str(path or "")[:200]
                return b, st
            bucket, path_streak = _bump_cooldown_bucket(bucket_key)
            family_bucket, family_streak = _bump_cooldown_bucket(family_key) if family_key else ({}, 0)
            streak = max(1, int(path_streak or 0), int(family_streak or 0))
            multiplier = Decimal("1")
            if API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_ENABLED and streak > 1:
                try:
                    multiplier = API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR ** (streak - 1)
                except Exception:
                    multiplier = Decimal("1")
            cooldown = int(min(max_cooldown, max(0, Decimal(base_cooldown) * multiplier)))
            if cooldown > 0:
                until = now + cooldown
                bucket["cooldown_seconds"] = cooldown
                bucket["until_ts"] = until
                bucket["path"] = str(path or "")[:200]
                meta["api_low_priority_read_cooldown_until_ts"] = max(int(meta.get("api_low_priority_read_cooldown_until_ts", 0) or 0), until)
                meta["api_low_priority_read_cooldown_last_path"] = str(path or "")[:200]
                meta["api_low_priority_read_cooldown_last_bucket"] = bucket_key
                meta["api_low_priority_read_cooldown_last_family"] = family_key
                meta["api_low_priority_read_cooldown_count"] = int(meta.get("api_low_priority_read_cooldown_count", 0) or 0) + 1
                meta["api_low_priority_read_cooldown_last_streak"] = streak
                meta["api_low_priority_read_cooldown_last_family_streak"] = family_streak
                meta["api_low_priority_read_cooldown_last_seconds"] = cooldown
                LOGGER.warning(
                    "Low-priority read slow-lane cooldown | path=%s | seconds=%s | streak=%s | until_ct=%s",
                    path, cooldown, streak, central_time_iso_from_ts(meta["api_low_priority_read_cooldown_until_ts"]),
                )
                try:
                    atomic_write_json(API_LOW_PRIORITY_READ_COOLDOWN_REPORT_PATH, {
                        "snapshot_ts": now,
                        "utc_day": utc_day_from_ts(now),
                        "instance": INSTANCE_NAME,
                        "build_id": BUILD_ID,
                        "last_path": meta.get("api_low_priority_read_cooldown_last_path", ""),
                        "last_bucket": meta.get("api_low_priority_read_cooldown_last_bucket", ""),
                        "last_family": meta.get("api_low_priority_read_cooldown_last_family", ""),
                        "last_cooldown_seconds": cooldown,
                        "last_streak": streak,
                        "last_family_streak": family_streak,
                        "global_until_ts": meta.get("api_low_priority_read_cooldown_until_ts", 0),
                        "global_until_ct": central_time_iso_from_ts(meta.get("api_low_priority_read_cooldown_until_ts", 0)),
                        "base_cooldown_seconds": API_LOW_PRIORITY_READ_COOLDOWN_SECONDS,
                        "max_cooldown_seconds": API_LOW_PRIORITY_READ_COOLDOWN_MAX_SECONDS,
                        "fail_fast_enabled": bool(API_LOW_PRIORITY_READ_COOLDOWN_FAIL_FAST_ENABLED),
                        "defer_count": int(meta.get("api_low_priority_read_defer_count", 0) or 0),
                        "last_defer_ts": int(meta.get("api_low_priority_read_last_defer_ts", 0) or 0),
                        "last_defer_context": meta.get("api_low_priority_read_last_defer_context", ""),
                        "escalation_enabled": bool(API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_ENABLED),
                        "escalation_factor": str(API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR),
                        "buckets": buckets,
                    })
                except Exception:
                    pass
    if API_429_ADAPTIVE_PENALTY_ENABLED and RATE_LIMITER:
        penalty = RATE_LIMITER.penalize(kind, cost, API_429_PENALTY_COST_MULTIPLIER)
        meta["api_last_429_penalty_tokens"] = str(penalty)
        LOGGER.warning("Adaptive 429 throttle penalty | kind=%s | path=%s | cost=%s | penalty_tokens=%s", kind, path, cost, penalty)


def load_private_key(path: str):
    path = validate_private_key_path(path, repository_root=Path(BASE_DIR))
    with open(path, "rb") as f:
        key = serialization.load_pem_private_key(f.read(), password=None, backend=default_backend())
    key_size = int(getattr(key, "key_size", 0) or 0)
    if key_size < 2048:
        raise RuntimeError("Kalshi private key must be an RSA key of at least 2048 bits")
    return key



def first_env_value(*names: str) -> str:
    for name in names:
        val = (os.getenv(name, "") or "").strip()
        if val:
            return val
    return ""


def _strip_wrapping_quotes(value: str) -> str:
    v = str(value or "").strip()
    while len(v) >= 2 and ((v[0] == v[-1] == '"') or (v[0] == v[-1] == "'")):
        v = v[1:-1].strip()
    return v


def resolve_private_key_path_runtime(raw_path: str) -> str:
    """Require an explicit key path outside the repository.

    The dry-run preview intentionally disables project-folder key discovery so a
    downloaded key cannot be committed or packaged by accident.
    """
    value = _strip_wrapping_quotes(raw_path)
    if not value:
        return ""
    return validate_private_key_path(value, repository_root=Path(BASE_DIR))

def initialize_runtime_config():
    global API_KEY_ID, PRIVATE_KEY_PATH, PRIVATE_KEY
    # Primary variable names used by the launchers. Aliases are accepted so older
    # local configs or hand-set environment variables keep working. Kalshi calls
    # this value the API Key ID and sends it as KALSHI-ACCESS-KEY.
    API_KEY_ID = first_env_value("KALSHI_API_KEY_ID", "KALSHI_KEY_ID", "KALSHI_ACCESS_KEY_ID", "KALSHI_ACCESS_KEY")
    PRIVATE_KEY_PATH = resolve_private_key_path_runtime(first_env_value("KALSHI_PRIVATE_KEY_PATH", "KALSHI_KEY_FILE", "KALSHI_PRIVATE_KEY_FILE"))
    if PRIVATE_KEY_PATH:
        os.environ["KALSHI_PRIVATE_KEY_PATH"] = PRIVATE_KEY_PATH
    if not API_KEY_ID:
        raise RuntimeError("KALSHI_API_KEY_ID is not configured. Run: python bot.py configure")
    if not PRIVATE_KEY_PATH:
        raise RuntimeError("KALSHI_PRIVATE_KEY_PATH is not configured. Run: python bot.py configure")
    if os.path.isdir(PRIVATE_KEY_PATH):
        raise RuntimeError("Private key path points to a folder. Run: python bot.py configure")
    if not os.path.exists(PRIVATE_KEY_PATH):
        raise RuntimeError("Private key file was not found. Run: python bot.py configure")
    PRIVATE_KEY = load_private_key(PRIVATE_KEY_PATH)


def warn_on_private_key_permissions(path: str):
    if os.name == "nt":
        return
    try:
        mode = os.stat(path).st_mode
    except OSError:
        return
    if mode & (stat.S_IRGRP | stat.S_IROTH):
        LOGGER.warning("Security warning: private key file may be readable by group/others: %s", path)


def validate_runtime_settings():
    if BUY_PRICE <= 0:
        raise RuntimeError(f"BUY_PRICE must be > 0, got {BUY_PRICE}")
    if SELL_PRICE <= 0:
        raise RuntimeError(f"SELL_PRICE must be > 0, got {SELL_PRICE}")
    if POLL_SECONDS < 1:
        raise RuntimeError(f"POLL_SECONDS must be >= 1, got {POLL_SECONDS}")
    if EVENT_WAKE_MIN_SECONDS < 0 or EVENT_WAKE_MAX_RUNS_PER_MINUTE < 1:
        raise RuntimeError("EVENT_WAKE settings are invalid")
    if MARKET_LIFECYCLE_PRICE_GRID_MAX_TICKERS < 1 or MARKET_LIFECYCLE_PRICE_GRID_MAX_RANGES < 1 or MARKET_LIFECYCLE_PRICE_GRID_MAX_AGE_SECONDS < 1:
        raise RuntimeError("MARKET_LIFECYCLE_PRICE_GRID settings are invalid")
    if STATE_FLUSH_INTERVAL_SECONDS < 1 or STATE_FLUSH_CRITICAL_INTERVAL_SECONDS < 0:
        raise RuntimeError("STATE_FLUSH settings are invalid")
    if min(STATE_SQLITE_BUSY_TIMEOUT_MS, STATE_SQLITE_SNAPSHOT_INTERVAL_SECONDS, STATE_SQLITE_EVENT_PAYLOAD_MAX_CHARS, STATE_IO_DOCTOR_INTERVAL_SECONDS) < 0:
        raise RuntimeError("STATE_SQLITE/STATE_IO settings must be non-negative")
    if STATE_SQLITE_EVENT_PAYLOAD_MAX_CHARS < 100:
        raise RuntimeError("STATE_SQLITE_EVENT_PAYLOAD_MAX_CHARS must be >= 100")
    if MACRO_REGIME_ADVISORY_INTERVAL_SECONDS < 1:
        raise RuntimeError("MACRO_REGIME_ADVISORY_INTERVAL_SECONDS must be >= 1")
    if SQLITE_REPLAY_RECONCILER_MAX_ROWS < 1 or SQLITE_REPLAY_RECONCILER_WARN_LAG_SECONDS < 0:
        raise RuntimeError("SQLITE_REPLAY_RECONCILER settings are invalid")
    if MACRO_SNAPSHOT_BACKTESTER_MIN_MATCHED_ROWS < 1:
        raise RuntimeError("MACRO_SNAPSHOT_BACKTESTER_MIN_MATCHED_ROWS must be >= 1")
    if min(MACRO_SNAPSHOT_BACKTESTER_STRONG_EDGE_CENTS, MACRO_SNAPSHOT_BACKTESTER_MIN_CLEAN_2C_RATE_PCT) < 0:
        raise RuntimeError("MACRO_SNAPSHOT_BACKTESTER positive thresholds must be non-negative")
    if WEBSOCKET_BUFFER_OVERFLOW_THROTTLE_SECONDS < 1:
        raise RuntimeError("WEBSOCKET_BUFFER_OVERFLOW_THROTTLE_SECONDS must be >= 1")
    if HTTP_SESSION_POOL_CONNECTIONS < 1 or HTTP_SESSION_POOL_MAXSIZE < 1:
        raise RuntimeError("HTTP session pool settings must be >= 1")
    if NETWORK_TRANSITION_PROBE_INTERVAL_SECONDS < 2 or NETWORK_TRANSITION_COOLDOWN_SECONDS < 1:
        raise RuntimeError("NETWORK_TRANSITION guard interval/cooldown settings are invalid")
    if NETWORK_TRANSITION_SOCKET_TIMEOUT_SECONDS <= 0:
        raise RuntimeError("NETWORK_TRANSITION_SOCKET_TIMEOUT_SECONDS must be > 0")
    if OUTCOME_REGIME_REHAB_INTERVAL_SECONDS < 1:
        raise RuntimeError("OUTCOME_REGIME_REHAB_INTERVAL_SECONDS must be >= 1")
    if min(API_WRITE_BURST_RESERVE_FRACTION, API_WRITE_BURST_RESERVE_MIN_TOKENS, API_WRITE_BURST_RESERVE_MAX_TOKENS) < 0:
        raise RuntimeError("API_WRITE_BURST reserve settings must be non-negative")
    if API_WRITE_BURST_RESERVE_FRACTION > Decimal("0.95"):
        raise RuntimeError("API_WRITE_BURST_RESERVE_FRACTION must be <= 0.95")
    if min(API_READ_PRIORITY_RESERVE_FRACTION, API_READ_PRIORITY_RESERVE_MIN_TOKENS, API_READ_PRIORITY_RESERVE_MAX_TOKENS) < 0:
        raise RuntimeError("API_READ_PRIORITY reserve settings must be non-negative")
    if API_READ_PRIORITY_RESERVE_FRACTION > Decimal("0.95"):
        raise RuntimeError("API_READ_PRIORITY_RESERVE_FRACTION must be <= 0.95")
    if API_429_BURST_WINDOW_SECONDS < 60 or API_429_BURST_MAX_READ_429 < 1 or API_429_BURST_MAX_WRITE_429 < 1:
        raise RuntimeError("API_429_BURST circuit settings are invalid")
    if LIVE_LAUNCH_SENTINEL_WINDOW_SECONDS < 10:
        raise RuntimeError("LIVE_LAUNCH_SENTINEL_WINDOW_SECONDS must be >= 10")
    if API_LOW_PRIORITY_READ_COOLDOWN_SECONDS < 0 or API_LOW_PRIORITY_READ_COOLDOWN_MAX_SECONDS < 0:
        raise RuntimeError("API_LOW_PRIORITY_READ_COOLDOWN settings must be non-negative")
    if ASSET_SESSION_OUTCOME_REVIEW_TOP_N < 1:
        raise RuntimeError("ASSET_SESSION_OUTCOME_REVIEW_TOP_N must be >= 1")
    if LOCAL_L2_ORDERBOOK_MAX_MARKETS < 1 or LOCAL_L2_ORDERBOOK_STALE_SECONDS < 1:
        raise RuntimeError("LOCAL_L2_ORDERBOOK settings are invalid")
    if LOCAL_L2_GAP_GUARD_HOLD_SECONDS < 0 or LOCAL_L2_GAP_GUARD_MAX_HOLDS < 1:
        raise RuntimeError("LOCAL_L2_GAP_GUARD settings are invalid")
    if LOCAL_L2_GAP_RESYNC_COOLDOWN_SECONDS < 0 or LOCAL_L2_GAP_RESYNC_MAX_TICKERS < 1:
        raise RuntimeError("LOCAL_L2_GAP_RESYNC settings are invalid")
    if min(LIP_ADJUSTED_MAX_BASE_SHORTFALL_CENTS_PER_CONTRACT, LIP_ADJUSTED_MIN_ADJUSTED_TOTAL_NET_CENTS, LIP_ADJUSTED_MIN_ADJUSTED_PC_CENTS) < 0:
        raise RuntimeError("LIP adjusted edge settings must be non-negative")
    if min(REALIZED_RECOVERY_QUALITY_INTERVAL_SECONDS, REALIZED_RECOVERY_QUALITY_CAUTION_BAD_SIGNALS, REALIZED_RECOVERY_QUALITY_SEVERE_BAD_SIGNALS, REALIZED_RECOVERY_QUALITY_FRONT_NO_FILL_ALERTS, REALIZED_RECOVERY_QUALITY_QUEUE_STALL_ALERTS) < 0:
        raise RuntimeError("REALIZED_RECOVERY_QUALITY counter settings must be non-negative")
    if min(REALIZED_RECOVERY_QUALITY_CAUTION_SIZE_MULTIPLIER, REALIZED_RECOVERY_QUALITY_SEVERE_SIZE_MULTIPLIER) < 0:
        raise RuntimeError("REALIZED_RECOVERY_QUALITY size multipliers must be non-negative")
    if ASSET_EXPOSURE_GOVERNOR_INTERVAL_SECONDS < 0 or ASSET_EXPOSURE_GOVERNOR_MIN_SERIES_FOR_ACTION < 0:
        raise RuntimeError("ASSET_EXPOSURE_GOVERNOR interval/min-series settings must be non-negative")
    if min(ASSET_EXPOSURE_GOVERNOR_CAUTION_SIZE_MULTIPLIER, ASSET_EXPOSURE_GOVERNOR_SEVERE_SIZE_MULTIPLIER, ASSET_EXPOSURE_GOVERNOR_MAX_ACTIVE_QTY_FP) < 0:
        raise RuntimeError("ASSET_EXPOSURE_GOVERNOR multipliers/caps must be non-negative")
    if ASSET_REALIZED_ROI_LEDGER_INTERVAL_SECONDS < 0 or ASSET_REALIZED_ROI_MIN_EVIDENCE_CONTRACTS_FP < 0:
        raise RuntimeError("ASSET_REALIZED_ROI ledger interval/evidence settings must be non-negative")
    if min(ASSET_REALIZED_ROI_STRONG_ADJUSTMENT_MULTIPLIER, ASSET_REALIZED_ROI_CAUTION_ADJUSTMENT_MULTIPLIER, ASSET_REALIZED_ROI_SEVERE_ADJUSTMENT_MULTIPLIER, ASSET_REALIZED_ROI_MAX_FINAL_SIZE_MULTIPLIER) < 0:
        raise RuntimeError("ASSET_REALIZED_ROI size multipliers must be non-negative")
    if ASSET_ROI_RECOVERY_LADDER_INTERVAL_SECONDS < 0 or ASSET_ROI_RECOVERY_LADDER_MIN_CLEAN_2C_RECOVERIES < 0 or ASSET_ROI_RECOVERY_LADDER_FULL_RESTORE_CLEAN_2C_RECOVERIES < 0:
        raise RuntimeError("ASSET_ROI_RECOVERY_LADDER interval/clean-recovery settings must be non-negative")
    if min(ASSET_ROI_RECOVERY_LADDER_HOLD_MULTIPLIER, ASSET_ROI_RECOVERY_LADDER_CAUTION_RELEASE_MULTIPLIER, ASSET_ROI_RECOVERY_LADDER_FULL_RELEASE_MULTIPLIER) < 0:
        raise RuntimeError("ASSET_ROI_RECOVERY_LADDER multipliers must be non-negative")
    if min(ASSET_ROI_RECOVERY_LADDER_MIN_POSITIVE_ROI_PCT, ASSET_ROI_RECOVERY_LADDER_MIN_PNL_PER_CONTRACT_CENTS) < 0:
        raise RuntimeError("ASSET_ROI_RECOVERY_LADDER positive ROI / PnL thresholds must be non-negative")
    if ASSET_SESSION_PERFORMANCE_INTERVAL_SECONDS < 0 or ASSET_SESSION_PERFORMANCE_LOOKBACK_DAYS < 0 or ASSET_SESSION_PERFORMANCE_MIN_EVIDENCE_CONTRACTS_FP < 0:
        raise RuntimeError("ASSET_SESSION_PERFORMANCE interval/lookback/evidence settings must be non-negative")
