    if LIFECYCLE_CAPITAL_LADDER_NO_HISTORY_LEVEL_CAP not in {"pilot", "normal", "aggressive"} or LIFECYCLE_CAPITAL_LADDER_CAUTION_LEVEL_CAP not in {"pilot", "normal", "aggressive"} or LIFECYCLE_CAPITAL_LADDER_SEVERE_LEVEL_CAP not in {"pilot", "normal", "aggressive"}:
        raise RuntimeError("Lifecycle Capital Ladder level caps must be pilot, normal, or aggressive")
    if min(LIFECYCLE_CAPITAL_LADDER_STRONG_SIZE_MULTIPLIER, LIFECYCLE_CAPITAL_LADDER_NEUTRAL_SIZE_MULTIPLIER, LIFECYCLE_CAPITAL_LADDER_NO_HISTORY_SIZE_MULTIPLIER, LIFECYCLE_CAPITAL_LADDER_CAUTION_SIZE_MULTIPLIER, LIFECYCLE_CAPITAL_LADDER_SEVERE_SIZE_MULTIPLIER, LIFECYCLE_CAPITAL_LADDER_MAX_SIZE_MULTIPLIER) < 0:
        raise RuntimeError("Lifecycle Capital Ladder multipliers must be non-negative")
    if LIFECYCLE_CAPITAL_LADDER_MAX_SIZE_MULTIPLIER < Decimal("1.00"):
        raise RuntimeError("Lifecycle Capital Ladder max multiplier must be >= 1.00")
    if API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR < Decimal("1.00"):
        raise RuntimeError("API_LOW_PRIORITY_READ_COOLDOWN_ESCALATION_FACTOR must be >= 1.00")
    if API_LOW_PRIORITY_READ_COOLDOWN_STREAK_RESET_SECONDS < 0:
        raise RuntimeError("API_LOW_PRIORITY_READ_COOLDOWN_STREAK_RESET_SECONDS must be >= 0")
    if ORDERBOOK_PRESSURE_DEPTH_LEVELS < 1 or ORDERBOOK_PRESSURE_MIN_TOTAL_DEPTH_FP < 0:
        raise RuntimeError("Orderbook pressure depth settings are invalid")
    if min(ORDERBOOK_PRESSURE_WARN_SCORE, ORDERBOOK_PRESSURE_TOXIC_SCORE, ORDERBOOK_PRESSURE_STRONG_SCORE, ORDERBOOK_PRESSURE_WARN_SIZE_MULTIPLIER, ORDERBOOK_PRESSURE_STRONG_SIZE_MULTIPLIER, ORDERBOOK_PRESSURE_MAX_SIZE_MULTIPLIER) < 0:
        raise RuntimeError("Orderbook pressure thresholds/multipliers must be non-negative")
    if ORDERBOOK_PRESSURE_TOXIC_SCORE > ORDERBOOK_PRESSURE_WARN_SCORE or ORDERBOOK_PRESSURE_WARN_SCORE > ORDERBOOK_PRESSURE_STRONG_SCORE:
        raise RuntimeError("Orderbook pressure scores must satisfy toxic <= warn <= strong")
    if ORDERBOOK_PRESSURE_MAX_SIZE_MULTIPLIER < Decimal("1.00"):
        raise RuntimeError("ORDERBOOK_PRESSURE_MAX_SIZE_MULTIPLIER must be >= 1.00")
    if BUY_SIDE_MIN_RECENT_TRADE_VOLUME_FP < 0 or BUY_SIDE_LOW_TRADE_TAPE_SIZE_MULTIPLIER < 0:
        raise RuntimeError("Buy-side trade-tape settings must be >= 0")
    if BUY_SIDE_MAX_NEW_BUY_COST_DOLLARS < 0 or BUY_SIDE_PRIORITY_TOP_N < 1 or BUY_SIDE_ALLOCATABLE_BALANCE_FRACTION < 0 or BUY_SIDE_ALLOCATABLE_BALANCE_FRACTION > 1:
        raise RuntimeError("Buy-side capital allocator settings are invalid")
    if BUY_SIDE_LADDER_PILOT_MAX_COST_DOLLARS < 0 or BUY_SIDE_LADDER_NORMAL_MAX_COST_DOLLARS < 0 or BUY_SIDE_LADDER_AGGRESSIVE_MAX_COST_DOLLARS < 0:
        raise RuntimeError("Buy-side capital ladder cost caps must be >= 0")
    if BUY_SIDE_LADDER_PILOT_MAX_QTY_FP < 0 or BUY_SIDE_LADDER_NORMAL_MIN_EVIDENCE_QTY_FP < 0 or BUY_SIDE_LADDER_AGGRESSIVE_MIN_EVIDENCE_QTY_FP < 0:
        raise RuntimeError("Buy-side capital ladder quantity thresholds must be >= 0")
    if BUY_SIDE_LADDER_NORMAL_MIN_SCORE < 0 or BUY_SIDE_LADDER_AGGRESSIVE_MIN_SCORE < 0 or BUY_SIDE_LADDER_AGGRESSIVE_MIN_VELOCITY_SCORE < 0 or BUY_SIDE_LADDER_AGGRESSIVE_MIN_ORDERBOOK_SCORE < 0:
        raise RuntimeError("Buy-side capital ladder score thresholds must be >= 0")
    if BUY_SIDE_UNPROVEN_MAX_NEW_BUY_QTY_FP < 0 or BUY_SIDE_MIN_EVIDENCE_QTY_FP < 0:
        raise RuntimeError("Buy-side unproven/evidence settings must be >= 0")
    if BUY_SIDE_COOLDOWN_BAD_FILL_COUNT < 0 or BUY_SIDE_COOLDOWN_NEGATIVE_NET_CENTS < 0 or BUY_SIDE_COOLDOWN_SECONDS < 0:
        raise RuntimeError("Buy-side cooldown settings must be >= 0")
    if SERIES_QUARANTINE_REHAB_MIN_CLEAN_2C_RECOVERIES < 0 or SERIES_QUARANTINE_REHAB_CLEAN_RECOVERY_QTY_FP <= 0 or SERIES_QUARANTINE_REHAB_PILOT_SIZE_MULTIPLIER < 0:
        raise RuntimeError("Series quarantine rehabilitation settings are invalid")
    if BUY_SIDE_TARGET_SERIES_POSITION_FP <= 0 or BUY_SIDE_MAX_SERIES_POSITION_FP <= 0:
        raise RuntimeError("Buy-side inventory position limits must be > 0")
    if BUY_SIDE_MAX_SERIES_POSITION_FP < BUY_SIDE_TARGET_SERIES_POSITION_FP:
        LOGGER.warning("BUY_SIDE_MAX_SERIES_POSITION_FP (%s) is below target (%s); buy-side signals may deny earlier than expected", BUY_SIDE_MAX_SERIES_POSITION_FP, BUY_SIDE_TARGET_SERIES_POSITION_FP)
    if SIDE_OVERRIDES_PARSE_ERROR:
        LOGGER.warning("SIDE_OVERRIDES_JSON could not be parsed and was ignored: %s", SIDE_OVERRIDES_PARSE_ERROR)


