def order_api_version_from_order(order) -> str:
    if isinstance(order, dict):
        for key in ("_api_version", "api_version", "order_api_version"):
            explicit = str(order.get(key, "")).lower().strip()
            if explicit in {"v2", "legacy"}:
                return explicit
        client_order_id = str(order.get("client_order_id", ""))
        if f"{CLIENT_PREFIX}-" in client_order_id and "-v2-" in client_order_id:
            return "v2"
        # Kalshi V2 event-order shapes expose single-book side/price fields such
        # as book_side/bid/ask/price. Treat those as V2 for hedge compliance so
        # older resting inverse NO orders are canceled/replaced safely.
        if any(order.get(k) not in {None, ""} for k in ("book_side", "order_side", "v2_side")):
            return "v2"
        if order.get("price") not in {None, ""} and not (order.get("yes_price_dollars") or order.get("no_price_dollars")):
            return "v2"
    return "legacy"


def active_order_is_v2(order) -> bool:
    return order_api_version_from_order(order) == "v2"


def batch_cancel_orders(order_items):
    items = [item for item in (order_items or []) if item]
    if not items:
        return {}
    normalized = []
    for item in items:
        if isinstance(item, dict):
            oid = item.get("order_id")
            if oid:
                normalized.append((str(oid), item))
        else:
            normalized.append((str(item), None))
    if not normalized:
        return {}
    if DRY_RUN:
        LOGGER.info("DRY_RUN would batch-cancel %s orders", len(normalized))
        return {}

    v2_items, legacy_ids = [], []
    v2_only_mutations = ORDER_API_VERSION == "v2" and not ORDER_API_LEGACY_FALLBACK
    for oid, order in normalized:
        if v2_only_mutations or (order is not None and active_order_is_v2(order)) or (order is None and ORDER_API_VERSION == "v2"):
            v2_items.append((oid, order))
        else:
            legacy_ids.append(oid)

    results = {}

    if v2_items:
        if not BATCH_CANCEL_ENABLED or len(v2_items) == 1:
            for oid, order in v2_items:
                try:
                    results[oid] = cancel_order(oid, order=order)
                except Exception as e:
                    LOGGER.warning("V2 cancel failed for %s: %s", oid, e)
        else:
            for i in range(0, len(v2_items), 20):
                chunk = v2_items[i:i + 20]
                body = {"orders": [{"order_id": oid, "subaccount": SUBACCOUNT, "exchange_index": EXCHANGE_INDEX} for oid, _ in chunk]}
                try:
                    data = signed_request("DELETE", "/portfolio/events/orders/batched", json_body=body, max_retries=1)
                    for row in data.get("orders", []) or []:
                        oid = row.get("order_id") or row.get("id")
                        if oid:
                            results[oid] = row
                    LOGGER.info("V2 batch cancel completed | count=%s", len(chunk))
                except Exception as e:
                    LOGGER.warning("V2 batch cancel failed for %s orders; falling back to single cancels: %s", len(chunk), e)
                    for oid, order in chunk:
                        try:
                            results[oid] = cancel_order(oid, order=order)
                        except Exception as inner:
                            LOGGER.warning("Fallback V2 cancel failed for %s: %s", oid, inner)

    if legacy_ids:
        if not BATCH_CANCEL_ENABLED or len(legacy_ids) == 1:
            for oid in legacy_ids:
                try:
                    results[oid] = cancel_order(oid)
                except Exception as e:
                    LOGGER.warning("Cancel failed for %s: %s", oid, e)
        else:
            for i in range(0, len(legacy_ids), 20):
                chunk = legacy_ids[i:i + 20]
                body = {"orders": [{"order_id": oid, "subaccount": SUBACCOUNT, "exchange_index": EXCHANGE_INDEX} for oid in chunk]}
                try:
                    data = signed_request("DELETE", "/portfolio/orders/batched", json_body=body, max_retries=1)
                    for row in data.get("orders", []) or []:
                        results[row.get("order_id", "")] = row
                    LOGGER.info("Legacy batch cancel completed | count=%s", len(chunk))
                except Exception as e:
                    LOGGER.warning("Batch cancel failed for %s legacy orders; falling back to single cancels: %s", len(chunk), e)
                    for oid in chunk:
                        try:
                            results[oid] = cancel_order(oid)
                        except Exception as inner:
                            LOGGER.warning("Fallback cancel failed for %s: %s", oid, inner)
    return results

