def get_recent_orders_by_status(status: str, min_ts: int = 0, max_pages: int = 1, limit: int = 200):
    orders, cursor, pages = [], None, 0
    status = str(status or "").strip().lower()
    while pages < max(1, int(max_pages or 1)):
        params = {"limit": max(1, min(int(limit or 200), 1000)), "status": status, "subaccount": SUBACCOUNT}
        if cursor:
            params["cursor"] = cursor
        data = signed_request("GET", "/portfolio/orders", params=params)
        batch = data.get("orders", []) or []
        for order in batch:
            ts = unix_ts_from_any(order.get("last_update_time") or order.get("created_time") or order.get("ts"), default=0)
            if min_ts and ts and ts < min_ts:
                continue
            orders.append(order)
        cursor = data.get("cursor")
        pages += 1
        if not cursor:
            break
    return orders


