def _mutation_event_error_fields(error) -> dict:
    if error is None:
        return {"error_class": "", "status_code": 0, "error": ""}
    try:
        status = int(getattr(error, "status_code", 0) or 0)
    except Exception:
        status = 0
    return {
        "error_class": error.__class__.__name__,
        "status_code": status,
        "error": str(error or "")[:500],
    }


def mutation_error_is_ambiguous(error) -> bool:
    """Return True when a write may have reached the matching engine.

    4xx validation/auth failures are definite rejects. Transport interruption,
    invalid/empty success bodies, and 5xx responses are treated as ambiguous and
    must be reconciled before a fresh write identity is considered.
    """
    if isinstance(error, MutationOutcomeUnresolvedError):
        return True
    if isinstance(error, KalshiApiError):
        status = int(getattr(error, "status_code", 0) or 0)
        if status >= 500 or status in {408, 425}:
            return True
        if 200 <= status < 300 and "invalid_json_response" in str(getattr(error, "body", "")).lower():
            return True
        return False
    text = str(error or "").lower()
    return any(token in text for token in (
        "transport error", "timed out", "timeout", "connection reset", "connection aborted",
        "connection refused", "remote end closed", "broken pipe", "temporarily unavailable",
        "exchange_unavailable", "invalid_json_response", "empty response", "network/session refresh",
    ))


def duplicate_client_order_id_error(error) -> bool:
    text = " ".join((
        str(error or ""),
        str(getattr(error, "body", "") or ""),
    )).lower()
    return ("client_order_id" in text or "client order id" in text or "clordid" in text) and any(
        token in text for token in ("duplicate", "already exists", "order_already_exists", "already_exists")
    )


def _mutation_compact_order(order: dict) -> dict:
    if not isinstance(order, dict):
        return {}
    keys = (
        "order_id", "client_order_id", "ticker", "market_ticker", "side", "action", "status",
        "remaining_count_fp", "remaining_count", "fill_count_fp", "fill_count", "initial_count_fp",
        "count", "price", "yes_price_dollars", "no_price_dollars", "created_time", "last_update_time",
        "last_update_reason", "exchange_index", "subaccount",
    )
    out = {k: order.get(k) for k in keys if order.get(k) not in (None, "")}
    out["_cached_ts"] = now_ts()
    return out


def cache_recent_ws_user_order_for_mutation_reconcile(msg: dict) -> None:
    if not isinstance(msg, dict):
        return
    order_id = str(msg.get("order_id") or "").strip()
    client_order_id = str(msg.get("client_order_id") or "").strip()
    if not order_id and not client_order_id:
        return
    meta = STATE.setdefault("meta", {})
    rows = meta.get("recent_ws_user_orders_for_mutation_reconcile", [])
    if not isinstance(rows, list):
        rows = []
    compact = _mutation_compact_order(msg)
    identity = (order_id, client_order_id)
    rows = [row for row in rows if (str(row.get("order_id") or ""), str(row.get("client_order_id") or "")) != identity]
    rows.append(compact)
    meta["recent_ws_user_orders_for_mutation_reconcile"] = rows[-MUTATION_WS_ORDER_CACHE_MAX_EVENTS:]
    meta["recent_ws_user_order_cache_last_ts"] = now_ts()


def _atomic_write_mutation_text(path: str, text: str) -> None:
    if not path:
        return
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    tmp = f"{path}.tmp.{os.getpid()}.{uuid.uuid4().hex[:8]}"
    with open(tmp, "w", encoding="utf-8", newline="\n") as f:
        f.write(text)
        f.flush()
        if globals().get("ATOMIC_WRITE_FSYNC_REPORTS_ENABLED", False):
            os.fsync(f.fileno())
    atomic_replace_with_retry(tmp, path, context="mutation_outcome_journal_txt")


def write_mutation_outcome_journal_report() -> dict:
    meta = STATE.setdefault("meta", {})
    events = meta.get("mutation_outcome_events", [])
    if not isinstance(events, list):
        events = []
    counts = {}
    operations = {}
    unresolved = []
    for event in events:
        if not isinstance(event, dict):
            continue
        phase = str(event.get("phase") or "unknown")
        operation = str(event.get("operation") or "unknown")
        counts[phase] = int(counts.get(phase, 0)) + 1
        operations[operation] = int(operations.get(operation, 0)) + 1
        if phase in {"ambiguous_unresolved", "response_identity_unresolved"}:
            unresolved.append(event)
    payload = {
        "generated_ct": central_time_iso_from_ts(now_ts()),
        "build_id": BUILD_ID,
        "instance": INSTANCE_SAFE,
        "enabled": bool(MUTATION_OUTCOME_RECONCILE_ENABLED),
        "response_identity_guard_enabled": bool(MUTATION_RESPONSE_IDENTITY_GUARD_ENABLED),
        "ambiguous_fail_closed": bool(MUTATION_AMBIGUOUS_FAIL_CLOSED),
        "settings": {
            "create_same_id_max_attempts": MUTATION_CREATE_SAME_ID_MAX_ATTEMPTS,
            "write_max_attempts": MUTATION_WRITE_MAX_ATTEMPTS,
            "poll_attempts": MUTATION_RECONCILE_POLL_ATTEMPTS,
            "wait_seconds": MUTATION_RECONCILE_WAIT_SECONDS,
            "lookback_seconds": MUTATION_RECONCILE_LOOKBACK_SECONDS,
            "max_pages": MUTATION_RECONCILE_MAX_PAGES,
        },
        "event_count": len(events),
        "phase_counts": counts,
        "operation_counts": operations,
        "unresolved_count": len(unresolved),
        "recent_unresolved": unresolved[-20:],
        "recent_events": events[-50:],
        "policy": "same-client-ID reconciliation; response identity validation; ambiguous writes fail closed; no strategy/FeeGuard relaxation",
    }
    meta["last_mutation_outcome_journal"] = payload
    try:
        atomic_write_json(MUTATION_OUTCOME_JOURNAL_JSON_PATH, payload)
    except Exception as exc:
        LOGGER.debug("Mutation outcome JSON report write failed: %s", exc)
    lines = [
        "Kalshi Mutation Outcome Journal",
        "===============================",
        f"Generated CT : {payload['generated_ct']}",
        f"Build ID     : {BUILD_ID}",
        f"Enabled      : {payload['enabled']}",
        f"IdentityGuard: {payload['response_identity_guard_enabled']}",
        f"Fail closed  : {payload['ambiguous_fail_closed']}",
        f"Events       : {payload['event_count']}",
        f"Unresolved   : {payload['unresolved_count']}",
        f"Phases       : {payload['phase_counts']}",
        f"Operations   : {payload['operation_counts']}",
        "Policy       : preserve client identity; reconcile before fallback; never loosen FeeGuard/2c contract.",
        "",
        "Recent events:",
    ]
    for event in payload["recent_events"][-20:]:
        lines.append(
            "- {ts} {operation}/{phase} ticker={ticker} order={order_id} client={client_order_id} evidence={evidence_source} error={error}".format(
                ts=event.get("ts_ct", ""), operation=event.get("operation", ""), phase=event.get("phase", ""),
                ticker=event.get("ticker", ""), order_id=event.get("order_id", ""), client_order_id=event.get("client_order_id", ""),
                evidence_source=event.get("evidence_source", ""), error=str(event.get("error", ""))[:180],
            )
        )
    try:
        _atomic_write_mutation_text(MUTATION_OUTCOME_JOURNAL_TXT_PATH, "\n".join(lines).rstrip() + "\n")
    except Exception as exc:
        LOGGER.debug("Mutation outcome TXT report write failed: %s", exc)
    return payload


def record_mutation_outcome(operation: str, phase: str, mutation_id: str = "", **fields) -> str:
    mutation_id = str(mutation_id or uuid.uuid4().hex[:16])
    event = {
        "ts": now_ts(),
        "ts_ct": central_time_iso_from_ts(now_ts()),
        "mutation_id": mutation_id,
        "operation": str(operation or "mutation"),
        "phase": str(phase or "unknown"),
        "build_id": BUILD_ID,
        "instance": INSTANCE_SAFE,
    }
    for key, value in fields.items():
        if value is None:
            continue
        if isinstance(value, Decimal):
            value = str(value)
        elif isinstance(value, Exception):
            value = str(value)
        event[str(key)] = value
    meta = STATE.setdefault("meta", {})
    events = meta.get("mutation_outcome_events", [])
    if not isinstance(events, list):
        events = []
    events.append(event)
    meta["mutation_outcome_events"] = events[-MUTATION_JOURNAL_MAX_EVENTS:]
    meta["mutation_outcome_last_phase"] = event["phase"]
    meta["mutation_outcome_last_ts"] = event["ts"]
    try:
        write_mutation_outcome_journal_report()
    except Exception as exc:
        LOGGER.debug("Mutation outcome report generation failed: %s", exc)
    return mutation_id


def _iter_local_order_candidates() -> list:
    rows = []
    meta_rows = STATE.setdefault("meta", {}).get("recent_ws_user_orders_for_mutation_reconcile", [])
    if isinstance(meta_rows, list):
        rows.extend(row for row in meta_rows if isinstance(row, dict))
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key.endswith("|_meta") or not isinstance(bucket, dict):
            continue
        for name in ("last_known_open_orders", "managed_orders"):
            values = bucket.get(name, [])
            if isinstance(values, list):
                rows.extend(row for row in values if isinstance(row, dict))
    return rows


def find_order_by_client_order_id(client_order_id: str, ticker: str = "", include_rest: bool = True) -> tuple:
    client_order_id = str(client_order_id or "").strip()
    ticker = str(ticker or "").strip()
    if not client_order_id:
        return {}, "missing_client_order_id"
    for order in reversed(_iter_local_order_candidates()):
        if str(order.get("client_order_id") or "") == client_order_id and (not ticker or str(order.get("ticker") or order.get("market_ticker") or "") == ticker):
            return dict(order), "local_ws_or_state_cache"
    if not include_rest:
        return {}, "local_not_found"
    min_ts = max(0, now_ts() - MUTATION_RECONCILE_LOOKBACK_SECONDS)
    for status in ("resting", "executed", "canceled"):
        cursor = None
        for _page in range(MUTATION_RECONCILE_MAX_PAGES):
            params = {
                "limit": MUTATION_RECONCILE_LIMIT_PER_PAGE,
                "status": status,
                "subaccount": SUBACCOUNT,
            }
            if ticker:
                params["ticker"] = ticker
            if cursor:
                params["cursor"] = cursor
            try:
                data = signed_request("GET", "/portfolio/orders", params=params, max_retries=2)
            except Exception as exc:
                LOGGER.debug("Mutation reconcile order scan failed | ticker=%s | status=%s | error=%s", ticker, status, exc)
                break
            for order in data.get("orders", []) or []:
                if str(order.get("client_order_id") or "") != client_order_id:
                    continue
                order_ts = unix_ts_from_any(order.get("last_update_time") or order.get("created_time") or order.get("ts"), default=0)
                if order_ts and order_ts < min_ts:
                    continue
                return dict(order), f"rest_orders_status_{status}"
            cursor = data.get("cursor")
            if not cursor:
                break
    return {}, "rest_not_found"


def find_orders_by_client_order_ids(client_order_ids, include_rest: bool = True) -> tuple:
    """Resolve many client IDs with one bounded cache/REST sweep.

    Batch-create ambiguity is a burst problem. Reconciling each intent with its
    own paginated scan multiplies read tokens and delays sell recovery. This
    helper drains the same local/WS cache once and scans each order status once,
    returning a map plus per-ID evidence sources.
    """
    wanted = {str(value or "").strip() for value in (client_order_ids or []) if str(value or "").strip()}
    found = {}
    sources = {}
    if not wanted:
        return found, sources
    for order in reversed(_iter_local_order_candidates()):
        client_id = str(order.get("client_order_id") or "").strip()
        if client_id in wanted and client_id not in found:
            found[client_id] = dict(order)
            sources[client_id] = "local_ws_or_state_cache"
    if not include_rest or len(found) >= len(wanted):
        return found, sources
    min_ts = max(0, now_ts() - MUTATION_RECONCILE_LOOKBACK_SECONDS)
    for status in ("resting", "executed", "canceled"):
        cursor = None
        for _page in range(MUTATION_RECONCILE_MAX_PAGES):
            params = {
                "limit": MUTATION_RECONCILE_LIMIT_PER_PAGE,
                "status": status,
                "subaccount": SUBACCOUNT,
            }
            if cursor:
                params["cursor"] = cursor
            try:
                data = signed_request("GET", "/portfolio/orders", params=params, max_retries=2)
            except Exception as exc:
                LOGGER.debug("Batch mutation reconcile order scan failed | status=%s | error=%s", status, exc)
                break
            for order in data.get("orders", []) or []:
                client_id = str(order.get("client_order_id") or "").strip()
                if client_id not in wanted or client_id in found:
                    continue
                order_ts = unix_ts_from_any(order.get("last_update_time") or order.get("created_time") or order.get("ts"), default=0)
                if order_ts and order_ts < min_ts:
                    continue
                found[client_id] = dict(order)
                sources[client_id] = f"rest_orders_status_{status}"
            if len(found) >= len(wanted):
                return found, sources
            cursor = data.get("cursor")
            if not cursor:
                break
    return found, sources


def reconcile_created_orders_batch(intents, mutation_id: str, error=None, context: str = "batch_create") -> dict:
    """Reconcile an ambiguous batch create without N-per-order REST scans."""
    if not MUTATION_OUTCOME_RECONCILE_ENABLED:
        return {}
    if error is not None and not mutation_error_is_ambiguous(error):
        return {}
    by_client = {
        str(intent.get("client_order_id") or ""): intent
        for intent in (intents or [])
        if str(intent.get("client_order_id") or "")
    }
    if not by_client:
        return {}
    err_fields = _mutation_event_error_fields(error)
    record_mutation_outcome(
        "batch_create", "ambiguous_reconcile_begin", mutation_id,
        order_count=len(by_client), client_order_ids=sorted(by_client), context=context, **err_fields,
    )
    resolved = {}
    sources = {}
    for attempt in range(1, MUTATION_RECONCILE_POLL_ATTEMPTS + 1):
        if attempt > 1 or MUTATION_RECONCILE_WAIT_SECONDS > 0:
            time.sleep(MUTATION_RECONCILE_WAIT_SECONDS)
        _drain_private_events_for_mutation_reconcile()
        found, found_sources = find_orders_by_client_order_ids(by_client.keys(), include_rest=True)
        for client_id, order in found.items():
            intent = by_client.get(client_id) or {}
            resolved[client_id] = wrap_order_response(
                {"order": order},
                intent.get("ticker", ""), intent.get("side", ""),
                parse_decimal(intent.get("qty", "0"), "0"),
                parse_decimal(intent.get("exit_price", SELL_PRICE), str(SELL_PRICE)),
                "v2", bool(intent.get("post_only", True)),
            )
            sources[client_id] = found_sources.get(client_id, "unknown")
        if len(resolved) >= len(by_client):
            break
    unresolved = sorted(set(by_client) - set(resolved))
    record_mutation_outcome(
        "batch_create",
        "reconciled_applied" if not unresolved else "partially_reconciled",
        mutation_id,
        order_count=len(by_client), resolved_count=len(resolved), unresolved_count=len(unresolved),
        unresolved_client_order_ids=unresolved, evidence_sources=sources, context=context, **err_fields,
    )
    return resolved


def _drain_private_events_for_mutation_reconcile() -> None:
    try:
        drain_ws_events(private_only=True)
    except Exception as exc:
        LOGGER.debug("Mutation reconcile private WebSocket drain skipped: %s", exc)


def reconcile_created_order(client_order_id: str, ticker: str, side: str, qty: Decimal, exit_price: Decimal, post_only: bool, mutation_id: str, error=None, context: str = "create"):
    if not MUTATION_OUTCOME_RECONCILE_ENABLED:
        return None
    if error is not None and not (mutation_error_is_ambiguous(error) or duplicate_client_order_id_error(error)):
        return None
    err_fields = _mutation_event_error_fields(error)
    record_mutation_outcome(
        "create", "ambiguous_reconcile_begin", mutation_id,
        ticker=ticker, side=side, qty_fp=qty_str(qty), price=price_str(exit_price), client_order_id=client_order_id,
        context=context, **err_fields,
    )
    last_source = "not_checked"
    for attempt in range(1, MUTATION_RECONCILE_POLL_ATTEMPTS + 1):
        if attempt > 1 or MUTATION_RECONCILE_WAIT_SECONDS > 0:
            time.sleep(MUTATION_RECONCILE_WAIT_SECONDS)
        _drain_private_events_for_mutation_reconcile()
        order, last_source = find_order_by_client_order_id(client_order_id, ticker=ticker, include_rest=True)
        if order:
            wrapped = wrap_order_response({"order": order}, ticker, side, qty, exit_price, "v2", post_only)
            record_mutation_outcome(
                "create", "reconciled_applied", mutation_id,
                ticker=ticker, side=side, qty_fp=qty_str(qty), price=price_str(exit_price),
                order_id=order.get("order_id", ""), client_order_id=client_order_id,
                evidence_source=last_source, poll_attempt=attempt, context=context,
            )
            return wrapped
    record_mutation_outcome(
        "create", "ambiguous_unresolved", mutation_id,
        ticker=ticker, side=side, qty_fp=qty_str(qty), price=price_str(exit_price), client_order_id=client_order_id,
        evidence_source=last_source, context=context, **err_fields,
    )
    if MUTATION_AMBIGUOUS_FAIL_CLOSED:
        raise MutationOutcomeUnresolvedError(
            "create", f"client_order_id={client_order_id} not found after bounded WebSocket/REST reconciliation", mutation_id=mutation_id, original_error=error,
        ) from error
    return None


def _response_order_dict(data) -> dict:
    if not isinstance(data, dict):
        return {}
    if isinstance(data.get("order"), dict):
        return dict(data.get("order") or {})
    return dict(data)


def _order_remaining(order: dict) -> Decimal:
    return parse_decimal((order or {}).get("remaining_count_fp", (order or {}).get("remaining_count", "0")), "0")


def _order_filled(order: dict) -> Decimal:
    return parse_decimal((order or {}).get("fill_count_fp", (order or {}).get("fill_count", "0")), "0")


def _order_terminal(order: dict) -> bool:
    status = str((order or {}).get("status") or "").lower()
    return status in {"canceled", "cancelled", "executed", "filled", "expired", "rejected"} or (_order_remaining(order) <= 0 and bool(status))


def _order_reflects_amend(order: dict, updated_client_order_id: str, target_total: Decimal, side: str, exit_price: Decimal) -> bool:
    if not isinstance(order, dict) or not order:
        return False
    if updated_client_order_id and str(order.get("client_order_id") or "") == str(updated_client_order_id):
        return True
    total = (_order_remaining(order) + _order_filled(order)).quantize(Decimal("0.00"))
    target_total = parse_decimal(target_total, "0").quantize(Decimal("0.00"))
    try:
        price_ok = price_str(order_exit_price(order, side)) == price_str(exit_price)
    except Exception:
        price_ok = False
    return total == target_total and price_ok


def reconcile_order_mutation(order_id: str, operation: str, mutation_id: str, predicate, error=None, response_order: dict = None, **fields):
    if not MUTATION_OUTCOME_RECONCILE_ENABLED:
        return None
    err_fields = _mutation_event_error_fields(error)
    record_mutation_outcome(operation, "ambiguous_reconcile_begin", mutation_id, order_id=order_id, **fields, **err_fields)
    last_source = "not_checked"
    for attempt in range(1, MUTATION_RECONCILE_POLL_ATTEMPTS + 1):
        if attempt > 1 or MUTATION_RECONCILE_WAIT_SECONDS > 0:
            time.sleep(MUTATION_RECONCILE_WAIT_SECONDS)
        _drain_private_events_for_mutation_reconcile()
        try:
            order = get_order(order_id)
            last_source = "get_order"
        except Exception as exc:
            if is_order_not_found_error(exc):
                order = {}
                last_source = "get_order_not_found"
            else:
                last_source = f"get_order_error:{exc.__class__.__name__}"
                continue
        try:
            applied = bool(predicate(order, last_source))
        except Exception:
            applied = False
        if applied:
            record_mutation_outcome(
                operation, "reconciled_applied", mutation_id,
                order_id=order_id, evidence_source=last_source, poll_attempt=attempt,
                response_order_id=str((response_order or {}).get("order_id") or ""), **fields,
            )
            return order
    record_mutation_outcome(
        operation, "ambiguous_unresolved", mutation_id,
        order_id=order_id, evidence_source=last_source,
        response_order_id=str((response_order or {}).get("order_id") or ""), **fields, **err_fields,
    )
    if MUTATION_AMBIGUOUS_FAIL_CLOSED:
        raise MutationOutcomeUnresolvedError(
            operation, f"order_id={order_id} did not reach the requested state after bounded reconciliation", mutation_id=mutation_id, original_error=error,
        ) from error
    return None


def guard_mutation_response_identity(data, expected_order_id: str, operation: str, mutation_id: str, predicate, **fields):
    response_order = _response_order_dict(data)
    response_order_id = str(response_order.get("order_id") or response_order.get("id") or "")
    if not MUTATION_RESPONSE_IDENTITY_GUARD_ENABLED:
        return data
    if response_order_id == str(expected_order_id):
        return data
    phase = "response_identity_mismatch" if response_order_id else "response_identity_missing"
    record_mutation_outcome(
        operation, phase, mutation_id,
        order_id=expected_order_id, response_order_id=response_order_id,
        response_client_order_id=str(response_order.get("client_order_id") or ""), **fields,
    )
    # V2 mutation responses are expected to identify the mutated order. An empty
    # or identity-free 2xx body is not proof of failure or success, so reconcile
    # the intended path order before returning to the strategy loop.
    target = reconcile_order_mutation(
        expected_order_id, operation, mutation_id, predicate,
        response_order=response_order, **fields,
    )
    if target is not None:
        return {"order": target, "_mutation_response_reconciled": True}
    detail = (
        f"response described order_id={response_order_id}, expected {expected_order_id}"
        if response_order_id else
        f"response omitted order identity for expected order_id={expected_order_id}"
    )
    raise MutationOutcomeUnresolvedError(operation, detail, mutation_id=mutation_id)


def get_queue_position(order_id: str):
    data = signed_request("GET", f"/portfolio/orders/{order_id}/queue_position", params={"subaccount": SUBACCOUNT})
    return parse_decimal(data.get("queue_position_fp", "0.00"), "0")


def get_queue_positions(market_tickers=None, active_orders=None):
    tickers = sorted({t for t in (market_tickers or []) if t})
    if not tickers:
        return {}
    try:
        params = {
            "subaccount": SUBACCOUNT,
            "market_tickers": ",".join(tickers),
        }
        data = signed_request("GET", "/portfolio/orders/queue_positions", params=params)
        out = {}
        for row in data.get("queue_positions") or []:
            order_id = row.get("order_id")
            if order_id:
                out[order_id] = parse_decimal(row.get("queue_position_fp", "0.00"), "0")
        return out
    except Exception as e:
        LOGGER.warning("Bulk queue lookup failed; falling back to per-order queue checks: %s", e)

    out = {}
    for order in (active_orders or []):
        order_id = order.get("order_id")
        if not order_id:
            continue
        try:
            out[order_id] = get_queue_position(order_id)
        except Exception as e:
            LOGGER.warning("Queue position lookup failed for %s: %s", order_id, e)
    return out


def is_order_not_found_error(error) -> bool:
    try:
        status = int(getattr(error, "status_code", 0) or 0)
    except Exception:
        status = 0
    body = str(getattr(error, "body", "") or "").lower()
    text = str(error or "").lower()
    return status == 404 and ("not_found" in body or "not found" in body or "not_found" in text or "not found" in text)


def cancel_order(order_id: str, order: dict = None):
    if DRY_RUN:
        LOGGER.info("DRY_RUN would cancel order %s", order_id)
        return {}
    mutation_id = record_mutation_outcome(
        "cancel", "pending", order_id=order_id,
        client_order_id=str((order or {}).get("client_order_id") or ""),
        endpoint="DELETE /portfolio/events/orders/{order_id}",
    )
    prefer_v2 = active_order_is_v2(order) or ORDER_API_VERSION == "v2"
    if ORDER_API_VERSION == "v2" and not ORDER_API_LEGACY_FALLBACK:
        attempts = ["v2"]
    else:
        attempts = ["v2", "legacy"] if prefer_v2 else ["legacy", "v2"]
    last_error = None
    not_found_seen = False
    predicate = lambda target, source: source == "get_order_not_found" or _order_terminal(target)
    for version in attempts:
        try:
            if version == "v2":
                data = signed_request("DELETE", f"/portfolio/events/orders/{order_id}", params={"subaccount": SUBACCOUNT}, max_retries=MUTATION_WRITE_MAX_ATTEMPTS)
            else:
                data = signed_request("DELETE", f"/portfolio/orders/{order_id}", params={"subaccount": SUBACCOUNT}, max_retries=MUTATION_WRITE_MAX_ATTEMPTS)
            data = guard_mutation_response_identity(
                data, order_id, "cancel", mutation_id, predicate,
                client_order_id=str((order or {}).get("client_order_id") or ""), route=version,
            )
            record_mutation_outcome("cancel", "request_success", mutation_id, order_id=order_id, route=version)
            return data
        except MutationOutcomeUnresolvedError as e:
            last_error = e
            LOGGER.error("Cancel outcome ambiguous; refusing legacy/fresh fallback | order_id=%s | mutation_id=%s | error=%s", order_id, e.mutation_id, e)
            break
        except Exception as e:
            last_error = e
            if is_order_not_found_error(e):
                not_found_seen = True
                continue
            if mutation_error_is_ambiguous(e):
                try:
                    target = reconcile_order_mutation(
                        order_id, "cancel", mutation_id, predicate, error=e,
                        client_order_id=str((order or {}).get("client_order_id") or ""), route=version,
                    )
                    if target is not None:
                        return {"order": target, "order_id": order_id, "status": str(target.get("status") or "canceled"), "_cancel_reconciled": True}
                except MutationOutcomeUnresolvedError as unresolved:
                    last_error = unresolved
                    LOGGER.error("Cancel outcome unresolved; preserving state and refusing alternate route | order_id=%s | mutation_id=%s", order_id, unresolved.mutation_id)
                    break
            record_mutation_outcome("cancel", "definite_failure", mutation_id, order_id=order_id, route=version, **_mutation_event_error_fields(e))
            LOGGER.debug("%s cancel path failed for %s: %s", version, order_id, e)
    if not_found_seen:
        LOGGER.info("Cancel skipped; order already gone | order_id=%s | attempts=%s", order_id, ",".join(attempts))
        record_mutation_outcome("cancel", "idempotent_not_found", mutation_id, order_id=order_id)
        return {"order_id": order_id, "status": "not_found", "_cancel_idempotent": True}
    raise last_error


def decrease_order_to(order_id: str, remaining_qty: Decimal):
    body = {"subaccount": SUBACCOUNT}
    body.update(reduce_to_for_order_body(remaining_qty))
    return signed_request("POST", f"/portfolio/orders/{order_id}/decrease", json_body=body).get("order", {})


def amend_order_count(order_id: str, client_order_id: str, ticker: str, side: str, max_fillable_qty: Decimal, exit_price: Decimal = None):
    body = {
        "ticker": ticker,
        "side": side,
        "action": "sell",
        "subaccount": SUBACCOUNT,
        "client_order_id": client_order_id,
        "updated_client_order_id": client_order_id_for(ticker, side, api_version="lgamend"),
    }
    body.update(qty_for_order_body(max_fillable_qty))
    body.update(legacy_price_fields_for_exit(side, exit_price if exit_price is not None else SELL_PRICE))
    return signed_request("POST", f"/portfolio/orders/{order_id}/amend", json_body=body).get("order", {})


def infer_side_from_position(ticker: str, position_fp_raw):
    override = SIDE_OVERRIDES.get(ticker)
    if isinstance(override, str) and override.lower().strip() in {"yes", "no"}:
        return override.lower().strip()
    pos = parse_decimal(position_fp_raw)
    if pos > 0:
        return "yes"
    if pos < 0:
        return "no"
    return None


def market_key(ticker: str, side: str) -> str:
    return f"{ticker}|{side}"


def get_bucket(ticker: str, side: str):
    return STATE.setdefault("markets", {}).setdefault(market_key(ticker, side), default_market_bucket(ticker, side))


def mark_market_terminal(ticker: str, reason: str):
    now = now_ts()
    markets = STATE.setdefault("markets", {})
    meta_bucket = markets.setdefault(f"{ticker}|_meta", {})
    meta_bucket["_status_cache"] = {
        "ts": now,
        "value": {"exists": False, "status": "not_found", "raw": {}},
    }
    for key, bucket in markets.items():
        if key.startswith(f"{ticker}|") and not key.endswith("|_meta"):
            if isinstance(bucket, dict):
                bucket["market_terminal"] = True
                bucket["terminal_reason"] = reason
                bucket["terminal_ts"] = now
                bucket["active_order_id"] = None
                bucket["active_order_accounted_fill_fp"] = "0.00"
                bucket["last_known_open_orders"] = []
                bucket["last_summary_state"] = ""


def clear_market_terminal(ticker: str):
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key.startswith(f"{ticker}|") and not key.endswith("|_meta") and isinstance(bucket, dict):
            bucket["market_terminal"] = False
            bucket["terminal_reason"] = ""
            bucket["terminal_ts"] = 0
            bucket["terminal_close_summary_logged"] = False
            bucket["terminal_close_summary_last_attempt_ts"] = 0
        if key == f"{ticker}|_meta" and isinstance(bucket, dict):
            bucket.pop("_status_cache", None)


def is_market_terminal_locally(ticker: str) -> bool:
    prefix = f"{ticker}|"
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key.startswith(prefix) and not key.endswith("|_meta") and isinstance(bucket, dict):
            if bucket.get("market_terminal", False):
                return True
    return False


def maybe_recheck_terminal_market(ticker: str, bucket: dict) -> bool:
    if not bucket.get("market_terminal", False):
        return False
    if TERMINAL_RECHECK_SECONDS <= 0:
        return True
    terminal_ts = int(bucket.get("terminal_ts", 0) or 0)
    if now_ts() - terminal_ts < TERMINAL_RECHECK_SECONDS:
        return True
    try:
        status_info = get_market_status_info(ticker, force_refresh=True)
        status = str(status_info.get("status", "")).lower()
        if status_info.get("exists", True) and status not in {"closed", "settled", "determined", "not_found"}:
            LOGGER.warning("Clearing sticky terminal flag after successful recheck | ticker=%s | status=%s", ticker, status)
            clear_market_terminal(ticker)
            return False
    except Exception as e:
        LOGGER.warning("Terminal recheck failed for %s: %s", ticker, e)
    return True


def previous_open_orders_exist(bucket: dict) -> bool:
    return bool(bucket.get("last_known_open_orders") or [])


def precheck_terminal_on_disappeared_order(ticker: str, bucket: dict, active_order_present: bool) -> bool:
    if bucket.get("market_terminal", False):
        return True
    if not previous_open_orders_exist(bucket):
        return False
    if active_order_present:
        return False
    try:
        status_info = get_market_status_info(ticker, force_refresh=True)
    except Exception as e:
        STATE.setdefault("meta", {})["terminal_disappeared_order_precheck_last_error"] = str(e)[:300]
        LOGGER.warning("Skipping terminal disappeared-order precheck after market-status read failure | ticker=%s | error=%s", ticker, e)
        return False
    status = str(status_info.get("status", "")).lower()
    if (not status_info.get("exists", True)) or status in {"closed", "settled", "determined", "not_found"}:
        mark_market_terminal(ticker, f"status:{status or 'not_found'}")
        return True
    return False


def maybe_log_pending_terminal_close_summaries():
    for key, bucket in list(STATE.setdefault("markets", {}).items()):
        if key.endswith("|_meta") or not isinstance(bucket, dict):
            continue
        if not bucket.get("market_terminal", False):
            continue
        ticker = bucket.get("ticker") or key.split("|", 1)[0]
        live_qty = parse_decimal(bucket.get("last_known_position_fp", "0.00"), "0")
        maybe_log_terminal_close_summary(ticker, bucket, live_qty)


def reset_error_streak(bucket: dict):
    bucket["cooldown_until_ts"] = 0
    bucket["last_error"] = ""
    bucket["insufficient_balance_streak"] = 0
    bucket["insufficient_balance_position_fp"] = None
    bucket["insufficient_balance_balance_cents"] = None
    bucket["insufficient_balance_open_orders"] = None


def apply_short_balance_cooldown(bucket: dict):
    streak = int(bucket.get("insufficient_balance_streak", 0) or 0) + 1
    bucket["insufficient_balance_streak"] = streak
    cooldown = min(ERROR_COOLDOWN_MAX_SECONDS, ERROR_COOLDOWN_BASE_SECONDS * (2 ** (streak - 1)))
    bucket["cooldown_until_ts"] = now_ts() + cooldown
    return cooldown, streak


def state_fingerprint(position_qty: int, balance_cents, open_orders_serialized):
    return (str(contracts_str(Decimal(position_qty))), balance_cents, json.dumps(open_orders_serialized, sort_keys=True))


def should_retry_after_insufficient_balance(bucket: dict, position_qty: int, balance_cents, open_orders_serialized) -> bool:
    prev = (
        bucket.get("insufficient_balance_position_fp"),
        bucket.get("insufficient_balance_balance_cents"),
        bucket.get("insufficient_balance_open_orders"),
    )
    current = state_fingerprint(position_qty, balance_cents, open_orders_serialized)
    return prev != current


def note_insufficient_balance_state(bucket: dict, position_qty: int, balance_cents, open_orders_serialized):
    fp = state_fingerprint(position_qty, balance_cents, open_orders_serialized)
    bucket["insufficient_balance_position_fp"] = fp[0]
    bucket["insufficient_balance_balance_cents"] = fp[1]
    bucket["insufficient_balance_open_orders"] = fp[2]


def in_post_fill_settle_window(bucket: dict) -> bool:
    return now_ts() < int(bucket.get("post_fill_settle_until_ts", 0) or 0)


def serialize_orders(orders, side: str):
    out = []
    for order in orders:
        if not order:
            continue
        out.append({
            "order_id": order.get("order_id"),
            "client_order_id": order.get("client_order_id"),
            "remaining_count_fp": str(order.get("remaining_count_fp", "0.00")),
            "fill_count_fp": str(order.get("fill_count_fp", "0.00")),
            "status": str(order.get("status", "")),
            "price": str(order.get("yes_price_dollars") if side == "yes" else order.get("no_price_dollars")),
        })
    return out


def sync_tracked_order_fill(bucket: dict, live_resting_orders_by_id: dict):
    order_id = bucket.get("active_order_id")
    if not order_id:
        return
    accounted_fill = parse_decimal(bucket.get("active_order_accounted_fill_fp", "0.00"), "0")
    processed_by_order = bucket.get("processed_order_fill_qty", {}) if isinstance(bucket.get("processed_order_fill_qty", {}), dict) else {}
    accounted_fill = max_decimal(accounted_fill, parse_decimal(processed_by_order.get(order_id, "0.00"), "0"))
    order = live_resting_orders_by_id.get(order_id)
    if order is None:
        try:
            order = get_order(order_id)
        except Exception as e:
            LOGGER.warning("Could not refresh tracked order %s: %s", order_id, e)
            return
    current_fill = parse_decimal(order.get("fill_count_fp", "0.00"), "0")
    delta = current_fill - accounted_fill
    if delta > 0:
        cum = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0")
        bucket["cum_filled_fp"] = contracts_str(cum + delta)
        bucket["post_fill_settle_until_ts"] = now_ts() + POST_FILL_SETTLE_SECONDS
    is_resting = str(order.get("status", "")).lower() == "resting"
    if is_resting:
        bucket["active_order_accounted_fill_fp"] = contracts_str(current_fill)
    else:
        bucket["active_order_id"] = None
        bucket["active_order_accounted_fill_fp"] = "0.00"
        if current_fill > 0:
            bucket["post_fill_settle_until_ts"] = now_ts() + POST_FILL_SETTLE_SECONDS


def register_managed_order(bucket: dict, order_or_id):
    if not bucket:
        return
    order_id = order_or_id.get("order_id") if isinstance(order_or_id, dict) else order_or_id
    if order_id:
        bucket["known_order_ids"] = bounded_append_unique(bucket.get("known_order_ids", []), order_id, KNOWN_ORDER_ID_LIMIT)


def cache_managed_order_after_write(bucket: dict, order: dict, ticker: str, side: str, qty=None, exit_price=None, api_version: str = "", context: str = "") -> dict:
    """Cache a just-created/amended managed order for same-cycle sell verification.

    Kalshi REST open-order reads can be a few moments behind a successful write.
    Without a short local grace cache, post-write diagnostics can falsely report
    `missing_order` even after a 2c hedge order was accepted. This cache never
    replaces exchange truth long-term; it only fills the gap until the order is
    visible in REST or private user_order updates.
    """
    if not isinstance(bucket, dict):
        return order if isinstance(order, dict) else {}
    order = dict(order or {})
    ticker = str(ticker or order.get("ticker") or "").strip()
    side = str(side or order.get("_managed_side") or order.get("side") or "").strip().lower()
    if side not in {"yes", "no"}:
        side = managed_side_from_order(order) or side
    p = parse_decimal(exit_price if exit_price is not None else order_exit_price(order, side), str(SELL_PRICE))
    q = parse_decimal(qty if qty is not None else order.get("remaining_count_fp", order.get("count", "0")), "0")
    fill = parse_decimal(order.get("fill_count_fp", order.get("fill_count", "0.00")), "0")
    remaining = parse_decimal(order.get("remaining_count_fp", order.get("remaining_count", "0.00")), "0")
    raw_status = str(order.get("status") or "").strip().lower()
    terminal_status = raw_status in {"canceled", "cancelled", "executed", "filled", "expired", "rejected"}
    if remaining <= 0 and q > 0 and fill < q and not terminal_status:
        remaining = max_decimal(Decimal("0"), q - fill)
    order.setdefault("ticker", ticker)
    order.setdefault("side", side)
    order.setdefault("action", "sell")
    order.setdefault("status", "resting" if remaining > 0 else "executed")
    order.setdefault("remaining_count_fp", qty_str(remaining))
    order.setdefault("fill_count_fp", qty_str(fill))
    order.setdefault("initial_count_fp", qty_str(q if q > 0 else remaining + fill))
    order.setdefault("_managed_side", side)
    if api_version:
        order.setdefault("_api_version", api_version)
    if side == "yes":
        order.setdefault("yes_price_dollars", price_str(p))
    elif side == "no":
        order.setdefault("no_price_dollars", price_str(p))
    order_id = str(order.get("order_id") or "").strip()
    if order_id:
        register_managed_order(bucket, order_id)
    if order_id and remaining > 0 and not terminal_status:
        bucket["active_order_id"] = order_id
    elif str(bucket.get("active_order_id") or "") == order_id or terminal_status:
        bucket["active_order_id"] = None
    bucket["active_order_accounted_fill_fp"] = contracts_str(fill if remaining > 0 and not terminal_status else Decimal("0"))
    bucket["last_successful_sell_order"] = order
    bucket["last_successful_sell_order_ts"] = now_ts()
    bucket["last_successful_sell_order_context"] = str(context or "")
    bucket["last_successful_sell_order_price"] = price_str(p)
    bucket["last_successful_sell_order_remaining_fp"] = qty_str(remaining)
    if remaining > 0 and not terminal_status:
        bucket["last_known_open_orders"] = serialize_orders([order], side)
    elif terminal_status:
        bucket["last_known_open_orders"] = []
    return order


def synthetic_active_order_from_bucket(ticker: str, side: str, bucket: dict, grace_seconds: int = None) -> dict:
    """Return a short-lived local active order if exchange open-order read lags.

    This is used only for diagnostics and immediate same-cycle coverage checks.
    It prevents false `missing_order` reports after a successful 2c placement.
    """
    if not isinstance(bucket, dict):
        return {}
    grace = int(grace_seconds if grace_seconds is not None else POST_WRITE_VERIFY_LOCAL_ORDER_GRACE_SECONDS)
    ts = int(bucket.get("last_successful_sell_order_ts", 0) or 0)
    if grace >= 0 and (not ts or now_ts() - ts > grace):
        return {}
    order = bucket.get("last_successful_sell_order")
    if not isinstance(order, dict):
        return {}
    order_id = str(order.get("order_id") or bucket.get("active_order_id") or "").strip()
    if not order_id:
        return {}
    remaining = parse_decimal(order.get("remaining_count_fp", bucket.get("last_successful_sell_order_remaining_fp", "0.00")), "0")
    if remaining <= 0:
        return {}
    side = str(side or order.get("_managed_side") or order.get("side") or "").lower()
    if side not in {"yes", "no"}:
        return {}
    p = parse_decimal(order_exit_price(order, side), str(HEDGE_EXIT_PRICE if HEDGE_2C_ONLY_MODE else SELL_PRICE))
    if HEDGE_2C_ONLY_MODE and not hedge_contract_price_ok(p):
        return {}
    out = dict(order)
    out["order_id"] = order_id
    out.setdefault("ticker", ticker)
    out["side"] = side
    out.setdefault("_managed_side", side)
    out["remaining_count_fp"] = qty_str(remaining)
    out.setdefault("status", "resting")
    out["local_post_write_grace"] = "1"
    return out


def merge_synthetic_orders_for_positions(positions, primary_by_key: dict, context: str = "") -> dict:
    merged = dict(primary_by_key or {})
    for p in positions or []:
        if not isinstance(p, dict):
            continue
        ticker = str(p.get("ticker") or "").strip()
        side = infer_side_from_position(ticker, p.get("position_fp", "0.00")) if ticker else None
        if not ticker or side not in {"yes", "no"}:
            continue
        key = market_key(ticker, side)
        if key in merged and isinstance(merged.get(key), dict) and merged[key].get("order_id"):
            continue
        order = synthetic_active_order_from_bucket(ticker, side, get_bucket(ticker, side))
        if order:
            LOGGER.info("Using local post-write managed order cache for sell verification | context=%s | ticker=%s | side=%s | order_id=%s | remaining=%s", context, ticker, side, order.get("order_id"), order.get("remaining_count_fp"))
            merged[key] = order
    return merged


def register_live_managed_orders(resting_orders):
    for order in filter_managed_orders(resting_orders):
        ticker = order.get("ticker")
        side = managed_side_from_order(order)
        if ticker and side in {"yes", "no"}:
            register_managed_order(get_bucket(ticker, side), order)


def find_bucket_for_managed_order_id(order_id: str, ticker: str = "", side: str = ""):
    oid = str(order_id or "").strip()
    ticker = str(ticker or "").strip()
    side = str(side or "").strip().lower()
    if ticker and side in {"yes", "no"}:
        bucket = get_bucket(ticker, side)
        if oid and (str(bucket.get("active_order_id") or "") == oid or oid in (bucket.get("known_order_ids", []) or [])):
            return market_key(ticker, side), bucket
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key.endswith("|_meta") or not isinstance(bucket, dict):
            continue
        if oid and str(bucket.get("active_order_id") or "") == oid:
            return key, bucket
        if oid and oid in (bucket.get("known_order_ids", []) or []):
            return key, bucket
        orders = bucket.get("last_known_open_orders", [])
        if isinstance(orders, list):
            for order in orders:
                if isinstance(order, dict) and oid and str(order.get("order_id") or "") == oid:
                    return key, bucket
    if ticker and side in {"yes", "no"}:
        return market_key(ticker, side), get_bucket(ticker, side)
    return "", None


def account_managed_ws_order_fill_hint(msg: dict) -> bool:
    """Use private user_order updates to account managed sell fills immediately.

    REST fill sync remains the realized PnL source of truth, but waiting for REST
    can leave residual positions marked no_target for a whole cycle. This updates
    cum_filled_fp from monotonic user_order fill_count_fp deltas so the next sell
    pass can cover leftover residual inventory immediately.
    """
    if not isinstance(msg, dict):
        return False
    order_id = str(msg.get("order_id") or "").strip()
    if not order_id:
        return False
    client_order_id = str(msg.get("client_order_id") or "")
    if client_order_id and not client_order_id.startswith(CLIENT_PREFIX):
        return False
    ticker = str(msg.get("ticker") or msg.get("market_ticker") or "").strip()
    side = managed_side_from_order(msg)
    key, bucket = find_bucket_for_managed_order_id(order_id, ticker=ticker, side=side or "")
    if not isinstance(bucket, dict):
        return False
    if not ticker:
        ticker = str(bucket.get("ticker") or (key.split("|", 1)[0] if "|" in key else ""))
    if not side:
        side = str(bucket.get("side") or (key.split("|", 1)[1] if "|" in key else "")).lower()
    if side not in {"yes", "no"}:
        return False
    register_managed_order(bucket, order_id)
    fill_count = parse_decimal(msg.get("fill_count_fp", msg.get("filled_count_fp", msg.get("fill_count", "0"))), "0").quantize(Decimal("0.00"))
    if fill_count <= 0:
        return False
    accounted = bucket.get("ws_order_accounted_fill_qty", {})
    if not isinstance(accounted, dict):
        accounted = {}
    prior = parse_decimal(accounted.get(order_id, bucket.get("active_order_accounted_fill_fp", "0.00")), "0").quantize(Decimal("0.00"))
    delta = (fill_count - prior).quantize(Decimal("0.00"))
    if delta <= 0:
        return False
    cum = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    bucket["cum_filled_fp"] = contracts_str(cum + delta)
    accounted[order_id] = contracts_str(fill_count)
    bucket["ws_order_accounted_fill_qty"] = accounted
    bucket["active_order_accounted_fill_fp"] = contracts_str(fill_count)
    bucket["last_ws_managed_sell_fill_accounted_ts"] = now_ts()
    bucket["last_ws_managed_sell_fill_delta_fp"] = contracts_str(delta)
    bucket["last_ws_managed_sell_fill_order_id"] = order_id
    bucket["post_fill_settle_until_ts"] = now_ts() + POST_FILL_SETTLE_SECONDS
    status = str(msg.get("status") or "").lower()
    remaining = parse_decimal(msg.get("remaining_count_fp", msg.get("remaining_count", "0")), "0")
    if status in {"executed", "filled", "canceled", "cancelled"} or remaining <= 0:
        if str(bucket.get("active_order_id") or "") == order_id:
            bucket["active_order_id"] = None
            bucket["active_order_accounted_fill_fp"] = "0.00"
            bucket["last_known_open_orders"] = []
    meta = STATE.setdefault("meta", {})
    meta["ws_managed_sell_fill_accounted_count"] = int(meta.get("ws_managed_sell_fill_accounted_count", 0) or 0) + 1
    meta["ws_managed_sell_fill_accounted_last_ts"] = now_ts()
    LOGGER.warning(
        "WSManagedSellFillAccounted | ticker=%s | side=%s | order_id=%s | delta=%s | fill_count=%s | cum_filled=%s",
        ticker, side, order_id, qty_str(delta), qty_str(fill_count), bucket.get("cum_filled_fp"),
    )
    return True


def filter_managed_orders(resting_orders):
    return [o for o in resting_orders if (o.get("client_order_id", "") or "").startswith(CLIENT_PREFIX)]


def build_managed_order_map(resting_orders):
    grouped = {}
    for order in filter_managed_orders(resting_orders):
        ticker = order.get("ticker")
        side = managed_side_from_order(order)
        if not ticker or side not in {"yes", "no"}:
            continue
        grouped.setdefault(market_key(ticker, side), []).append(order)
    return grouped


def adopt_primary_managed_orders(primary_by_key: dict):
    """Adopt the exchange's currently-resting managed orders into local state.

    This is intentionally conservative: duplicate/orphan cleanup still decides
    what to cancel, but the state file no longer starts from saved=[] when a
    valid managed 2c order is already resting on Kalshi. That reduces duplicate
    repair churn after restarts, support-bundle restores, and nested-folder moves.
    """
    for key, order in (primary_by_key or {}).items():
        if not isinstance(order, dict):
            continue
        order_id = order.get("order_id")
        if not order_id or "|" not in str(key):
            continue
        ticker, side = str(key).rsplit("|", 1)
        if side not in {"yes", "no"}:
            continue
        bucket = get_bucket(ticker, side)
        previous_order_id = bucket.get("active_order_id")
        register_managed_order(bucket, order)
        bucket["last_known_open_orders"] = serialize_orders([order], side)
        bucket["active_order_id"] = order_id
        bucket["active_order_accounted_fill_fp"] = contracts_str(parse_decimal(order.get("fill_count_fp", "0.00"), "0"))
        if previous_order_id and previous_order_id != order_id:
            LOGGER.info("Adopt live managed order | ticker=%s | side=%s | previous_order_id=%s | live_order_id=%s", ticker, side, previous_order_id, order_id)


def normalized_outcome_side(row: dict, fallback: str = "") -> str:
    """Return yes/no from Kalshi legacy or normalized direction fields.

    Kalshi has added outcome_side/book_side to Order/Fill/Trade responses.
    This helper lets the bot keep accepting older action/side payloads while
    avoiding missed fill/order hints when newer payloads omit legacy side.
    """
    if not isinstance(row, dict):
        return str(fallback or "").lower()
    for name in ("outcome_side", "side"):
        val = str(row.get(name) or "").strip().lower()
        if val in {"yes", "no"}:
            return val
    book_side = str(row.get("book_side") or "").strip().lower()
    if book_side == "bid":
        return "yes"
    if book_side == "ask":
        return "no"
    return str(fallback or "").strip().lower()


def normalized_action(row: dict, fallback: str = "") -> str:
    if not isinstance(row, dict):
        return str(fallback or "").lower()
    val = str(row.get("action") or fallback or "").strip().lower()
    if val in {"buy", "sell"}:
        return val
    return str(fallback or "").strip().lower()

def managed_side_from_client_order_id(client_order_id: str):
    cid = str(client_order_id or "").lower()
    prefix = f"{CLIENT_PREFIX}-"
    if cid.startswith(prefix):
        rest = cid[len(prefix):]
        first = rest.split("-", 1)[0]
        if first in {"yes", "no"}:
            return first
    return None


def managed_side_from_order(order: dict):
    if not isinstance(order, dict):
        return None
    tagged = managed_side_from_client_order_id(order.get("client_order_id", ""))
    if tagged in {"yes", "no"}:
        return tagged
    outcome_side = str(order.get("outcome_side") or "").strip().lower()
    if outcome_side in {"yes", "no"}:
        return outcome_side
    side = str(order.get("side") or "").lower()
    if side in {"yes", "no"}:
        return side
    # V2 order side=ask means a YES-side ask in older payloads. Prefer the
    # tagged client id whenever present; this fallback preserves restart
    # adoption for older managed orders that were created before outcome_side.
    if side == "ask":
        return "yes"
    book_side = str(order.get("book_side") or "").strip().lower()
    if book_side == "bid":
        return "yes"
    if book_side == "ask":
        return "no"
    return None


def write_managed_order_backfill_audit(rows, force: bool = False) -> dict:
    now = now_ts()
    rows = list(rows or [])[-max(1, MANAGED_ORDER_BACKFILL_MAX_AUDIT_ROWS):]
    status_counts = {}
    for r in rows:
        status_counts[str(r.get("status", "unknown"))] = status_counts.get(str(r.get("status", "unknown")), 0) + 1
    snap = {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "enabled": bool(MANAGED_ORDER_BACKFILL_ENABLED),
        "row_count": len(rows),
        "status_counts": status_counts,
        "settings": {
            "managed_order_backfill_interval_seconds": MANAGED_ORDER_BACKFILL_INTERVAL_SECONDS,
            "managed_order_backfill_lookback_seconds": MANAGED_ORDER_BACKFILL_LOOKBACK_SECONDS,
            "managed_order_backfill_statuses": list(MANAGED_ORDER_BACKFILL_STATUSES),
            "managed_order_backfill_max_pages": MANAGED_ORDER_BACKFILL_MAX_PAGES,
            "managed_order_backfill_limit_per_page": MANAGED_ORDER_BACKFILL_LIMIT_PER_PAGE,
        },
        "rows": rows,
    }
    STATE.setdefault("meta", {})["last_managed_order_backfill"] = snap
    atomic_write_json(MANAGED_ORDER_BACKFILL_LATEST_JSON_PATH, snap)
    fields = ["snapshot_ts", "status", "ticker", "side", "order_id", "client_order_id", "order_status", "fill_count_fp", "remaining_count_fp", "created_time", "last_update_time", "reason"]
    atomic_write_csv(MANAGED_ORDER_BACKFILL_LATEST_CSV_PATH, fields, rows or [{k: "" for k in fields}])
    for row in rows:
        append_csv_row(MANAGED_ORDER_BACKFILL_HISTORY_CSV_PATH, fields, row)
    return snap


def backfill_recent_managed_orders(force: bool = False) -> dict:
    if not MANAGED_ORDER_BACKFILL_ENABLED:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("managed_order_backfill_last_run_ts", 0) or 0) < MANAGED_ORDER_BACKFILL_INTERVAL_SECONDS:
        return meta.get("last_managed_order_backfill", {}) or {}
    meta["managed_order_backfill_last_run_ts"] = now
    min_ts = max(0, now - MANAGED_ORDER_BACKFILL_LOOKBACK_SECONDS)
    rows = []
    registered = 0
    try:
        for status in MANAGED_ORDER_BACKFILL_STATUSES:
            orders = get_recent_orders_by_status(status, min_ts=min_ts, max_pages=MANAGED_ORDER_BACKFILL_MAX_PAGES, limit=MANAGED_ORDER_BACKFILL_LIMIT_PER_PAGE)
            for order in orders:
                cid = str(order.get("client_order_id", "") or "")
                if not cid.startswith(CLIENT_PREFIX):
                    continue
                ticker = order.get("ticker") or order.get("market_ticker") or ""
                side = managed_side_from_order(order)
                order_id = str(order.get("order_id") or "")
                if not ticker or side not in {"yes", "no"} or not order_id:
                    rows.append({"snapshot_ts": now, "status": "skipped", "ticker": ticker, "side": side or "", "order_id": order_id, "client_order_id": cid, "order_status": status, "fill_count_fp": str(order.get("fill_count_fp", order.get("fill_count", ""))), "remaining_count_fp": str(order.get("remaining_count_fp", order.get("remaining_count", ""))), "created_time": order.get("created_time", ""), "last_update_time": order.get("last_update_time", ""), "reason": "missing_ticker_side_or_order_id"})
                    continue
                bucket = get_bucket(ticker, side)
                before = set(bucket.get("known_order_ids", []) or [])
                register_managed_order(bucket, order)
                order_status = str(order.get("status", status))
                remaining_fp = str(order.get("remaining_count_fp", order.get("remaining_count", "")))
                terminal_backfill = _order_fill_visibility_terminal_status(order_status)
                reason = "already_known" if order_id in before else "recent_managed_order_backfilled"
                if terminal_backfill:
                    reason = f"{reason};terminal_order_not_active"
                if order_id not in before:
                    registered += 1
                rows.append({"snapshot_ts": now, "status": "terminal_registered" if terminal_backfill else "registered", "ticker": ticker, "side": side, "order_id": order_id, "client_order_id": cid, "order_status": order_status, "fill_count_fp": str(order.get("fill_count_fp", order.get("fill_count", ""))), "remaining_count_fp": remaining_fp, "created_time": order.get("created_time", ""), "last_update_time": order.get("last_update_time", ""), "reason": reason})
    except Exception as e:
        LOGGER.warning("Managed order backfill failed: %s", e)
        rows.append({"snapshot_ts": now, "status": "scan_failed", "ticker": "", "side": "", "order_id": "", "client_order_id": "", "order_status": "", "fill_count_fp": "", "remaining_count_fp": "", "created_time": "", "last_update_time": "", "reason": str(e)[:300]})
    meta["managed_order_backfill_registered_count"] = int(meta.get("managed_order_backfill_registered_count", 0) or 0) + registered
    return write_managed_order_backfill_audit(rows, force=True)


def is_strict_2c_recovery_price(price: Decimal) -> bool:
    try:
        return abs(parse_decimal(price, "0") - TARGET_2C_PRICE) <= RECOVERY_PACKET_FILL_PRICE_TOLERANCE
    except Exception:
        return False


def client_order_id_for(ticker: str, side: str, api_version: str = "legacy") -> str:
    suffix = uuid.uuid4().hex[:18]
    safe_side = side if side in {"yes", "no"} else "unk"
    safe_version = "v2" if api_version == "v2" else "lg"
    return f"{CLIENT_PREFIX}-{safe_side}-{safe_version}-{suffix}"


def hedge_contract_price(exit_price=None) -> Decimal:
    return parse_decimal(exit_price if exit_price is not None else HEDGE_EXIT_PRICE, str(HEDGE_EXIT_PRICE)).quantize(Decimal("0.0001"))


def hedge_contract_price_ok(price) -> bool:
    try:
        return abs(parse_decimal(price, "0") - HEDGE_EXIT_PRICE) <= Decimal("0.0001")
    except Exception:
        return False


def hedge_target_total_qty(current_position_qty: Decimal, bucket: dict) -> Decimal:
    cum_filled = parse_decimal((bucket or {}).get("cum_filled_fp", "0.00"), "0")
    original_estimate = max_decimal(Decimal("0"), parse_decimal(current_position_qty, "0") + cum_filled)
    if original_estimate <= 0:
        return Decimal("0.00")
    return (original_estimate * HEDGE_TARGET_FRACTION).quantize(Decimal("0.00"), rounding=ROUND_FLOOR)


def v2_payload_display_contract_price(side: str, body: dict) -> Decimal:
    """Return the contract-side display price implied by a V2 YES-book payload.

    V2 event orders quote the YES book. For a NO hedge, a YES-book bid at
    0.9800 is economically equivalent to selling NO at 0.0200. Strict hedge mode
    validates the reconstructed economic/display price, not only the raw YES-book
    price, so the bot can use V2 without leaking non-2c exits.
    """
    p = parse_decimal((body or {}).get("price", "0"), "0")
    v2_side = str((body or {}).get("side") or "").strip().lower()
    side = str(side or "").strip().lower()
    if side == "yes" and v2_side == "ask":
        return p
    if side == "no" and v2_side == "bid":
        return max(Decimal("0"), Decimal("1") - p)
    return p


def hedge_order_payload_compliant(side: str, qty, exit_price, api_version: str, body: dict) -> tuple:
    """Validate outbound sell payload against the hedge-only contract.

    Returns (ok, reason). This is fail-closed for anything that would place a
    non-2c hedge order. For NO-side V2, raw YES-book 98c is allowed only when
    the reconstructed contract-side display exit is exactly 2c.
    """
    if not HEDGE_2C_ONLY_MODE:
        return True, "hedge_mode_disabled"
    side = str(side or "").strip().lower()
    api_version = str(api_version or "").strip().lower()
    p = parse_decimal(exit_price if exit_price is not None else SELL_PRICE, str(SELL_PRICE))
    if HEDGE_BLOCK_NON_2C_SELL_PAYLOAD and not hedge_contract_price_ok(p):
        return False, f"blocked_non_2c_exit_price_{price_str(p)}"
    if api_version == "v2":
        v2_side = str((body or {}).get("side") or "").strip().lower()
        v2_price = parse_decimal((body or {}).get("price", "0"), "0")
        display_contract = v2_payload_display_contract_price(side, body or {})
        if HEDGE_BLOCK_NO_SIDE_V2_INVERSE and side == "no" and v2_side == "bid" and v2_price > Decimal("0.50"):
            return False, f"blocked_no_side_v2_inverse_yes_book_price_{price_str(v2_price)}_contract_price_{price_str(display_contract)}"
        if HEDGE_BLOCK_NON_2C_SELL_PAYLOAD and not hedge_contract_price_ok(display_contract):
            return False, f"blocked_v2_display_contract_price_{price_str(display_contract)}"
        if side == "yes" and v2_side != "ask":
            return False, f"blocked_yes_exit_wrong_v2_side_{v2_side}"
        if side == "no" and v2_side not in {"bid"}:
            return False, f"blocked_no_exit_wrong_v2_side_{v2_side}"
    return True, "ok"


def write_hedge_order_guard_report(status: str, ticker: str = "", side: str = "", qty=None, exit_price=None, api_version: str = "", body: dict = None, reason: str = "", context: str = "") -> dict:
    payload = {
        "snapshot_ts": now_ts(),
        "snapshot_ct": central_time_iso_from_ts(now_ts()),
        "build_id": BUILD_ID,
        "instance": INSTANCE_NAME,
        "status": status,
        "context": context,
        "ticker": ticker,
        "side": side,
        "qty_fp": qty_str(qty or Decimal("0")),
        "exit_price_dollars": price_str(exit_price if exit_price is not None else SELL_PRICE),
        "api_version": api_version,
        "reason": reason,
        "hedge_2c_only_mode": bool(HEDGE_2C_ONLY_MODE),
        "target_fraction": str(HEDGE_TARGET_FRACTION),
        "target_price_dollars": price_str(HEDGE_EXIT_PRICE),
        "body_side": str((body or {}).get("side", "")),
        "body_price": str((body or {}).get("price", "")),
        "client_order_id": str((body or {}).get("client_order_id", "")),
    }
    try:
        atomic_write_json(HEDGE_ORDER_GUARD_LATEST_JSON_PATH, payload)
        lines = [
            "Kalshi 15m 2c Sell Bot - Hedge Order Guard",
            "============================================",
            f"Generated CT : {payload['snapshot_ct']}",
            f"Build ID     : {BUILD_ID}",
            f"Status       : {status}",
            f"Context      : {context}",
            f"Ticker/Side  : {ticker}|{side}",
            f"Qty          : {payload['qty_fp']}",
            f"Exit price   : {payload['exit_price_dollars']}",
            f"API/body     : {api_version} side={payload['body_side']} price={payload['body_price']}",
            f"Reason       : {reason}",
            "",
            "Policy       : sell exactly the 40% sell target at contract-side 2c only; YES exits show as V2 ask @2c, while NO exits can show as V2 YES-book bid near 98c but are decoded/audited as economic NO-side 2c exits.",
        ]
        os.makedirs(os.path.dirname(HEDGE_ORDER_GUARD_LATEST_TXT_PATH) or ".", exist_ok=True)
        with open(HEDGE_ORDER_GUARD_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception:
        pass
    STATE.setdefault("meta", {})["last_hedge_order_guard"] = payload
    return payload


def order_exit_price(order: dict, managed_side: str) -> Decimal:
    if managed_side == "yes":
        return parse_decimal(order.get("yes_price_dollars", order.get("price", SELL_PRICE)), str(SELL_PRICE))
    if managed_side == "no":
        no_raw = order.get("no_price_dollars")
        if no_raw is not None:
            return parse_decimal(no_raw, str(SELL_PRICE))
        yes_raw = order.get("yes_price_dollars", order.get("price", None))
        if yes_raw is not None:
            return max(Decimal("0"), Decimal("1") - parse_decimal(yes_raw, "1"))
    return SELL_PRICE


def legacy_price_fields_for_exit(side: str, exit_price: Decimal) -> dict:
    p = parse_decimal(exit_price, str(SELL_PRICE))
    return {"yes_price_dollars" if side == "yes" else "no_price_dollars": price_str(p)}


def active_order_hedge_compliant(order: dict, managed_side: str, exit_price=None) -> tuple:
    """Validate an already-resting managed order against strict hedge-only mode.

    Outbound strict mode still avoids creating NO-side V2 inverse payloads when
    the legacy contract-side sell route is available. However, Kalshi order and
    WebSocket echoes can normalize a perfectly valid sell/no/0.0200 order into a
    YES-book representation near 0.9800. The compliance check must therefore
    judge active orders by the recovered contract-side display price first, or
    it churns valid 2c orders by canceling/replacing them repeatedly.
    """
    if not HEDGE_2C_ONLY_MODE:
        return True, "hedge_mode_disabled"
    if not isinstance(order, dict) or not order.get("order_id"):
        return True, "no_active_order"
    side = str(managed_side or order.get("managed_side") or order.get("side") or "").strip().lower()
    wanted_price = hedge_contract_price(exit_price if exit_price is not None else HEDGE_EXIT_PRICE)
    display_price = order_exit_price(order, side)
    display_ok = hedge_contract_price_ok(display_price)
    if HEDGE_BLOCK_NON_2C_SELL_PAYLOAD and not display_ok:
        return False, f"active_order_non_2c_display_price_{price_str(display_price)}_wanted_{price_str(wanted_price)}"
    if active_order_is_v2(order) and side == "no" and HEDGE_BLOCK_NO_SIDE_V2_INVERSE:
        raw_price = parse_decimal(
            order.get("price", order.get("yes_price_dollars", order.get("price_dollars", "0"))),
            "0",
        )
        raw_book_side = str(order.get("book_side") or order.get("v2_side") or order.get("order_side") or "").strip().lower()
        outcome_side = str(order.get("outcome_side") or order.get("outcome") or "").strip().lower()
        if display_ok:
            return True, f"ok_no_side_active_display_2c_raw_{price_str(raw_price)}"
        # If the display-price reconstruction fails, keep the older fail-closed
        # behavior so a genuine 98c/99c mistake cannot leak through.
        if raw_price > Decimal("0.50") or raw_book_side == "bid" or outcome_side == "yes":
            return False, f"active_no_side_v2_inverse_order_blocked_price_{price_str(raw_price)}_display_{price_str(display_price)}"
        return False, "active_no_side_v2_order_blocked_in_strict_hedge_mode"
    if side == "yes" and active_order_is_v2(order):
        raw_book_side = str(order.get("book_side") or order.get("v2_side") or order.get("order_side") or "ask").strip().lower()
        if raw_book_side and raw_book_side != "ask":
            return False, f"active_yes_side_v2_wrong_book_side_{raw_book_side}"
    return True, "ok"


def v2_side_price_for_exit(side: str, exit_price: Decimal):
    p = parse_decimal(exit_price, str(SELL_PRICE))
    if side == "yes":
        return "ask", p
    # V2 quotes the YES book, so a NO-side sell at economic 2c is represented as
    # a near-98c YES-book bid. Hedge guards reconstruct the display/economic
    # price and still require 2c exactly.
    return "bid", max(Decimal("0.0001"), min(Decimal("0.9999"), Decimal("1") - p))


def v2_side_price_for_buy_entry(side: str, buy_price: Decimal):
    """Return Kalshi V2 single-book side/price for an advisory buy entry.

    The V2 event-order endpoint quotes the YES book only: bid means buy YES,
    ask means sell YES. Buying NO at p is therefore equivalent to asking YES at
    1-p. This helper is export-only for the buy-bot handoff rows.
    """
    p = parse_decimal(buy_price, str(BUY_PRICE))
    p = max(Decimal("0.0001"), min(Decimal("0.9999"), p))
    if str(side or "").lower() == "yes":
        return "bid", p
    return "ask", max(Decimal("0.0001"), min(Decimal("0.9999"), Decimal("1") - p))


def safe_client_order_id(seed: str, prefix: str = None) -> str:
    """Create a deterministic, compact, API-safe client_order_id string."""
    raw_prefix = (prefix or BUY_ACTION_PLAN_CLIENT_ORDER_ID_PREFIX or "K15M").strip()[:12] or "K15M"
    safe_prefix = "".join(ch if ch.isalnum() or ch in ("-", "_") else "-" for ch in raw_prefix)[:12] or "K15M"
    digest = uuid.uuid5(uuid.NAMESPACE_URL, str(seed or "")).hex[:24]
    return f"{safe_prefix}-{digest}"


def action_idempotency_window(ts: int = None) -> int:
    ts = int(ts or now_ts())
    window = max(5, int(BUY_ACTION_PLAN_IDEMPOTENCY_WINDOW_SECONDS or 60))
    return int(ts // window * window)


def buy_action_handoff_fields(ticker: str, side: str, level: str, buy_price: Decimal, qty: Decimal, target: Decimal, snapshot_ts: int) -> dict:
    """Build buy-bot handoff fields; this bot still never places buy orders."""
    window_ts = action_idempotency_window(snapshot_ts)
    seed = f"{ticker}|{side}|{level}|{price_str(buy_price)}|{qty_str(qty)}|{price_str(target)}|{window_ts}"
    client_order_id = safe_client_order_id(seed)
    expires_ts = int(snapshot_ts) + max(5, int(BUY_ACTION_PLAN_TTL_SECONDS or 45))
    v2_side, v2_price = v2_side_price_for_buy_entry(side, buy_price)
    order_group_id = ""
    order_group_error = ""
    if ORDER_GROUP_ENABLED:
        try:
            order_group_id = ensure_order_group_id()
        except Exception as e:
            order_group_error = str(e)[:240]
            LOGGER.warning("Buy action handoff could not resolve order group id | ticker=%s | side=%s | error=%s", ticker, side, e)
    return {
        "action_plan_version": "2",
        "source_snapshot_ts": int(snapshot_ts),
        "expires_ts": expires_ts,
        "ttl_seconds": int(max(5, int(BUY_ACTION_PLAN_TTL_SECONDS or 45))),
        "idempotency_window_ts": window_ts,
        "idempotency_key": f"{ticker}|{side}|{level}|{price_str(buy_price)}|{price_str(target)}|{window_ts}",
        "v2_client_order_id": client_order_id,
        "v2_order_side": v2_side,
        "v2_order_price_dollars": price_str(v2_price),
        "v2_order_count_fp": qty_str(qty),
        "v2_time_in_force": BUY_ACTION_PLAN_ENTRY_TIF,
        "v2_post_only": "1" if BUY_ACTION_PLAN_ENTRY_POST_ONLY else "0",
        "v2_reduce_only": "0",
        "v2_cancel_order_on_pause": "1",
        "v2_self_trade_prevention_type": SELF_TRADE_PREVENTION_TYPE,
        "v2_subaccount": SUBACCOUNT,
        "v2_order_group_id": order_group_id,
        "v2_order_group_required": "1" if (ORDER_GROUP_ENABLED and ORDER_GROUP_REQUIRE_FOR_BUY_ACTION_HANDOFF) else "0",
        "v2_order_group_error": order_group_error,
    }


def buy_action_exit_depth_capacity(row: dict, level: str) -> tuple:
    """Return quantity cap and reason based on visible exit depth.

    Uses near-exit depth when present, falling back to exact-at-target depth. A
    cap of 0 with a reason indicates that the action should be downgraded or
    rejected, depending on the level and settings.
    """
    if not BUY_ACTION_PLAN_EXIT_DEPTH_CAP_ENABLED:
        return Decimal("0"), "exit_depth_cap_disabled"
    depth_near = parse_decimal(row.get("book_depth_near_exit_fp", "0"), "0")
    depth_at = parse_decimal(row.get("book_depth_at_exit_fp", "0"), "0")
    depth = max(depth_near, depth_at)
    if depth <= 0:
        return Decimal("0"), "exit_depth_unknown_or_zero"
    if depth < BUY_ACTION_PLAN_MIN_EXIT_DEPTH_FP:
        return Decimal("0"), f"exit_depth_below_min_{qty_str(depth)}"
    share = max(Decimal("0"), min(Decimal("1"), BUY_ACTION_PLAN_EXIT_DEPTH_TARGET_SHARE))
    cap = (depth * share).quantize(Decimal("0.00"), rounding=ROUND_FLOOR)
    return cap, f"exit_depth_cap={qty_str(cap)} from depth={qty_str(depth)} share={cents4_str(share)}"


def edge_proof_min_qty_for_2c(buy_price: Decimal, target_price: Decimal, rate: Decimal, *, ticker: str = "", series_ticker: str = "", min_total_cents: Decimal = None, min_pc_cents: Decimal = None) -> dict:
    """Find the smallest quantity that clears total and per-contract net at 2c.

    This is intentionally simple and deterministic. It exists to make fee-rounding
    cliffs visible to the miner/action plan, not to replace live FeeGuard.
    """
    buy_price = parse_decimal(buy_price, str(BUY_PRICE))
    target_price = parse_decimal(target_price, str(TARGET_2C_PRICE))
    min_total_cents = parse_decimal(min_total_cents if min_total_cents is not None else EDGE_PROOF_MIN_TOTAL_NET_CENTS, str(EDGE_PROOF_MIN_TOTAL_NET_CENTS))
    min_pc_cents = parse_decimal(min_pc_cents if min_pc_cents is not None else EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS, str(EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS))
    step = max(Decimal("0.01"), parse_decimal(EDGE_PROOF_MIN_QTY_STEP_FP, "1.00"))
    q = max(parse_decimal(EDGE_PROOF_MIN_QTY_FLOOR_FP, "1.00"), step).quantize(Decimal("0.00"), rounding=ROUND_UP)
    max_q = max(q, parse_decimal(EDGE_PROOF_MAX_QTY_SCAN_FP, "1000.00"))
    last_est = {}
    while q <= max_q:
        est = estimate_trade_net_with_entry(q, buy_price, target_price, rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=series_ticker)
        last_est = est
        net_cents = parse_decimal(est.get("net_cents", "0"), "0")
        pc = parse_decimal(est.get("net_per_contract_cents", "0"), "0")
        if net_cents >= min_total_cents and pc >= min_pc_cents:
            return {
                "found": True,
                "min_qty_fp": q,
                "net_cents": net_cents,
                "net_per_contract_cents": pc,
                "net_dollars": parse_decimal(est.get("net_dollars", "0"), "0"),
                "searched_to_fp": q,
                "reason": "ok",
            }
        q = (q + step).quantize(Decimal("0.00"), rounding=ROUND_UP)
    return {
        "found": False,
        "min_qty_fp": Decimal("0"),
        "net_cents": parse_decimal(last_est.get("net_cents", "0"), "0"),
        "net_per_contract_cents": parse_decimal(last_est.get("net_per_contract_cents", "0"), "0"),
        "net_dollars": parse_decimal(last_est.get("net_dollars", "0"), "0"),
        "searched_to_fp": max_q,
        "reason": f"not_found_within_{qty_str(max_q)}",
    }


def compute_lip_adjusted_edge_overlay(row: dict, qty: Decimal, base_total_net_cents: Decimal, base_pc_cents: Decimal) -> dict:
    """Conservative optional edge overlay for liquidity incentives.

    Default is disabled. When enabled, the overlay can only rescue a thin row if
    the normal fee math is non-negative (by default), the LIP boost is active and
    post-only safe, and reward credit is capped. This absorbs the code-review idea
    without allowing incentive labels to override weak or unsafe trades.
    """
    row = row or {}
    qty = max(Decimal("0"), parse_decimal(qty, "0"))
    base_total = parse_decimal(base_total_net_cents, "0")
    base_pc = parse_decimal(base_pc_cents, "0")
    credit_pc = parse_decimal(row.get("liquidity_incentive_reward_credit_cents_per_contract", "0"), "0")
    if credit_pc <= 0:
        credit_pc = parse_decimal(row.get("liquidity_incentive_estimated_reward_credit_cents_per_contract", "0"), "0")
    credit_pc = max(Decimal("0"), min(credit_pc, LIQUIDITY_INCENTIVE_REWARD_MAX_CREDIT_CENTS_PER_CONTRACT))
    adjusted_pc = (base_pc + credit_pc).quantize(Decimal("0.0001"))
    adjusted_total = (base_total + (credit_pc * qty)).quantize(Decimal("0.0001")) if qty > 0 else base_total
    active = str(row.get("liquidity_incentive_active", row.get("liquidity_incentive_program_active", "0"))).lower() in {"1", "true", "yes"}
    boost_allowed = str(row.get("liquidity_incentive_boost_allowed", "0")).lower() in {"1", "true", "yes"}
    post_only_safe = str(row.get("liquidity_incentive_post_only_safe", "1")).lower() not in {"0", "false", "no"}
    seconds_left = parse_decimal(row.get("liquidity_incentive_seconds_left", "0"), "0")
    base_shortfall_pc = max(Decimal("0"), (EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS + EDGE_PROOF_MIN_MAKER_BUFFER_CENTS) - base_pc).quantize(Decimal("0.0001"))
    reasons = []
    if not FEE_GUARD_LIP_ADJUSTED:
        reasons.append("disabled")
    if not active:
        reasons.append("no_active_lip")
    if not boost_allowed:
        reasons.append("lip_boost_not_allowed")
    if not post_only_safe:
        reasons.append("lip_post_only_not_safe")
    if credit_pc <= 0:
        reasons.append("no_reward_credit")
    if seconds_left and seconds_left < LIQUIDITY_INCENTIVE_MIN_SECONDS_LEFT:
        reasons.append("lip_window_too_short")
    if LIP_ADJUSTED_REQUIRE_BASE_NONNEGATIVE and base_total < 0:
        reasons.append("base_total_negative")
    if base_shortfall_pc > LIP_ADJUSTED_MAX_BASE_SHORTFALL_CENTS_PER_CONTRACT:
        reasons.append(f"base_shortfall_too_large={cents4_str(base_shortfall_pc)}")
    if adjusted_total < LIP_ADJUSTED_MIN_ADJUSTED_TOTAL_NET_CENTS:
        reasons.append(f"adjusted_total_low={cents4_str(adjusted_total)}")
    if adjusted_pc < LIP_ADJUSTED_MIN_ADJUSTED_PC_CENTS:
        reasons.append(f"adjusted_pc_low={cents4_str(adjusted_pc)}")
    allowed = not reasons
    return {
        "lip_adjusted_gate_enabled": "1" if FEE_GUARD_LIP_ADJUSTED else "0",
        "lip_adjusted_edge_pass": "1" if allowed else "0",
        "lip_adjusted_edge_reason": "ok" if allowed else ";".join(reasons[:10]),
        "lip_reward_credit_cents_per_contract": credit_pc,
        "lip_adjusted_maker_total_net_cents": adjusted_total,
        "lip_adjusted_maker_net_per_contract_cents": adjusted_pc,
        "lip_base_shortfall_cents_per_contract": base_shortfall_pc,
        "lip_adjusted_require_base_nonnegative": "1" if LIP_ADJUSTED_REQUIRE_BASE_NONNEGATIVE else "0",
    }

def compute_2c_edge_proof(row: dict, qty: Decimal, buy_price: Decimal = None, target_price: Decimal = None, series_row: dict = None) -> dict:
    """Explain the minimum size/capacity needed for strict 2c to be worth taking."""
    row = row or {}
    series_row = series_row or {}
    ticker = str(row.get("ticker") or "")
    series = str(row.get("series_ticker") or "")
    qty = max(Decimal("0"), parse_decimal(qty, "0"))
    buy_price = parse_decimal(buy_price if buy_price is not None else row.get("buy_price_dollars", BUY_PRICE), str(BUY_PRICE))
    target_price = parse_decimal(target_price if target_price is not None else row.get("sell_target_price_dollars", row.get("target_sell_price_dollars", TARGET_2C_PRICE)), str(TARGET_2C_PRICE))
    if TARGET_2C_ASSURANCE_ENABLED:
        target_price = TARGET_2C_PRICE
    fee_profile, maker_exit_rate, taker_exit_rate = candidate_fee_rates(row, series_row=series_row)
    maker_min = edge_proof_min_qty_for_2c(
        buy_price,
        target_price,
        maker_exit_rate,
        ticker=ticker,
        series_ticker=series,
        min_total_cents=EDGE_PROOF_MIN_TOTAL_NET_CENTS,
        min_pc_cents=EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS + EDGE_PROOF_MIN_MAKER_BUFFER_CENTS,
    )
    taker_min = edge_proof_min_qty_for_2c(
        buy_price,
        target_price,
        taker_exit_rate,
        ticker=ticker,
        series_ticker=series,
        min_total_cents=EDGE_PROOF_MIN_TOTAL_NET_CENTS,
        min_pc_cents=EDGE_PROOF_MIN_TAKER_NET_PER_CONTRACT_CENTS,
    )
    maker_required = parse_decimal(maker_min.get("min_qty_fp", "0"), "0") if maker_min.get("found") else Decimal("0")
    taker_required = parse_decimal(taker_min.get("min_qty_fp", "0"), "0") if taker_min.get("found") else Decimal("0")
    required_qty = maker_required
    if EDGE_PROOF_REQUIRE_TAKER_FALLBACK:
        required_qty = max(required_qty, taker_required)
    ask_size = parse_decimal(row.get("ask_size_fp", row.get("recommended_buy_qty_fp", "0")), "0")
    depth = max(
        parse_decimal(row.get("book_depth_at_exit_fp", "0"), "0"),
        parse_decimal(row.get("edge_exit_depth_fp", "0"), "0"),
        parse_decimal(row.get("book_depth_near_exit_fp", "0"), "0"),
    )
    depth_share = max(Decimal("0"), min(Decimal("1"), BUY_ACTION_PLAN_EXIT_DEPTH_TARGET_SHARE if BUY_ACTION_PLAN_EXIT_DEPTH_CAP_ENABLED else Decimal("1")))
    exit_capacity = (depth * depth_share).quantize(Decimal("0.00"), rounding=ROUND_FLOOR) if depth > 0 else Decimal("0")
    capacity_candidates = [x for x in (ask_size, exit_capacity) if x > 0]
    capacity_qty = min(capacity_candidates) if capacity_candidates else Decimal("0")
    maker_est = estimate_trade_net_with_entry(qty, buy_price, target_price, maker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=series)
    taker_est = estimate_trade_net_with_entry(qty, buy_price, target_price, taker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=series)
    planned_maker_net_cents = parse_decimal(maker_est.get("net_cents", "0"), "0")
    planned_maker_pc = parse_decimal(maker_est.get("net_per_contract_cents", "0"), "0")
    planned_taker_pc = parse_decimal(taker_est.get("net_per_contract_cents", "0"), "0")
    reasons = []
    if not maker_min.get("found"):
        reasons.append("maker_min_qty_not_found")
    if EDGE_PROOF_REQUIRE_TAKER_FALLBACK and not taker_min.get("found"):
        reasons.append("taker_min_qty_not_found")
    if required_qty > 0 and qty < required_qty:
        reasons.append(f"planned_qty_below_min_{qty_str(required_qty)}")
    if ask_size > 0 and required_qty > 0 and ask_size < required_qty:
        reasons.append(f"ask_size_below_min_{qty_str(ask_size)}")
    if depth > 0 and required_qty > 0 and exit_capacity < required_qty:
        reasons.append(f"exit_capacity_below_min_{qty_str(exit_capacity)}")
    if depth <= 0 and EDGE_PROOF_REQUIRE_EXIT_CAPACITY:
        reasons.append("exit_depth_unknown_or_zero")
    elif depth <= 0:
        reasons.append("exit_depth_advisory_missing_buy_priority")
    if planned_maker_net_cents < EDGE_PROOF_MIN_TOTAL_NET_CENTS:
        reasons.append(f"planned_total_net_low={cents4_str(planned_maker_net_cents)}c")
    if planned_maker_pc < EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS + EDGE_PROOF_MIN_MAKER_BUFFER_CENTS:
        reasons.append(f"planned_maker_pc_low={cents4_str(planned_maker_pc)}")
    if EDGE_PROOF_REQUIRE_TAKER_FALLBACK and planned_taker_pc < EDGE_PROOF_MIN_TAKER_NET_PER_CONTRACT_CENTS:
        reasons.append(f"planned_taker_pc_low={cents4_str(planned_taker_pc)}")
    required_coverage_pct = Decimal("0")
    if required_qty > 0:
        required_coverage_pct = (capacity_qty / required_qty * Decimal("100")).quantize(Decimal("0.0001")) if capacity_qty > 0 else Decimal("0")
    planned_coverage_pct = Decimal("0")
    if qty > 0:
        planned_coverage_pct = (depth / qty * Decimal("100")).quantize(Decimal("0.0001")) if depth > 0 else Decimal("0")
    pass_required = maker_min.get("found") and (required_qty <= 0 or qty >= required_qty) and planned_maker_net_cents >= EDGE_PROOF_MIN_TOTAL_NET_CENTS and planned_maker_pc >= (EDGE_PROOF_MIN_MAKER_NET_PER_CONTRACT_CENTS + EDGE_PROOF_MIN_MAKER_BUFFER_CENTS)
    if EDGE_PROOF_REQUIRE_TAKER_FALLBACK:
        pass_required = pass_required and taker_min.get("found") and planned_taker_pc >= EDGE_PROOF_MIN_TAKER_NET_PER_CONTRACT_CENTS
    pass_capacity = (required_qty > 0 and capacity_qty >= required_qty and required_coverage_pct >= EDGE_PROOF_MIN_EXIT_DEPTH_COVERAGE_PCT) if EDGE_PROOF_REQUIRE_EXIT_CAPACITY else True
    proof_pass = bool(pass_required and pass_capacity)
    lip_overlay = compute_lip_adjusted_edge_overlay(row, qty, planned_maker_net_cents, planned_maker_pc)
    if (not proof_pass) and pass_capacity and str(lip_overlay.get("lip_adjusted_edge_pass", "0")) == "1":
        proof_pass = True
        reasons.append("edge_proof_pass_via_lip_adjusted_gate")
    if proof_pass:
        reasons.append("edge_proof_pass")
    throughput_window = max(Decimal("1"), Decimal(str(max(1, EDGE_PROOF_THROUGHPUT_WINDOW_SECONDS))) / Decimal("60"))
    queue_velocity = parse_decimal(row.get("queue_velocity_fp_per_min", series_row.get("queue_velocity_fp_per_min", "0")), "0")
    # Conservative throughput proxy: visible capacity plus observed queue velocity over the configured window.
    throughput_qty = max(Decimal("0"), min(capacity_qty if capacity_qty > 0 else qty, (queue_velocity * throughput_window) if queue_velocity > 0 else (capacity_qty if capacity_qty > 0 else qty)))
    throughput_est = estimate_trade_net_with_entry(throughput_qty, buy_price, target_price, maker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=series) if throughput_qty > 0 else {"net_dollars": Decimal("0"), "net_per_contract_cents": Decimal("0")}
    return {
        "edge_proof_pass": "1" if proof_pass else "0",
        "edge_proof_reason": ";".join(reasons[:12]) or "ok",
        "edge_proof_required_qty_fp": required_qty,
        "edge_min_maker_qty_for_2c_fp": maker_required,
        "edge_min_taker_qty_for_2c_fp": taker_required,
        "edge_min_qty_step_fp": EDGE_PROOF_MIN_QTY_STEP_FP,
        "edge_proof_planned_qty_fp": qty,
        "edge_proof_capacity_qty_fp": capacity_qty,
        "edge_proof_exit_capacity_fp": exit_capacity,
        "edge_proof_ask_size_fp": ask_size,
        "edge_proof_required_coverage_pct": required_coverage_pct,
        "edge_proof_planned_depth_coverage_pct": planned_coverage_pct,
        "edge_proof_planned_maker_total_net_cents": planned_maker_net_cents,
        "edge_proof_planned_maker_net_per_contract_cents": planned_maker_pc,
        "edge_proof_planned_taker_net_per_contract_cents": planned_taker_pc,
        "edge_proof_throughput_qty_fp": throughput_qty,
        "edge_proof_throughput_net_dollars": parse_decimal(throughput_est.get("net_dollars", "0"), "0"),
        "edge_proof_throughput_net_per_contract_cents": parse_decimal(throughput_est.get("net_per_contract_cents", "0"), "0"),
        "edge_fee_profile_source": str(fee_profile.get("source", fee_profile.get("fee_type", ""))),
        "edge_fee_profile_known": "1" if fee_profile.get("known") else "0",
        "edge_maker_exit_fee_rate": maker_exit_rate,
        "edge_taker_exit_fee_rate": taker_exit_rate,
        **lip_overlay,
    }

def compute_2c_edge_metrics(row: dict, qty: Decimal, buy_price: Decimal = None, target_price: Decimal = None, series_row: dict = None) -> dict:
    """Compute strict-2c edge quality for a candidate buy/action row.

    The metric is advisory. It rewards orders that clear FeeGuard at 2c and have
    enough visible same-side exit depth to support the suggested size.
    """
    row = row or {}
    series_row = series_row or {}
    qty = max(Decimal("0"), parse_decimal(qty, "0"))
    buy_price = parse_decimal(buy_price if buy_price is not None else row.get("buy_price_dollars", BUY_PRICE), str(BUY_PRICE))
    target_price = parse_decimal(target_price if target_price is not None else row.get("sell_target_price_dollars", row.get("target_sell_price_dollars", TARGET_2C_PRICE)), str(TARGET_2C_PRICE))
    if TARGET_2C_ASSURANCE_ENABLED:
        target_price = TARGET_2C_PRICE
    fee_profile, maker_exit_rate, taker_exit_rate = candidate_fee_rates(row, series_row=series_row)
    maker_est = estimate_trade_net_with_entry(qty, buy_price, target_price, maker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=str(row.get("ticker") or ""), series_ticker=str(row.get("series_ticker") or ""))
    taker_est = estimate_trade_net_with_entry(qty, buy_price, target_price, taker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=str(row.get("ticker") or ""), series_ticker=str(row.get("series_ticker") or ""))
    maker_pc = parse_decimal(maker_est.get("net_per_contract_cents", "0"), "0")
    taker_pc = parse_decimal(taker_est.get("net_per_contract_cents", "0"), "0")
    maker_buffer = (maker_pc - BUY_ACTION_PLAN_MIN_NET_PER_CONTRACT_CENTS).quantize(Decimal("0.0001"))
    taker_buffer = (taker_pc - EDGE_SCOUT_MIN_TAKER_NET_CENTS).quantize(Decimal("0.0001"))
    depth = max(
        parse_decimal(row.get("book_depth_at_exit_fp", "0"), "0"),
        parse_decimal(row.get("edge_exit_depth_fp", "0"), "0"),
        parse_decimal(row.get("book_depth_near_exit_fp", "0"), "0"),
    )
    coverage_pct = Decimal("0")
    if qty > 0:
        coverage_pct = (depth / qty * Decimal("100")).quantize(Decimal("0.0001"))
    maker_net = parse_decimal(maker_est.get("net_dollars", "0"), "0")
    taker_net = parse_decimal(taker_est.get("net_dollars", "0"), "0")
    gross = max(Decimal("0.000001"), (target_price - buy_price) * qty)
    fee_drag = Decimal("0")
    if gross > 0:
        # Conservative proxy: gross spread minus maker net as percentage of gross.
        fee_drag = max(Decimal("0"), (gross - maker_net) / gross * Decimal("100")).quantize(Decimal("0.0001"))
    reasons = []
    score = Decimal("0")
    if maker_pc >= BUY_ACTION_PLAN_MIN_NET_PER_CONTRACT_CENTS + EDGE_SCOUT_MIN_MAKER_BUFFER_CENTS:
        score += Decimal("30")
    elif maker_pc >= BUY_ACTION_PLAN_MIN_NET_PER_CONTRACT_CENTS:
        score += Decimal("20")
        reasons.append("maker_buffer_thin")
    else:
        reasons.append(f"maker_net_low={cents4_str(maker_pc)}")
    if taker_pc >= EDGE_SCOUT_MIN_TAKER_NET_CENTS:
        score += Decimal("20")
    else:
        reasons.append(f"taker_net_low={cents4_str(taker_pc)}")
    if coverage_pct >= EDGE_SCOUT_MIN_EXIT_DEPTH_COVERAGE_PCT:
        score += Decimal("25")
    elif depth > 0:
        score += min(Decimal("20"), coverage_pct / max(Decimal("1"), EDGE_SCOUT_MIN_EXIT_DEPTH_COVERAGE_PCT) * Decimal("20"))
        reasons.append(f"exit_depth_coverage={cents4_str(coverage_pct)}pct")
    else:
        reasons.append("no_visible_exit_depth")
    if buy_price <= BUY_PRICE:
        score += Decimal("8")
    else:
        score -= Decimal("5")
        reasons.append(f"buy_price_above_1c={price_str(buy_price)}")
    ob_score = parse_decimal(row.get("deep_orderbook_score", series_row.get("avg_orderbook_liquidity_score", "0")), "0")
    tape_score = parse_decimal(row.get("deep_trade_tape_score", series_row.get("avg_trade_tape_score", "0")), "0")
    velocity_score = parse_decimal(row.get("deep_velocity_score", series_row.get("avg_velocity_score", "0")), "0")
    if ob_score > 0:
        score += min(Decimal("7"), ob_score / Decimal("100") * Decimal("7"))
    if tape_score > 0:
        score += min(Decimal("5"), tape_score / Decimal("100") * Decimal("5"))
    if velocity_score > 0:
        score += min(Decimal("5"), velocity_score / Decimal("100") * Decimal("5"))
    pnl_pc = parse_decimal(row.get("pnl_per_evidence_contract_cents", series_row.get("pnl_per_evidence_contract_cents", "0")), "0")
    if pnl_pc > 0:
        score += min(Decimal("5"), pnl_pc * Decimal("4"))
    elif pnl_pc < 0:
        score -= Decimal("8")
        reasons.append(f"series_pnl_negative={cents4_str(pnl_pc)}")
    feedback = str(row.get("buy_feedback_band", series_row.get("buy_feedback_band", "unknown"))).lower()
    if feedback in {"bad", "stale"}:
        score -= Decimal("10")
        reasons.append(f"feedback={feedback}")
    elif feedback in {"good", "strong"}:
        score += Decimal("5")
    queue_eta_band = str(row.get("queue_eta_band", series_row.get("queue_eta_band", ""))).lower()
    queue_eta_seconds = parse_decimal(row.get("queue_eta_seconds", series_row.get("queue_eta_seconds", "0")), "0")
    queue_velocity = parse_decimal(row.get("queue_velocity_fp_per_min", series_row.get("queue_velocity_fp_per_min", "0")), "0")
    if queue_eta_band == "stalled" or queue_eta_seconds >= Decimal(str(QUEUE_ETA_STALLED_SECONDS)):
        score -= Decimal("8")
        reasons.append(f"queue_eta_stalled={cents4_str(queue_eta_seconds)}s")
    elif queue_eta_band == "slow" or queue_eta_seconds >= Decimal(str(QUEUE_ETA_SLOW_SECONDS)):
        score -= Decimal("4")
        reasons.append(f"queue_eta_slow={cents4_str(queue_eta_seconds)}s")
    elif queue_velocity > 0 and queue_velocity < QUEUE_ETA_MIN_VELOCITY_FP_PER_MIN:
        score -= Decimal("2")
        reasons.append(f"queue_velocity_low={cents4_str(queue_velocity)}fp_min")
    proof = compute_2c_edge_proof(row, qty=qty, buy_price=buy_price, target_price=target_price, series_row=series_row) if EDGE_PROOF_ENABLED else {}
    proof_pass = str((proof or {}).get("edge_proof_pass", "1")) == "1"
    if EDGE_PROOF_ENABLED:
        if proof_pass:
            score += Decimal("4")
        else:
            score -= Decimal("12")
            reasons.append(f"edge_proof={str((proof or {}).get('edge_proof_reason', 'fail'))[:80]}")
    score = max(Decimal("0"), min(Decimal("100"), score)).quantize(Decimal("0.01"))
    if score >= EDGE_SCOUT_AGGRESSIVE_SCORE:
        band = "aggressive_edge"
    elif score >= EDGE_SCOUT_NORMAL_SCORE:
        band = "normal_edge"
    elif score >= EDGE_SCOUT_PILOT_SCORE:
        band = "pilot_edge"
    else:
        band = "avoid_edge"
    edge_pass = score >= EDGE_SCOUT_PILOT_SCORE and maker_pc >= BUY_ACTION_PLAN_MIN_NET_PER_CONTRACT_CENTS and maker_buffer >= EDGE_SCOUT_MIN_MAKER_BUFFER_CENTS and coverage_pct >= min(EDGE_SCOUT_MIN_EXIT_DEPTH_COVERAGE_PCT, Decimal("100"))
    edge_pass_normal = score >= EDGE_SCOUT_NORMAL_SCORE and maker_pc >= BUY_ACTION_PLAN_MIN_NET_PER_CONTRACT_CENTS and coverage_pct >= EDGE_SCOUT_MIN_EXIT_DEPTH_COVERAGE_PCT
    edge_pass_aggressive = score >= EDGE_SCOUT_AGGRESSIVE_SCORE and taker_pc >= EDGE_SCOUT_MIN_TAKER_NET_CENTS and coverage_pct >= EDGE_SCOUT_MIN_EXIT_DEPTH_COVERAGE_PCT
    if EDGE_PROOF_ENABLED and EDGE_PROOF_REQUIRE_FOR_ACTION_PLAN and not proof_pass:
        edge_pass = edge_pass_normal = edge_pass_aggressive = False
    if edge_pass:
        reasons.append("edge_pass")
    return {
        "edge_score": score,
        "edge_band": band,
        "edge_pass": "1" if edge_pass else "0",
        "edge_pass_normal": "1" if edge_pass_normal else "0",
        "edge_pass_aggressive": "1" if edge_pass_aggressive else "0",
        "edge_reason": ";".join(reasons[:10]) or "ok",
        "edge_qty_fp": qty,
        "edge_buy_price_dollars": buy_price,
        "edge_sell_price_dollars": target_price,
        "edge_maker_net_per_contract_cents": maker_pc,
        "edge_taker_net_per_contract_cents": taker_pc,
        "edge_maker_buffer_cents": maker_buffer,
        "edge_taker_buffer_cents": taker_buffer,
        "edge_fee_drag_pct": fee_drag,
        "edge_exit_depth_coverage_pct": coverage_pct,
        "edge_exit_depth_fp": depth,
        "edge_expected_maker_net_dollars": maker_net,
        "edge_expected_taker_net_dollars": taker_net,
        "edge_fee_profile_source": str(fee_profile.get("source", fee_profile.get("fee_type", ""))),
        "edge_fee_profile_known": "1" if fee_profile.get("known") else "0",
        "edge_maker_exit_fee_rate": maker_exit_rate,
        "edge_taker_exit_fee_rate": taker_exit_rate,
        "edge_queue_eta_band": queue_eta_band,
        "edge_queue_eta_seconds": queue_eta_seconds,
        "edge_queue_velocity_fp_per_min": queue_velocity,
        **(proof if EDGE_PROOF_ENABLED else {}),
    }


