        "bad_fill_count", "queue_zero_checks", "queue_stagnation_checks", "queue_eta_band", "queue_eta_seconds",
        "queue_velocity_fp_per_min", "urgent_exit_attempts", "urgent_exit_filled_fp",
        "last_urgent_exit_price", "seconds_to_close", "same_side_best_bid_dollars", "same_side_best_bid_size_fp",
        "book_best_bid_dollars", "book_best_bid_size_fp", "book_depth_at_exit_fp", "book_depth_near_exit_fp",
        "book_level_count", "orderbook_liquidity_score", "orderbook_liquidity_band",
        "orderbook_pressure_score", "orderbook_pressure_band", "orderbook_pressure_reason", "orderbook_imbalance",
        "orderbook_bid_depth_fp", "orderbook_ask_depth_fp", "orderbook_microprice_dollars", "orderbook_vamp_price_dollars",
        "orderbook_weighted_depth_price_dollars", "orderbook_mid_price_dollars", "orderbook_pressure_edge_cents", "orderbook_pressure_size_multiplier",
        "last_orderbook_signal_ts",
        "dead_market_escape", "dead_market_escape_reason",
