def compare_and_log(label: str, saved_value, live_value):
    if saved_value != live_value:
        LOGGER.info("Reconcile | %s | saved=%s | live=%s", label, saved_value, live_value)


def load_transactions_index():
    path = (TRANSACTIONS_CSV_PATH or "").strip()
    if not path:
        return {}
    if not os.path.exists(path):
        return {}

    try:
        mtime = os.path.getmtime(path)
    except Exception:
        return {}

    if TRANSACTIONS_CACHE.get("path") == path and TRANSACTIONS_CACHE.get("mtime") == mtime:
        return TRANSACTIONS_CACHE.get("index", {})

    index = {}
    try:
        with open(path, "r", encoding="utf-8-sig", newline="") as f:
            reader = csv.DictReader(f)
            for row in reader:
                ticker = str((row.get("market_ticker") or "")).strip()
                if not ticker:
                    continue
                quantity = parse_decimal(row.get("quantity", "0"), "0")
                exit_price = parse_decimal(row.get("exit_price_cents", "0"), "0")
                pnl_with_fees = int(parse_decimal(row.get("realized_pnl_with_fees_cents", "0"), "0"))
                pnl_without_fees = int(parse_decimal(row.get("realized_pnl_without_fees_cents", "0"), "0"))
                close_ts = str(row.get("close_timestamp") or "").strip()
                side = str(row.get("side") or "").strip().lower()
                item = index.setdefault(ticker, {
                    "trade_count": 0,
                    "total_qty": Decimal("0"),
                    "weighted_exit_sum": Decimal("0"),
                    "pnl_with_fees_cents": 0,
                    "pnl_without_fees_cents": 0,
                    "latest_close_timestamp": "",
                    "sides": set(),
                })
                item["trade_count"] += 1
                item["total_qty"] += quantity
                item["weighted_exit_sum"] += (exit_price * Decimal(quantity))
                item["pnl_with_fees_cents"] += pnl_with_fees
                item["pnl_without_fees_cents"] += pnl_without_fees
                if close_ts and close_ts > item["latest_close_timestamp"]:
                    item["latest_close_timestamp"] = close_ts
                if side:
                    item["sides"].add(side)
    except Exception as e:
        LOGGER.warning("Transactions CSV load failed: %s", e)
        return {}

    for item in index.values():
        total_qty = item["total_qty"]
        item["avg_exit_cents"] = (item["weighted_exit_sum"] / total_qty) if total_qty else Decimal("0")
        item["side"] = ",".join(sorted(item["sides"])) if item["sides"] else ""
        item.pop("weighted_exit_sum", None)
        item.pop("sides", None)

    TRANSACTIONS_CACHE["path"] = path
    TRANSACTIONS_CACHE["mtime"] = mtime
    TRANSACTIONS_CACHE["index"] = index
    return index


def maybe_log_terminal_close_summary(ticker: str, bucket: dict, live_position_qty: int):
    if bucket.get("terminal_close_summary_logged", False):
        return

    last_attempt = int(bucket.get("terminal_close_summary_last_attempt_ts", 0) or 0)
    if now_ts() - last_attempt < TRANSACTION_SUMMARY_RETRY_SECONDS:
        return
    bucket["terminal_close_summary_last_attempt_ts"] = now_ts()

    summary = load_transactions_index().get(ticker)
    if not summary:
        return

    bucket["terminal_close_summary_logged"] = True
    LOGGER.info(
        "CloseSummary | ticker=%s | side=%s | trade_count=%s | sold_qty=%s | avg_exit_cents=%s | pnl_with_fees_cents=%s | pnl_without_fees_cents=%s | latest_close=%s | terminal_reason=%s | live_position=%s",
        ticker,
        summary.get("side", bucket.get("side", "")),
        summary.get("trade_count", 0),
        summary.get("total_qty", 0),
        f"{summary.get('avg_exit_cents', Decimal('0')):.2f}",
        summary.get("pnl_with_fees_cents", 0),
        summary.get("pnl_without_fees_cents", 0),
        summary.get("latest_close_timestamp", ""),
        bucket.get("terminal_reason", ""),
        live_position_qty,
    )


def append_csv_row(path: str, fieldnames, row: dict) -> None:
    if not path:
        return
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    exists = os.path.exists(path) and os.path.getsize(path) > 0
    with open(path, "a", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        if not exists:
            writer.writeheader()
        writer.writerow({name: row.get(name, "") for name in fieldnames})


def atomic_write_csv(path: str, fieldnames, rows) -> None:
    if not path:
        return
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    tmp = f"{path}.tmp"
    with open(tmp, "w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for row in rows or []:
            writer.writerow({name: row.get(name, "") for name in fieldnames})
        if ATOMIC_WRITE_FSYNC_REPORTS_ENABLED:
            try:
                f.flush()
                os.fsync(f.fileno())
            except OSError as e:
                LOGGER.debug("CSV report fsync skipped: %s", e)
    atomic_replace_with_retry(tmp, path, context="atomic_write_csv")


def atomic_write_json(path: str, payload) -> None:
    if not path:
        return
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    tmp = f"{path}.tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(_json_storage_safe(payload), f, indent=2, sort_keys=True)
        if ATOMIC_WRITE_FSYNC_REPORTS_ENABLED:
            try:
                f.flush()
                os.fsync(f.fileno())
            except OSError as e:
                LOGGER.debug("JSON report fsync skipped: %s", e)
    atomic_replace_with_retry(tmp, path, context="atomic_write_json")




LIVE_STARTUP_SLA_STAGE_ORDER = [
    "process_start", "config_ok", "lock_acquired", "startup_banner_logged",
    "auth_preflight_complete", "endpoint_costs_complete", "account_limits_complete",
    "websocket_start_requested", "startup_reconcile_complete", "first_run_once_begin",
    "first_sell_management_begin", "first_sell_management_complete", "first_run_once_complete",
]


def _safe_lock_metadata_snapshot() -> dict:
    """Return current lock metadata without tripping over Windows byte-range locks.

    On Windows the active process owns an msvcrt byte-range lock on the first byte
    of the lock file.  A same-process path re-open can fail while the bot is
    healthy, which made the Live Startup SLA report say lock metadata was missing
    even after sell-management startup succeeded.  Prefer the active guard's
    in-memory metadata when available, then fall back to reading the file path.
    """
    try:
        guard = globals().get("LOCK_GUARD")
        if guard is not None and getattr(guard, "fp", None):
            snapshot = guard.snapshot_metadata() if hasattr(guard, "snapshot_metadata") else {}
            if isinstance(snapshot, dict) and snapshot:
                return snapshot
    except Exception:
        pass
    try:
        return _read_lock_metadata_for_launch(LOCK_FILE)
    except Exception:
        return {}


def _live_startup_sla_meta() -> dict:
    meta = STATE.setdefault("meta", {}) if isinstance(STATE, dict) else {}
    events = meta.setdefault("live_startup_sla_events", {}) if isinstance(meta, dict) else {}
    if not isinstance(events, dict):
        events = {}
        try:
            meta["live_startup_sla_events"] = events
        except Exception:
            pass
    return meta


def _live_startup_sla_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m Live Startup SLA Reporter",
        "====================================",
        f"Build ID: {payload.get('build_id', '')}",
        f"Instance: {payload.get('instance', '')}",
        f"Status: {payload.get('status', '')}",
        f"Current stage: {payload.get('current_stage', '')}",
        f"Elapsed seconds: {payload.get('elapsed_seconds', '')}",
        f"SLA seconds: {payload.get('sla_seconds', '')}",
        f"Sell-path elapsed / SLA: {payload.get('sell_path_elapsed_seconds', '')} / {payload.get('sell_path_sla_seconds', '')}",
        f"First-cycle elapsed / SLA: {payload.get('full_cycle_elapsed_seconds', '')} / {payload.get('full_cycle_sla_seconds', '')}",
        f"Startup band: {payload.get('startup_band', '')}",
        f"Started CT: {payload.get('startup_ct', '')}",
        f"Updated CT: {payload.get('snapshot_ct', '')}",
        f"Lock PID: {payload.get('lock', {}).get('pid', '') if isinstance(payload.get('lock'), dict) else ''}",
        f"Lock heartbeat age seconds: {payload.get('lock_heartbeat_age_seconds', '')}",
        "",
        "Milestones:",
    ]
    for stage in LIVE_STARTUP_SLA_STAGE_ORDER:
        row = (payload.get("milestones", {}) or {}).get(stage, {})
        lines.append(f"- {stage}: ts={row.get('ts', '')} elapsed={row.get('elapsed_seconds', '')} note={row.get('note', '')}")
    if payload.get("slow_spans"):
        lines.extend(["", "Slow spans:"])
        for row in payload.get("slow_spans", [])[:12]:
            lines.append(f"- {row.get('from')} -> {row.get('to')}: {row.get('duration_seconds')}s")
    if payload.get("warnings"):
        lines.extend(["", "Warnings:"])
        lines.extend([f"- {w}" for w in payload.get("warnings", [])])
    if payload.get("recommendations"):
        lines.extend(["", "Recommendations:"])
        lines.extend([f"- {r}" for r in payload.get("recommendations", [])])
    return "\n".join(lines) + "\n"


def write_live_startup_sla_report(stage: str, note: str = "", force: bool = False, extra: dict = None) -> dict:
    if not LIVE_STARTUP_SLA_ENABLED and not force:
        return {}
    try:
        meta = _live_startup_sla_meta()
        now = now_ts()
        # A new option-2 process must start a fresh SLA timeline. Reusing the
        # prior run's persisted milestones can make support bundles look stale
        # and can incorrectly satisfy or fail startup-to-sell gates.
        if str(stage or "") == "process_start":
            meta["live_startup_sla_start_ts"] = now
            meta["live_startup_sla_start_ct"] = central_time_iso_from_ts(now)
            meta["live_startup_sla_start_build_id"] = BUILD_ID
            meta["live_startup_sla_start_pid"] = os.getpid()
            meta["live_startup_sla_start_monotonic"] = time.monotonic()
            meta["live_startup_sla_events"] = {}
            meta["live_startup_sla_current_stage"] = "process_start"
            meta.pop("live_startup_sla_first_sell_begin", None)
            meta.pop("live_startup_sla_first_sell_complete", None)
            meta.pop("live_startup_sla_first_loop_started", None)
            meta.pop("live_startup_sla_first_loop_completed", None)
            for key in (
                "last_engine_ts_ms", "last_engine_ts_local_ms", "last_engine_ts_lag_ms", "last_engine_ts_context",
                "engine_ts_max_lag_ms", "engine_ts_last_warning_log_ts",
            ):
                meta.pop(key, None)
            meta["engine_ts_event_count"] = 0
            meta["engine_ts_warning_count"] = 0
        if not meta.get("live_startup_sla_start_ts"):
            meta["live_startup_sla_start_ts"] = now
        start_ts = int(meta.get("live_startup_sla_start_ts", now) or now)
        events = meta.setdefault("live_startup_sla_events", {})
        if stage:
            stage_name = str(stage)
            events[stage_name] = {"ts": now, "ct": central_time_iso_from_ts(now), "elapsed_seconds": max(0, now - start_ts), "note": str(note or "")[:300]}
            meta["live_startup_sla_current_stage"] = stage_name
            meta["live_startup_sla_last_update_ts"] = now
            if stage_name == "first_sell_management_begin":
                meta["live_startup_sla_first_sell_begin"] = now
            if stage_name == "first_sell_management_complete":
                if "first_sell_management_begin" not in events:
                    events["first_sell_management_begin"] = {"ts": now, "ct": central_time_iso_from_ts(now), "elapsed_seconds": max(0, now - start_ts), "note": "auto-repaired missing begin from complete"}
                meta["live_startup_sla_first_sell_begin"] = int((events.get("first_sell_management_begin") or {}).get("ts", now) or now)
                meta["live_startup_sla_first_sell_complete"] = now
        milestones = {k: events.get(k, {}) for k in LIVE_STARTUP_SLA_STAGE_ORDER if isinstance(events, dict)}
        elapsed = max(0, now - start_ts)
        lock_meta = _safe_lock_metadata_snapshot()
        hb_ts = int((lock_meta or {}).get("heartbeat_ts", 0) or 0)
        hb_age = max(0, now - hb_ts) if hb_ts else ""
        complete = "first_run_once_complete" in events or "first_sell_management_complete" in events
        first_sell_begin_ts = int((events.get("first_sell_management_begin") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
        first_sell_complete_ts = int((events.get("first_sell_management_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
        first_run_complete_ts = int((events.get("first_run_once_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
        sell_path_elapsed = max(0, first_sell_begin_ts - start_ts) if first_sell_begin_ts else ""
        sell_complete_elapsed = max(0, first_sell_complete_ts - start_ts) if first_sell_complete_ts else ""
        full_cycle_elapsed = max(0, first_run_complete_ts - start_ts) if first_run_complete_ts else ""
        ordered_events = []
        if isinstance(events, dict):
            for _stage, _row in events.items():
                try:
                    ordered_events.append((_stage, int((_row or {}).get("ts", 0) or 0)))
                except Exception:
                    pass
        ordered_events = [(a, b) for a, b in ordered_events if b]
        ordered_events.sort(key=lambda x: x[1])
        slow_spans = []
        for idx in range(1, len(ordered_events)):
            prev_stage, prev_ts = ordered_events[idx - 1]
            cur_stage, cur_ts = ordered_events[idx]
            dur = max(0, cur_ts - prev_ts)
            if dur >= max(10, LIVE_STARTUP_SELL_PATH_SLA_SECONDS // 2):
                slow_spans.append({"from": prev_stage, "to": cur_stage, "duration_seconds": dur})
        startup_band = "starting"
        if first_sell_begin_ts:
            startup_band = "sell_path_ready"
        if first_run_complete_ts:
            startup_band = "full_cycle_complete"
        if isinstance(sell_path_elapsed, int) and sell_path_elapsed > LIVE_STARTUP_SELL_PATH_SLA_SECONDS:
            startup_band = "sell_path_slow"
        if isinstance(full_cycle_elapsed, int) and full_cycle_elapsed > LIVE_STARTUP_FULL_CYCLE_SLA_SECONDS:
            startup_band = "full_cycle_slow"
        warnings = []
        if elapsed > LIVE_STARTUP_SLA_SECONDS and not complete:
            warnings.append(f"startup_sla_exceeded_before_first_sell_management_or_run_once:{elapsed}s")
        if isinstance(sell_path_elapsed, int) and sell_path_elapsed > LIVE_STARTUP_SELL_PATH_SLA_SECONDS:
            warnings.append(f"sell_path_sla_slow:{sell_path_elapsed}s>{LIVE_STARTUP_SELL_PATH_SLA_SECONDS}s")
        if isinstance(full_cycle_elapsed, int) and full_cycle_elapsed > LIVE_STARTUP_FULL_CYCLE_SLA_SECONDS:
            warnings.append(f"first_cycle_sla_slow:{full_cycle_elapsed}s>{LIVE_STARTUP_FULL_CYCLE_SLA_SECONDS}s")
        if lock_meta == {} and stage not in {"process_start", "config_ok"}:
            warnings.append("lock_metadata_unreadable_or_missing")
        elif isinstance(lock_meta, dict) and not str(lock_meta.get("build_id", "")).strip():
            warnings.append("lock_metadata_missing_build_id")
        if hb_ts and isinstance(hb_age, int) and hb_age > max(LOCK_HEARTBEAT_INTERVAL_SECONDS * 3, 90):
            warnings.append(f"lock_heartbeat_stale:{hb_age}s")
        status = "complete" if complete else ("watch" if warnings else "starting")
        payload = {
            "build_id": BUILD_ID,
            "instance": INSTANCE_NAME,
            "enabled": LIVE_STARTUP_SLA_ENABLED,
            "status": status,
            "current_stage": meta.get("live_startup_sla_current_stage", stage),
            "startup_ts": start_ts,
            "startup_ct": central_time_iso_from_ts(start_ts),
            "startup_process_build_id": meta.get("live_startup_sla_start_build_id", ""),
            "startup_process_pid": meta.get("live_startup_sla_start_pid", ""),
            "startup_process_current": bool(str(meta.get("live_startup_sla_start_build_id", "")) == BUILD_ID and int(meta.get("live_startup_sla_start_pid", 0) or 0) == os.getpid()),
            "snapshot_ts": now,
            "snapshot_ct": central_time_iso_from_ts(now),
            "elapsed_seconds": elapsed,
            "sla_seconds": LIVE_STARTUP_SLA_SECONDS,
            "sell_path_sla_seconds": LIVE_STARTUP_SELL_PATH_SLA_SECONDS,
            "full_cycle_sla_seconds": LIVE_STARTUP_FULL_CYCLE_SLA_SECONDS,
            "sell_path_elapsed_seconds": sell_path_elapsed,
            "sell_complete_elapsed_seconds": sell_complete_elapsed,
            "full_cycle_elapsed_seconds": full_cycle_elapsed,
            "startup_band": startup_band,
            "slow_spans": slow_spans,
            "milestones": milestones,
            "lock": lock_meta,
            "lock_heartbeat_age_seconds": hb_age,
            "warnings": warnings,
            "recommendations": [
                "If this report stays before first_sell_management_begin, upload it with the log tail and launch-lock reports.",
                "If lock metadata is stale or missing, use START_HERE option 2 so Launch Guard can repair or hand off safely.",
            ],
        }
        if isinstance(extra, dict):
            payload["extra"] = extra
        atomic_write_json(LIVE_STARTUP_SLA_JSON_PATH, payload)
        try:
            os.makedirs(os.path.dirname(LIVE_STARTUP_SLA_TXT_PATH) or ".", exist_ok=True)
            tmp = f"{LIVE_STARTUP_SLA_TXT_PATH}.tmp"
            with open(tmp, "w", encoding="utf-8") as fh:
                fh.write(_live_startup_sla_text(payload))
            atomic_replace_with_retry(tmp, LIVE_STARTUP_SLA_TXT_PATH, context="live_startup_sla_txt")
        except Exception:
            pass
        try:
            append_csv_row(LIVE_STARTUP_SLA_HISTORY_CSV_PATH, ["snapshot_ts", "snapshot_ct", "build_id", "instance", "status", "stage", "startup_band", "elapsed_seconds", "sell_path_elapsed_seconds", "full_cycle_elapsed_seconds", "warnings"], {
                "snapshot_ts": now,
                "snapshot_ct": payload.get("snapshot_ct", ""),
                "build_id": BUILD_ID,
                "instance": INSTANCE_NAME,
                "status": status,
                "stage": payload.get("current_stage", ""),
                "startup_band": startup_band,
                "elapsed_seconds": elapsed,
                "sell_path_elapsed_seconds": sell_path_elapsed,
                "full_cycle_elapsed_seconds": full_cycle_elapsed,
                "warnings": ";".join(warnings),
            })
        except Exception:
            pass
        return payload
    except Exception as e:
        try:
            LOGGER.debug("Live Startup SLA report failed: %s", e)
        except Exception:
            pass
        return {}


def _json_file_payload_for_build_gate(path: str):
    try:
        if not path or not os.path.exists(path) or not os.path.isfile(path):
            return None
        with open(path, "r", encoding="utf-8-sig", errors="replace") as fh:
            raw = fh.read(2 * 1024 * 1024)
        if not raw.strip():
            return None
        return json.loads(raw)
    except Exception:
        return None


def _path_age_seconds(path: str):
    try:
        if not path or not os.path.exists(path) or not os.path.isfile(path):
            return None
        return max(0, int(now_ts() - int(os.path.getmtime(path))))
    except Exception:
        return None


def _latest_logged_live_builds(limit: int = 5) -> list:
    try:
        if not os.path.exists(LOG_FILE) or not os.path.isfile(LOG_FILE):
            return []
        with open(LOG_FILE, "rb") as fh:
            fh.seek(0, os.SEEK_END)
            end = fh.tell()
            fh.seek(max(0, end - 400000))
            text = fh.read().decode("utf-8", errors="replace")
        found = []
        pat = re.compile(r"Starting LIVE Kalshi 15m sell bot \| build_id=([^\s|]+)")
        for m in pat.finditer(text):
            found.append(m.group(1))
        return found[-max(1, limit):]
    except Exception:
        return []


def _report_build_row(name: str, path: str) -> dict:
    payload = _json_file_payload_for_build_gate(path)
    age = _path_age_seconds(path)
    build = ""
    status = "missing"
    if isinstance(payload, dict):
        build = str(payload.get("build_id") or payload.get("build") or "").strip()
        status = str(payload.get("status") or payload.get("band") or payload.get("plan_band") or "present").strip()
    elif payload is not None:
        status = "unreadable_shape"
    return {
        "name": name,
        "path": path,
        "exists": bool(path and os.path.exists(path)),
        "age_seconds": "" if age is None else age,
        "build_id": build,
        "matches_current_build": bool(build == BUILD_ID) if build else "",
        "status": status,
    }


def build_current_build_freshness_gate_payload(context: str = "snapshot", mutate: bool = False) -> dict:
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    reports = [
        _report_build_row("live_startup_sla", LIVE_STARTUP_SLA_JSON_PATH),
        _report_build_row("launch_blocker", LAUNCH_BLOCKER_JSON_PATH),
        _report_build_row("auth_doctor", AUTH_DIAGNOSTIC_JSON_PATH),
        _report_build_row("private_stream_sla", PRIVATE_STREAM_SLA_LATEST_JSON_PATH),
        _report_build_row("post_fill_sell_sla", POST_FILL_SELL_SLA_LATEST_JSON_PATH),
        _report_build_row("sell_path_watchdog", SELL_PATH_WATCHDOG_LATEST_JSON_PATH),
        _report_build_row("sell_queue_exit_optimizer", SELL_QUEUE_EXIT_LATEST_JSON_PATH),
        _report_build_row("residual_sell_tuner", RESIDUAL_SELL_TUNER_LATEST_JSON_PATH),
        _report_build_row("startup_to_sell_autorepair", STARTUP_TO_SELL_AUTOREPAIR_JSON_PATH),
    ]
    recent_mismatched_reports = []
    old_or_missing_reports = []
    for row in reports:
        age = row.get("age_seconds")
        is_recent = isinstance(age, int) and age <= CURRENT_BUILD_FRESHNESS_GATE_REPORT_MAX_AGE_SECONDS
        if row.get("build_id") and row.get("build_id") != BUILD_ID and is_recent:
            recent_mismatched_reports.append(row.get("name"))
        if not row.get("exists") or (isinstance(age, int) and age > CURRENT_BUILD_FRESHNESS_GATE_REPORT_MAX_AGE_SECONDS * 4):
            old_or_missing_reports.append(row.get("name"))
    log_builds = _latest_logged_live_builds(limit=5)
    latest_log_build = log_builds[-1] if log_builds else ""
    lock_meta = _safe_lock_metadata_snapshot()
    lock_build = str((lock_meta or {}).get("build_id", "") or "") if isinstance(lock_meta, dict) else ""
    hb_ts = int((lock_meta or {}).get("heartbeat_ts", 0) or 0) if isinstance(lock_meta, dict) else 0
    hb_age = max(0, now - hb_ts) if hb_ts else ""
    events = meta.get("live_startup_sla_events", {}) if isinstance(meta.get("live_startup_sla_events"), dict) else {}
    start_ts = int(meta.get("live_startup_sla_start_ts", 0) or 0)
    startup_age = max(0, now - start_ts) if start_ts else 0
    first_sell_begin = int((events.get("first_sell_management_begin") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    first_sell_complete = int((events.get("first_sell_management_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    missing_begin_repaired = False
    if not first_sell_begin and first_sell_complete:
        first_sell_begin = first_sell_complete
        missing_begin_repaired = True
    warnings = []
    blockers = []
    if missing_begin_repaired:
        warnings.append("first_sell_begin_missing_repaired_from_complete")
    current_runtime_evidence = bool(lock_build == BUILD_ID)
    if not current_runtime_evidence:
        current_runtime_evidence = any(bool(row.get("matches_current_build")) and isinstance(row.get("age_seconds"), int) and row.get("age_seconds") <= CURRENT_BUILD_FRESHNESS_GATE_REPORT_MAX_AGE_SECONDS for row in reports)
    if not current_runtime_evidence and (first_sell_begin or first_sell_complete):
        current_runtime_evidence = True
    latest_logged_live_build_warning_suppressed = False
    if latest_log_build and latest_log_build != BUILD_ID:
        if current_runtime_evidence:
            latest_logged_live_build_warning_suppressed = True
        else:
            warnings.append(f"latest_logged_live_build_is_old:{latest_log_build}")
    if lock_build and lock_build != BUILD_ID:
        warnings.append(f"lock_build_mismatch:{lock_build}")
    if isinstance(hb_age, int) and hb_age > max(LOCK_HEARTBEAT_INTERVAL_SECONDS * 3, 90):
        blockers.append(f"lock_heartbeat_stale:{hb_age}s")
    if recent_mismatched_reports:
        warnings.append("recent_old_build_reports:" + ",".join(recent_mismatched_reports[:8]))
    if CURRENT_BUILD_FRESHNESS_GATE_REQUIRE_SELL_PASS and start_ts and not first_sell_begin and startup_age > STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS:
        msg = f"startup_has_not_reached_sell_management:{startup_age}s"
        if BUY_PRIORITY_HEDGE_ADVISORY_MODE:
            warnings.append(msg + ";buy_priority_advisory")
        else:
            blockers.append(msg)
    elif CURRENT_BUILD_FRESHNESS_GATE_REQUIRE_SELL_PASS and first_sell_begin and not first_sell_complete and startup_age > max(STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS, LIVE_STARTUP_SLA_SECONDS):
        warnings.append(f"sell_management_started_not_complete:{startup_age}s")
    pause_until = int(meta.get("current_build_freshness_buy_pause_until_ts", 0) or 0)
    if mutate and blockers and CURRENT_BUILD_FRESHNESS_GATE_BLOCK_BUY_ACTION:
        pause_until = max(pause_until, now + CURRENT_BUILD_FRESHNESS_GATE_PAUSE_SECONDS)
        meta["current_build_freshness_buy_pause_until_ts"] = pause_until
        meta["current_build_freshness_buy_pause_reason"] = ";".join(blockers)[:300]
    pause_remaining = max(0, pause_until - now) if pause_until else 0
    band = "blocked" if blockers else ("watch" if warnings else "healthy")
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": context,
        "enabled": bool(CURRENT_BUILD_FRESHNESS_GATE_ENABLED),
        "band": band,
        "buy_action_pause_active": bool(CURRENT_BUILD_FRESHNESS_GATE_BLOCK_BUY_ACTION and pause_remaining > 0),
        "buy_action_pause_remaining_seconds": int(pause_remaining),
        "buy_action_pause_reason": meta.get("current_build_freshness_buy_pause_reason", ""),
        "current_build_id": BUILD_ID,
        "latest_logged_live_build_id": latest_log_build,
        "recent_logged_live_build_ids": log_builds,
        "latest_logged_live_build_warning_suppressed": bool(latest_logged_live_build_warning_suppressed),
        "current_runtime_evidence": bool(current_runtime_evidence),
        "lock_build_id": lock_build,
        "lock_heartbeat_age_seconds": hb_age,
        "startup_age_seconds": startup_age,
        "first_sell_management_begin_ts": first_sell_begin,
        "first_sell_management_complete_ts": first_sell_complete,
        "first_sell_begin_missing_repaired": bool(missing_begin_repaired),
        "recent_mismatched_reports": recent_mismatched_reports,
        "old_or_missing_reports": old_or_missing_reports,
        "warnings": warnings,
        "blockers": blockers,
        "reports": reports,
        "policy": "pause only new buy-action handoff if current startup does not reach sell management; sell placement/repair remain active",
    }
    meta["last_current_build_freshness_gate"] = {k: v for k, v in payload.items() if k != "reports"}
    return payload


def _current_build_freshness_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m Current-Build Freshness Gate",
        "========================================",
        f"Generated CT : {payload.get('snapshot_ct', '')}",
        f"Build ID     : {payload.get('build_id', '')}",
        f"Context      : {payload.get('context', '')}",
        f"Band         : {payload.get('band', '')}",
        f"Buy pause    : {payload.get('buy_action_pause_active')} remaining={payload.get('buy_action_pause_remaining_seconds', 0)}s reason={payload.get('buy_action_pause_reason', '')}",
        f"Latest log   : {payload.get('latest_logged_live_build_id', '') or '[none]'} suppressed={payload.get('latest_logged_live_build_warning_suppressed', False)}",
        f"Runtime proof: current_runtime_evidence={payload.get('current_runtime_evidence', False)}",
        f"Lock build   : {payload.get('lock_build_id', '') or '[none]'} heartbeat_age={payload.get('lock_heartbeat_age_seconds', '')}",
        f"Startup age  : {payload.get('startup_age_seconds', 0)}s first_sell_begin={payload.get('first_sell_management_begin_ts', '')} first_sell_complete={payload.get('first_sell_management_complete_ts', '')}",
        "",
    ]
    if payload.get("blockers"):
        lines.append("Blockers:")
        lines.extend([f"- {x}" for x in payload.get("blockers", [])])
        lines.append("")
    if payload.get("warnings"):
        lines.append("Warnings:")
        lines.extend([f"- {x}" for x in payload.get("warnings", [])])
        lines.append("")
    lines.append("Report freshness:")
    for row in payload.get("reports", []) or []:
        lines.append(f"- {row.get('name')}: exists={row.get('exists')} age={row.get('age_seconds')} build={row.get('build_id') or '[none]'} match={row.get('matches_current_build')} status={row.get('status')}")
    lines.extend(["", "Recommendation:", "- Use this report with Live Startup SLA and Launch Unblocker to distinguish an old/stale report from the currently running build."])
    return "\n".join(lines) + "\n"


def write_current_build_freshness_gate_report(context: str = "cycle", force: bool = False, mutate: bool = False) -> dict:
    if not CURRENT_BUILD_FRESHNESS_GATE_ENABLED and not force:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_current_build_freshness_gate_report_ts", 0) or 0) < 15:
        return meta.get("last_current_build_freshness_gate", {}) or {}
    payload = build_current_build_freshness_gate_payload(context=context, mutate=mutate)
    meta["last_current_build_freshness_gate_report_ts"] = now
    try:
        atomic_write_json(CURRENT_BUILD_FRESHNESS_GATE_JSON_PATH, payload)
        os.makedirs(os.path.dirname(CURRENT_BUILD_FRESHNESS_GATE_TXT_PATH) or ".", exist_ok=True)
        tmp = f"{CURRENT_BUILD_FRESHNESS_GATE_TXT_PATH}.tmp"
        with open(tmp, "w", encoding="utf-8") as fh:
            fh.write(_current_build_freshness_text(payload))
        atomic_replace_with_retry(tmp, CURRENT_BUILD_FRESHNESS_GATE_TXT_PATH, context="current_build_freshness_txt")
        append_csv_row(CURRENT_BUILD_FRESHNESS_GATE_HISTORY_CSV_PATH, ["snapshot_ts", "snapshot_ct", "build_id", "context", "band", "buy_action_pause_active", "buy_action_pause_remaining_seconds", "latest_logged_live_build_id", "lock_build_id", "startup_age_seconds", "blockers", "warnings"], {
            "snapshot_ts": payload.get("snapshot_ts"),
            "snapshot_ct": payload.get("snapshot_ct"),
            "build_id": BUILD_ID,
            "context": context,
            "band": payload.get("band"),
            "buy_action_pause_active": payload.get("buy_action_pause_active"),
            "buy_action_pause_remaining_seconds": payload.get("buy_action_pause_remaining_seconds"),
            "latest_logged_live_build_id": payload.get("latest_logged_live_build_id"),
            "lock_build_id": payload.get("lock_build_id"),
            "startup_age_seconds": payload.get("startup_age_seconds"),
            "blockers": ";".join(payload.get("blockers", [])),
            "warnings": ";".join(payload.get("warnings", [])),
        })
    except Exception as e:
        try:
            LOGGER.debug("Current-build freshness report failed: %s", e)
        except Exception:
            pass
    return payload



def _live_startup_timeline_context(meta: dict = None, now: int = None) -> dict:
    meta = meta if isinstance(meta, dict) else STATE.setdefault("meta", {})
    now = int(now if now is not None else now_ts())
    events = meta.get("live_startup_sla_events", {}) if isinstance(meta.get("live_startup_sla_events"), dict) else {}
    start_ts = int(meta.get("live_startup_sla_start_ts", 0) or 0)
    process_event = events.get("process_start", {}) if isinstance(events, dict) else {}
    process_event_ts = int((process_event or {}).get("ts", 0) or 0) if isinstance(process_event, dict) else 0
    if process_event_ts and (not start_ts or process_event_ts > start_ts):
        start_ts = process_event_ts
    start_build = str(meta.get("live_startup_sla_start_build_id", "") or "")
    start_pid = int(meta.get("live_startup_sla_start_pid", 0) or 0)
    current_pid = os.getpid()
    timeline_current = bool(start_ts and start_build == BUILD_ID and start_pid == current_pid)
    return {
        "startup_ts": start_ts,
        "startup_ct": central_time_iso_from_ts(start_ts) if start_ts else "",
        "startup_age_seconds": max(0, now - start_ts) if start_ts else 0,
        "startup_process_build_id": start_build,
        "startup_process_pid": start_pid,
        "current_process_pid": current_pid,
        "timeline_current": timeline_current,
        "timeline_reason": "current_process" if timeline_current else ("missing_startup_ts" if not start_ts else "stale_or_external_process"),
    }

def build_startup_to_sell_autorepair_payload(context: str = "snapshot", positions=None, primary_by_key=None, mutate: bool = False) -> dict:
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    events = meta.get("live_startup_sla_events", {}) if isinstance(meta.get("live_startup_sla_events"), dict) else {}
    timeline_ctx = _live_startup_timeline_context(meta, now=now)
    start_ts = int(timeline_ctx.get("startup_ts", 0) or 0)
    startup_age = int(timeline_ctx.get("startup_age_seconds", 0) or 0)
    timeline_current = bool(timeline_ctx.get("timeline_current"))
    first_run_begin = int((events.get("first_run_once_begin") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    first_sell_begin = int((events.get("first_sell_management_begin") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    first_sell_complete = int((events.get("first_sell_management_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    missing_begin_repaired = False
    if not first_sell_begin and first_sell_complete:
        first_sell_begin = first_sell_complete
        missing_begin_repaired = True
    private_sla = build_private_stream_sla_payload(context="startup_to_sell_autorepair", mutate=mutate) if PRIVATE_STREAM_SLA_ENABLED else {"enabled": False, "band": "disabled"}
    # Build a fresh sell-path view when the caller did not just supply one. This
    # makes the manual dashboard useful from a support bundle instead of relying
    # on stale last_* meta snapshots. update_missing_since stays False here so a
    # report-only command does not age/trigger new live watchdog state.
    if positions is None and SELL_PATH_WATCHDOG_ENABLED:
        try:
            sell_watchdog = write_sell_path_watchdog_report(positions=None, primary_by_key=primary_by_key, writes_allowed=True, context="startup_to_sell_autorepair", update_missing_since=False, force=True)
        except Exception:
            sell_watchdog = meta.get("last_sell_path_watchdog", {}) if isinstance(meta.get("last_sell_path_watchdog"), dict) else {}
    else:
        sell_watchdog = meta.get("last_sell_path_watchdog", {}) if isinstance(meta.get("last_sell_path_watchdog"), dict) else {}
    try:
        post_fill = write_post_fill_sell_sla_report(positions=positions, primary_by_key=primary_by_key, context="startup_to_sell_autorepair", force=True, mutate=False) if POST_FILL_SELL_SLA_ENABLED else {"enabled": False, "band": "disabled", "breach_count": 0}
    except Exception:
        post_fill = meta.get("last_post_fill_sell_sla", {}) if isinstance(meta.get("last_post_fill_sell_sla"), dict) else {}
    if positions is None and RESIDUAL_SELL_TUNER_ENABLED:
        try:
            residual = write_residual_sell_tuner_report(positions=None, primary_by_key=primary_by_key, context="startup_to_sell_autorepair", force=True)
        except Exception:
            residual = meta.get("last_residual_sell_tuner", {}) if isinstance(meta.get("last_residual_sell_tuner"), dict) else {}
    else:
        residual = meta.get("last_residual_sell_tuner", {}) if isinstance(meta.get("last_residual_sell_tuner"), dict) else {}
    active_positions = 0
    managed_sells = 0
    try:
        if positions is not None:
            active_positions = len([p for p in positions or [] if abs(parse_decimal((p or {}).get("position_fp", (p or {}).get("position", "0")), "0")) > 0])
        else:
            active_positions = int(_active_position_qty_from_state() > 0)
        if isinstance(primary_by_key, dict):
            managed_sells = len(primary_by_key)
    except Exception:
        pass
    blockers = []
    warnings = []
    if missing_begin_repaired:
        warnings.append("first_sell_begin_missing_repaired_from_complete")
    if start_ts and not timeline_current and startup_age > STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS:
        warnings.append(f"startup_timeline_stale_not_blocking:{timeline_ctx.get('timeline_reason', 'unknown')}:{startup_age}s")
    if start_ts and timeline_current and not first_sell_begin and startup_age > STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS:
        blockers.append(f"first_sell_management_not_reached_after_{startup_age}s")
    if timeline_current and first_sell_begin and not first_sell_complete and startup_age > max(STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS, LIVE_STARTUP_SLA_SECONDS):
        warnings.append(f"first_sell_management_not_completed_after_{startup_age}s")
    if isinstance(private_sla, dict) and private_sla.get("buy_action_pause_active"):
        warnings.append(f"private_stream_sla_pause_{private_sla.get('buy_action_pause_remaining_seconds', 0)}s")
    sell_watchdog_uncovered = int((sell_watchdog or {}).get("triggered_uncovered_count", 0) or 0)
    post_fill_breaches = int((post_fill or {}).get("breach_count", 0) or 0)
    residual_needed_count = int((residual or {}).get("coverage_needed_count", 0) or 0)
    if active_positions > 0 and sell_watchdog_uncovered > 0:
        blockers.append(f"sell_path_watchdog_uncovered_{sell_watchdog_uncovered}")
    elif sell_watchdog_uncovered > 0:
        warnings.append(f"sell_path_watchdog_uncovered_ignored_no_live_positions_{sell_watchdog_uncovered}")
    if active_positions > 0 and post_fill_breaches > 0:
        blockers.append(f"post_fill_sell_sla_breach_{post_fill_breaches}")
    elif post_fill_breaches > 0:
        warnings.append(f"post_fill_sell_sla_breach_ignored_no_live_positions_{post_fill_breaches}")
    residual_blocks_buy_action = bool(RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION)
    if active_positions > 0 and residual_needed_count > 0:
        if residual_blocks_buy_action:
            blockers.append(f"residual_coverage_needed_{residual_needed_count}")
        else:
            warnings.append(f"residual_coverage_advisory_not_blocking_{residual_needed_count}")
    elif residual_needed_count > 0:
        warnings.append(f"residual_coverage_needed_ignored_no_live_positions_{residual_needed_count}")
    reconnect_requested = False
    if mutate and blockers and STARTUP_TO_SELL_AUTOREPAIR_BLOCK_BUY_ACTION:
        pause_until = now + STARTUP_TO_SELL_AUTOREPAIR_BUY_PAUSE_SECONDS
        meta["startup_to_sell_autorepair_buy_pause_until_ts"] = max(int(meta.get("startup_to_sell_autorepair_buy_pause_until_ts", 0) or 0), pause_until)
        meta["startup_to_sell_autorepair_buy_pause_reason"] = ";".join(blockers)[:300]
        if STARTUP_TO_SELL_AUTOREPAIR_RECONNECT_ENABLED and (not first_sell_begin or "post_fill" in ";".join(blockers)):
            reconnect_requested = request_websocket_reconnect("startup_to_sell_autorepair:" + ";".join(blockers)[:90])
    pause_until = int(meta.get("startup_to_sell_autorepair_buy_pause_until_ts", 0) or 0)
    pause_remaining = max(0, pause_until - now) if pause_until else 0
    if mutate and pause_remaining <= 0 and not blockers:
        meta["startup_to_sell_autorepair_buy_pause_reason"] = ""
    pause_reason = meta.get("startup_to_sell_autorepair_buy_pause_reason", "") if pause_remaining > 0 else ""
    band = "breach" if blockers else ("watch" if warnings or not first_sell_complete else "healthy")
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": context,
        "enabled": bool(STARTUP_TO_SELL_AUTOREPAIR_ENABLED),
        "band": band,
        "startup_age_seconds": startup_age,
        "sla_seconds": STARTUP_TO_SELL_AUTOREPAIR_MAX_SECONDS,
        "timeline_current": bool(timeline_current),
        "timeline_reason": timeline_ctx.get("timeline_reason", ""),
        "startup_process_build_id": timeline_ctx.get("startup_process_build_id", ""),
        "startup_process_pid": timeline_ctx.get("startup_process_pid", ""),
        "current_process_pid": timeline_ctx.get("current_process_pid", ""),
        "first_run_once_begin_ts": first_run_begin,
        "first_sell_management_begin_ts": first_sell_begin,
        "first_sell_management_complete_ts": first_sell_complete,
        "active_positions_seen": active_positions,
        "managed_sell_count": managed_sells,
        "buy_action_pause_active": bool(STARTUP_TO_SELL_AUTOREPAIR_BLOCK_BUY_ACTION and pause_remaining > 0),
        "buy_action_pause_remaining_seconds": int(pause_remaining),
        "buy_action_pause_reason": pause_reason,
        "reconnect_requested": bool(reconnect_requested),
        "private_stream_sla": private_sla,
        "sell_path_watchdog": sell_watchdog,
        "post_fill_sell_sla": post_fill,
        "residual_sell_tuner": residual,
        "blockers": blockers,
        "warnings": warnings,
        "policy": "pause new buys and request private WS reconnect when startup does not reach sell management; sell repair remains live",
    }
    meta["last_startup_to_sell_autorepair"] = {k: v for k, v in payload.items() if k not in {"private_stream_sla", "sell_path_watchdog", "post_fill_sell_sla", "residual_sell_tuner"}}
    return payload


def _startup_to_sell_autorepair_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m Startup-to-Sell Autorepair Dashboard",
        "================================================",
        f"Generated CT : {payload.get('snapshot_ct', '')}",
        f"Build ID     : {payload.get('build_id', '')}",
        f"Context      : {payload.get('context', '')}",
        f"Band         : {payload.get('band', '')}",
        f"Startup age  : {payload.get('startup_age_seconds', 0)}s / SLA {payload.get('sla_seconds', '')}s",
        f"First sell   : begin={payload.get('first_sell_management_begin_ts', '')} complete={payload.get('first_sell_management_complete_ts', '')}",
        f"Positions    : active_seen={payload.get('active_positions_seen', '')} managed_sells={payload.get('managed_sell_count', '')}",
        f"Buy pause    : {payload.get('buy_action_pause_active')} remaining={payload.get('buy_action_pause_remaining_seconds', 0)}s reason={payload.get('buy_action_pause_reason', '')}",
        f"Reconnect    : {payload.get('reconnect_requested')}",
        "",
    ]
    if payload.get("blockers"):
        lines.append("Blockers:")
        lines.extend([f"- {x}" for x in payload.get("blockers", [])])
        lines.append("")
    if payload.get("warnings"):
        lines.append("Warnings:")
        lines.extend([f"- {x}" for x in payload.get("warnings", [])])
        lines.append("")
    ps = payload.get("private_stream_sla") if isinstance(payload.get("private_stream_sla"), dict) else {}
    sw = payload.get("sell_path_watchdog") if isinstance(payload.get("sell_path_watchdog"), dict) else {}
    pf = payload.get("post_fill_sell_sla") if isinstance(payload.get("post_fill_sell_sla"), dict) else {}
    rs = payload.get("residual_sell_tuner") if isinstance(payload.get("residual_sell_tuner"), dict) else {}
    lines.extend([
        "Sell-path components:",
        f"- Private Stream SLA: band={ps.get('band', '')} pause={ps.get('buy_action_pause_active', False)} queue={ps.get('private_queue_depth', '')} lag={ps.get('last_private_event_lag_seconds', '')}",
        f"- Sell Path Watchdog: uncovered={sw.get('triggered_uncovered_count', sw.get('uncovered_count', ''))} active={sw.get('active_position_count', '')}",
        f"- Post-Fill Sell SLA: band={pf.get('band', '')} breaches={pf.get('breach_count', '')}",
        f"- Residual Sell Tuner: coverage_needed={rs.get('coverage_needed_count', '')} low_probability={rs.get('low_probability_count', '')}",
        "",
        "Recommendation:",
        "- If band is breach, keep buys paused and upload this report plus Live Startup SLA; sell repair paths remain enabled.",
    ])
    return "\n".join(lines) + "\n"


def write_startup_to_sell_autorepair_dashboard(context: str = "cycle", positions=None, primary_by_key=None, force: bool = False, mutate: bool = False) -> dict:
    if not STARTUP_TO_SELL_AUTOREPAIR_ENABLED and not force:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_startup_to_sell_autorepair_report_ts", 0) or 0) < 10:
        return meta.get("last_startup_to_sell_autorepair", {}) or {}
    payload = build_startup_to_sell_autorepair_payload(context=context, positions=positions, primary_by_key=primary_by_key, mutate=mutate)
    meta["last_startup_to_sell_autorepair_report_ts"] = now
    try:
        atomic_write_json(STARTUP_TO_SELL_AUTOREPAIR_JSON_PATH, payload)
        os.makedirs(os.path.dirname(STARTUP_TO_SELL_AUTOREPAIR_TXT_PATH) or ".", exist_ok=True)
        tmp = f"{STARTUP_TO_SELL_AUTOREPAIR_TXT_PATH}.tmp"
        with open(tmp, "w", encoding="utf-8") as fh:
            fh.write(_startup_to_sell_autorepair_text(payload))
        atomic_replace_with_retry(tmp, STARTUP_TO_SELL_AUTOREPAIR_TXT_PATH, context="startup_to_sell_autorepair_txt")
        append_csv_row(STARTUP_TO_SELL_AUTOREPAIR_HISTORY_CSV_PATH, ["snapshot_ts", "snapshot_ct", "build_id", "context", "band", "startup_age_seconds", "first_sell_management_begin_ts", "first_sell_management_complete_ts", "active_positions_seen", "managed_sell_count", "buy_action_pause_active", "buy_action_pause_remaining_seconds", "reconnect_requested", "blockers", "warnings"], {
            "snapshot_ts": payload.get("snapshot_ts"),
            "snapshot_ct": payload.get("snapshot_ct"),
            "build_id": BUILD_ID,
            "context": context,
            "band": payload.get("band"),
            "startup_age_seconds": payload.get("startup_age_seconds"),
            "first_sell_management_begin_ts": payload.get("first_sell_management_begin_ts"),
            "first_sell_management_complete_ts": payload.get("first_sell_management_complete_ts"),
            "active_positions_seen": payload.get("active_positions_seen"),
            "managed_sell_count": payload.get("managed_sell_count"),
            "buy_action_pause_active": payload.get("buy_action_pause_active"),
            "buy_action_pause_remaining_seconds": payload.get("buy_action_pause_remaining_seconds"),
            "reconnect_requested": payload.get("reconnect_requested"),
            "blockers": ";".join(payload.get("blockers", [])),
            "warnings": ";".join(payload.get("warnings", [])),
        })
    except Exception as e:
        try:
            LOGGER.debug("Startup-to-sell autorepair dashboard failed: %s", e)
        except Exception:
            pass
    return payload



def _live_launch_sentinel_position_summary(positions=None, primary_by_key=None) -> dict:
    active_count = 0
    active_qty = Decimal("0")
    try:
        if positions is not None:
            for p in positions or []:
                if not isinstance(p, dict):
                    continue
                qty = abs(parse_decimal(p.get("position_fp", p.get("position", "0")), "0"))
                if qty > 0:
                    active_count += 1
                    active_qty += qty
        else:
            active_qty = abs(parse_decimal(_active_position_qty_from_state(), "0"))
            active_count = int(active_qty > 0)
    except Exception:
        active_count = 0
        active_qty = Decimal("0")
    managed_count = 0
    try:
        if isinstance(primary_by_key, dict):
            managed_count = len([o for o in primary_by_key.values() if isinstance(o, dict) and o.get("order_id")])
        else:
            managed_count = int(STATE.setdefault("meta", {}).get("startup_managed_sell_count", 0) or 0)
    except Exception:
        managed_count = 0
    return {"active_position_count": int(active_count), "active_position_qty_fp": qty_str(active_qty), "managed_sell_count": int(managed_count)}


def build_live_launch_sentinel_payload(context: str = "snapshot", positions=None, primary_by_key=None, mutate: bool = False) -> dict:
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    timeline_ctx = _live_startup_timeline_context(meta, now=now)
    events = meta.get("live_startup_sla_events", {}) if isinstance(meta.get("live_startup_sla_events"), dict) else {}
    start_ts = int(timeline_ctx.get("startup_ts", 0) or 0)
    timeline_current = bool(timeline_ctx.get("timeline_current"))
    startup_age = int(timeline_ctx.get("startup_age_seconds", 0) or 0)
    first_sell_begin = int((events.get("first_sell_management_begin") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    first_sell_complete = int((events.get("first_sell_management_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    missing_begin_repaired = False
    if not first_sell_begin and first_sell_complete:
        first_sell_begin = first_sell_complete
        missing_begin_repaired = True
    first_run_complete = int((events.get("first_run_once_complete") or {}).get("ts", 0) or 0) if isinstance(events, dict) else 0
    pos_summary = _live_launch_sentinel_position_summary(positions=positions, primary_by_key=primary_by_key)
    position_load_ts = int(meta.get("startup_position_load_ts", 0) or 0)
    order_load_ts = int(meta.get("startup_order_load_ts", 0) or meta.get("startup_resting_order_load_ts", 0) or 0)
    position_loaded = bool(position_load_ts and (not start_ts or position_load_ts >= max(0, start_ts - 5)))
    order_loaded = bool(order_load_ts and (not start_ts or order_load_ts >= max(0, start_ts - 5)))
    ws_state = str(meta.get("ws_connection_state", "disabled" if not WEBSOCKET_ENABLED else "not_connected") or "unknown")
    ws429_context = {
        "enabled": bool(WEBSOCKET_429_BACKOFF_ENABLED),
        "active": bool(WEBSOCKET_429_BACKOFF_ENABLED and (ws_state == "rate_limited_429" or int(meta.get("ws_handshake_429_consecutive_count", 0) or 0) > 0)),
        "count_run": int(meta.get("ws_handshake_429_count_run", 0) or 0),
        "total_count": int(meta.get("ws_handshake_429_total_count", 0) or 0),
        "consecutive_count": int(meta.get("ws_handshake_429_consecutive_count", 0) or 0),
        "last_ct": meta.get("ws_handshake_429_last_ct", ""),
        "next_retry_ct": meta.get("ws_next_retry_ct", ""),
        "next_retry_delay_seconds": meta.get("ws_handshake_429_next_retry_delay_seconds", 0),
        "last_status_code": int(meta.get("ws_last_error_status_code", 0) or 0),
        "last_error": str(meta.get("ws_handshake_429_last_error", "") or meta.get("ws_last_error", ""))[:240],
        "policy": {
            "base_seconds": WEBSOCKET_429_BACKOFF_BASE_SECONDS,
            "max_seconds": WEBSOCKET_429_BACKOFF_MAX_SECONDS,
            "reset_seconds": WEBSOCKET_429_BACKOFF_RESET_SECONDS,
        },
    }
    ws_health = build_websocket_health_payload() if WEBSOCKET_HEALTH_ENABLED else {"enabled": False, "band": "disabled"}
    channel_status = _private_stream_required_channel_status() if WEBSOCKET_ENABLED else {"present": False, "missing_required_private_channels": ["fill", "market_position"], "configured_private_channels": []}
    sell_watchdog = meta.get("last_sell_path_watchdog", {}) if isinstance(meta.get("last_sell_path_watchdog"), dict) else {}
    try:
        post_fill = write_post_fill_sell_sla_report(positions=positions, primary_by_key=primary_by_key, context="live_launch_sentinel", force=True, mutate=False) if POST_FILL_SELL_SLA_ENABLED else {"enabled": False, "band": "disabled", "breach_count": 0}
    except Exception:
        post_fill = meta.get("last_post_fill_sell_sla", {}) if isinstance(meta.get("last_post_fill_sell_sla"), dict) else {}
    residual = meta.get("last_residual_sell_tuner", {}) if isinstance(meta.get("last_residual_sell_tuner"), dict) else {}
    hedge = meta.get("last_hedge_compliance_sla", {}) if isinstance(meta.get("last_hedge_compliance_sla"), dict) else {}
    active_count = int(pos_summary.get("active_position_count", 0) or 0)
    managed_count = int(pos_summary.get("managed_sell_count", 0) or 0)
    private_ws_ok = (not LIVE_LAUNCH_SENTINEL_REQUIRE_PRIVATE_WS) or (WEBSOCKET_ENABLED and ws_state == "connected" and bool(channel_status.get("present")))
    position_load_ok = (not LIVE_LAUNCH_SENTINEL_REQUIRE_POSITION_LOAD) or position_loaded
    sell_heartbeat_ok = (not LIVE_LAUNCH_SENTINEL_REQUIRE_SELL_HEARTBEAT) or bool(first_sell_begin and (not start_ts or first_sell_begin >= max(0, start_ts - 5)))
    no_position_pass = bool(LIVE_LAUNCH_SENTINEL_ALLOW_NO_POSITION_PASS and position_load_ok and active_count == 0)
    uncovered = int((sell_watchdog or {}).get("triggered_uncovered_count", (sell_watchdog or {}).get("uncovered_count", 0)) or 0)
    post_breaches = int((post_fill or {}).get("breach_count", 0) or 0)
    residual_needed = int((residual or {}).get("coverage_needed_count", 0) or 0)
    residual_blocks_buy_action = bool(RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION)
    residual_blocking_needed = residual_needed if residual_blocks_buy_action else 0
    residual_advisory_needed = residual_needed if not residual_blocks_buy_action else 0
    hedge_needed = int((hedge or {}).get("action_needed_count", 0) or 0)
    coverage_ok = (not LIVE_LAUNCH_SENTINEL_REQUIRE_ACTIVE_SELL_COVERAGE) or no_position_pass or (position_load_ok and sell_heartbeat_ok and managed_count >= active_count and uncovered <= 0 and post_breaches <= 0 and residual_blocking_needed <= 0 and hedge_needed <= 0)
    checks = {
        "timeline_current": bool(timeline_current),
        "private_ws": bool(private_ws_ok),
        "position_load": bool(position_load_ok),
        "order_load": bool(order_loaded),
        "sell_heartbeat": bool(sell_heartbeat_ok),
        "active_sell_coverage": bool(coverage_ok),
    }
    blockers = []
    warnings = []
    if missing_begin_repaired:
        warnings.append("first_sell_begin_missing_repaired_from_complete")
    if not timeline_current:
        warnings.append(f"startup_timeline_not_current:{timeline_ctx.get('timeline_reason', 'unknown')}")
    if timeline_current:
        if not private_ws_ok:
            if ws429_context.get("active"):
                blockers.append(f"private_ws_429_backoff:run={ws429_context.get('count_run', 0)}:consecutive={ws429_context.get('consecutive_count', 0)}:next_retry={ws429_context.get('next_retry_ct', '')}")
            else:
                blockers.append(f"private_ws_not_ready:{ws_state}:missing={','.join(channel_status.get('missing_required_private_channels', []))}")
        if not position_load_ok:
            blockers.append("startup_positions_not_loaded")
        if not sell_heartbeat_ok:
            blockers.append("first_sell_path_heartbeat_not_seen")
        if not coverage_ok:
            blockers.append(f"active_sell_coverage_not_verified:active={active_count}:managed={managed_count}:uncovered={uncovered}:post_breaches={post_breaches}:residual_blocking={residual_blocking_needed}:hedge={hedge_needed}")
        if residual_advisory_needed > 0:
            warnings.append(f"residual_coverage_advisory_not_blocking:{residual_advisory_needed}")
        if startup_age > LIVE_LAUNCH_SENTINEL_WINDOW_SECONDS and blockers:
            warnings.append(f"launch_window_elapsed_with_blockers:{startup_age}s")
    window_active = bool(timeline_current and startup_age <= LIVE_LAUNCH_SENTINEL_WINDOW_SECONDS)
    should_block = bool(timeline_current and blockers and (window_active or LIVE_LAUNCH_SENTINEL_HARD_BLOCK_UNTIL_PASS))
    if mutate and should_block and LIVE_LAUNCH_SENTINEL_BLOCK_BUY_ACTION:
        pause_until = now + LIVE_LAUNCH_SENTINEL_BUY_PAUSE_SECONDS
        meta["live_launch_sentinel_buy_pause_until_ts"] = max(int(meta.get("live_launch_sentinel_buy_pause_until_ts", 0) or 0), pause_until)
        meta["live_launch_sentinel_buy_pause_reason"] = ";".join(blockers)[:300]
        meta["live_launch_sentinel_last_block_ts"] = now
    pause_until = int(meta.get("live_launch_sentinel_buy_pause_until_ts", 0) or 0)
    pause_remaining = max(0, pause_until - now) if pause_until else 0
    if mutate and pause_remaining <= 0 and not should_block:
        meta["live_launch_sentinel_buy_pause_reason"] = ""
    pause_reason = meta.get("live_launch_sentinel_buy_pause_reason", "") if pause_remaining > 0 else ""
    if not LIVE_LAUNCH_SENTINEL_ENABLED:
        band = "disabled"
    elif not timeline_current:
        band = "stale_timeline"
    elif should_block or pause_remaining > 0:
        band = "block_buys"
    elif blockers:
        band = "watch"
    else:
        band = "healthy"
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": context,
        "enabled": bool(LIVE_LAUNCH_SENTINEL_ENABLED),
        "band": band,
        "startup_age_seconds": startup_age,
        "window_seconds": LIVE_LAUNCH_SENTINEL_WINDOW_SECONDS,
        "window_active": bool(window_active),
        "hard_block_until_pass": bool(LIVE_LAUNCH_SENTINEL_HARD_BLOCK_UNTIL_PASS),
        "timeline": timeline_ctx,
        "checks": checks,
        "private_ws": {"enabled": bool(WEBSOCKET_ENABLED), "state": ws_state, "health_band": ws_health.get("band", ""), "required_channels_present": bool(channel_status.get("present")), "channel_status": channel_status, "ws_429_backoff": ws429_context},
        "startup_position_load_ts": position_load_ts,
        "startup_order_load_ts": order_load_ts,
        "first_sell_management_begin_ts": first_sell_begin,
        "first_sell_management_complete_ts": first_sell_complete,
        "first_sell_begin_missing_repaired": bool(missing_begin_repaired),
        "first_run_once_complete_ts": first_run_complete,
        "active_position_count": active_count,
        "active_position_qty_fp": pos_summary.get("active_position_qty_fp", "0.00"),
        "managed_sell_count": managed_count,
        "coverage_inputs": {"uncovered_count": uncovered, "post_fill_breach_count": post_breaches, "residual_coverage_needed_count": residual_needed, "residual_coverage_blocking_count": residual_blocking_needed, "residual_coverage_advisory_count": residual_advisory_needed, "residual_block_buy_action_enabled": bool(residual_blocks_buy_action), "hedge_action_needed_count": hedge_needed},
        "buy_action_pause_active": bool(LIVE_LAUNCH_SENTINEL_BLOCK_BUY_ACTION and pause_remaining > 0),
        "buy_action_pause_remaining_seconds": int(pause_remaining),
        "buy_action_pause_reason": pause_reason,
        "blockers": blockers,
        "warnings": warnings,
        "policy": "pause new buy handoff until launch has fresh private WS, REST positions, sell heartbeat, and coverage; sell repair remains live",
    }
    meta["last_live_launch_sentinel"] = {k: v for k, v in payload.items() if k not in {"private_ws"}}
    return payload


def _live_launch_sentinel_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m Live Launch Sentinel",
        "=================================",
        f"Generated CT : {payload.get('snapshot_ct', '')}",
        f"Build ID     : {payload.get('build_id', '')}",
        f"Context      : {payload.get('context', '')}",
        f"Band         : {payload.get('band', '')}",
        f"Startup age  : {payload.get('startup_age_seconds', 0)}s / window {payload.get('window_seconds', '')}s",
        f"Timeline     : current={payload.get('timeline', {}).get('timeline_current')} reason={payload.get('timeline', {}).get('timeline_reason', '')} pid={payload.get('timeline', {}).get('startup_process_pid', '')}->{payload.get('timeline', {}).get('current_process_pid', '')}",
        f"Private WS   : state={payload.get('private_ws', {}).get('state', '')} band={payload.get('private_ws', {}).get('health_band', '')} channels_ok={payload.get('private_ws', {}).get('required_channels_present')}",
        f"WS 429       : {payload.get('private_ws', {}).get('ws_429_backoff', {})}",
        f"REST loads   : positions_ts={payload.get('startup_position_load_ts', '')} orders_ts={payload.get('startup_order_load_ts', '')}",
        f"Sell path    : begin={payload.get('first_sell_management_begin_ts', '')} complete={payload.get('first_sell_management_complete_ts', '')}",
        f"Coverage     : active={payload.get('active_position_count', 0)} managed={payload.get('managed_sell_count', 0)} inputs={payload.get('coverage_inputs', {})}",
        f"Buy pause    : {payload.get('buy_action_pause_active')} remaining={payload.get('buy_action_pause_remaining_seconds', 0)}s reason={payload.get('buy_action_pause_reason', '')}",
        "",
    ]
    if payload.get("blockers"):
        lines.append("Blockers:")
        lines.extend([f"- {x}" for x in payload.get("blockers", [])])
        lines.append("")
    if payload.get("warnings"):
        lines.append("Warnings:")
        lines.extend([f"- {x}" for x in payload.get("warnings", [])])
        lines.append("")
    lines.extend([
        "Recommendation:",
        "- If band is block_buys, keep the bot running; sell repair remains enabled while launch proof catches up.",
    ])
    return "\n".join(lines) + "\n"


def write_live_launch_sentinel_report(context: str = "cycle", positions=None, primary_by_key=None, force: bool = False, mutate: bool = False) -> dict:
    if not LIVE_LAUNCH_SENTINEL_ENABLED and not force:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_live_launch_sentinel_report_ts", 0) or 0) < 10:
        return meta.get("last_live_launch_sentinel", {}) or {}
    payload = build_live_launch_sentinel_payload(context=context, positions=positions, primary_by_key=primary_by_key, mutate=mutate)
    meta["last_live_launch_sentinel_report_ts"] = now
    try:
        atomic_write_json(LIVE_LAUNCH_SENTINEL_JSON_PATH, payload)
        os.makedirs(os.path.dirname(LIVE_LAUNCH_SENTINEL_TXT_PATH) or ".", exist_ok=True)
        tmp = f"{LIVE_LAUNCH_SENTINEL_TXT_PATH}.tmp"
        with open(tmp, "w", encoding="utf-8") as fh:
            fh.write(_live_launch_sentinel_text(payload))
        atomic_replace_with_retry(tmp, LIVE_LAUNCH_SENTINEL_TXT_PATH, context="live_launch_sentinel_txt")
        append_csv_row(LIVE_LAUNCH_SENTINEL_HISTORY_CSV_PATH, ["snapshot_ts", "snapshot_ct", "build_id", "context", "band", "startup_age_seconds", "timeline_current", "private_ws", "position_load", "sell_heartbeat", "active_sell_coverage", "active_position_count", "managed_sell_count", "buy_action_pause_active", "buy_action_pause_remaining_seconds", "blockers", "warnings"], {
            "snapshot_ts": payload.get("snapshot_ts"),
            "snapshot_ct": payload.get("snapshot_ct"),
            "build_id": BUILD_ID,
            "context": context,
            "band": payload.get("band"),
            "startup_age_seconds": payload.get("startup_age_seconds"),
            "timeline_current": (payload.get("checks") or {}).get("timeline_current"),
            "private_ws": (payload.get("checks") or {}).get("private_ws"),
            "position_load": (payload.get("checks") or {}).get("position_load"),
            "sell_heartbeat": (payload.get("checks") or {}).get("sell_heartbeat"),
            "active_sell_coverage": (payload.get("checks") or {}).get("active_sell_coverage"),
            "active_position_count": payload.get("active_position_count"),
            "managed_sell_count": payload.get("managed_sell_count"),
            "buy_action_pause_active": payload.get("buy_action_pause_active"),
            "buy_action_pause_remaining_seconds": payload.get("buy_action_pause_remaining_seconds"),
            "blockers": ";".join(payload.get("blockers", [])),
            "warnings": ";".join(payload.get("warnings", [])),
        })
    except Exception as e:
        try:
            LOGGER.debug("Live launch sentinel report failed: %s", e)
        except Exception:
            pass
    return payload


def record_api_429_burst_event(kind: str, method: str, path: str, cost=None) -> None:
    if not API_429_BURST_CIRCUIT_ENABLED:
        return
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    events = meta.get("api_429_recent_events", [])
    if not isinstance(events, list):
        events = []
    cutoff = now - max(API_429_BURST_WINDOW_SECONDS * 4, 3600)
    cleaned = []
    for row in events[-API_429_BURST_MAX_EVENTS:]:
        if not isinstance(row, dict):
            continue
        try:
            ts = int(row.get("ts", 0) or 0)
        except Exception:
            ts = 0
        if ts >= cutoff:
            cleaned.append(row)
    cleaned.append({"ts": now, "ct": central_time_iso_from_ts(now), "kind": str(kind or "unknown"), "method": str(method or "").upper(), "path": str(path or "")[:240], "cost": str(cost if cost is not None else "")})
    meta["api_429_recent_events"] = cleaned[-API_429_BURST_MAX_EVENTS:]


def build_api_429_burst_circuit_payload(context: str = "snapshot", mutate: bool = False) -> dict:
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    events = meta.get("api_429_recent_events", [])
    if not isinstance(events, list):
        events = []
    cutoff = now - API_429_BURST_WINDOW_SECONDS
    window_events = []
    for row in events:
        if not isinstance(row, dict):
            continue
        try:
            ts = int(row.get("ts", 0) or 0)
        except Exception:
            ts = 0
        if ts >= cutoff:
            window_events.append(row)
    read_count = sum(1 for r in window_events if str(r.get("kind", "")).lower() == "read")
    write_count = sum(1 for r in window_events if str(r.get("kind", "")).lower() == "write")
    blockers = []
    warnings = []
    if read_count >= API_429_BURST_MAX_READ_429:
        blockers.append(f"read_429_burst_{read_count}_in_{API_429_BURST_WINDOW_SECONDS}s")
    elif read_count >= max(1, int(API_429_BURST_MAX_READ_429 * 0.50)):
        warnings.append(f"read_429_caution_{read_count}_in_{API_429_BURST_WINDOW_SECONDS}s")
    if write_count >= API_429_BURST_MAX_WRITE_429:
        blockers.append(f"write_429_burst_{write_count}_in_{API_429_BURST_WINDOW_SECONDS}s")
    elif write_count >= max(1, int(API_429_BURST_MAX_WRITE_429 * 0.50)):
        warnings.append(f"write_429_caution_{write_count}_in_{API_429_BURST_WINDOW_SECONDS}s")
    if mutate and blockers and API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION:
        pause_until = now + API_429_BURST_BUY_PAUSE_SECONDS
        meta["api_429_burst_buy_pause_until_ts"] = max(int(meta.get("api_429_burst_buy_pause_until_ts", 0) or 0), pause_until)
        meta["api_429_burst_buy_pause_reason"] = ";".join(blockers)[:300]
        meta["api_429_burst_last_block_ts"] = now
        if read_count >= API_429_BURST_MAX_READ_429:
            meta["api_low_priority_read_cooldown_until_ts"] = max(int(meta.get("api_low_priority_read_cooldown_until_ts", 0) or 0), now + API_429_BURST_LOW_READ_COOLDOWN_SECONDS)
            meta["api_low_priority_read_cooldown_last_path"] = "api_429_burst_circuit"
            meta["api_low_priority_read_cooldown_last_bucket"] = "global_burst_circuit"
            meta["api_low_priority_read_cooldown_last_seconds"] = API_429_BURST_LOW_READ_COOLDOWN_SECONDS
    pause_until = int(meta.get("api_429_burst_buy_pause_until_ts", 0) or 0)
    pause_remaining = max(0, pause_until - now) if pause_until else 0
    if not API_429_BURST_CIRCUIT_ENABLED:
        band = "disabled"
    elif blockers or pause_remaining > 0:
        band = "block_buys"
    elif warnings:
        band = "watch"
    else:
        band = "healthy"
    top_paths = {}
    for r in window_events:
        key = f"{r.get('kind', 'unknown')} {r.get('method', '')} {str(r.get('path', ''))[:120]}"
        top_paths[key] = top_paths.get(key, 0) + 1
    top_paths = dict(sorted(top_paths.items(), key=lambda kv: (-kv[1], kv[0]))[:12])
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": context,
        "enabled": bool(API_429_BURST_CIRCUIT_ENABLED),
        "band": band,
        "window_seconds": API_429_BURST_WINDOW_SECONDS,
        "read_429_count_window": int(read_count),
        "write_429_count_window": int(write_count),
        "total_429_count_window": int(len(window_events)),
        "max_read_429": API_429_BURST_MAX_READ_429,
        "max_write_429": API_429_BURST_MAX_WRITE_429,
        "buy_action_pause_active": bool(API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION and pause_remaining > 0),
        "buy_action_pause_remaining_seconds": int(pause_remaining),
        "buy_action_pause_reason": meta.get("api_429_burst_buy_pause_reason", ""),
        "low_priority_read_cooldown_active_seconds": max(0, int(meta.get("api_low_priority_read_cooldown_until_ts", 0) or 0) - now),
        "top_window_429_paths": top_paths,
        "recent_events_sample": window_events[-10:],
        "blockers": blockers,
        "warnings": warnings,
        "policy": "pause new buys and cool low-priority reads during 429 bursts; sell-critical writes/reads remain prioritized",
    }
    meta["last_api_429_burst_circuit"] = {k: v for k, v in payload.items() if k not in {"recent_events_sample"}}
    return payload


def _api_429_burst_circuit_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m API 429 Burst Circuit",
        "=================================",
        f"Generated CT : {payload.get('snapshot_ct', '')}",
        f"Build ID     : {payload.get('build_id', '')}",
        f"Context      : {payload.get('context', '')}",
        f"Band         : {payload.get('band', '')}",
        f"Window       : {payload.get('window_seconds', '')}s read={payload.get('read_429_count_window', 0)}/{payload.get('max_read_429', '')} write={payload.get('write_429_count_window', 0)}/{payload.get('max_write_429', '')}",
        f"Buy pause    : {payload.get('buy_action_pause_active')} remaining={payload.get('buy_action_pause_remaining_seconds', 0)}s reason={payload.get('buy_action_pause_reason', '')}",
        f"Low-read cd  : {payload.get('low_priority_read_cooldown_active_seconds', 0)}s",
        "",
    ]
    if payload.get("blockers"):
        lines.append("Blockers:")
        lines.extend([f"- {x}" for x in payload.get("blockers", [])])
        lines.append("")
    if payload.get("warnings"):
        lines.append("Warnings:")
        lines.extend([f"- {x}" for x in payload.get("warnings", [])])
        lines.append("")
    if payload.get("top_window_429_paths"):
        lines.append("Top 429 paths in window:")
        for key, count in payload.get("top_window_429_paths", {}).items():
            lines.append(f"- {count}x {key}")
        lines.append("")
    lines.extend([
        "Recommendation:",
        "- If band is block_buys, reduce discovery/read pressure or raise Kalshi tier before adding more 1c inventory.",
    ])
    return "\n".join(lines) + "\n"


def write_api_429_burst_circuit_report(context: str = "cycle", force: bool = False, mutate: bool = False) -> dict:
    if not API_429_BURST_CIRCUIT_ENABLED and not force:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_api_429_burst_circuit_report_ts", 0) or 0) < 10:
        return meta.get("last_api_429_burst_circuit", {}) or {}
    payload = build_api_429_burst_circuit_payload(context=context, mutate=mutate)
    meta["last_api_429_burst_circuit_report_ts"] = now
    try:
        atomic_write_json(API_429_BURST_CIRCUIT_JSON_PATH, payload)
        os.makedirs(os.path.dirname(API_429_BURST_CIRCUIT_TXT_PATH) or ".", exist_ok=True)
        tmp = f"{API_429_BURST_CIRCUIT_TXT_PATH}.tmp"
        with open(tmp, "w", encoding="utf-8") as fh:
            fh.write(_api_429_burst_circuit_text(payload))
        atomic_replace_with_retry(tmp, API_429_BURST_CIRCUIT_TXT_PATH, context="api_429_burst_circuit_txt")
        append_csv_row(API_429_BURST_CIRCUIT_HISTORY_CSV_PATH, ["snapshot_ts", "snapshot_ct", "build_id", "context", "band", "read_429_count_window", "write_429_count_window", "total_429_count_window", "buy_action_pause_active", "buy_action_pause_remaining_seconds", "blockers", "warnings"], {
            "snapshot_ts": payload.get("snapshot_ts"),
            "snapshot_ct": payload.get("snapshot_ct"),
            "build_id": BUILD_ID,
            "context": context,
            "band": payload.get("band"),
            "read_429_count_window": payload.get("read_429_count_window"),
            "write_429_count_window": payload.get("write_429_count_window"),
            "total_429_count_window": payload.get("total_429_count_window"),
            "buy_action_pause_active": payload.get("buy_action_pause_active"),
            "buy_action_pause_remaining_seconds": payload.get("buy_action_pause_remaining_seconds"),
            "blockers": ";".join(payload.get("blockers", [])),
            "warnings": ";".join(payload.get("warnings", [])),
        })
    except Exception as e:
        try:
            LOGGER.debug("API 429 burst circuit report failed: %s", e)
        except Exception:
            pass
    return payload

def _dashboard_rows(payload: dict, *keys: str):
    if isinstance(payload, list):
        return [r for r in payload if isinstance(r, dict)]
    if isinstance(payload, dict):
        for key in keys:
            rows = payload.get(key)
            if isinstance(rows, list):
                return [r for r in rows if isinstance(r, dict)]
    return []


def _dashboard_band_counts(rows, key: str) -> dict:
    out = {}
    for row in rows or []:
        val = str((row or {}).get(key, "") or "unknown")
        out[val] = out.get(val, 0) + 1
    return dict(sorted(out.items(), key=lambda kv: (-kv[1], kv[0])))



ACTIVE_SELL_COVERAGE_AUTOPRUNER_FIELDS = [
    "snapshot_ts", "utc_day", "instance", "build_id", "context", "ticker", "side", "series_ticker",
    "state_status", "position_fp", "active_order_id", "active_remaining_fp", "queue_ahead_fp",
    "queue_band", "terminal", "terminal_age_seconds", "action", "reason",
]
QUEUE_POSITION_BACKFILL_FIELDS = [
    "snapshot_ts", "utc_day", "instance", "build_id", "context", "scope", "series_ticker", "side", "ct_hour",
    "rows", "covered_rows", "missing_rows", "undercovered_rows", "stalled_queue_rows", "clean_fill_rows",
    "fill_rate_pct", "avg_queue_ahead_fp", "max_queue_ahead_fp", "band", "level_cap", "reason",
]


def _active_sell_series_from_ticker(ticker: str, bucket: dict = None) -> str:
    if isinstance(bucket, dict) and bucket.get("series_ticker"):
        return str(bucket.get("series_ticker") or "")
    text = str(ticker or "").strip()
    if "-" in text:
        return text.split("-", 1)[0]
    return text[:24] or "unknown"


def _active_sell_ct_hour_from_ts(ts) -> str:
    try:
        ts_i = int(float(ts or 0))
        if ts_i <= 0:
            return "unknown"
        return central_time_iso_from_ts(ts_i)[11:13]
    except Exception:
        return "unknown"


def _active_sell_position_rows_from_state() -> list:
    rows = []
    now = now_ts()
    for key, bucket in STATE.setdefault("markets", {}).items():
        if not isinstance(bucket, dict) or str(key).endswith("|_meta") or str(key).startswith("series:"):
            continue
        ticker = str(bucket.get("ticker") or (str(key).split("|", 1)[0] if "|" in str(key) else "")).strip()
        side = str(bucket.get("side") or (str(key).split("|", 1)[1] if "|" in str(key) else "")).strip().lower()
        pos = parse_decimal(bucket.get("last_known_position_fp", "0"), "0")
        if not (ticker and side in {"yes", "no"} and abs(pos) > 0):
            continue
        seen_ts = 0
        for ts_key in ("last_known_position_ts", "last_ws_position_ts", "position_last_seen_ts", "post_fill_sell_sla_position_ts", "last_realized_fill_ts"):
            try:
                seen_ts = max(seen_ts, int(bucket.get(ts_key, 0) or 0))
            except Exception:
                pass
        # This helper is used only when a caller has no live REST position list
        # (primarily toolbox/offline reports).  A nonzero historical quantity
        # without a source timestamp is not current-inventory evidence and must
        # never be promoted into an active sell obligation indefinitely.
        if seen_ts <= 0:
            bucket["active_sell_state_position_stale_last_ts"] = now
            bucket["active_sell_state_position_stale_reason"] = "missing_position_source_timestamp"
            continue
        if now - seen_ts > ACTIVE_SELL_STATE_POSITION_MAX_AGE_SECONDS:
            bucket["active_sell_state_position_stale_last_ts"] = now
            bucket["active_sell_state_position_stale_age_seconds"] = now - seen_ts
            bucket["active_sell_state_position_stale_reason"] = "position_source_too_old"
            continue
        rows.append({"ticker": ticker, "position_fp": contracts_str(pos if side == "yes" else -abs(pos)), "_source": "state_last_known_position", "_state_position_seen_ts": seen_ts})
    return rows


def _active_sell_current_maps(positions=None, primary_by_key: dict = None):
    pos_rows = list(positions or []) if positions is not None else _active_sell_position_rows_from_state()
    active_keys = set()
    position_qty_by_key = {}
    for p in pos_rows:
        if not isinstance(p, dict):
            continue
        ticker = str(p.get("ticker") or "").strip()
        if not ticker:
            continue
        side = infer_side_from_position(ticker, p.get("position_fp", "0"))
        if side not in {"yes", "no"}:
            continue
        qty = abs(parse_decimal(p.get("position_fp", "0"), "0")).quantize(Decimal("0.00"))
        if qty <= 0:
            continue
        key = market_key(ticker, side)
        active_keys.add(key)
        position_qty_by_key[key] = qty
    primary = primary_by_key if isinstance(primary_by_key, dict) else {}
    active_order_ids = set()
    for order in primary.values():
        if isinstance(order, dict) and order.get("order_id"):
            active_order_ids.add(str(order.get("order_id")))
    return pos_rows, active_keys, position_qty_by_key, primary, active_order_ids


def _active_sell_backfill_queue_to_bucket(key: str, bucket: dict, active_order: dict, queue_positions_by_order: dict) -> Decimal:
    if not (isinstance(bucket, dict) and isinstance(active_order, dict) and active_order.get("order_id") and isinstance(queue_positions_by_order, dict)):
        return Decimal("0")
    qraw = queue_positions_by_order.get(active_order.get("order_id"))
    if qraw is None:
        return Decimal("0")
    q = normalize_queue_ahead_fp(qraw)
    bucket["sell_queue_backfill_last_ts"] = now_ts()
    bucket["sell_queue_backfill_order_id"] = str(active_order.get("order_id") or "")
    bucket["sell_queue_backfill_queue_ahead_fp"] = contracts_str(q)
    prior = parse_decimal(bucket.get("sell_queue_backfill_prev_queue_ahead_fp", bucket.get("sell_queue_backfill_queue_ahead_fp", "0")), "0")
    bucket["sell_queue_backfill_prev_queue_ahead_fp"] = bucket.get("sell_queue_backfill_queue_ahead_fp", contracts_str(q))
    if prior > 0 and q < prior:
        bucket["sell_queue_backfill_last_improvement_fp"] = contracts_str(prior - q)
    return q


def _queue_backfill_collect_history(export_dirs=None, support_zips=None) -> tuple:
    roots = []
    for root in (export_dirs or [EXPORT_DIR]):
        if root and os.path.isdir(root) and root not in roots:
            roots.append(root)
    temp_root = None
    extracted = []
    zip_paths = []
    rows_by_kind = {"sell_coverage": [], "sell_queue": [], "recovery_cycle": [], "sell_liveness": [], "fills": []}
    try:
        extras = []
        if QUEUE_POSITION_BACKFILL_SUPPORT_ZIPS:
            extras.append(QUEUE_POSITION_BACKFILL_SUPPORT_ZIPS)
        extras.extend(support_zips or [])
        zip_paths = _support_zip_candidates(extras)
        if zip_paths:
            temp_root = tempfile.mkdtemp(prefix="kalshi15m_queue_backfill_")
            for zp in zip_paths:
                try:
                    root = _extract_support_zip_to_temp(zp, temp_root)
                    extracted.append(root)
                    roots.append(root)
                except Exception as e:
                    LOGGER.debug("Queue backfill support bundle skipped | zip=%s | error=%s", zp, e)
        for root in roots:
            if not root or not os.path.isdir(root):
                continue
            for dirpath, _dirs, files in os.walk(root):
                for name in files:
                    low = name.lower()
                    if not low.endswith(".csv"):
                        continue
                    path = os.path.join(dirpath, name)
                    if "sell_coverage_audit" in low:
                        rows_by_kind["sell_coverage"].extend(_read_csv_rows_safe(path, 30000))
                    elif "sell_queue_exit_optimizer" in low:
                        rows_by_kind["sell_queue"].extend(_read_csv_rows_safe(path, 30000))
                    elif "recovery_cycle_audit" in low:
                        rows_by_kind["recovery_cycle"].extend(_read_csv_rows_safe(path, 30000))
                    elif "sell_liveness" in low:
                        rows_by_kind["sell_liveness"].extend(_read_csv_rows_safe(path, 30000))
                    elif "fill_ledger" in low:
                        rows_by_kind["fills"].extend(_read_csv_rows_safe(path, 30000))
        return rows_by_kind, {"roots": roots, "support_zips": zip_paths, "extracted_roots": extracted}
    finally:
        if temp_root:
            try:
                shutil.rmtree(temp_root, ignore_errors=True)
            except Exception:
                pass


def _queue_backfill_touch_group(groups: dict, scope: str, series: str, side: str, hour: str):
    key = f"{scope}|{series or 'unknown'}|{side or ''}|{hour or 'all'}"
    if key not in groups:
        groups[key] = {
            "scope": scope, "series_ticker": series or "unknown", "side": side or "", "ct_hour": hour or "all",
            "rows": 0, "covered_rows": 0, "missing_rows": 0, "undercovered_rows": 0, "stalled_queue_rows": 0,
            "clean_fill_rows": 0, "queue_sum": Decimal("0"), "queue_count": 0, "queue_max": Decimal("0"), "sample": [],
        }
    return groups[key]


def _queue_backfill_history_rows(rows_by_kind: dict) -> list:
    groups = {}
    def add(row, status_hint: str = ""):
        ticker = str(row.get("ticker") or row.get("market_ticker") or "").strip()
        if not ticker:
            return
        side = normalized_outcome_side(row)
        if side not in {"yes", "no"}:
            side = "unknown"
        series = str(row.get("series_ticker") or "").strip() or _active_sell_series_from_ticker(ticker)
        hour = _active_sell_ct_hour_from_ts(row.get("snapshot_ts") or row.get("processed_ts") or row.get("fill_ts"))
        status = str(status_hint or row.get("status") or row.get("cycle_status") or row.get("action") or "").lower()
        q = parse_decimal(row.get("queue_ahead_fp", row.get("queue_position_fp", "0")), "0")
        scopes = [("series", series, "all"), ("series_hour", series, hour)]
        for scope, ser, hr in scopes:
            g = _queue_backfill_touch_group(groups, scope, ser, side, hr)
            g["rows"] += 1
            if status in {"covered", "alive", "front_of_queue", "recovered_by_sell", "ok"} or "covered" in status or "recovered" in status:
                g["covered_rows"] += 1
            if "missing" in status or "no_active" in status:
                g["missing_rows"] += 1
            if "undercovered" in status or "gap" in status or "price_mismatch" in status:
                g["undercovered_rows"] += 1
            if q >= QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP or "stalled" in status or "long_queue" in status:
                g["stalled_queue_rows"] += 1
            if status in {"recovered_by_sell", "sell", "filled"} or "filled" in status or "recovered" in status:
                g["clean_fill_rows"] += 1
            if q > 0:
                g["queue_sum"] += q
                g["queue_count"] += 1
                if q > g["queue_max"]:
                    g["queue_max"] = q
            if len(g["sample"]) < 5:
                g["sample"].append(ticker)
    for row in rows_by_kind.get("sell_coverage", []) or []:
        add(row)
    for row in rows_by_kind.get("sell_queue", []) or []:
        add(row)
    for row in rows_by_kind.get("sell_liveness", []) or []:
        add(row)
    for row in rows_by_kind.get("recovery_cycle", []) or []:
        add(row)
    for row in rows_by_kind.get("fills", []) or []:
        if str(row.get("action", "")).lower() == "sell":
            add(row, "filled")
    out = []
    for g in groups.values():
        rows = int(g["rows"] or 0)
        if rows <= 0:
            continue
        clean = int(g["covered_rows"] or 0) + int(g["clean_fill_rows"] or 0)
        bad = int(g["missing_rows"] or 0) + int(g["undercovered_rows"] or 0) + int(g["stalled_queue_rows"] or 0)
        fill_rate = (Decimal(clean) / Decimal(rows) * Decimal("100")).quantize(Decimal("0.0001")) if rows else Decimal("0")
        avg_q = (g["queue_sum"] / Decimal(g["queue_count"])).quantize(Decimal("0.00")) if g["queue_count"] else Decimal("0.00")
        max_q = g["queue_max"]
        if rows < QUEUE_POSITION_BACKFILL_LEARNER_MIN_ROWS:
            band, cap, reason = "insufficient_evidence", "normal", f"rows_{rows}_below_{QUEUE_POSITION_BACKFILL_LEARNER_MIN_ROWS}"
        elif bad >= max(2, rows // 2) or max_q >= QUEUE_POSITION_BACKFILL_SEVERE_QUEUE_AHEAD_FP:
            band, cap, reason = "severe", "pilot", f"bad_or_deep_queue bad={bad} max_q={contracts_str(max_q)}"
        elif fill_rate >= QUEUE_POSITION_BACKFILL_STRONG_FILL_RATE_PCT and avg_q <= QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP:
            band, cap, reason = "strong", "aggressive", f"fill_rate={cents4_str(fill_rate)} avg_q={contracts_str(avg_q)}"
        elif fill_rate < QUEUE_POSITION_BACKFILL_WARN_FILL_RATE_PCT or avg_q >= QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP:
            band, cap, reason = "caution", "normal", f"fill_rate={cents4_str(fill_rate)} avg_q={contracts_str(avg_q)}"
        else:
            band, cap, reason = "neutral", "normal", f"fill_rate={cents4_str(fill_rate)} avg_q={contracts_str(avg_q)}"
        out.append({
            "snapshot_ts": now_ts(), "utc_day": utc_day_from_ts(now_ts()), "instance": INSTANCE_NAME, "build_id": BUILD_ID,
            "context": "history", "scope": g["scope"], "series_ticker": g["series_ticker"], "side": g["side"], "ct_hour": g["ct_hour"],
            "rows": rows, "covered_rows": int(g["covered_rows"]), "missing_rows": int(g["missing_rows"]),
            "undercovered_rows": int(g["undercovered_rows"]), "stalled_queue_rows": int(g["stalled_queue_rows"]),
            "clean_fill_rows": int(g["clean_fill_rows"]), "fill_rate_pct": cents4_str(fill_rate),
            "avg_queue_ahead_fp": contracts_str(avg_q), "max_queue_ahead_fp": contracts_str(max_q),
            "band": band, "level_cap": cap, "reason": reason,
        })
    out.sort(key=lambda r: (r.get("band") == "strong", parse_decimal(r.get("fill_rate_pct", "0"), "0"), -parse_decimal(r.get("max_queue_ahead_fp", "0"), "0")), reverse=True)
    return out


def write_queue_position_backfill_learner_report(positions=None, primary_by_key: dict = None, queue_positions_by_order: dict = None, context: str = "cycle", force: bool = False, export_dirs=None, support_zips=None) -> dict:
    if not QUEUE_POSITION_BACKFILL_LEARNER_ENABLED:
        return {"enabled": False, "row_count": 0}
    now = now_ts()
    meta = STATE.setdefault("meta", {})
    if not force and now - int(meta.get("last_queue_position_backfill_learner_report_ts", 0) or 0) < QUEUE_POSITION_BACKFILL_LEARNER_INTERVAL_SECONDS:
        return meta.get("last_queue_position_backfill_learner", {}) or {"enabled": True, "throttled": True, "row_count": 0}
    meta["last_queue_position_backfill_learner_report_ts"] = now
    rows_by_kind, collect_meta = _queue_backfill_collect_history(export_dirs=export_dirs, support_zips=support_zips)
    rows = _queue_backfill_history_rows(rows_by_kind)
    current_rows = []
    if primary_by_key is not None:
        _pos_rows, active_keys, pos_qty, primary, _ids = _active_sell_current_maps(positions, primary_by_key)
        for key in sorted(active_keys):
            bucket = STATE.setdefault("markets", {}).get(key, {})
            if not isinstance(bucket, dict):
                continue
            active = primary.get(key) if isinstance(primary, dict) else None
            ticker = key.split("|", 1)[0]
            side = key.split("|", 1)[1] if "|" in key else str(bucket.get("side", ""))
            q = _active_sell_backfill_queue_to_bucket(key, bucket, active, queue_positions_by_order or {}) if active else Decimal("0")
            rem = parse_decimal((active or {}).get("remaining_count_fp", (active or {}).get("remaining_count", "0")), "0") if isinstance(active, dict) else Decimal("0")
            band = "covered" if rem > 0 and q < QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP else ("deep_queue" if q >= QUEUE_POSITION_BACKFILL_SEVERE_QUEUE_AHEAD_FP else "watch")
            current_rows.append({
                "snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID,
                "context": context, "scope": "current_active_sell", "series_ticker": _active_sell_series_from_ticker(ticker, bucket),
                "side": side, "ct_hour": _active_sell_ct_hour_from_ts(now), "rows": 1,
                "covered_rows": 1 if rem > 0 else 0, "missing_rows": 0 if rem > 0 else 1,
                "undercovered_rows": 0, "stalled_queue_rows": 1 if q >= QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP else 0,
                "clean_fill_rows": 0, "fill_rate_pct": "", "avg_queue_ahead_fp": contracts_str(q), "max_queue_ahead_fp": contracts_str(q),
                "band": band, "level_cap": "pilot" if band == "deep_queue" else "normal", "reason": f"active_remaining={contracts_str(rem)} queue_ahead={contracts_str(q)}",
            })
    all_rows = current_rows + rows
    counts = {}
    for r in all_rows:
        counts[r.get("band", "unknown")] = counts.get(r.get("band", "unknown"), 0) + 1
    payload = {
        "snapshot_ts": now, "snapshot_ct": central_time_iso_from_ts(now), "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME, "build_id": BUILD_ID, "enabled": True, "context": context,
        "row_count": len(all_rows), "current_row_count": len(current_rows), "history_row_count": len(rows),
        "band_counts": counts, "source_counts": {k: len(v or []) for k, v in rows_by_kind.items()}, "collection": collect_meta,
        "settings": {
            "min_rows": QUEUE_POSITION_BACKFILL_LEARNER_MIN_ROWS,
            "warn_queue_ahead_fp": contracts_str(QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP),
            "severe_queue_ahead_fp": contracts_str(QUEUE_POSITION_BACKFILL_SEVERE_QUEUE_AHEAD_FP),
            "strong_fill_rate_pct": cents4_str(QUEUE_POSITION_BACKFILL_STRONG_FILL_RATE_PCT),
            "warn_fill_rate_pct": cents4_str(QUEUE_POSITION_BACKFILL_WARN_FILL_RATE_PCT),
        },
        "rows": all_rows[:500],
    }
    try:
        atomic_write_json(QUEUE_POSITION_BACKFILL_JSON_PATH, payload)
        atomic_write_csv(QUEUE_POSITION_BACKFILL_CSV_PATH, QUEUE_POSITION_BACKFILL_FIELDS, all_rows[:1000] or [{k: "" for k in QUEUE_POSITION_BACKFILL_FIELDS}])
        for row in current_rows:
            append_csv_row(QUEUE_POSITION_BACKFILL_HISTORY_CSV_PATH, QUEUE_POSITION_BACKFILL_FIELDS, row)
        lines = [
            "Kalshi 15m 2c Sell Bot - Queue-Position Backfill Learner",
            "========================================================",
            f"Generated CT : {payload['snapshot_ct']}",
            f"Build ID     : {BUILD_ID}",
            f"Context      : {context}",
            f"Rows         : {payload['row_count']} current={payload['current_row_count']} history={payload['history_row_count']}",
            f"Bands        : {payload['band_counts']}",
            "Policy       : backfill active sell queue position and learn which series/hour pockets fill 2c exits quickly enough for sizing.",
            "",
            "Top rows:",
        ]
        for row in all_rows[:40]:
            lines.append(f"- {row.get('scope')} {row.get('series_ticker')}|{row.get('side')} h={row.get('ct_hour')} band={row.get('band')} cap={row.get('level_cap')} rows={row.get('rows')} q_avg={row.get('avg_queue_ahead_fp')} reason={row.get('reason')}")
        os.makedirs(os.path.dirname(QUEUE_POSITION_BACKFILL_TXT_PATH) or ".", exist_ok=True)
        with open(QUEUE_POSITION_BACKFILL_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception as e:
        LOGGER.debug("Queue-position backfill report failed: %s", e)
    meta["last_queue_position_backfill_learner"] = {k: v for k, v in payload.items() if k != "rows"}
    return payload


def write_active_sell_coverage_autopruner_report(positions=None, primary_by_key: dict = None, queue_positions_by_order: dict = None, context: str = "cycle", force: bool = False, mutate: bool = False) -> dict:
    if not ACTIVE_SELL_COVERAGE_AUTOPRUNER_ENABLED:
        return {"enabled": False, "pruned_terminal_count": 0, "current_uncovered_count": 0}
    now = now_ts()
    meta = STATE.setdefault("meta", {})
    if not force and now - int(meta.get("last_active_sell_coverage_autopruner_report_ts", 0) or 0) < ACTIVE_SELL_COVERAGE_AUTOPRUNER_INTERVAL_SECONDS:
        return meta.get("last_active_sell_coverage_autopruner", {}) or {"enabled": True, "throttled": True, "pruned_terminal_count": 0, "current_uncovered_count": 0}
    meta["last_active_sell_coverage_autopruner_report_ts"] = now
    pos_rows, active_keys, position_qty_by_key, primary, active_order_ids = _active_sell_current_maps(positions, primary_by_key)
    rows = []
    prune_keys = []
    clear_keys = []
    current_uncovered = 0
    deep_queue_current = 0
    markets = STATE.setdefault("markets", {})
    for key, bucket in list(markets.items()):
        if not isinstance(bucket, dict) or str(key).endswith("|_meta") or str(key).startswith("series:"):
            continue
        ticker = str(bucket.get("ticker") or (str(key).split("|", 1)[0] if "|" in str(key) else "")).strip()
        side = str(bucket.get("side") or (str(key).split("|", 1)[1] if "|" in str(key) else "")).strip().lower()
        if not ticker or side not in {"yes", "no"}:
            continue
        active = primary.get(key) if isinstance(primary, dict) else None
        active_order_id = str((active or {}).get("order_id") or bucket.get("active_order_id") or "")
        has_active_order = bool(active_order_id and (active_order_id in active_order_ids or isinstance(active, dict)))
        active_remaining = parse_decimal((active or {}).get("remaining_count_fp", (active or {}).get("remaining_count", "0")), "0") if isinstance(active, dict) else Decimal("0")
        position_qty = position_qty_by_key.get(key, abs(parse_decimal(bucket.get("last_known_position_fp", "0"), "0"))).quantize(Decimal("0.00"))
        has_active_pos = key in active_keys and position_qty > 0
        terminal = bool(bucket.get("market_terminal") or str(bucket.get("status", "")).lower() in {"closed", "settled", "finalized", "determined"})
        terminal_ts = int(bucket.get("terminal_ts", bucket.get("last_terminal_ts", 0)) or 0)
        terminal_age = max(0, now - terminal_ts) if terminal_ts else 0
        q = Decimal("0")
        if isinstance(active, dict) and active.get("order_id"):
            q = _active_sell_backfill_queue_to_bucket(key, bucket, active, queue_positions_by_order or {})
        q_band = "front" if active_remaining > 0 and q <= 0 else ("deep" if q >= QUEUE_POSITION_BACKFILL_SEVERE_QUEUE_AHEAD_FP else ("warn" if q >= QUEUE_POSITION_BACKFILL_WARN_QUEUE_AHEAD_FP else "unknown"))
        action = "keep"
        reason = "active_or_recent"
        if has_active_pos and (not has_active_order or active_remaining <= 0) and not terminal:
            current_uncovered += 1
            action = "protective_sell_repair_needed"
            reason = "live_position_without_active_2c_sell"
        elif has_active_pos and q >= QUEUE_POSITION_BACKFILL_SEVERE_QUEUE_AHEAD_FP:
            deep_queue_current += 1
            action = "queue_backfill_warn"
            reason = f"deep_queue_{contracts_str(q)}"
        elif (not has_active_pos) and (not has_active_order) and terminal and terminal_age >= ACTIVE_SELL_COVERAGE_AUTOPRUNER_MIN_TERMINAL_AGE_SECONDS:
            action = "prune_terminal_state" if ACTIVE_SELL_COVERAGE_AUTOPRUNER_REMOVE_TERMINAL else "would_prune_terminal_state"
            reason = f"terminal_no_position_no_order_age_{terminal_age}s"
            prune_keys.append(key)
        elif (not has_active_pos) and (not has_active_order) and any(k in bucket for k in ("sell_watchdog_missing_since_ts", "startup_to_sell_autorepair_buy_pause_until_ts", "residual_sell_tuner_buy_pause_until_ts")):
            action = "clear_stale_sell_flags" if ACTIVE_SELL_COVERAGE_AUTOPRUNER_CLEAR_STALE_FLAGS else "would_clear_stale_sell_flags"
            reason = "no_position_no_order_with_stale_sell_pause_flags"
            clear_keys.append(key)
        rows.append({
            "snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID,
            "context": context, "ticker": ticker, "side": side, "series_ticker": _active_sell_series_from_ticker(ticker, bucket),
            "state_status": str(bucket.get("status", "")), "position_fp": contracts_str(position_qty),
            "active_order_id": active_order_id, "active_remaining_fp": contracts_str(active_remaining), "queue_ahead_fp": contracts_str(q) if q else "",
            "queue_band": q_band, "terminal": bool(terminal), "terminal_age_seconds": terminal_age, "action": action, "reason": reason,
        })
    actual_pruned = 0
    actual_cleared = 0
    if mutate and ACTIVE_SELL_COVERAGE_AUTOPRUNER_MUTATE_STATE:
        archive = STATE.setdefault("meta", {}).setdefault("active_sell_coverage_autoprune_archive", [])
        if not isinstance(archive, list):
            archive = []
            STATE.setdefault("meta", {})["active_sell_coverage_autoprune_archive"] = archive
        for key in prune_keys:
            bucket = markets.get(key)
            if not isinstance(bucket, dict):
                continue
            archive.append({"ts": now, "key": key, "ticker": bucket.get("ticker", ""), "side": bucket.get("side", ""), "reason": "terminal_no_position_no_order"})
            markets.pop(key, None)
            actual_pruned += 1
        if len(archive) > 100:
            del archive[:-100]
        for key in clear_keys:
            bucket = markets.get(key)
            if not isinstance(bucket, dict):
                continue
            for flag in ("sell_watchdog_missing_since_ts", "sell_watchdog_last_trigger_ts", "startup_to_sell_autorepair_buy_pause_until_ts", "residual_sell_tuner_buy_pause_until_ts"):
                bucket.pop(flag, None)
            actual_cleared += 1
    pause_active = False
    if ACTIVE_SELL_COVERAGE_AUTOPRUNER_BLOCK_BUY_ACTION and (current_uncovered > 0 or deep_queue_current > 0):
        pause_active = True
        STATE.setdefault("meta", {})["active_sell_coverage_buy_pause_until_ts"] = max(int(STATE.setdefault("meta", {}).get("active_sell_coverage_buy_pause_until_ts", 0) or 0), now + ACTIVE_SELL_COVERAGE_AUTOPRUNER_BUY_PAUSE_SECONDS)
        STATE.setdefault("meta", {})["active_sell_coverage_buy_pause_reason"] = f"uncovered={current_uncovered};deep_queue={deep_queue_current}"
    remaining_pause = max(0, int(STATE.setdefault("meta", {}).get("active_sell_coverage_buy_pause_until_ts", 0) or 0) - now)
    action_counts = {}
    for r in rows:
        action_counts[r.get("action", "unknown")] = action_counts.get(r.get("action", "unknown"), 0) + 1
    payload = {
        "snapshot_ts": now, "snapshot_ct": central_time_iso_from_ts(now), "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME, "build_id": BUILD_ID, "enabled": True, "context": context,
        "mutate_requested": bool(mutate), "mutate_state_enabled": bool(ACTIVE_SELL_COVERAGE_AUTOPRUNER_MUTATE_STATE),
        "active_position_count": len(active_keys), "current_uncovered_count": int(current_uncovered), "deep_queue_current_count": int(deep_queue_current),
        "prune_candidate_count": len(prune_keys), "pruned_terminal_count": int(actual_pruned),
        "clear_flag_candidate_count": len(clear_keys), "cleared_stale_flag_count": int(actual_cleared),
        "buy_action_pause_active": bool(pause_active or remaining_pause > 0), "buy_action_pause_remaining_seconds": int(remaining_pause),
        "buy_action_pause_reason": STATE.setdefault("meta", {}).get("active_sell_coverage_buy_pause_reason", ""),
        "action_counts": action_counts,
        "policy": "prune only terminal/no-position/no-order state; backfill queue for active sells; pause only new buys when live sell coverage is unsafe",
        "rows": rows[:500],
    }
    try:
        atomic_write_json(ACTIVE_SELL_COVERAGE_AUTOPRUNER_JSON_PATH, payload)
        atomic_write_csv(ACTIVE_SELL_COVERAGE_AUTOPRUNER_CSV_PATH, ACTIVE_SELL_COVERAGE_AUTOPRUNER_FIELDS, rows[:1000] or [{k: "" for k in ACTIVE_SELL_COVERAGE_AUTOPRUNER_FIELDS}])
        append_csv_row(ACTIVE_SELL_COVERAGE_AUTOPRUNER_HISTORY_CSV_PATH, [
            "snapshot_ts", "utc_day", "instance", "build_id", "context", "active_position_count", "current_uncovered_count", "deep_queue_current_count", "prune_candidate_count", "pruned_terminal_count", "clear_flag_candidate_count", "cleared_stale_flag_count", "buy_action_pause_active", "buy_action_pause_remaining_seconds"
        ], {
            "snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID, "context": context,
            "active_position_count": len(active_keys), "current_uncovered_count": current_uncovered, "deep_queue_current_count": deep_queue_current,
            "prune_candidate_count": len(prune_keys), "pruned_terminal_count": actual_pruned, "clear_flag_candidate_count": len(clear_keys), "cleared_stale_flag_count": actual_cleared,
            "buy_action_pause_active": bool(pause_active or remaining_pause > 0), "buy_action_pause_remaining_seconds": remaining_pause,
        })
        lines = [
            "Kalshi 15m 2c Sell Bot - Active Sell Coverage Autopruner",
            "========================================================",
            f"Generated CT : {payload['snapshot_ct']}",
            f"Build ID     : {BUILD_ID}",
            f"Context      : {context}",
            f"Active pos   : {payload['active_position_count']}",
            f"Uncovered    : {payload['current_uncovered_count']}",
            f"Deep queue   : {payload['deep_queue_current_count']}",
            f"Pruned       : {payload['pruned_terminal_count']} / candidates {payload['prune_candidate_count']}",
            f"Flags cleared: {payload['cleared_stale_flag_count']} / candidates {payload['clear_flag_candidate_count']}",
            f"Buy pause    : {payload['buy_action_pause_active']} remaining={payload['buy_action_pause_remaining_seconds']}s reason={payload.get('buy_action_pause_reason','')}",
            "",
            "Rows:",
        ]
        for row in rows[:60]:
            lines.append(f"- {row.get('ticker')}|{row.get('side')} pos={row.get('position_fp')} rem={row.get('active_remaining_fp')} q={row.get('queue_ahead_fp')} action={row.get('action')} reason={row.get('reason')}")
        os.makedirs(os.path.dirname(ACTIVE_SELL_COVERAGE_AUTOPRUNER_TXT_PATH) or ".", exist_ok=True)
        with open(ACTIVE_SELL_COVERAGE_AUTOPRUNER_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception as e:
        LOGGER.debug("Active Sell Coverage Autopruner report failed: %s", e)
    meta["last_active_sell_coverage_autopruner"] = {k: v for k, v in payload.items() if k != "rows"}
    return payload


def _active_position_qty_from_state() -> Decimal:
    total = Decimal("0")
    for key, bucket in STATE.setdefault("markets", {}).items():
        if not isinstance(bucket, dict) or str(key).endswith("|_meta"):
            continue
        ticker = str(key).split("|", 1)[0]
        if bucket.get("market_terminal") or str(bucket.get("status", "")).lower() in {"closed", "settled", "finalized", "determined"}:
            continue
        if _state_bucket_position_is_time_expired(ticker, bucket, grace_seconds=21600, ignore_order_hints=True):
            continue
        total += abs(parse_decimal(bucket.get("last_known_position_fp", "0"), "0"))
    return total.quantize(Decimal("0.00"), rounding=ROUND_FLOOR)


