    if not LIVE_PROFIT_DASHBOARD_ENABLED:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_live_profit_dashboard_ts", 0) or 0) < max(30, LIVE_PROFIT_DASHBOARD_INTERVAL_SECONDS):
        return meta.get("last_live_profit_safety_dashboard", {}) or {}
    payload = build_live_profit_safety_dashboard_payload()
    meta["last_live_profit_dashboard_ts"] = now
    meta["last_live_profit_safety_dashboard"] = payload
    atomic_write_json(LIVE_PROFIT_DASHBOARD_LATEST_JSON_PATH, payload)
    write_market_metadata_guard_snapshot(context="live_dashboard")
