SELL_PLACEMENT_AUDIT_ROWS = deque(maxlen=max(1, SELL_PLACEMENT_AUDIT_MAX_ROWS))
SELL_PLACEMENT_AUDIT_FIELDS = [
    "snapshot_ts", "utc_day", "instance", "build_id", "status", "context", "api_version",
    "ticker", "side", "qty_fp", "exit_price_dollars", "tif", "post_only", "reduce_only_sent",
    "book_side", "book_price", "display_route",
    "client_order_id", "order_id", "error_bucket", "error", "note",
]


def sell_route_visibility_hint(side: str, api_version: str, body: dict = None, exit_price=None) -> str:
    body = body if isinstance(body, dict) else {}
    api = str(api_version or "").lower()
    contract_side = str(side or body.get("contract_side") or "").lower()
    book_side = str(body.get("side") or "").lower()
    book_price = str(body.get("price") or "")
    economic_price = price_str(parse_decimal(exit_price if exit_price is not None else SELL_PRICE, str(SELL_PRICE)))
    if api == "v2":
        if contract_side == "yes" and book_side == "ask":
            return f"visible YES-side sell: V2 ask @{book_price or economic_price} = contract-side YES exit @{economic_price}"
        if contract_side == "no" and book_side == "bid":
            return f"economic NO-side sell: V2 YES-book bid @{book_price or '0.9800'} = contract-side NO exit @{economic_price}; UI/orderbook may label this as a bid/buy rather than a sell"
        if contract_side == "no":
            return f"NO-side exit requested via V2; expected YES-book bid near {price_str(Decimal('1') - parse_decimal(economic_price, '0.02'))}"
    if api == "legacy":
        return f"legacy visible contract-side sell route: {contract_side or 'unknown'} @{economic_price}"
    return "route unavailable"


def sell_placement_error_bucket(error) -> str:
    text = str(error or "").lower()
    if not text:
        return ""
    if reduce_only_rejected_error(text):
        return "v2_reduce_only_rejected"
    if "market_not_found" in text or "market not found" in text or "not_found" in text:
        return "market_not_found"
    if "market terminal" in text or "closed" in text or "settled" in text or "determined" in text:
        return "market_terminal"
    if "user data stale" in text:
        return "user_data_stale"
    if "exchange/trading inactive" in text or "maintenance" in text or "announcement" in text:
        return "exchange_write_guard"
    if "feeguard" in text or "fee guard" in text:
        return "fee_guard"
    if "ssl" in text or "transport" in text or "connection" in text:
        return "transport"
    if "post_only" in text or "post only" in text or "post-only" in text:
        return "post_only_rejected"
    if "invalid_order" in text or "invalid order" in text:
        return "invalid_order"
    if "429" in text or "rate" in text:
        return "rate_limit"
    # Normalize Python-dict-looking exchange errors like "{'code': '...'}".
    if "'code'" in text or '"code"' in text:
        if "insufficient" in text:
            return "insufficient_balance"
        if "not_found" in text:
            return "market_not_found"
        return "exchange_error"
    first = text.split(" ", 1)[0].strip("{}[](),'").strip('\"')
    return (first or "unknown")[:80]


def record_sell_placement_event(status: str, ticker: str, side: str, qty, tif: str, post_only: bool, exit_price=None, api_version: str = "", context: str = "", body: dict = None, order: dict = None, error=None, note: str = "") -> None:
    if not SELL_PLACEMENT_AUDIT_ENABLED:
        return
    body = body if isinstance(body, dict) else {}
    order = order if isinstance(order, dict) else {}
    row = {
        "snapshot_ts": now_ts(),
        "utc_day": utc_day_from_ts(now_ts()),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "status": str(status or ""),
        "context": str(context or ""),
        "api_version": str(api_version or order.get("_api_version") or ""),
        "ticker": str(ticker or order.get("ticker") or body.get("ticker") or ""),
        "side": str(side or order.get("side") or ""),
        "qty_fp": qty_str(parse_decimal(qty if qty is not None else body.get("count", order.get("remaining_count_fp", order.get("remaining_count", "0"))), "0")),
        "exit_price_dollars": price_str(parse_decimal(exit_price if exit_price is not None else order.get("exit_price_dollars", SELL_PRICE), str(SELL_PRICE))),
        "tif": str(tif or body.get("time_in_force") or ""),
        "post_only": "1" if bool(post_only or body.get("post_only")) else "0",
        "reduce_only_sent": "1" if bool(body.get("reduce_only")) else "0",
        "book_side": str(body.get("side") or ""),
        "book_price": str(body.get("price") or ""),
        "display_route": sell_route_visibility_hint(side or order.get("side"), api_version or order.get("_api_version") or "", body, exit_price),
        "client_order_id": str(body.get("client_order_id") or order.get("client_order_id") or ""),
        "order_id": str(order.get("order_id") or ""),
        "error_bucket": sell_placement_error_bucket(error),
        "error": str(error or "")[:500],
        "note": str(note or "")[:500],
    }
    if str(status or "").lower() == "success" and row.get("ticker") and row.get("side"):
        try:
            note_post_fill_sell_placed(row.get("ticker"), row.get("side"), order_id=row.get("order_id"), qty=row.get("qty_fp"), context=context)
        except Exception:
            pass
    if row.get("error_bucket") == "market_not_found" and row.get("ticker"):
        try:
            mark_market_terminal(row.get("ticker"), "order-market-not-found")
        except Exception:
            pass
    try:
        SELL_PLACEMENT_AUDIT_ROWS.append(row)
        append_csv_row(SELL_PLACEMENT_AUDIT_HISTORY_CSV_PATH, SELL_PLACEMENT_AUDIT_FIELDS, row)
        rows = list(SELL_PLACEMENT_AUDIT_ROWS)[-SELL_PLACEMENT_AUDIT_MAX_ROWS:]
        atomic_write_csv(SELL_PLACEMENT_AUDIT_LATEST_CSV_PATH, SELL_PLACEMENT_AUDIT_FIELDS, rows)
        counts = {}
        for r in rows:
            key = r.get("error_bucket") or r.get("status") or "unknown"
            counts[key] = counts.get(key, 0) + 1
        atomic_write_json(SELL_PLACEMENT_AUDIT_LATEST_JSON_PATH, {
            "snapshot_ts": now_ts(),
            "utc_day": utc_day_from_ts(now_ts()),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "row_count": len(rows),
            "reason_counts": counts,
            "settings": {
                "order_api_version": ORDER_API_VERSION,
                "v2_reduce_only_mode": V2_REDUCE_ONLY_MODE,
                "v2_retry_without_reduce_only": V2_RETRY_WITHOUT_REDUCE_ONLY,
                "strict_2c_price": price_str(TARGET_2C_PRICE),
                "route_visibility_hints_enabled": bool(SELL_ROUTE_VISIBILITY_HINTS_ENABLED),
                "v2_yes_exit_display": "contract-side YES sell => V2 ask @ 0.0200",
                "v2_no_exit_display": "contract-side NO sell => V2 YES-book bid @ 0.9800",
            },
            "rows": rows,
        })
    except Exception as audit_error:
        LOGGER.debug("Could not write sell placement audit: %s", audit_error)


