def record_sell_coverage_event(ticker: str, side: str, position_qty=None, target_total=None, desired_remaining=None, active_order=None, bucket: dict = None, queue_positions_by_order: dict = None, exit_price=None, context: str = "cycle", note: str = "") -> None:
    if not SELL_COVERAGE_AUDIT_ENABLED:
        return
    bucket = bucket if isinstance(bucket, dict) else {}
    active_order = active_order if isinstance(active_order, dict) else None
    position = parse_decimal(position_qty if position_qty is not None else bucket.get("last_known_position_fp", "0.00"), "0")
    target = parse_decimal(target_total if target_total is not None else "0", "0")
    desired = parse_decimal(desired_remaining if desired_remaining is not None else "0", "0")
    active_remaining = parse_decimal(active_order.get("remaining_count_fp", active_order.get("remaining_count", "0.00")), "0") if active_order else Decimal("0")
    gap = max_decimal(Decimal("0"), desired - active_remaining).quantize(Decimal("0.00"))
    coverage = Decimal("100") if desired <= 0 else min(Decimal("9999"), (active_remaining / desired * Decimal("100"))).quantize(Decimal("0.0001"))
    active_price = order_exit_price(active_order, side) if active_order else Decimal("0")
    target_price = parse_decimal(exit_price if exit_price is not None else SELL_PRICE, str(SELL_PRICE))
    qraw = None
    if active_order and queue_positions_by_order:
        qraw = queue_positions_by_order.get(active_order.get("order_id"))
    queue_ahead = normalize_queue_ahead_fp(qraw) if qraw is not None else None
    if desired <= 0:
        status = "no_target"
    elif active_order and gap <= 0 and price_str(active_price) == price_str(target_price):
        status = "covered"
    elif active_order and gap > 0:
        status = "undercovered"
    elif not active_order:
        status = "missing_order"
    else:
        status = "price_mismatch"
    row = {
        "snapshot_ts": now_ts(),
        "utc_day": utc_day_from_ts(now_ts()),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": str(context or ""),
        "ticker": str(ticker or ""),
        "side": str(side or ""),
        "position_fp": qty_str(position),
        "target_total_fp": qty_str(target),
        "desired_remaining_fp": qty_str(desired),
        "active_remaining_fp": qty_str(active_remaining),
        "gap_fp": qty_str(gap),
        "coverage_pct": cents4_str(coverage),
        "active_order_id": str(active_order.get("order_id") if active_order else ""),
        "active_price_dollars": price_str(active_price) if active_order else "",
        "target_price_dollars": price_str(target_price),
        "queue_ahead_fp": contracts_str(queue_ahead) if queue_ahead is not None else "",
        "queue_gap_age_seconds": str(int(bucket.get("queue_gap_age_seconds", 0) or 0)),
        "status": status,
        "note": str(note or "")[:500],
    }
    try:
        SELL_COVERAGE_AUDIT_ROWS.append(row)
        append_csv_row(SELL_COVERAGE_AUDIT_HISTORY_CSV_PATH, SELL_COVERAGE_AUDIT_FIELDS, row)
        rows = list(SELL_COVERAGE_AUDIT_ROWS)[-SELL_COVERAGE_AUDIT_MAX_ROWS:]
        atomic_write_csv(SELL_COVERAGE_AUDIT_LATEST_CSV_PATH, SELL_COVERAGE_AUDIT_FIELDS, rows)
        latest_by_key = {}
        for r in rows:
            latest_by_key[f"{r.get('ticker','')}|{r.get('side','')}"] = r
        current_rows = []
        for r in latest_by_key.values():
            ticker_r = str(r.get("ticker", ""))
            side_r = str(r.get("side", ""))
            b = STATE.setdefault("markets", {}).get(f"{ticker_r}|{side_r}", {})
            if isinstance(b, dict):
                if b.get("market_terminal") or str(b.get("status", "")).lower() in {"closed", "settled", "finalized", "determined"}:
                    continue
                live_pos = abs(parse_decimal(b.get("last_known_position_fp", r.get("position_fp", "0")), "0"))
            else:
                live_pos = abs(parse_decimal(r.get("position_fp", "0"), "0"))
            desired_r = parse_decimal(r.get("desired_remaining_fp", "0"), "0")
            active_r = parse_decimal(r.get("active_remaining_fp", "0"), "0")
            if live_pos <= 0 and desired_r <= 0 and active_r <= 0:
                continue
            rr = dict(r)
            rr["current_live_position_fp"] = qty_str(live_pos)
            current_rows.append(rr)
        counts = {}
        undercovered = []
        for r in current_rows:
            key = r.get("status") or "unknown"
            counts[key] = counts.get(key, 0) + 1
            if key in {"undercovered", "missing_order", "price_mismatch"}:
                undercovered.append(r)
        payload = {
            "snapshot_ts": now_ts(),
            "utc_day": utc_day_from_ts(now_ts()),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "row_count": len(current_rows),
            "historical_row_count": len(rows),
            "status_counts": counts,
            "settings": {
                "target_fraction": str(target_fraction()),
                "sell_price": price_str(SELL_PRICE),
                "strict_2c": bool(TARGET_2C_ASSURANCE_ENABLED and TARGET_2C_STRICT_SELL_PRICE),
                "preserve_queue_on_increase": bool(PRESERVE_QUEUE_ON_INCREASE),
                "queue_gap_repair_enabled": bool(QUEUE_GAP_REPAIR_ENABLED),
                "queue_gap_repair_after_seconds": QUEUE_GAP_REPAIR_AFTER_SECONDS,
                "queue_gap_repair_min_gap_fp": qty_str(QUEUE_GAP_REPAIR_MIN_GAP_FP),
                "queue_gap_repair_min_coverage_pct": cents4_str(QUEUE_GAP_REPAIR_MIN_COVERAGE_PCT),
            },
            "undercovered_rows": undercovered[-50:],
            "current_rows": current_rows,
            "rows": rows,
        }
        STATE.setdefault("meta", {})["last_sell_coverage_audit"] = payload
        atomic_write_json(SELL_COVERAGE_AUDIT_LATEST_JSON_PATH, payload)
    except Exception as audit_error:
        LOGGER.debug("Could not write sell coverage audit: %s", audit_error)


def queue_gap_repair_due(bucket: dict, desired_remaining: Decimal, current_remaining: Decimal) -> tuple:
    """Return (repair_due, gap_age, coverage_pct, reason) for an undercovered resting sell."""
    bucket = bucket if isinstance(bucket, dict) else {}
    desired = parse_decimal(desired_remaining, "0")
    current = parse_decimal(current_remaining, "0")
    gap = max_decimal(Decimal("0"), desired - current).quantize(Decimal("0.00"))
    if desired <= 0 or gap <= 0:
        bucket.pop("queue_gap_since_ts", None)
        bucket["queue_gap_age_seconds"] = 0
        return False, 0, Decimal("100"), "covered"
    coverage = Decimal("0") if desired <= 0 else (current / desired * Decimal("100")).quantize(Decimal("0.0001"))
    if not QUEUE_GAP_REPAIR_ENABLED:
        return False, 0, coverage, "repair_disabled"
    if gap < QUEUE_GAP_REPAIR_MIN_GAP_FP:
        return False, 0, coverage, "gap_below_min"
    now = now_ts()
    since = int(bucket.get("queue_gap_since_ts", 0) or 0)
    if not since:
        bucket["queue_gap_since_ts"] = now
        bucket["queue_gap_age_seconds"] = 0
        return False, 0, coverage, "gap_timer_started"
    age = max(0, now - since)
    bucket["queue_gap_age_seconds"] = age
    if coverage < QUEUE_GAP_REPAIR_MIN_COVERAGE_PCT:
        if age >= QUEUE_GAP_REPAIR_AFTER_SECONDS:
            return True, age, coverage, "coverage_below_threshold_due"
        return False, age, coverage, "coverage_below_threshold_wait"
    if age >= QUEUE_GAP_REPAIR_AFTER_SECONDS:
        return True, age, coverage, "gap_age_due"
    return False, age, coverage, "preserve_queue_wait"



