def market_discovery_rejection_diagnostic(market: dict, side: str, row: dict = None, reason: str = "") -> dict:
    """Create a compact diagnostic row explaining why discovery did not export a candidate."""
    market = market or {}
    row = row or {}
    ticker = str(market.get("ticker") or row.get("ticker") or "")
    event_ticker = str(market.get("event_ticker") or row.get("event_ticker") or "")
    series = str(market.get("series_ticker") or row.get("series_ticker") or "")
    status = normalize_market_status(market.get("status") or row.get("market_status") or "")
    close_ts = normalize_epoch_seconds(market.get("close_time") or market.get("expected_expiration_time") or market.get("expiration_time"))
    seconds_to_close = close_ts - now_ts() if close_ts else ""
    ask = discovery_side_ask_price(market, side) if market else api_price_to_dollars(row.get("buy_price_dollars", "0"), "0")
    ask_size = discovery_side_ask_size(market, side) if market else parse_decimal(row.get("ask_size_fp", "0"), "0")
    volume_24h = parse_decimal(market.get("volume_24h_fp", market.get("volume_fp", row.get("volume_24h_fp", "0"))), "0")
    open_interest = parse_decimal(market.get("open_interest_fp", row.get("open_interest_fp", "0")), "0")
    if not reason:
        if not ticker:
            reason = "missing_ticker"
        elif status and not market_is_open_status(status):
            reason = f"status_{status}"
        elif isinstance(seconds_to_close, int) and seconds_to_close < MARKET_DISCOVERY_MIN_SECONDS_TO_CLOSE:
            reason = f"too_close_{seconds_to_close}s"
        elif ask <= 0:
            reason = "no_ask_or_equivalent_bid"
        elif ask > MARKET_DISCOVERY_MAX_BUY_PRICE:
            reason = f"ask_above_max_{price_str(ask)}"
        elif ask_size > 0 and ask_size < MARKET_DISCOVERY_MIN_ASK_SIZE_FP:
            reason = f"ask_size_below_min_{qty_str(ask_size)}"
        elif volume_24h < MARKET_DISCOVERY_MIN_VOLUME_24H_FP:
            reason = f"volume_below_min_{qty_str(volume_24h)}"
        elif open_interest < MARKET_DISCOVERY_MIN_OPEN_INTEREST_FP:
            reason = f"open_interest_below_min_{qty_str(open_interest)}"
        else:
            reason = "not_exported"
    return {
        "snapshot_ts": now_ts(),
        "utc_day": utc_day_from_ts(now_ts()),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "ticker": ticker,
        "event_ticker": event_ticker,
        "series_ticker": series,
        "side": str(side or ""),
        "status": status,
        "seconds_to_close": seconds_to_close,
        "buy_price_dollars": price_str(ask) if ask else "",
        "ask_size_fp": qty_str(ask_size) if ask_size else "0.00",
        "volume_24h_fp": qty_str(volume_24h),
        "open_interest_fp": qty_str(open_interest),
        "market_discovery_score": row.get("market_discovery_score", ""),
        "fee_safe_ok": row.get("fee_safe_ok", ""),
        "edge_band": row.get("edge_band", ""),
        "edge_pass": row.get("edge_pass", ""),
        "edge_proof_pass": row.get("edge_proof_pass", ""),
        "edge_proof_required_qty_fp": row.get("edge_proof_required_qty_fp", ""),
        "edge_proof_reason": row.get("edge_proof_reason", ""),
        "exit_readiness_score": row.get("exit_readiness_score", ""),
        "exit_readiness_band": row.get("exit_readiness_band", ""),
        "exit_readiness_pass": row.get("exit_readiness_pass", ""),
        "exit_readiness_reason": row.get("exit_readiness_reason", ""),
        "discovery_window_minutes": market.get("_discovery_window_minutes", row.get("discovery_window_minutes", "")),
        "reason": str(reason)[:240],
    }


def canonical_discovery_rejection_reason(reason: str) -> str:
    r = str(reason or "unknown").strip().lower()
    if not r:
        return "unknown"
    if r.startswith("scan_failed") or "ssl" in r or "connection" in r or "timeout" in r:
        return "scan_failed"
    if r.startswith("ask_above_max"):
        return "ask_above_max"
    if r.startswith("no_ask") or r.startswith("missing_price") or r.startswith("no_quote"):
        return "no_quote"
    if r.startswith("ask_size_below") or r.startswith("qty_below") or "below_min_profit" in r:
        return "too_small"
    if r.startswith("volume_below") or r.startswith("open_interest_below"):
        return "thin_market"
    if r.startswith("too_close"):
        return "too_close"
    if r.startswith("strict_2c_fee_safe") or r.startswith("maker_net_pc") or "fee_safe" in r or "net_pc" in r:
        return "fee_edge_fail"
    if r.startswith("edge_scout") or "edge_scout" in r:
        return "edge_scout_fail"
    if "exit_readiness" in r:
        return "exit_readiness_fail"
    if "edge_proof" in r or "required_qty" in r or "depth_coverage" in r:
        return "edge_proof_fail"
    if "dead" in r or "stalled" in r:
        return "dead_or_stalled_flow"
    if "score_below" in r:
        return "weak_quality_score"
    if r.startswith("status_"):
        return "not_open"
    if "cost_cap" in r or "capital" in r:
        return "capital_cap"
    return r.split(":", 1)[0].split(";", 1)[0][:80]


def edge_health_recommendation(primary: str, reason_counts: dict, action_count: int, discovery_count: int) -> str:
    primary = str(primary or "unknown")
    if action_count >= EDGE_HEALTH_MIN_ACTION_ROWS:
        return "action_plan_has_rows_keep_strict_2c_and_prioritize_high_edge_proof_rows"
    if primary == "ask_above_max":
        return "no_enough_1c_supply_seen_keep_strict_1c_and_watch_near_miss_rows_for_pullbacks"
    if primary == "no_quote":
        return "market_scan_found_markets_without_usable_1c_side_quotes_check_deeper_windows_and_orderbook_depth"
    if primary == "too_small":
        return "available_1c_size_below_minimum_wait_for_size_or_reduce_buy_bot_pilot_size_only_if_edge_proof_still_passes"
    if primary == "thin_market":
        return "volume_or_open_interest_filter_is_blocking_candidates_focus_on_more_liquid_series"
    if primary == "too_close":
        return "close_time_filter_is_dominant_use_15m_windows_only_when_depth_and_queue_are_strong"
    if primary == "fee_edge_fail":
        return "strict_2c_fee_math_is_not_clear_do_not_buy_until_size_or_fee_buffer_improves"
    if primary == "edge_scout_fail":
        return "2c_edge_score_or_depth_is_weak_prioritize_candidates_with_better_exit_depth_flow_and_queue_velocity"
    if primary == "edge_proof_fail":
        return "edge_proof_requires_more_size_or_visible_2c_capacity_skip_until_required_qty_and_depth_pass"
    if primary == "exit_readiness_fail":
        return "2c_exit_readiness_is_weak_wait_for_more_time_depth_flow_or_queue_movement_before_new_buys"
    if primary == "scan_failed":
        return "transport_or_api_scan_failures_are_dominant_check_auth_network_ssl_and_rate_limit_health_before_strategy_tuning"
    if discovery_count <= 0:
        return "no_discovery_rows_yet_review_rejection_file_for_exact_blocker_and_keep_strict_2c"
    return "watch_near_miss_rows_and_scale_only_when_edge_pass_and_edge_proof_pass_are_both_true"

def write_market_discovery_rejections(rows: list, force: bool = False) -> dict:
    rows = [r for r in (rows or []) if isinstance(r, dict)]
    limit = max(0, int(MARKET_DISCOVERY_REJECTION_SAMPLE_LIMIT or 0))
    sample = rows[:limit] if limit else []
    counts = {}
    for r in rows:
        reason = str(r.get("reason") or "unknown")
        key = canonical_discovery_rejection_reason(reason)
        r["reason_bucket"] = key
        counts[key] = counts.get(key, 0) + 1
    fieldnames = [
        "snapshot_ts", "utc_day", "instance", "build_id", "ticker", "event_ticker", "series_ticker", "side",
        "status", "seconds_to_close", "buy_price_dollars", "ask_size_fp", "volume_24h_fp", "open_interest_fp",
        "market_discovery_score", "fee_safe_ok", "edge_band", "edge_pass", "edge_proof_pass", "edge_proof_required_qty_fp", "edge_proof_reason",
        "exit_readiness_score", "exit_readiness_band", "exit_readiness_pass", "exit_readiness_reason",
        "discovery_window_minutes", "reason_bucket", "reason",
    ]
    atomic_write_csv(MARKET_DISCOVERY_REJECTIONS_LATEST_CSV_PATH, fieldnames, [{k: r.get(k, "") for k in fieldnames} for r in sample])
    payload = {
        "snapshot_ts": now_ts(),
        "utc_day": utc_day_from_ts(now_ts()),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "row_count": len(rows),
        "sample_count": len(sample),
        "reason_counts": counts,
        "rows": sample,
    }
    atomic_write_json(MARKET_DISCOVERY_REJECTIONS_LATEST_JSON_PATH, payload)
    STATE.setdefault("meta", {})["market_discovery_rejection_count"] = len(rows)
    STATE.setdefault("meta", {})["market_discovery_rejection_reason_counts"] = counts
    return payload



