        "edge_maker_buffer_cents", "edge_taker_buffer_cents", "edge_fee_drag_pct", "edge_exit_depth_coverage_pct", "edge_exit_depth_fp",
        "edge_expected_maker_net_dollars", "edge_expected_taker_net_dollars", "edge_fee_profile_source", "edge_fee_profile_known", "edge_maker_exit_fee_rate", "edge_taker_exit_fee_rate", "edge_queue_eta_band", "edge_queue_eta_seconds", "edge_queue_velocity_fp_per_min",
