def _series_signal_index(signal_rows) -> dict:
    out = {}
    for row in signal_rows or []:
        if not isinstance(row, dict):
            continue
        series = str(row.get("series_ticker") or "").strip()
        if not series:
            continue
        prev = out.get(series)
        score = parse_decimal(row.get("priority_score", row.get("opportunity_score", "0")), "0")
        prev_score = parse_decimal(prev.get("priority_score", prev.get("opportunity_score", "0")), "0") if prev else Decimal("-1")
        if prev is None or score > prev_score:
            out[series] = row
    return out


def _buy_action_level(row: dict, series_row: dict) -> tuple:
    band = str(row.get("market_discovery_band", "")).lower()
    score = parse_decimal(row.get("market_discovery_score", "0"), "0")
    feedback = str((series_row or {}).get("buy_feedback_band", row.get("buy_feedback_band", ""))).lower()
    ladder = str((series_row or {}).get("capital_ladder_level", "")).lower()
    audit_band = str((series_row or {}).get("action_execution_audit_band", row.get("action_execution_audit_band", ""))).lower()
    fee_safe = str(row.get("fee_safe_ok", "0")).lower() in {"1", "true", "yes"}
    if band in {"deny", "avoid"}:
        return "deny", f"discovery_{band}"
    if BUY_ACTION_PLAN_REQUIRE_FEE_SAFE and not fee_safe:
        return "deny", "not_fee_safe"
    if BUY_ACTION_AUDIT_ENABLED and BUY_ACTION_AUDIT_BAD_DENY and audit_band == "bad":
        return "deny", "action_execution_audit_bad"
    if BUY_ACTION_PLAN_SKIP_DEAD_FLOW:
        for field in ("orderbook_liquidity_band", "trade_tape_band", "velocity_band", "deep_orderbook_band", "deep_trade_tape_band", "deep_velocity_band"):
            val = str(row.get(field, "")).lower()
            if val in {"dead", "deny"}:
                return "deny", f"{field}_{val}"
    if score < BUY_ACTION_PLAN_MIN_SCORE and not (BUY_ACTION_PLAN_ALLOW_PILOT_ONLY and band == "pilot_only"):
        return "deny", f"score_below_{cents4_str(BUY_ACTION_PLAN_MIN_SCORE)}"
    audit_blocks_aggressive = BUY_ACTION_AUDIT_ENABLED and audit_band in {"bad", "caution"} and BUY_ACTION_AUDIT_BLOCK_AGGRESSIVE_ON_CAUTION
    audit_blocks_normal = BUY_ACTION_AUDIT_ENABLED and audit_band == "bad" and BUY_ACTION_AUDIT_BLOCK_NORMAL_ON_BAD
    if band == "aggressive_candidate" and ladder == "aggressive" and not audit_blocks_aggressive:
        if (not BUY_ACTION_PLAN_REQUIRE_GOOD_FEEDBACK_FOR_AGGRESSIVE) or feedback in {"good", "strong"}:
            return "aggressive", "aggressive_discovery_plus_series_proof"
    if band in {"aggressive_candidate", "normal_candidate"} and ladder in {"normal", "aggressive"} and not audit_blocks_normal:
        reason = "normal_discovery_plus_series_proof"
        if audit_blocks_aggressive:
            reason += ";audit_blocks_aggressive"
        return "normal", reason
    if BUY_ACTION_PLAN_ALLOW_PILOT_ONLY and band in {"pilot_only", "normal_candidate", "aggressive_candidate"}:
        return "pilot", "pilot_discovery"
    return "deny", "no_allowed_action_level"


def _buy_action_level_caps(level: str, goal: dict) -> tuple:
    level = str(level or "pilot").lower()
    if level == "aggressive":
        qty_cap = ENTRY_LADDER_AGGRESSIVE_QTY_FP
        cost_cap = BUY_ACTION_PLAN_AGGRESSIVE_COST_DOLLARS
        sell_default = ENTRY_LADDER_AGGRESSIVE_SELL_PRICE
        if str((goal or {}).get("goal_band", "")).lower() in {"behind", "hard_push"}:
            cost_cap = max(cost_cap, min(DAILY_GOAL_AGGRESSIVE_SERIES_MAX_COST_DOLLARS, BUY_ACTION_PLAN_MAX_SERIES_COST_DOLLARS))
    elif level == "normal":
        qty_cap = ENTRY_LADDER_NORMAL_QTY_FP
        cost_cap = BUY_ACTION_PLAN_NORMAL_COST_DOLLARS
        sell_default = ENTRY_LADDER_NORMAL_SELL_PRICE
        if str((goal or {}).get("goal_band", "")).lower() in {"behind", "hard_push"}:
            cost_cap = max(cost_cap, min(DAILY_GOAL_NORMAL_SERIES_MAX_COST_DOLLARS, BUY_ACTION_PLAN_MAX_SERIES_COST_DOLLARS))
    else:
        qty_cap = ENTRY_LADDER_PILOT_QTY_FP
        cost_cap = BUY_ACTION_PLAN_PILOT_COST_DOLLARS
        sell_default = ENTRY_LADDER_PILOT_SELL_PRICE
    if TARGET_2C_ASSURANCE_ENABLED and TARGET_2C_STRICT_ACTION_PLAN:
        sell_default = TARGET_2C_PRICE
    return max(Decimal("0"), qty_cap), max(Decimal("0"), cost_cap), sell_default



RECOVERY_ENTRY_PROJECTION_FIELDS = [
    "snapshot_ts", "utc_day", "instance", "build_id", "source", "ticker", "series_ticker", "side", "action_level",
    "projection_pass", "projection_band", "projection_reason",
    "entry_qty_fp", "target_sell_qty_fp", "remaining_upside_fp", "buy_price_dollars", "sell_target_price_dollars",
    "gross_recovered_dollars", "entry_cost_dollars", "entry_fee_dollars", "exit_fee_dollars",
    "exit_fee_rate", "fee_profile_source", "fee_profile_known",
    "net_after_entry_dollars", "net_after_entry_cents", "gross_cost_ratio_pct", "net_cost_ratio_pct",
    "exit_depth_available_fp", "exit_depth_needed_fp", "exit_depth_coverage_pct",
]


def _projection_depth_from_row(row: dict) -> Decimal:
    for key in (
        "exit_readiness_depth_fp", "book_depth_near_exit_fp", "book_depth_at_exit_fp",
        "edge_proof_exit_capacity_fp", "edge_exit_depth_fp", "exit_depth_cap_fp",
    ):
        val = parse_decimal((row or {}).get(key, "0"), "0")
        if val > 0:
            return val
    return Decimal("0")


def recovery_entry_target_sell_qty(entry_qty: Decimal, sell_price: Decimal = None) -> Decimal:
    q = parse_decimal(entry_qty, "0")
    if q <= 0:
        return Decimal("0.00")
    target = parse_decimal(sell_price if sell_price is not None else SELL_PRICE, str(SELL_PRICE))
    tf = target_fraction(target)
    sell_qty = (q * tf).quantize(Decimal("0.00"), rounding=ROUND_FLOOR)
    if TARGET_TRANCHE_SELL_ENABLED and q >= RECOVERY_PACKET_ENTRY_QTY_FP and RECOVERY_PACKET_TARGET_SELL_QTY_FP > 0:
        # For the working 10-contract packet, keep the projected sell leg exactly
        # aligned with the live 4-at-2c recovery behavior. Larger packets still
        # use the configured 40% fraction.
        if q == RECOVERY_PACKET_ENTRY_QTY_FP:
            sell_qty = RECOVERY_PACKET_TARGET_SELL_QTY_FP
    return min_decimal(q, max_decimal(Decimal("0.00"), sell_qty)).quantize(Decimal("0.00"))


def compute_recovery_entry_projection(row: dict, entry_qty: Decimal, buy_price: Decimal, target_price: Decimal, source: str = "action_plan", action_level: str = "") -> dict:
    now = now_ts()
    ticker = str((row or {}).get("ticker", ""))
    series = str((row or {}).get("series_ticker", ""))
    side = str((row or {}).get("side", ""))
    q = parse_decimal(entry_qty, "0")
    buy = clamp_price(parse_decimal(buy_price, str(BUY_PRICE)))
    target = clamp_price(parse_decimal(target_price, str(SELL_PRICE)))
    sell_qty = recovery_entry_target_sell_qty(q, target)
    remaining_upside = max_decimal(Decimal("0"), q - sell_qty)
    gross = (sell_qty * target).quantize(Decimal("0.000001"))
    basis = (q * buy).quantize(Decimal("0.000001"))
    fee_profile, maker_exit_rate, taker_exit_rate = candidate_fee_rates(row)
    entry_fee = fee_dollars(q, buy, ENTRY_TAKER_FEE_RATE, action="buy") if FEE_GUARD_INCLUDE_ENTRY_FEE else Decimal("0.00")
    exit_fee = fee_dollars(sell_qty, target, maker_exit_rate, action="sell") if sell_qty > 0 else Decimal("0.00")
    net = (gross - basis - entry_fee - exit_fee).quantize(Decimal("0.000001"))
    net_cents = (net * Decimal("100")).quantize(Decimal("0.0001"))
    gross_ratio = Decimal("0") if basis <= 0 else (gross / basis * Decimal("100")).quantize(Decimal("0.0001"))
    net_ratio = Decimal("0") if basis <= 0 else ((gross - entry_fee - exit_fee) / basis * Decimal("100")).quantize(Decimal("0.0001"))
    depth = _projection_depth_from_row(row or {})
    depth_pct = Decimal("0") if sell_qty <= 0 else (depth / sell_qty * Decimal("100")).quantize(Decimal("0.0001"))
    reasons = []
    projection_pass = True
    if q <= 0:
        projection_pass = False; reasons.append("entry_qty_missing")
    if sell_qty < RECOVERY_ENTRY_PROJECTION_MIN_SELL_QTY_FP:
        projection_pass = False; reasons.append(f"target_sell_qty<{qty_str(RECOVERY_ENTRY_PROJECTION_MIN_SELL_QTY_FP)}")
    if gross_ratio < RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT:
        projection_pass = False; reasons.append(f"gross_cost_ratio<{cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT)}")
    if net_cents < RECOVERY_ENTRY_PROJECTION_MIN_NET_AFTER_ENTRY_CENTS:
        projection_pass = False; reasons.append(f"net_after_entry_cents<{cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_NET_AFTER_ENTRY_CENTS)}")
    if RECOVERY_ENTRY_PROJECTION_REQUIRE_DEPTH and depth_pct < RECOVERY_ENTRY_PROJECTION_MIN_DEPTH_COVERAGE_PCT:
        projection_pass = False; reasons.append(f"exit_depth_coverage<{cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_DEPTH_COVERAGE_PCT)}pct")
    if projection_pass and net_cents >= RECOVERY_ENTRY_PROJECTION_WARN_NET_AFTER_ENTRY_CENTS and depth_pct >= max(RECOVERY_ENTRY_PROJECTION_MIN_DEPTH_COVERAGE_PCT, Decimal("150")):
        band = "packet_strong"
    elif projection_pass:
        band = "packet_ok"
    elif net_cents >= RECOVERY_ENTRY_PROJECTION_MIN_NET_AFTER_ENTRY_CENTS and gross_ratio >= RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT:
        band = "packet_watch"
    else:
        band = "packet_block"
    return {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "source": source,
        "ticker": ticker,
        "series_ticker": series,
        "side": side,
        "action_level": action_level,
        "projection_pass": "1" if projection_pass else "0",
        "projection_band": band,
        "projection_reason": ";".join(dict.fromkeys(reasons)) or "10x4_packet_projection_ok",
        "entry_qty_fp": qty_str(q),
        "target_sell_qty_fp": qty_str(sell_qty),
        "remaining_upside_fp": qty_str(remaining_upside),
        "buy_price_dollars": price_str(buy),
        "sell_target_price_dollars": price_str(target),
        "gross_recovered_dollars": money6_str(gross),
        "entry_cost_dollars": money6_str(basis),
        "entry_fee_dollars": money6_str(entry_fee),
        "exit_fee_dollars": money6_str(exit_fee),
        "exit_fee_rate": cents4_str(maker_exit_rate),
        "fee_profile_source": str(fee_profile.get("source", fee_profile.get("fee_type", ""))),
        "fee_profile_known": "1" if fee_profile.get("known") else "0",
        "net_after_entry_dollars": money6_str(net),
        "net_after_entry_cents": cents4_str(net_cents),
        "gross_cost_ratio_pct": cents4_str(gross_ratio),
        "net_cost_ratio_pct": cents4_str(net_ratio),
        "exit_depth_available_fp": qty_str(depth),
        "exit_depth_needed_fp": qty_str(sell_qty),
        "exit_depth_coverage_pct": cents4_str(depth_pct),
    }


def write_recovery_entry_projection_report(action_plan=None, market_discovery_rows=None, force: bool = False) -> dict:
    if not RECOVERY_ENTRY_PROJECTION_ENABLED:
        return {}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_recovery_entry_projection_ts", 0) or 0) < max(15, BUY_ACTION_PLAN_INTERVAL_SECONDS):
        return meta.get("last_recovery_entry_projection", {}) or {}
    rows = []
    for src_name, src_rows in (("action_plan", (action_plan or {}).get("rows", []) if isinstance(action_plan, dict) else []), ("market_discovery", market_discovery_rows or [])):
        for src in src_rows or []:
            if not isinstance(src, dict):
                continue
            ticker = str(src.get("ticker", ""))
            side = str(src.get("side", ""))
            if not ticker or side not in {"yes", "no"}:
                continue
            qty = parse_decimal(src.get("buy_qty_fp", src.get("ask_size_fp", RECOVERY_PACKET_ENTRY_QTY_FP)), str(RECOVERY_PACKET_ENTRY_QTY_FP))
            if src_name == "market_discovery":
                qty = min_decimal(qty, RECOVERY_PACKET_ENTRY_QTY_FP)
            buy = parse_decimal(src.get("buy_price_dollars", BUY_PRICE), str(BUY_PRICE))
            target = parse_decimal(src.get("sell_target_price_dollars", src.get("target_sell_price_dollars", TARGET_2C_PRICE)), str(TARGET_2C_PRICE))
            rows.append(compute_recovery_entry_projection(src, qty, buy, target, source=src_name, action_level=str(src.get("action_level", ""))))
    rows.sort(key=lambda r: (r.get("projection_pass") == "1", parse_decimal(r.get("net_after_entry_cents", "0"), "0"), parse_decimal(r.get("exit_depth_coverage_pct", "0"), "0")), reverse=True)
    rows = rows[:max(1, RECOVERY_ENTRY_PROJECTION_MAX_ROWS)]
    band_counts = {}
    for r in rows:
        band_counts[r.get("projection_band", "unknown")] = band_counts.get(r.get("projection_band", "unknown"), 0) + 1
    snap = {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "enabled": True,
        "row_count": len(rows),
        "pass_count": len([r for r in rows if r.get("projection_pass") == "1"]),
        "band_counts": band_counts,
        "settings": {
            "recovery_entry_projection_require_for_action_plan": bool(RECOVERY_ENTRY_PROJECTION_REQUIRE_FOR_ACTION_PLAN),
            "recovery_entry_projection_min_sell_qty_fp": qty_str(RECOVERY_ENTRY_PROJECTION_MIN_SELL_QTY_FP),
            "recovery_entry_projection_min_gross_cost_ratio_pct": cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_GROSS_COST_RATIO_PCT),
            "recovery_entry_projection_min_net_after_entry_cents": cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_NET_AFTER_ENTRY_CENTS),
            "recovery_entry_projection_min_depth_coverage_pct": cents4_str(RECOVERY_ENTRY_PROJECTION_MIN_DEPTH_COVERAGE_PCT),
            "recovery_entry_projection_require_depth": bool(RECOVERY_ENTRY_PROJECTION_REQUIRE_DEPTH),
        },
        "problem_rows": [r for r in rows if r.get("projection_pass") != "1"][:50],
        "rows": rows,
    }
    meta["last_recovery_entry_projection_ts"] = now
    meta["last_recovery_entry_projection"] = snap
    atomic_write_json(RECOVERY_ENTRY_PROJECTION_LATEST_JSON_PATH, snap)
    atomic_write_csv(RECOVERY_ENTRY_PROJECTION_LATEST_CSV_PATH, RECOVERY_ENTRY_PROJECTION_FIELDS, rows or [{k: "" for k in RECOVERY_ENTRY_PROJECTION_FIELDS}])
    for row in rows:
        append_csv_row(RECOVERY_ENTRY_PROJECTION_HISTORY_CSV_PATH, RECOVERY_ENTRY_PROJECTION_FIELDS, row)
    return snap


