def _split_receipt_bridge_paths(raw: str) -> list:
    out = []
    for part in str(raw or "").split(";"):
        part = part.strip().strip('"')
        if part:
            out.append(part)
    return out


def buybot_receipt_bridge_candidate_paths() -> list:
    candidates = []
    candidates.extend(_split_receipt_bridge_paths(BUYBOT_RECEIPT_BRIDGE_PATHS))
    rels = [
        "BUYBOT_RECEIPTS_FOR_SELLBOT.jsonl",
        "buybot_round_slots_live.jsonl",
        "latest_live_buybot_round_slot.json",
        os.path.join("buybot_inbox", "BUYBOT_RECEIPTS_FOR_SELLBOT.jsonl"),
        os.path.join("buybot_inbox", "buybot_round_slots_live.jsonl"),
        os.path.join("buybot_inbox", "latest_live_buybot_round_slot.json"),
        os.path.join("logs", "buybot_inbox", "BUYBOT_RECEIPTS_FOR_SELLBOT.jsonl"),
        os.path.join("logs", "buybot_inbox", "buybot_round_slots_live.jsonl"),
        os.path.join("logs", "buybot_inbox", "latest_live_buybot_round_slot.json"),
        os.path.join("logs", "sellbot_handshake", "BUYBOT_RECEIPTS_FOR_SELLBOT.jsonl"),
        os.path.join("logs", "sellbot_handshake", "buybot_round_slots_live.jsonl"),
        os.path.join("logs", "sellbot_handshake", "latest_live_buybot_round_slot.json"),
        os.path.join("logs", "sellbot_inbox", "BUYBOT_RECEIPTS_FOR_SELLBOT.jsonl"),
        os.path.join("logs", "sellbot_inbox", "buybot_round_slots_live.jsonl"),
        os.path.join("logs", "sellbot_inbox", "latest_live_buybot_round_slot.json"),
    ]
    for rel in rels:
        candidates.append(os.path.join(BASE_DIR, rel))
    seen = set()
    uniq = []
    for c in candidates:
        try:
            full = os.path.abspath(os.path.expanduser(c))
        except Exception:
            full = str(c)
        k = full.lower() if os.name == "nt" else full
        if k not in seen:
            seen.add(k)
            uniq.append(full)
    return uniq


def _load_jsonl_tail_objects(path: str, max_lines: int) -> list:
    rows = []
    try:
        with open(path, "rb") as f:
            data = f.read()
        lines = data.splitlines()[-max(1, max_lines):]
        for raw in lines:
            try:
                text = raw.decode("utf-8", "replace").strip()
                if not text:
                    continue
                obj = json.loads(text)
                if isinstance(obj, dict):
                    rows.append(obj)
            except Exception:
                continue
    except Exception:
        return []
    return rows


def _load_json_or_jsonl_receipts(path: str, max_lines: int) -> list:
    if not os.path.exists(path):
        return []
    lower = str(path).lower()
    if lower.endswith(".jsonl") or lower.endswith(".ndjson"):
        return _load_jsonl_tail_objects(path, max_lines)
    try:
        with open(path, "r", encoding="utf-8") as f:
            obj = json.load(f)
        if isinstance(obj, list):
            return [x for x in obj[-max(1, max_lines):] if isinstance(x, dict)]
        if isinstance(obj, dict):
            return [obj]
    except Exception:
        return []
    return []


def _receipt_sort_key(obj: dict):
    ts_ms = obj.get("engine_ts_ms") or obj.get("ts_ms") or obj.get("received_ts_ms")
    try:
        return int(ts_ms)
    except Exception:
        pass
    ts = obj.get("snapshot_ts") or obj.get("ts") or obj.get("created_ts")
    try:
        return int(ts) * 1000
    except Exception:
        return 0




def _receipt_dedupe_key(obj: dict) -> str:
    if not isinstance(obj, dict):
        return "unknown"
    order_id = str(obj.get("order_id") or "").strip()
    client_order_id = str(obj.get("client_order_id") or "").strip()
    ticker = str(obj.get("ticker") or "").strip()
    side = normalized_outcome_side(obj)
    round_key = str(obj.get("round_key") or obj.get("round_id") or "").strip()
    fill = str(obj.get("fill_count") or obj.get("filled_count") or "").strip()
    rem = str(obj.get("remaining_count") or obj.get("remaining") or "").strip()
    status = str(obj.get("buybot_status") or obj.get("status") or obj.get("response_status") or "").strip().lower()
    if order_id:
        return "order:" + order_id
    if client_order_id:
        return "client:" + client_order_id
    return "slot:" + "|".join([round_key, ticker, side, fill, rem, status])

def _receipt_public_view(obj: dict) -> dict:
    if not isinstance(obj, dict):
        return {}
    keys = [
        "event", "receipt_schema", "version", "time", "engine_ts_ms", "round_id", "round_key",
        "series", "ticker", "side", "outcome_side", "book_side", "economic_price_dollars",
        "count", "count_fp", "fill_count", "remaining_count", "buybot_status", "response_status",
        "order_id", "client_order_id", "source_event", "sellbot_expected_receipt_event",
    ]
    return {k: obj.get(k, "") for k in keys if k in obj}


def build_buybot_receipt_bridge_payload(context: str = "dashboard", write: bool = False) -> dict:
    """Summarize latest buybot handoff receipts; resting unfilled buys do not need 2c sell coverage yet."""
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    files = []
    receipts = []
    if BUYBOT_RECEIPT_BRIDGE_ENABLED:
        for path in buybot_receipt_bridge_candidate_paths():
            exists = os.path.exists(path)
            info = {
                "path": path,
                "exists": bool(exists),
                "size_bytes": 0,
                "mtime_ts": 0,
                "loaded_rows": 0,
            }
            if exists:
                try:
                    st = os.stat(path)
                    info["size_bytes"] = int(st.st_size)
                    info["mtime_ts"] = int(st.st_mtime)
                    rows = _load_json_or_jsonl_receipts(path, BUYBOT_RECEIPT_BRIDGE_MAX_LINES)
                    info["loaded_rows"] = len(rows)
                    for r in rows:
                        rr = dict(r)
                        rr["_source_path"] = path
                        receipts.append(rr)
                except Exception as e:
                    info["error"] = str(e)[:200]
            files.append(info)
    raw_loaded_receipt_count = len(receipts)
    deduped = {}
    duplicate_receipt_count = 0
    receipts.sort(key=_receipt_sort_key)
    for r in receipts:
        key = _receipt_dedupe_key(r)
        if key in deduped:
            duplicate_receipt_count += 1
        deduped[key] = r
    receipts = sorted(deduped.values(), key=_receipt_sort_key)
    latest = receipts[-1] if receipts else {}
    latest_public = _receipt_public_view(latest)
    status_counts = {}
    event_counts = {}
    filled_receipt_count = 0
    resting_unfilled_count = 0
    total_fill_count = Decimal("0")
    total_remaining_count = Decimal("0")
    for r in receipts:
        status = str(r.get("buybot_status", r.get("status", r.get("response_status", "unknown"))) or "unknown").lower()
        status_counts[status] = status_counts.get(status, 0) + 1
        ev = str(r.get("event", "unknown") or "unknown")
        event_counts[ev] = event_counts.get(ev, 0) + 1
        fill = parse_decimal(r.get("fill_count", r.get("filled_count", "0")), "0")
        rem = parse_decimal(r.get("remaining_count", r.get("remaining", "0")), "0")
        total_fill_count += fill
        total_remaining_count += rem
        if fill > 0:
            filled_receipt_count += 1
        if status == "resting" and fill <= 0 and rem > 0:
            resting_unfilled_count += 1
    latest_fill = parse_decimal(latest.get("fill_count", latest.get("filled_count", "0")), "0") if latest else Decimal("0")
    latest_remaining = parse_decimal(latest.get("remaining_count", latest.get("remaining", "0")), "0") if latest else Decimal("0")
    latest_status = str(latest.get("buybot_status", latest.get("status", latest.get("response_status", ""))) or "").lower() if latest else ""
    if not BUYBOT_RECEIPT_BRIDGE_ENABLED:
        action = "disabled"
        band = "disabled"
    elif not receipts:
        action = "no_receipts_seen"
        band = "watch"
    elif latest_fill <= 0 and latest_remaining > 0 and latest_status == "resting":
        action = "latest_buy_order_resting_no_fill_no_hedge_inventory_yet"
        band = "resting_no_fill"
    elif latest_fill > 0:
        action = "filled_inventory_seen_sell_management_should_cover_2c_hedge"
        band = "filled_inventory"
    else:
        action = "receipt_seen_monitor_for_fill_transition"
        band = "watch"
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "context": str(context or ""),
        "enabled": bool(BUYBOT_RECEIPT_BRIDGE_ENABLED),
        "band": band,
        "bridge_action": action,
        "policy": "buybot resting orders do not require 2c sell coverage until an actual fill/position event exists; once inventory exists, sell management still attempts strict 2c hedge coverage.",
        "source_file_count": len([f for f in files if f.get("exists")]),
        "loaded_receipt_count": len(receipts),
        "raw_loaded_receipt_count": raw_loaded_receipt_count,
        "deduped_receipt_count": len(receipts),
        "duplicate_receipt_count": duplicate_receipt_count,
        "status_counts": status_counts,
        "event_counts": event_counts,
        "filled_receipt_count": filled_receipt_count,
        "resting_unfilled_count": resting_unfilled_count,
        "total_fill_count_fp": qty_str(total_fill_count),
        "total_remaining_count_fp": qty_str(total_remaining_count),
        "latest": latest_public,
        "latest_source_path": latest.get("_source_path", "") if latest else "",
        "latest_fill_count_fp": qty_str(latest_fill),
        "latest_remaining_count_fp": qty_str(latest_remaining),
        "latest_ticker": latest.get("ticker", "") if latest else "",
        "latest_order_id": latest.get("order_id", "") if latest else "",
        "latest_client_order_id": latest.get("client_order_id", "") if latest else "",
        "source_files": files,
    }
    meta["last_buybot_receipt_bridge"] = payload
    if write:
        try:
            atomic_write_json(BUYBOT_RECEIPT_BRIDGE_JSON_PATH, payload)
            lines = [
                "Kalshi 15m Sell Bot - Buybot Receipt Bridge",
                "==============================================",
                f"Generated CT : {payload['snapshot_ct']}",
                f"Build ID     : {BUILD_ID}",
                f"Band         : {payload['band']}",
                f"Action       : {payload['bridge_action']}",
                f"Receipts     : loaded={payload['loaded_receipt_count']} raw={payload.get('raw_loaded_receipt_count', payload['loaded_receipt_count'])} duplicates={payload.get('duplicate_receipt_count', 0)} source_files={payload['source_file_count']}",
                f"Latest       : ticker={payload['latest_ticker'] or '[none]'} status={latest_status or '[none]'} fill={payload['latest_fill_count_fp']} remaining={payload['latest_remaining_count_fp']}",
                "",
                "Policy:",
                "- Resting buybot orders with fill_count=0 do not create sellbot hedge inventory.",
                "- Filled buybot inventory should be covered by sell management at strict 2c when possible.",
                "- Buy priority remains active; the 2c hedge is secondary protection.",
            ]
            os.makedirs(os.path.dirname(BUYBOT_RECEIPT_BRIDGE_TXT_PATH) or ".", exist_ok=True)
            with open(BUYBOT_RECEIPT_BRIDGE_TXT_PATH, "w", encoding="utf-8") as f:
                f.write("\n".join(lines) + "\n")
        except Exception as e:
            LOGGER.debug("Could not write buybot receipt bridge: %s", e)
    return payload


def build_buy_action_live_safety_gate() -> dict:
    now = now_ts()
    if not BUY_ACTION_LIVE_SAFETY_INTERLOCK_ENABLED:
        return {
            "gate": "allow",
            "reason": "interlock_disabled",
            "mode": "disabled",
            "recent_429": "0",
            "open_1c_position_qty_fp": qty_str(_active_position_qty_from_state()),
        }
    dashboard = build_live_profit_safety_dashboard_payload() if LIVE_PROFIT_DASHBOARD_ENABLED else {}
    private_stream_sla_gate = (dashboard or {}).get("private_stream_sla") if isinstance((dashboard or {}).get("private_stream_sla"), dict) else build_private_stream_sla_payload(context="buy_action_live_safety_gate", mutate=True)
    mode = str((dashboard or {}).get("mode", "OK_TO_CONSIDER_ACTION_PLAN_ROWS"))
    open_qty = parse_decimal((dashboard or {}).get("open_1c_position_qty_fp", _active_position_qty_from_state()), "0")
    last_429_ts = int(STATE.setdefault("meta", {}).get("api_last_429_ts", 0) or 0)
    recent_429_age = now - last_429_ts if last_429_ts else None
    reasons = []
    if BUY_ACTION_LIVE_SAFETY_REQUIRE_OK_MODE and mode != "OK_TO_CONSIDER_ACTION_PLAN_ROWS":
        reasons.append(f"live_safety_mode_{mode}")
    if BUY_ACTION_LIVE_SAFETY_BLOCK_ON_RECENT_429 and last_429_ts and recent_429_age is not None and recent_429_age < BUY_ACTION_LIVE_SAFETY_429_COOLDOWN_SECONDS:
        reasons.append(f"recent_api_429_{recent_429_age}s_ago")
    if BUY_ACTION_LIVE_SAFETY_MAX_OPEN_1C_QTY_FP > 0 and open_qty > BUY_ACTION_LIVE_SAFETY_MAX_OPEN_1C_QTY_FP:
        reasons.append(f"open_1c_qty_{qty_str(open_qty)}_above_{qty_str(BUY_ACTION_LIVE_SAFETY_MAX_OPEN_1C_QTY_FP)}")
    if SELL_PATH_WATCHDOG_ENABLED and SELL_PATH_WATCHDOG_BLOCK_BUY_ACTION and bool(STATE.setdefault("meta", {}).get("sell_path_watchdog_active")):
        reasons.append(f"sell_path_watchdog_uncovered_{int(STATE.setdefault('meta', {}).get('sell_path_watchdog_triggered_count', 0) or 0)}")
    if SELL_QUEUE_EXIT_OPTIMIZER_ENABLED and SELL_QUEUE_EXIT_BLOCK_BUY_ACTION and bool(STATE.setdefault("meta", {}).get("sell_queue_exit_optimizer_active")):
        reasons.append(f"sell_queue_exit_optimizer_active_{int(STATE.setdefault('meta', {}).get('sell_queue_exit_optimizer_active_count', 0) or 0)}")
    if PRIVATE_STREAM_SLA_ENABLED and PRIVATE_STREAM_SLA_BLOCK_BUY_ACTION and bool((private_stream_sla_gate or {}).get("buy_action_pause_active")):
        reasons.append(f"private_stream_sla_{(private_stream_sla_gate or {}).get('band', 'pause')}_{(private_stream_sla_gate or {}).get('buy_action_pause_remaining_seconds', 0)}s")
    current_build_gate = (dashboard or {}).get("current_build_freshness_gate") if isinstance((dashboard or {}).get("current_build_freshness_gate"), dict) else build_current_build_freshness_gate_payload(context="buy_action_live_safety_gate", mutate=True)
    if CURRENT_BUILD_FRESHNESS_GATE_ENABLED and CURRENT_BUILD_FRESHNESS_GATE_BLOCK_BUY_ACTION and bool((current_build_gate or {}).get("buy_action_pause_active")):
        reasons.append(f"current_build_freshness_{(current_build_gate or {}).get('band', 'pause')}_{(current_build_gate or {}).get('buy_action_pause_remaining_seconds', 0)}s")
    startup_sell_gate = (dashboard or {}).get("startup_to_sell_autorepair") if isinstance((dashboard or {}).get("startup_to_sell_autorepair"), dict) else build_startup_to_sell_autorepair_payload(context="buy_action_live_safety_gate", mutate=True)
    if STARTUP_TO_SELL_AUTOREPAIR_ENABLED and STARTUP_TO_SELL_AUTOREPAIR_BLOCK_BUY_ACTION and bool((startup_sell_gate or {}).get("buy_action_pause_active")):
        reasons.append(f"startup_to_sell_autorepair_{(startup_sell_gate or {}).get('band', 'pause')}_{(startup_sell_gate or {}).get('buy_action_pause_remaining_seconds', 0)}s")
    live_launch_sentinel_gate = (dashboard or {}).get("live_launch_sentinel") if isinstance((dashboard or {}).get("live_launch_sentinel"), dict) else build_live_launch_sentinel_payload(context="buy_action_live_safety_gate", mutate=True)
    if LIVE_LAUNCH_SENTINEL_ENABLED and LIVE_LAUNCH_SENTINEL_BLOCK_BUY_ACTION and bool((live_launch_sentinel_gate or {}).get("buy_action_pause_active")):
        reasons.append(f"live_launch_sentinel_{(live_launch_sentinel_gate or {}).get('band', 'pause')}_{(live_launch_sentinel_gate or {}).get('buy_action_pause_remaining_seconds', 0)}s")
    api_429_burst_gate = (dashboard or {}).get("api_429_burst_circuit") if isinstance((dashboard or {}).get("api_429_burst_circuit"), dict) else build_api_429_burst_circuit_payload(context="buy_action_live_safety_gate", mutate=True)
    if API_429_BURST_CIRCUIT_ENABLED and API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION and bool((api_429_burst_gate or {}).get("buy_action_pause_active")):
        reasons.append(f"api_429_burst_circuit_{(api_429_burst_gate or {}).get('band', 'pause')}_{(api_429_burst_gate or {}).get('buy_action_pause_remaining_seconds', 0)}s")
    residual_pause_until = int(STATE.setdefault("meta", {}).get("residual_sell_tuner_buy_pause_until_ts", 0) or 0)
    residual_active = bool(STATE.setdefault("meta", {}).get("residual_sell_tuner_active", False))
    if RESIDUAL_SELL_TUNER_ENABLED and RESIDUAL_SELL_TUNER_BLOCK_BUY_ACTION and (residual_active or residual_pause_until > now):
        remaining = max(0, residual_pause_until - now) if residual_pause_until else 0
        reasons.append(f"residual_sell_tuner_{int(STATE.setdefault('meta', {}).get('residual_sell_tuner_low_probability_count', 0) or 0)}_residual_risk_{remaining}s")
    hedge_pause_until = int(STATE.setdefault("meta", {}).get("hedge_compliance_sla_buy_pause_until_ts", 0) or 0)
    if HEDGE_COMPLIANCE_SLA_ENABLED and HEDGE_COMPLIANCE_SLA_BLOCK_BUY_ACTION and hedge_pause_until > now:
        remaining = max(0, hedge_pause_until - now)
        reasons.append(f"hedge_compliance_sla_action_needed_{remaining}s_{STATE.setdefault('meta', {}).get('hedge_compliance_sla_buy_pause_reason', '')}")
    active_sell_pause_until = int(STATE.setdefault("meta", {}).get("active_sell_coverage_buy_pause_until_ts", 0) or 0)
    if ACTIVE_SELL_COVERAGE_AUTOPRUNER_ENABLED and ACTIVE_SELL_COVERAGE_AUTOPRUNER_BLOCK_BUY_ACTION and active_sell_pause_until > now:
        remaining = max(0, active_sell_pause_until - now)
        reasons.append(f"active_sell_coverage_pause_{remaining}s_{STATE.setdefault('meta', {}).get('active_sell_coverage_buy_pause_reason', '')}")
    return {
        "gate": "block" if reasons else "allow",
        "reason": ";".join(reasons) or "live_safety_clean",
        "mode": mode,
        "recent_429": "1" if (last_429_ts and recent_429_age is not None and recent_429_age < BUY_ACTION_LIVE_SAFETY_429_COOLDOWN_SECONDS) else "0",
        "last_429_age_seconds": "" if recent_429_age is None else int(recent_429_age),
        "open_1c_position_qty_fp": qty_str(open_qty),
        "risk_flags": (dashboard or {}).get("risk_flags", []),
        "private_stream_sla": private_stream_sla_gate,
        "current_build_freshness_gate": current_build_gate,
        "startup_to_sell_autorepair": startup_sell_gate,
        "live_launch_sentinel": live_launch_sentinel_gate,
        "api_429_burst_circuit": api_429_burst_gate,
        "buy_priority_hedge_policy": build_buy_priority_hedge_policy_payload(context="buy_action_live_safety_gate", write=False),
        "buybot_receipt_bridge": build_buybot_receipt_bridge_payload(context="buy_action_live_safety_gate", write=False) if BUYBOT_RECEIPT_BRIDGE_ENABLED else {"enabled": False},
    }


def compute_buy_action_plan(goal: dict, market_discovery_rows=None, signal_rows=None) -> dict:
    now = now_ts()
    if not BUY_ACTION_PLAN_ENABLED:
        return {"snapshot_ts": now, "utc_day": utc_day_from_ts(now), "enabled": False, "plan_band": "disabled", "rows": []}
    execution_gate = build_buy_action_live_safety_gate()
    if execution_gate.get("gate") == "block":
        return {
            "snapshot_ts": now,
            "utc_day": utc_day_from_ts(now),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "enabled": True,
            "plan_band": "blocked_by_live_safety_interlock",
            "candidate_count": 0,
            "rejected_count": 1,
            "planned_buy_cost_dollars": "0.000000",
            "expected_maker_net_dollars": "0.000000",
            "execution_gate": execution_gate,
            "settings": {
                "buy_action_live_safety_interlock_enabled": bool(BUY_ACTION_LIVE_SAFETY_INTERLOCK_ENABLED),
                "buy_action_live_safety_require_ok_mode": bool(BUY_ACTION_LIVE_SAFETY_REQUIRE_OK_MODE),
                "buy_action_live_safety_block_on_recent_429": bool(BUY_ACTION_LIVE_SAFETY_BLOCK_ON_RECENT_429),
                "buy_action_live_safety_429_cooldown_seconds": BUY_ACTION_LIVE_SAFETY_429_COOLDOWN_SECONDS,
                "buy_action_live_safety_max_open_1c_qty_fp": str(BUY_ACTION_LIVE_SAFETY_MAX_OPEN_1C_QTY_FP),
                "private_stream_sla_enabled": bool(PRIVATE_STREAM_SLA_ENABLED),
                "private_stream_sla_block_buy_action": bool(PRIVATE_STREAM_SLA_BLOCK_BUY_ACTION),
                "current_build_freshness_gate_enabled": bool(CURRENT_BUILD_FRESHNESS_GATE_ENABLED),
                "current_build_freshness_gate_block_buy_action": bool(CURRENT_BUILD_FRESHNESS_GATE_BLOCK_BUY_ACTION),
                "startup_to_sell_autorepair_enabled": bool(STARTUP_TO_SELL_AUTOREPAIR_ENABLED),
                "startup_to_sell_autorepair_block_buy_action": bool(STARTUP_TO_SELL_AUTOREPAIR_BLOCK_BUY_ACTION),
                "live_launch_sentinel_enabled": bool(LIVE_LAUNCH_SENTINEL_ENABLED),
                "live_launch_sentinel_block_buy_action": bool(LIVE_LAUNCH_SENTINEL_BLOCK_BUY_ACTION),
                "api_429_burst_circuit_enabled": bool(API_429_BURST_CIRCUIT_ENABLED),
                "api_429_burst_circuit_block_buy_action": bool(API_429_BURST_CIRCUIT_BLOCK_BUY_ACTION),
                "buy_priority_hedge_advisory_mode": bool(BUY_PRIORITY_HEDGE_ADVISORY_MODE),
                "buy_priority_keep_fee_gates_strict": bool(BUY_PRIORITY_KEEP_FEE_GATES_STRICT),
            },
            "rows": [],
            "actions": [],
            "rejected_sample": [{"reason": execution_gate.get("reason", "blocked_by_live_safety_interlock"), "gate": execution_gate}],
            "rejected_rows": [{"reason": execution_gate.get("reason", "blocked_by_live_safety_interlock"), "gate": execution_gate}],
        }
    engine_ts_gate = build_engine_ts_payload()
    websocket_health_gate = build_websocket_health_payload() if WEBSOCKET_HEALTH_ENABLED else {}
    websocket_band = str(websocket_health_gate.get("band", "disabled" if not WEBSOCKET_ENABLED else "unknown")).lower() if isinstance(websocket_health_gate, dict) else "unknown"
    if BUY_ACTION_LIVE_SAFETY_BLOCK_ON_WS_STALE and WEBSOCKET_HEALTH_ENABLED and WEBSOCKET_ENABLED and websocket_band == "stale":
        return {
            "snapshot_ts": now,
            "utc_day": utc_day_from_ts(now),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "enabled": True,
            "plan_band": "blocked_by_websocket_health",
            "candidate_count": 0,
            "rejected_count": 1,
            "planned_buy_cost_dollars": "0.000000",
            "expected_maker_net_dollars": "0.000000",
            "execution_gate": {"gate": "block", "reason": f"websocket_health_{websocket_band}", "websocket_health": websocket_health_gate},
            "engine_ts_telemetry": engine_ts_gate,
            "websocket_health": websocket_health_gate,
            "rows": [],
            "actions": [],
            "rejected_sample": [{"reason": f"websocket_health_{websocket_band}", "websocket_health": websocket_health_gate}],
            "rejected_rows": [{"reason": f"websocket_health_{websocket_band}", "websocket_health": websocket_health_gate}],
        }
    if engine_ts_gate.get("buy_action_blocking"):
        return {
            "snapshot_ts": now,
            "utc_day": utc_day_from_ts(now),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "enabled": True,
            "plan_band": "blocked_by_engine_ts_lag",
            "candidate_count": 0,
            "rejected_count": 1,
            "planned_buy_cost_dollars": "0.000000",
            "expected_maker_net_dollars": "0.000000",
            "execution_gate": execution_gate,
            "engine_ts_telemetry": engine_ts_gate,
            "websocket_health": websocket_health_gate,
            "market_metadata_guard": market_metadata_guard_status(""),
            "rows": [],
            "actions": [],
            "rejected_sample": [{"reason": f"engine_ts_lag_ms_{engine_ts_gate.get('last_lag_ms')}", "engine_ts": engine_ts_gate}],
            "rejected_rows": [{"reason": f"engine_ts_lag_ms_{engine_ts_gate.get('last_lag_ms')}", "engine_ts": engine_ts_gate}],
        }
    series_ctx = _series_signal_index(signal_rows or [])
    rows = []
    rejected = []
    total_cost = Decimal("0")
    series_costs = {}
    sorted_discovery = sorted(
        [dict(r) for r in (market_discovery_rows or []) if isinstance(r, dict)],
        key=lambda r: (parse_decimal(r.get("market_discovery_score", "0"), "0"), parse_decimal(r.get("maker_net_per_contract_cents_at_2c", "0"), "0"), parse_decimal(r.get("ask_size_fp", "0"), "0")),
        reverse=True,
    )
    for row in sorted_discovery:
        ticker = str(row.get("ticker") or "").strip()
        series = str(row.get("series_ticker") or "").strip()
        side = str(row.get("side") or "").lower()
        if not ticker or side not in {"yes", "no"}:
            rejected.append({"ticker": ticker, "series_ticker": series, "reason": "missing_ticker_or_side"})
            continue
        metadata_guard = market_metadata_guard_status(ticker)
        if MARKET_METADATA_GUARD_ENABLED and MARKET_METADATA_GUARD_BLOCK_BUY_ACTION and metadata_guard.get("active"):
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": f"market_metadata_hold_active_{metadata_guard.get('seconds_remaining', 0)}s", "metadata_guard": metadata_guard})
            continue
        l2_gap_guard = local_l2_gap_guard_status(ticker)
        if LOCAL_L2_GAP_GUARD_ENABLED and LOCAL_L2_GAP_GUARD_BLOCK_BUY_ACTION and l2_gap_guard.get("active"):
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": f"local_l2_sequence_gap_hold_active_{l2_gap_guard.get('seconds_remaining', 0)}s", "local_l2_gap_guard": l2_gap_guard})
            continue
        blocked_by_recovery_scorecard, recovery_scorecard_reason = recovery_scorecard_guard_for_candidate(ticker, series)
        if blocked_by_recovery_scorecard:
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": recovery_scorecard_reason})
            continue
        blocked_by_recovery_packet, recovery_packet_reason = recovery_packet_guard_for_candidate(ticker, series)
        if blocked_by_recovery_packet:
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": recovery_packet_reason})
            continue
        blocked_by_recovery_cycle, recovery_cycle_reason = recovery_cycle_guard_for_candidate(ticker, series)
        if blocked_by_recovery_cycle:
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": recovery_cycle_reason})
            continue
        blocked_by_recovery_timing, recovery_timing_reason = recovery_timing_guard_for_candidate(ticker, series)
        if blocked_by_recovery_timing:
            rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": recovery_timing_reason})
            continue
        repeat_ctx = recovery_repeat_context_for_candidate(ticker, series, side)
        repeat_band_for_guard = str((repeat_ctx or {}).get("repeat_band", ""))
        repeat_guard_for_guard = str((repeat_ctx or {}).get("repeat_guard", ""))
        if BUY_ACTION_PLAN_RECOVERY_REPEAT_GUARD_ENABLED and repeat_ctx:
            if BUY_ACTION_PLAN_RECOVERY_REPEAT_REJECT_BLOCKED and (repeat_band_for_guard == "blocked" or repeat_guard_for_guard == "block_repeat"):
                rejected.append({"ticker": ticker, "series_ticker": series, "side": side, "reason": f"recovery_repeat_guard_blocks_{repeat_band_for_guard or repeat_guard_for_guard}"})
                continue
        srow = series_ctx.get(series, {})
        adverse_flow_band = str(row.get("adverse_flow_band", srow.get("adverse_flow_band", "unknown"))).lower()
        adverse_flow_score = parse_decimal(row.get("adverse_flow_score", srow.get("adverse_flow_score", "60")), "60")
        adverse_flow_reason = str(row.get("adverse_flow_reason", srow.get("adverse_flow_reason", "")) or "")[:240]
        recent_opposite_side_taker_ratio_pct_dec = parse_decimal(row.get("recent_opposite_side_taker_ratio_pct", srow.get("recent_opposite_side_taker_ratio_pct", "50")), "50")
        recent_opposite_side_taker_ratio_pct = cents4_str(recent_opposite_side_taker_ratio_pct_dec)
        orderbook_pressure_score = parse_decimal(row.get("orderbook_pressure_score", srow.get("orderbook_pressure_score", "50")), "50")
        orderbook_pressure_band = str(row.get("orderbook_pressure_band", srow.get("orderbook_pressure_band", "unknown")) or "unknown").lower()
        orderbook_pressure_reason = str(row.get("orderbook_pressure_reason", srow.get("orderbook_pressure_reason", "")) or "")[:240]
        orderbook_imbalance = str(row.get("orderbook_imbalance", srow.get("orderbook_imbalance", "")) or "")
        orderbook_vamp_price_dollars = str(row.get("orderbook_vamp_price_dollars", srow.get("orderbook_vamp_price_dollars", "")) or "")
        orderbook_microprice_dollars = str(row.get("orderbook_microprice_dollars", srow.get("orderbook_microprice_dollars", "")) or "")
        orderbook_mid_price_dollars = str(row.get("orderbook_mid_price_dollars", srow.get("orderbook_mid_price_dollars", "")) or "")
        orderbook_pressure_edge_cents = str(row.get("orderbook_pressure_edge_cents", srow.get("orderbook_pressure_edge_cents", "")) or "")
        orderbook_pressure_size_multiplier = Decimal("1.00")
        adverse_size_multiplier = Decimal("1.00")
        autotune_ctx = strategy_autotune_context_for_candidate(ticker, series) if STRATEGY_AUTOTUNE_ENABLED and STRATEGY_AUTOTUNE_APPLY_TO_ACTION_PLAN else {}
        autotune_size_multiplier = parse_decimal((autotune_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(autotune_ctx, dict) else Decimal("1.00")
        autotune_band = str((autotune_ctx or {}).get("tune_band", "disabled" if not STRATEGY_AUTOTUNE_ENABLED else "unknown")) if isinstance(autotune_ctx, dict) else "unknown"
        autotune_reason = str((autotune_ctx or {}).get("reason", "") or "")[:240] if isinstance(autotune_ctx, dict) else ""
        autotune_warn_pct = parse_decimal((autotune_ctx or {}).get("recommended_adverse_warn_pct", ADVERSE_FLOW_OPPOSITE_RATIO_WARN_PCT), str(ADVERSE_FLOW_OPPOSITE_RATIO_WARN_PCT)) if isinstance(autotune_ctx, dict) else ADVERSE_FLOW_OPPOSITE_RATIO_WARN_PCT
        autotune_block_pct = parse_decimal((autotune_ctx or {}).get("recommended_adverse_block_pct", ADVERSE_FLOW_OPPOSITE_RATIO_BLOCK_PCT), str(ADVERSE_FLOW_OPPOSITE_RATIO_BLOCK_PCT)) if isinstance(autotune_ctx, dict) else ADVERSE_FLOW_OPPOSITE_RATIO_BLOCK_PCT
        queue_fill_ctx = queue_fill_context_for_candidate(ticker, series) if QUEUE_FILL_LEARNER_ENABLED and QUEUE_FILL_LEARNER_APPLY_TO_ACTION_PLAN else {}
        queue_fill_size_multiplier = parse_decimal((queue_fill_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(queue_fill_ctx, dict) else Decimal("1.00")
        queue_fill_band = str((queue_fill_ctx or {}).get("learner_band", "disabled" if not QUEUE_FILL_LEARNER_ENABLED else "unknown")) if isinstance(queue_fill_ctx, dict) else "unknown"
        queue_fill_reason = str((queue_fill_ctx or {}).get("reason", "") or "")[:240] if isinstance(queue_fill_ctx, dict) else ""
        markout_ctx = markout_exit_speed_context_for_candidate(ticker, series) if MARKOUT_EXIT_SPEED_LEARNER_ENABLED and MARKOUT_EXIT_SPEED_APPLY_TO_ACTION_PLAN else {}
        markout_size_multiplier = parse_decimal((markout_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(markout_ctx, dict) else Decimal("1.00")
        markout_band = str((markout_ctx or {}).get("markout_band", "disabled" if not MARKOUT_EXIT_SPEED_LEARNER_ENABLED else "unknown")) if isinstance(markout_ctx, dict) else "unknown"
        markout_reason = str((markout_ctx or {}).get("reason", "") or "")[:240] if isinstance(markout_ctx, dict) else ""
        lifecycle_ctx = real_fill_lifecycle_context_for_candidate(ticker, series) if REAL_FILL_LIFECYCLE_REPLAY_ENABLED and REAL_FILL_LIFECYCLE_APPLY_TO_ACTION_PLAN else {}
        lifecycle_size_multiplier = parse_decimal((lifecycle_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(lifecycle_ctx, dict) else Decimal("1.00")
        lifecycle_band = str((lifecycle_ctx or {}).get("lifecycle_band", "disabled" if not REAL_FILL_LIFECYCLE_REPLAY_ENABLED else "unknown")) if isinstance(lifecycle_ctx, dict) else "unknown"
        lifecycle_reason = str((lifecycle_ctx or {}).get("reason", "") or "")[:240] if isinstance(lifecycle_ctx, dict) else ""
        lifecycle_capital_ctx = lifecycle_capital_ladder_context_for_candidate(lifecycle_ctx) if LIFECYCLE_CAPITAL_LADDER_ENABLED else {"ladder_band": "disabled", "size_multiplier": "1.0000", "level_cap": "aggressive", "reason": "disabled"}
        lifecycle_capital_size_multiplier = parse_decimal((lifecycle_capital_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(lifecycle_capital_ctx, dict) else Decimal("1.00")
        lifecycle_capital_band = str((lifecycle_capital_ctx or {}).get("ladder_band", "disabled" if not LIFECYCLE_CAPITAL_LADDER_ENABLED else "unknown")) if isinstance(lifecycle_capital_ctx, dict) else "unknown"
        lifecycle_capital_reason = str((lifecycle_capital_ctx or {}).get("reason", "") or "")[:240] if isinstance(lifecycle_capital_ctx, dict) else ""
        outcome_regime_ctx = outcome_regime_rehab_context_for_candidate(ticker, series) if OUTCOME_REGIME_REHAB_ENABLED and OUTCOME_REGIME_REHAB_APPLY_TO_ACTION_PLAN else {"outcome_regime_band": "disabled", "size_multiplier": "1.0000", "level_cap": "aggressive", "reason": "disabled"}
        outcome_regime_size_multiplier = parse_decimal((outcome_regime_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(outcome_regime_ctx, dict) else Decimal("1.00")
        outcome_regime_band = str((outcome_regime_ctx or {}).get("outcome_regime_band", "disabled" if not OUTCOME_REGIME_REHAB_ENABLED else "unknown")) if isinstance(outcome_regime_ctx, dict) else "unknown"
        outcome_regime_reason = str((outcome_regime_ctx or {}).get("reason", "") or "")[:240] if isinstance(outcome_regime_ctx, dict) else ""
        write_token_roi_ctx = write_token_roi_context_for_candidate(ticker, series) if WRITE_TOKEN_ROI_GOVERNOR_ENABLED and WRITE_TOKEN_ROI_GOVERNOR_APPLY_TO_ACTION_PLAN else {"write_token_roi_band": "disabled", "size_multiplier": "1.0000", "level_cap": "aggressive", "reason": "disabled"}
        write_token_roi_size_multiplier = parse_decimal((write_token_roi_ctx or {}).get("size_multiplier", "1.0000"), "1") if isinstance(write_token_roi_ctx, dict) else Decimal("1.00")
        write_token_roi_band = str((write_token_roi_ctx or {}).get("write_token_roi_band", "disabled" if not WRITE_TOKEN_ROI_GOVERNOR_ENABLED else "unknown")) if isinstance(write_token_roi_ctx, dict) else "unknown"
        write_token_roi_reason = str((write_token_roi_ctx or {}).get("reason", "") or "")[:240] if isinstance(write_token_roi_ctx, dict) else ""
        queue_fill_current_fields = default_queue_fill_current_fields()
