        taker_est = estimate_trade_net_with_entry(qty, buy_price, target, taker_exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=series)
        maker_pc = parse_decimal(maker_est.get("net_per_contract_cents", "0"), "0")
