def maybe_log_cycle_heartbeat(positions_count: int, managed_orders_count: int, terminal_count: int, balance_cents):
    meta = STATE.setdefault("meta", {})
    last = int(meta.get("last_scan_log_ts", 0) or 0)
    if now_ts() - last < SCAN_LOG_INTERVAL_SECONDS:
        return
    meta["last_scan_log_ts"] = now_ts()
    balance_text = "n/a" if balance_cents is None else f"${(Decimal(str(balance_cents)) / Decimal(100)):.2f}"
    LOGGER.info(
        "Heartbeat | balance=%s | positions=%s | managed_orders=%s | terminal_markets=%s",
        balance_text,
        positions_count,
        managed_orders_count,
        terminal_count,
    )


def should_log_milestone(check_count: int, milestones) -> bool:
    if check_count in milestones:
        return True
    if milestones:
        max_milestone = max(milestones)
        return check_count > max_milestone and check_count % max_milestone == 0
    return False


def log_market_outcome(ticker: str, bucket: dict, outcome: str, details: str = ""):
    marker = f"{outcome}|{details}"
    if bucket.get("last_outcome") == marker:
        return
    bucket["last_outcome"] = marker
    if details:
        LOGGER.info("Outcome | ticker=%s | %s | %s", ticker, outcome, details)
    else:
        LOGGER.info("Outcome | ticker=%s | %s", ticker, outcome)


def classify_snapshot_transition(ticker: str, bucket: dict, new_position_qty: int, live_orders):
    old_position = parse_decimal(bucket.get("last_known_position_fp", "0.00"), "0")
    old_orders = bucket.get("last_known_open_orders", []) or []
    new_position = Decimal(new_position_qty)

    if old_orders and not live_orders:
        if new_position < old_position:
            log_market_outcome(
                ticker,
                bucket,
                "ORDER_GONE_WITH_POSITION_DROP",
                f"old_pos={contracts_str(old_position)} new_pos={contracts_str(new_position)}",
            )
        elif bucket.get("market_terminal", False):
            log_market_outcome(ticker, bucket, "ORDER_GONE_MARKET_TERMINAL", bucket.get("terminal_reason", ""))
        else:
            log_market_outcome(
                ticker,
                bucket,
                "ORDER_GONE_UNKNOWN",
                f"old_pos={contracts_str(old_position)} new_pos={contracts_str(new_position)}",
            )
    elif new_position < old_position:
        delta = old_position - new_position
        log_market_outcome(
            ticker,
            bucket,
            "POSITION_DROP",
            f"drop_fp={contracts_str(delta)} old_pos={contracts_str(old_position)} new_pos={contracts_str(new_position)}",
        )
    elif new_position > old_position:
        delta = new_position - old_position
        log_market_outcome(
            ticker,
            bucket,
            "POSITION_INCREASE",
            f"add_fp={contracts_str(delta)} old_pos={contracts_str(old_position)} new_pos={contracts_str(new_position)}",
        )


def maybe_log_market_summary(ticker: str, bucket: dict, position_qty: Decimal, target_total: Decimal, desired_remaining: Decimal, active_order, queue_positions_by_order: dict, exit_price: Decimal = None):
    if bucket.get("market_terminal", False):
        return
    order_id = active_order.get("order_id") if active_order else None
    active_remaining = parse_decimal(active_order.get("remaining_count_fp", "0.00"), "0") if active_order else Decimal("0")
    queue_ahead_raw = queue_positions_by_order.get(order_id) if order_id else None
    queue_ahead = normalize_queue_ahead_fp(queue_ahead_raw) if queue_ahead_raw is not None else None
    summary = json.dumps({
        "position": qty_str(position_qty),
        "target_total": qty_str(target_total),
        "desired_remaining": qty_str(desired_remaining),
        "active_remaining": qty_str(active_remaining),
        "queue_ahead": str(queue_ahead) if queue_ahead is not None else None,
        "exit_price": price_str(exit_price if exit_price is not None else SELL_PRICE),
        "terminal": bool(bucket.get("market_terminal", False)),
    }, sort_keys=True)
    if bucket.get("last_summary_state") != summary:
        bucket["last_summary_state"] = summary
        LOGGER.info(
            "Summary | ticker=%s | position=%s | target_total=%s | desired_remaining=%s | active_remaining=%s | queue_ahead=%s | exit_price=%s | terminal=%s",
            ticker,
            qty_str(position_qty),
            qty_str(target_total),
            qty_str(desired_remaining),
            qty_str(active_remaining),
            contracts_str(queue_ahead) if queue_ahead is not None else "n/a",
            price_str(exit_price if exit_price is not None else SELL_PRICE),
            bucket.get("market_terminal", False),
        )


def prune_state():
    to_delete = []
    now = now_ts()
    meta_ttl = max(MARKET_STATUS_CACHE_SECONDS * 4, EVENT_CACHE_SECONDS * 2, FEE_PROFILE_CACHE_SECONDS * 2, 60)
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key.endswith("|_meta"):
            if not isinstance(bucket, dict):
                to_delete.append(key)
                continue
            cache_timestamps = []
            for cache_name in ("_status_cache", "_event_cache", "_series_cache"):
                cache = bucket.get(cache_name, {}) or {}
                ts = int(cache.get("ts", 0) or 0)
                if ts:
                    cache_timestamps.append(ts)
            if cache_timestamps and all(now - ts > meta_ttl for ts in cache_timestamps):
                to_delete.append(key)
            continue
        live_position_zero = str(bucket.get("last_known_position_fp", "0.00")) == "0.00"
        no_open_orders = not bucket.get("last_known_open_orders")
        no_active_order = not bucket.get("active_order_id")
        no_cooldown = int(bucket.get("cooldown_until_ts", 0) or 0) <= now
        no_fill_history = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0") == 0
        ticker = str(key).split("|", 1)[0]
        time_expired_no_order = _state_bucket_position_is_time_expired(ticker, bucket, now=now, grace_seconds=21600) and no_open_orders and no_active_order
        if time_expired_no_order:
            bucket["last_known_position_fp"] = "0.00"
            bucket["market_terminal"] = True
            bucket.setdefault("terminal_ts", now)
            bucket["stale_state_autocleared_ts"] = now
            bucket["stale_state_autocleared_reason"] = "15m_market_far_past_close_no_live_order_hint"
            live_position_zero = True
        terminal_long_ago = bucket.get("market_terminal", False) and (now - int(bucket.get("terminal_ts", 0) or 0) > TERMINAL_TTL_SECONDS)
        if (live_position_zero and no_open_orders and no_active_order and no_cooldown and no_fill_history) or terminal_long_ago:
            to_delete.append(key)
    for key in to_delete:
        del STATE["markets"][key]


def refresh_market_snapshot(ticker: str, side: str, position_qty: int, active_order, suppress_logs: bool = False):
    bucket = get_bucket(ticker, side)
    live_orders = serialize_orders([active_order] if active_order else [], side)
    if not suppress_logs:
        classify_snapshot_transition(ticker, bucket, position_qty, live_orders)

    live_pos_fp = contracts_str(Decimal(position_qty))
    if not suppress_logs:
        compare_and_log(f"{ticker} position", bucket.get("last_known_position_fp", "0.00"), live_pos_fp)
    bucket["last_known_position_fp"] = live_pos_fp
    if not suppress_logs:
        compare_and_log(f"{ticker} open_orders", bucket.get("last_known_open_orders", []), live_orders)
    bucket["last_known_open_orders"] = live_orders
    if active_order and active_order.get("order_id"):
        register_managed_order(bucket, active_order)
        bucket["active_order_id"] = active_order.get("order_id")
        bucket["active_order_accounted_fill_fp"] = contracts_str(parse_decimal(active_order.get("fill_count_fp", "0.00"), "0"))
    else:
        bucket["active_order_id"] = None
        bucket["active_order_accounted_fill_fp"] = "0.00"


def cleanup_orphans(primary_by_key: dict, active_position_keys: set):
    orphan_orders = []
    orphan_ids = []
    orphan_keys = []
    for key, order in list(primary_by_key.items()):
        if key in active_position_keys:
            continue
        oid = order.get("order_id")
        if not oid:
            continue
        orphan_orders.append(order)
        orphan_ids.append(oid)
        orphan_keys.append(key)
    if orphan_orders:
        LOGGER.info("Cancel orphan managed orders | count=%s | ids=%s", len(orphan_orders), ",".join(orphan_ids))
        batch_cancel_orders(orphan_orders)
    for key in orphan_keys:
        bucket = STATE.setdefault("markets", {}).setdefault(key, {})
        bucket["active_order_id"] = None
        bucket["active_order_accounted_fill_fp"] = "0.00"
        bucket["last_known_open_orders"] = []
        bucket["last_known_position_fp"] = "0.00"



def record_ws_position_hint(ticker: str, position_fp_raw, msg: dict = None, source: str = "market_position") -> bool:
    """Keep a short-lived WS position snapshot for sell-path rescue.

    REST positions are still preferred, but a fresh WebSocket market_position event
    should be enough to attempt a covered 2c exit when REST was read before the WS
    queue drained or briefly returns zero rows.
    """
    if not WS_POSITION_SELL_FALLBACK_ENABLED:
        return False
    ticker = str(ticker or "").strip()
    if not ticker:
        return False
    msg = msg if isinstance(msg, dict) else {}
    pos = parse_decimal(position_fp_raw, "0").quantize(Decimal("0.00"))
    now = now_ts()
    hints = STATE.setdefault("meta", {}).get("ws_recent_position_hints", {})
    if not isinstance(hints, dict):
        hints = {}
    hints[ticker] = {
        "ticker": ticker,
        "position_fp": contracts_str(pos),
        "abs_position_fp": contracts_str(abs(pos)),
        "side": infer_side_from_position(ticker, pos) or "",
        "realized_pnl_dollars": str(msg.get("realized_pnl_dollars", "")),
        "fees_paid_dollars": str(msg.get("fees_paid_dollars", "")),
        "position_fee_cost_dollars": str(msg.get("position_fee_cost_dollars", "")),
        "position_cost_dollars": str(msg.get("position_cost_dollars", "")),
        "volume_fp": str(msg.get("volume_fp", "")),
        "ts": now,
        "ct": central_time_iso_from_ts(now),
        "source": source,
    }
    if len(hints) > max(10, WS_POSITION_SELL_HINT_LIMIT):
        hints = dict(sorted(hints.items(), key=lambda kv: int((kv[1] or {}).get("ts", 0) or 0), reverse=True)[:max(10, WS_POSITION_SELL_HINT_LIMIT)])
    STATE.setdefault("meta", {})["ws_recent_position_hints"] = hints
    STATE.setdefault("meta", {})["ws_recent_position_hints_last_ts"] = now
    try:
        side = infer_side_from_position(ticker, pos)
        if side in {"yes", "no"} and abs(pos) > 0:
            note_post_fill_position_seen(ticker, side, abs(pos), source=source, exchange_ts=unix_ts_from_any(msg.get("ts") or msg.get("time") or msg.get("created_time"), default=0))
    except Exception:
        pass
    return True


def augment_positions_with_ws_hints(positions, context: str = "cycle"):
    if not WS_POSITION_SELL_FALLBACK_ENABLED:
        return positions or []
    now = now_ts()
    base = [p for p in (positions or []) if isinstance(p, dict)]
    existing = {str(p.get("ticker") or "").strip() for p in base if str(p.get("ticker") or "").strip()}
    hints = STATE.setdefault("meta", {}).get("ws_recent_position_hints", {})
    if not isinstance(hints, dict) or not hints:
        return base
    added = []
    expired = []
    for ticker, row in list(hints.items()):
        if not isinstance(row, dict):
            expired.append(ticker)
            continue
        ticker = str(row.get("ticker") or ticker or "").strip()
        if not ticker or ticker in existing:
            continue
        ts = int(row.get("ts", 0) or 0)
        if ts <= 0 or now - ts > max(1, WS_POSITION_SELL_HINT_MAX_AGE_SECONDS):
            expired.append(ticker)
            continue
        pos = parse_decimal(row.get("position_fp", "0"), "0").quantize(Decimal("0.00"))
        if abs(pos) <= 0:
            continue
        side = infer_side_from_position(ticker, pos)
        if side not in {"yes", "no"}:
            continue
        if is_market_terminal_locally(ticker):
            continue
        synthetic = {
            "ticker": ticker,
            "position_fp": contracts_str(pos),
            "realized_pnl_dollars": row.get("realized_pnl_dollars", ""),
            "fees_paid_dollars": row.get("fees_paid_dollars", ""),
            "position_cost_dollars": row.get("position_cost_dollars", ""),
            "_source": "ws_position_hint",
            "_ws_hint_age_seconds": str(max(0, now - ts)),
        }
        base.append(synthetic)
        existing.add(ticker)
        added.append(ticker)
    if expired:
        for ticker in expired:
            hints.pop(ticker, None)
        STATE.setdefault("meta", {})["ws_recent_position_hints"] = hints
    if added:
        meta = STATE.setdefault("meta", {})
        meta["ws_position_sell_fallback_last_added"] = added[:20]
        meta["ws_position_sell_fallback_last_added_count"] = len(added)
        meta["ws_position_sell_fallback_last_context"] = context
        meta["ws_position_sell_fallback_last_ts"] = now
        LOGGER.warning("WSPositionSellFallback added %s live position(s) to sell loop | context=%s | tickers=%s", len(added), context, ",".join(added[:10]))
    return base


def _sell_watchdog_state_positions():
    # Offline/toolbox reports should not treat very old last-known positions as live.
    # Reuse the stale-aware state-position helper so Sell Path Watchdog and
    # Sell Queue Exit Optimizer stay consistent with Active Sell Coverage.
    return _active_sell_position_rows_from_state()


def _sell_watchdog_active_order_for_key(key: str, bucket: dict, primary_by_key: dict = None):
    active = (primary_by_key or {}).get(key) if isinstance(primary_by_key, dict) else None
    if isinstance(active, dict) and active.get("order_id"):
        return active
    # Toolbox/offline mode: the live REST order map is unavailable, so fall back
    # to state only when the caller did not supply primary_by_key.
    if primary_by_key is None and isinstance(bucket, dict) and bucket.get("active_order_id"):
        remaining = Decimal("0")
        orders = bucket.get("last_known_open_orders", [])
        if isinstance(orders, list):
            for order in orders:
                if isinstance(order, dict) and str(order.get("order_id") or "") == str(bucket.get("active_order_id") or ""):
                    row = dict(order)
                    row.setdefault("ticker", bucket.get("ticker", ""))
                    row.setdefault("side", bucket.get("side", ""))
                    return row
                if isinstance(order, dict):
                    remaining += parse_decimal(order.get("remaining_count_fp", order.get("remaining_count", "0")), "0")
        return {
            "order_id": bucket.get("active_order_id"),
            "ticker": bucket.get("ticker", ""),
            "side": bucket.get("side", ""),
            "remaining_count_fp": contracts_str(remaining),
            "status": "state_active_order_id",
        }
    return None


def sell_path_watchdog_bucket_due(bucket: dict) -> bool:
    if not SELL_PATH_WATCHDOG_ENABLED or not isinstance(bucket, dict):
        return False
    since = int(bucket.get("sell_watchdog_missing_since_ts", 0) or 0)
    return bool(since and now_ts() - since >= max(1, SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS))


def write_sell_path_watchdog_report(positions=None, primary_by_key: dict = None, writes_allowed: bool = True, context: str = "cycle", update_missing_since: bool = False, force: bool = False) -> dict:
    if not SELL_PATH_WATCHDOG_ENABLED:
        return {"enabled": False, "triggered_uncovered_count": 0, "uncovered_position_count": 0}
    now = now_ts()
    pos_rows = list(positions or []) if positions is not None else _sell_watchdog_state_positions()
    rows = []
    current_residual_keys = set()
    historical_residual_count = 0
    active_count = 0
    uncovered_count = 0
    triggered_count = 0
    fee_blocked_uncovered = 0
    for p in pos_rows:
        if not isinstance(p, dict):
            continue
        ticker = str(p.get("ticker") or "").strip()
        if not ticker:
            continue
        raw_pos = p.get("position_fp", "0")
        side = infer_side_from_position(ticker, raw_pos)
        if side not in {"yes", "no"}:
            continue
        key = market_key(ticker, side)
        bucket = get_bucket(ticker, side)
        position_qty = abs(parse_decimal(raw_pos, "0")).quantize(Decimal("0.00"))
        if position_qty <= 0:
            continue
        terminal = bool(bucket.get("market_terminal", False) or is_market_terminal_locally(ticker))
        active = _sell_watchdog_active_order_for_key(key, bucket, primary_by_key)
        active_remaining = parse_decimal((active or {}).get("remaining_count_fp", (active or {}).get("remaining_count", "0")), "0") if isinstance(active, dict) else Decimal("0")
        has_managed = bool(isinstance(active, dict) and active.get("order_id") and active_remaining > 0)
        active_count += 1
        missing_since = int(bucket.get("sell_watchdog_missing_since_ts", 0) or 0)
        if not has_managed and not terminal:
            uncovered_count += 1
            if update_missing_since and missing_since <= 0:
                missing_since = now
                bucket["sell_watchdog_missing_since_ts"] = missing_since
            age = max(0, now - missing_since) if missing_since else 0
            triggered = bool(age >= max(1, SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS))
            if triggered:
                triggered_count += 1
            last_guard = str(bucket.get("last_fee_guard_state", ""))
            if "allowed\": false" in last_guard or "allowed': False" in last_guard:
                fee_blocked_uncovered += 1
        else:
            age = 0
            triggered = False
            if update_missing_since:
                bucket.pop("sell_watchdog_missing_since_ts", None)
                bucket.pop("sell_watchdog_last_trigger_ts", None)
        if triggered and update_missing_since:
            bucket["sell_watchdog_last_trigger_ts"] = now
            bucket["sell_watchdog_last_trigger_reason"] = "uncovered_position_no_managed_2c_sell"
        rows.append({
            "ticker": ticker,
            "side": side,
            "position_fp": contracts_str(position_qty),
            "source": p.get("_source", "rest"),
            "terminal": bool(terminal),
            "has_managed_sell": bool(has_managed),
            "active_order_id": str((active or {}).get("order_id", "")) if isinstance(active, dict) else "",
            "active_remaining_fp": contracts_str(active_remaining),
            "missing_since_ct": central_time_iso_from_ts(missing_since) if missing_since else "",
            "missing_age_seconds": int(age),
            "watchdog_triggered": bool(triggered),
            "last_error": str(bucket.get("last_error", ""))[:180],
            "last_fee_guard_state": str(bucket.get("last_fee_guard_state", ""))[:300],
        })
    meta = STATE.setdefault("meta", {})
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "enabled": True,
        "context": context,
        "writes_allowed": bool(writes_allowed),
        "active_position_count": active_count,
        "uncovered_position_count": uncovered_count,
        "triggered_uncovered_count": triggered_count,
        "fee_blocked_uncovered_count": fee_blocked_uncovered,
        "missing_sell_seconds_threshold": SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS,
        "buy_action_block_enabled": bool(SELL_PATH_WATCHDOG_BLOCK_BUY_ACTION),
        "market_quality_bypass_enabled": bool(SELL_PATH_WATCHDOG_BYPASS_MARKET_QUALITY_BLOCKS),
        "policy": "pause buy/discovery handoff and prioritize sell management when inventory lacks a managed 2c exit; never loosen FeeGuard",
        "rows": rows[:200],
    }
    meta["sell_path_watchdog_active"] = bool(triggered_count > 0)
    meta["sell_path_watchdog_uncovered_count"] = int(uncovered_count)
    meta["sell_path_watchdog_triggered_count"] = int(triggered_count)
    meta["sell_path_watchdog_fee_blocked_uncovered_count"] = int(fee_blocked_uncovered)
    meta["sell_path_watchdog_last_ts"] = now
    meta["last_sell_path_watchdog"] = {k: v for k, v in payload.items() if k != "rows"}
    try:
        atomic_write_json(SELL_PATH_WATCHDOG_LATEST_JSON_PATH, payload)
        lines = [
            "Kalshi 15m 2c Sell Bot - Sell Path Watchdog",
            "================================================",
            f"Generated CT : {payload['snapshot_ct']}",
            f"Build ID     : {BUILD_ID}",
            f"Context      : {context}",
            f"Writes OK    : {writes_allowed}",
            f"Active pos   : {active_count}",
            f"Uncovered    : {uncovered_count}",
            f"Triggered    : {triggered_count}",
            f"Fee-blocked  : {fee_blocked_uncovered}",
            f"Threshold    : {SELL_PATH_WATCHDOG_MISSING_SELL_SECONDS}s",
            "",
            "Rows:",
        ]
        for row in rows[:60]:
            lines.append(
                f"- {row.get('ticker')}|{row.get('side')} pos={row.get('position_fp')} managed={row.get('has_managed_sell')} "
                f"remaining={row.get('active_remaining_fp')} age={row.get('missing_age_seconds')}s triggered={row.get('watchdog_triggered')} fee={row.get('last_fee_guard_state')}"
            )
        os.makedirs(os.path.dirname(SELL_PATH_WATCHDOG_LATEST_TXT_PATH) or ".", exist_ok=True)
        with open(SELL_PATH_WATCHDOG_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception as e:
        try:
            LOGGER.debug("Sell Path Watchdog report failed: %s", e)
        except Exception:
            pass
    return payload


def maybe_promote_residual_target_to_fee_safe(ticker: str, side: str, desired_remaining: Decimal, position_qty: Decimal, target_total: Decimal, bucket: dict, fee_profile: dict, exit_price: Decimal, active_order=None):
    if not SELL_RESIDUAL_PROMOTE_FEE_SAFE_REPLACEMENT_ENABLED:
        return desired_remaining, target_total, ""
    desired = parse_decimal(desired_remaining, "0").quantize(Decimal("0.00"))
    pos = parse_decimal(position_qty, "0").quantize(Decimal("0.00"))
    if desired <= 0 or pos <= desired:
        return desired_remaining, target_total, ""
    cum_filled = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    current_remaining = parse_decimal((active_order or {}).get("remaining_count_fp", (active_order or {}).get("remaining_count", "0")), "0") if isinstance(active_order, dict) else Decimal("0")
    current_fill = parse_decimal((active_order or {}).get("fill_count_fp", (active_order or {}).get("fill_count", "0")), "0") if isinstance(active_order, dict) else Decimal("0")
    if max(cum_filled, current_fill) < SELL_RESIDUAL_PROMOTE_MIN_CUM_FILLED_FP:
        return desired_remaining, target_total, ""
    base_guard = fee_guard_state(ticker, side, desired, is_taker=False, profile=fee_profile, exit_price=exit_price)
    if base_guard.get("allowed"):
        return desired_remaining, target_total, ""
    max_candidate = min_decimal(pos, desired + max_decimal(Decimal("0"), SELL_RESIDUAL_PROMOTE_MAX_EXTRA_OVER_TARGET_FP)).quantize(Decimal("0.00"))
    raw_candidates = [
        TARGET_TRANCHE_SELL_MIN_QTY_FP,
        MIN_PROFITABLE_ORDER_QTY_FP,
        max_candidate,
        pos,
    ]
    candidates = []
    for raw in raw_candidates:
        q = parse_decimal(raw, "0").quantize(Decimal("0.00"))
        if q > desired and q <= pos and q <= max_candidate and q >= MIN_ORDER_QTY_FP and q not in candidates:
            candidates.append(q)
    candidates = sorted(candidates)
    for q in candidates:
        guard = fee_guard_state(ticker, side, q, is_taker=False, profile=fee_profile, exit_price=exit_price)
        if guard.get("allowed"):
            new_target_total = max_decimal(parse_decimal(target_total, "0"), cum_filled + q).quantize(Decimal("0.00"))
            reason = f"partial_fill_residual_promoted_to_fee_safe_qty_{qty_str(q)}_from_{qty_str(desired)}"
            bucket["sell_residual_promote_last_ts"] = now_ts()
            bucket["sell_residual_promote_last_reason"] = reason
            bucket["sell_residual_promote_from_fp"] = contracts_str(desired)
            bucket["sell_residual_promote_to_fp"] = contracts_str(q)
            LOGGER.warning(
                "SellResidualRescue promoted target to keep replacement fee-safe | ticker=%s | side=%s | old_desired=%s | new_desired=%s | position=%s | cum_filled=%s | reason=%s",
                ticker, side, qty_str(desired), qty_str(q), qty_str(pos), qty_str(cum_filled), reason,
            )
            return q, new_target_total, reason
    bucket["sell_residual_promote_last_block_ts"] = now_ts()
    bucket["sell_residual_promote_last_block_reason"] = "; ".join(base_guard.get("reasons", []))[:300]
    return desired_remaining, target_total, ""


def recovery_remainder_base_target_total(position_qty: Decimal, bucket: dict, exit_price: Decimal = None) -> Decimal:
    pos = parse_decimal(position_qty, "0").quantize(Decimal("0.00"))
    cum_filled = parse_decimal((bucket or {}).get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    original_estimate = (pos + cum_filled).quantize(Decimal("0.00"))
    if original_estimate <= 0:
        return Decimal("0.00")
    raw = original_estimate * target_fraction(exit_price=exit_price)
    return raw.quantize(Decimal("0.00"), rounding=ROUND_UP)


def recovery_remainder_group_guard_state(ticker: str, side: str, qty: Decimal, is_taker: bool, profile: dict, exit_price: Decimal = None, bucket: dict = None, position_qty: Decimal = None, target_total: Decimal = None) -> dict:
    """Fee-safe guard for the residual left after the configured recovery packet fills.

    The normal FeeGuard intentionally blocks tiny standalone sell packets. After a
    fee-approved 40% target sell has filled, however, the remaining position is
    no longer a fresh standalone strategy entry; it is residual live inventory.
    This guard allows a strict 2c residual sell only when the combined recovered
    position and the incremental residual transaction both remain after-fee safe.
    """
    b = bucket or {}
    profile = profile or {}
    q = parse_decimal(qty, "0").quantize(Decimal("0.00"))
    pos = parse_decimal(position_qty if position_qty is not None else b.get("last_known_position_fp", "0"), "0").quantize(Decimal("0.00"))
    p = parse_decimal(exit_price if exit_price is not None else SELL_PRICE, str(SELL_PRICE))
    exit_rate = select_exit_fee_rate(profile, is_taker=is_taker)
    cum_filled = parse_decimal(b.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    original_estimate = (pos + cum_filled).quantize(Decimal("0.00"))
    base_target = recovery_remainder_base_target_total(pos, b, exit_price=p)
    target_total_dec = parse_decimal(target_total if target_total is not None else base_target, "0").quantize(Decimal("0.00"))
    candidate_total = min_decimal(original_estimate, cum_filled + q).quantize(Decimal("0.00")) if original_estimate > 0 else q
    group_est = estimate_trade_net(candidate_total, p, exit_rate, include_entry_fee=FEE_GUARD_INCLUDE_ENTRY_FEE, ticker=ticker, series_ticker=profile.get("series_ticker", ""))
    incremental_est = estimate_trade_net_with_entry(q, BUY_PRICE, p, exit_rate, include_entry_fee=False, ticker=ticker, series_ticker=profile.get("series_ticker", ""))
    reasons = []
    if not SELL_REMAINDER_AFTER_RECOVERY_ENABLED:
        reasons.append("SELL_REMAINDER_AFTER_RECOVERY_ENABLED=0")
    if q < MIN_ORDER_QTY_FP:
        reasons.append(f"qty {qty_str(q)} < MIN_ORDER_QTY_FP {qty_str(MIN_ORDER_QTY_FP)}")
    if pos <= 0:
        reasons.append("no_live_residual_position")
    if q > pos + Decimal("0.0001"):
        reasons.append(f"qty {qty_str(q)} > residual_position {qty_str(pos)}")
    if q > SELL_REMAINDER_AFTER_RECOVERY_MAX_QTY_FP:
        reasons.append(f"qty {qty_str(q)} > SELL_REMAINDER_AFTER_RECOVERY_MAX_QTY_FP {qty_str(SELL_REMAINDER_AFTER_RECOVERY_MAX_QTY_FP)}")
    if SELL_REMAINDER_AFTER_RECOVERY_STRICT_2C and price_str(p) != price_str(TARGET_2C_PRICE):
        reasons.append(f"exit_price {price_str(p)} != strict_2c {price_str(TARGET_2C_PRICE)}")
    if cum_filled < SELL_REMAINDER_AFTER_RECOVERY_MIN_CUM_FILLED_FP:
        reasons.append(f"cum_filled {qty_str(cum_filled)} < min {qty_str(SELL_REMAINDER_AFTER_RECOVERY_MIN_CUM_FILLED_FP)}")
    if SELL_REMAINDER_AFTER_RECOVERY_REQUIRE_BASE_TARGET_FILLED and cum_filled + Decimal("0.0001") < base_target:
        reasons.append(f"base_recovery_target_not_filled cum={qty_str(cum_filled)} target={qty_str(base_target)}")
    # The candidate must actually extend coverage beyond the configured recovery target.
    if candidate_total <= max_decimal(base_target, target_total_dec if target_total_dec > base_target else base_target) - Decimal("0.0001"):
        reasons.append(f"candidate_total {qty_str(candidate_total)} does_not_extend_recovery_target {qty_str(base_target)}")
    if group_est["net_cents"] < SELL_REMAINDER_AFTER_RECOVERY_MIN_GROUP_NET_CENTS:
        reasons.append(f"group_net_cents {money_str(group_est['net_cents'])} < min_group_net_cents {money_str(SELL_REMAINDER_AFTER_RECOVERY_MIN_GROUP_NET_CENTS)}")
    if incremental_est["net_cents"] < SELL_REMAINDER_AFTER_RECOVERY_MIN_INCREMENTAL_NET_CENTS:
        reasons.append(f"incremental_net_cents {money_str(incremental_est['net_cents'])} < min_incremental_net_cents {money_str(SELL_REMAINDER_AFTER_RECOVERY_MIN_INCREMENTAL_NET_CENTS)}")
    if incremental_est["net_per_contract_cents"] < SELL_REMAINDER_AFTER_RECOVERY_MIN_PER_CONTRACT_CENTS:
        reasons.append(f"incremental_net_per_contract_cents {money_str(incremental_est['net_per_contract_cents'])} < min_per_contract_cents {money_str(SELL_REMAINDER_AFTER_RECOVERY_MIN_PER_CONTRACT_CENTS)}")
    return {
        "allowed": not reasons,
        "reasons": reasons,
        "ticker": ticker,
        "side": side,
        "is_taker": is_taker,
        "small_position_rescue": False,
        "target_tranche_rescue": False,
        "remainder_after_recovery_rescue": True,
        "effective_min_total_net_cents": SELL_REMAINDER_AFTER_RECOVERY_MIN_INCREMENTAL_NET_CENTS,
        "effective_min_per_contract_cents": SELL_REMAINDER_AFTER_RECOVERY_MIN_PER_CONTRACT_CENTS,
        "exit_price": p,
        "exit_rate": exit_rate,
        "profile": profile,
        "estimate": incremental_est,
        "group_estimate": group_est,
        "base_target_total_fp": contracts_str(base_target),
        "target_total_fp": contracts_str(target_total_dec),
        "cum_filled_fp": contracts_str(cum_filled),
        "residual_position_fp": contracts_str(pos),
        "original_estimate_fp": contracts_str(original_estimate),
        "candidate_total_fp": contracts_str(candidate_total),
    }


def sell_order_fee_guard_state(ticker: str, side: str, qty: Decimal, is_taker: bool, profile: dict, exit_price: Decimal = None, bucket: dict = None, position_qty: Decimal = None, target_total: Decimal = None) -> dict:
    guard = fee_guard_state(ticker, side, qty, is_taker=is_taker, profile=profile, exit_price=exit_price)
    if guard.get("allowed"):
        return guard
    remainder_guard = recovery_remainder_group_guard_state(
        ticker, side, qty, is_taker=is_taker, profile=profile, exit_price=exit_price,
        bucket=bucket, position_qty=position_qty, target_total=target_total,
    )
    if remainder_guard.get("allowed"):
        try:
            if isinstance(bucket, dict):
                bucket["sell_remainder_after_recovery_last_ts"] = now_ts()
                bucket["sell_remainder_after_recovery_last_qty_fp"] = contracts_str(parse_decimal(qty, "0"))
                bucket["sell_remainder_after_recovery_last_group_net_cents"] = money_str(remainder_guard.get("group_estimate", {}).get("net_cents", Decimal("0")))
                bucket["sell_remainder_after_recovery_last_incremental_net_cents"] = money_str(remainder_guard.get("estimate", {}).get("net_cents", Decimal("0")))
        except Exception:
            pass
        return remainder_guard
    return guard


def maybe_expand_target_to_full_position_coverage(ticker: str, side: str, desired_remaining: Decimal, position_qty: Decimal, target_total: Decimal, bucket: dict, fee_profile: dict, exit_price: Decimal, active_order=None):
    if not SELL_FULL_POSITION_2C_COVERAGE_ENABLED:
        return desired_remaining, target_total, ""
    desired = parse_decimal(desired_remaining, "0").quantize(Decimal("0.00"))
    pos = parse_decimal(position_qty, "0").quantize(Decimal("0.00"))
    if pos < MIN_ORDER_QTY_FP or desired >= pos:
        return desired_remaining, target_total, ""
    cum_filled = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    base_target = recovery_remainder_base_target_total(pos, bucket, exit_price=exit_price)
    if cum_filled + Decimal("0.0001") < base_target:
        return desired_remaining, target_total, ""
    if price_str(exit_price) != price_str(TARGET_2C_PRICE):
        return desired_remaining, target_total, ""
    if pos - desired < SELL_FULL_POSITION_2C_COVERAGE_MIN_DELTA_FP:
        return desired_remaining, target_total, ""
    if SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_NO_ACTIVE_ORDER and isinstance(active_order, dict) and active_order.get("order_id"):
        current_remaining = parse_decimal(active_order.get("remaining_count_fp", active_order.get("remaining_count", "0")), "0")
        if current_remaining >= MIN_ORDER_QTY_FP:
            return desired_remaining, target_total, ""
    guard_source = "not_checked"
    if SELL_FULL_POSITION_2C_COVERAGE_REQUIRE_FEE_GUARD:
        full_guard = fee_guard_state(ticker, side, pos, is_taker=False, profile=fee_profile, exit_price=exit_price)
        guard_source = "standalone_fee_guard"
        if not full_guard.get("allowed"):
            remainder_guard = recovery_remainder_group_guard_state(
                ticker, side, pos, is_taker=False, profile=fee_profile, exit_price=exit_price,
                bucket=bucket, position_qty=pos, target_total=target_total,
            )
            if not remainder_guard.get("allowed"):
                bucket["sell_full_position_coverage_last_block_ts"] = now_ts()
                bucket["sell_full_position_coverage_last_block_reason"] = "; ".join(remainder_guard.get("reasons", full_guard.get("reasons", [])))[:300]
                bucket["sell_full_position_coverage_last_block_qty_fp"] = contracts_str(pos)
                return desired_remaining, target_total, ""
            full_guard = remainder_guard
            guard_source = "remainder_after_recovery_group_guard"
        full_net = money_str(full_guard.get("estimate", {}).get("net_cents", Decimal("0")))
        group_net = money_str(full_guard.get("group_estimate", {}).get("net_cents", Decimal("0"))) if full_guard.get("group_estimate") else ""
    else:
        full_net = "not_checked"
        group_net = ""
    cum_filled = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    new_target_total = max_decimal(parse_decimal(target_total, "0"), cum_filled + pos).quantize(Decimal("0.00"))
    reason = f"full_position_2c_coverage_to_{qty_str(pos)}_from_{qty_str(desired)}_{guard_source}"
    bucket["sell_full_position_coverage_last_ts"] = now_ts()
    bucket["sell_full_position_coverage_last_reason"] = reason
    bucket["sell_full_position_coverage_from_fp"] = contracts_str(desired)
    bucket["sell_full_position_coverage_to_fp"] = contracts_str(pos)
    bucket["sell_full_position_coverage_guard_source"] = guard_source
    if group_net:
        bucket["sell_full_position_coverage_group_net_cents"] = group_net
    LOGGER.warning(
        "SellFullCoverage expanded 2c target to cover full live position | ticker=%s | side=%s | old_desired=%s | new_desired=%s | position=%s | guard_source=%s | incremental_net_cents=%s | group_net_cents=%s",
        ticker, side, qty_str(desired), qty_str(pos), qty_str(pos), guard_source, full_net, group_net,
    )
    return pos, new_target_total, reason


def maybe_promote_fee_blocked_target_to_full_position(ticker: str, side: str, desired_remaining: Decimal, position_qty: Decimal, target_total: Decimal, bucket: dict, fee_profile: dict, exit_price: Decimal, active_order=None):
    if not SELL_FULL_POSITION_FEE_SAFE_ESCALATION_ENABLED:
        return desired_remaining, target_total, ""
    desired = parse_decimal(desired_remaining, "0").quantize(Decimal("0.00"))
    pos = parse_decimal(position_qty, "0").quantize(Decimal("0.00"))
    if desired <= 0 or pos <= desired or pos < MIN_ORDER_QTY_FP:
        return desired_remaining, target_total, ""
    if SELL_FULL_POSITION_ESCALATION_REQUIRE_NO_ACTIVE_ORDER and isinstance(active_order, dict) and active_order.get("order_id"):
        current_remaining = parse_decimal(active_order.get("remaining_count_fp", active_order.get("remaining_count", "0")), "0")
        if current_remaining >= MIN_ORDER_QTY_FP:
            return desired_remaining, target_total, ""
    base_guard = fee_guard_state(ticker, side, desired, is_taker=False, profile=fee_profile, exit_price=exit_price)
    if base_guard.get("allowed"):
        return desired_remaining, target_total, ""
    full_guard = fee_guard_state(ticker, side, pos, is_taker=False, profile=fee_profile, exit_price=exit_price)
    if not full_guard.get("allowed"):
        bucket["sell_full_position_escalation_last_block_ts"] = now_ts()
        bucket["sell_full_position_escalation_last_block_reason"] = "; ".join(full_guard.get("reasons", []))[:300]
        return desired_remaining, target_total, ""
    cum_filled = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0").quantize(Decimal("0.00"))
    new_target_total = max_decimal(parse_decimal(target_total, "0"), cum_filled + pos).quantize(Decimal("0.00"))
    reason = f"fee_safe_full_position_escalation_to_{qty_str(pos)}_from_{qty_str(desired)}"
    bucket["sell_full_position_escalation_last_ts"] = now_ts()
    bucket["sell_full_position_escalation_last_reason"] = reason
    bucket["sell_full_position_escalation_from_fp"] = contracts_str(desired)
    bucket["sell_full_position_escalation_to_fp"] = contracts_str(pos)
    LOGGER.warning(
        "SellFeeGuardRescue escalated fractional recovery to full-position fee-safe 2c sell | ticker=%s | side=%s | old_desired=%s | new_desired=%s | position=%s | base_reasons=%s | full_net_cents=%s",
        ticker, side, qty_str(desired), qty_str(pos), qty_str(pos), "; ".join(base_guard.get("reasons", [])), money_str(full_guard.get("estimate", {}).get("net_cents", Decimal("0"))),
    )
    return pos, new_target_total, reason


def should_preserve_partial_fill_residual_order(ticker: str, side: str, active_order: dict, bucket: dict, fee_profile: dict, exit_price: Decimal) -> tuple:
    if not SELL_RESIDUAL_KEEP_APPROVED_ORDER_ENABLED or not isinstance(active_order, dict) or not active_order.get("order_id"):
        return False, "residual_preserve_disabled_or_no_order"
    current_remaining = parse_decimal(active_order.get("remaining_count_fp", active_order.get("remaining_count", "0")), "0").quantize(Decimal("0.00"))
    current_fill = parse_decimal(active_order.get("fill_count_fp", active_order.get("fill_count", "0")), "0").quantize(Decimal("0.00"))
    if current_remaining < MIN_ORDER_QTY_FP:
        return False, "current_remaining_below_min_order_qty"
    if current_fill <= 0:
        return False, "order_not_partially_filled"
    current_price = order_exit_price(active_order, side)
    if price_str(current_price) != price_str(exit_price):
        return False, "residual_order_price_mismatch"
    original_qty = max(
        current_remaining + current_fill,
        parse_decimal(active_order.get("initial_count_fp", active_order.get("initial_count", "0")), "0"),
        parse_decimal(active_order.get("count_fp", active_order.get("count", "0")), "0"),
    ).quantize(Decimal("0.00"))
    original_guard = fee_guard_state(ticker, side, original_qty, is_taker=False, profile=fee_profile, exit_price=exit_price)
    prior_recovery_packet = bool(
        price_str(exit_price) == price_str(TARGET_2C_PRICE)
        and original_qty >= TARGET_TRANCHE_SELL_MIN_QTY_FP
        and original_qty <= max_decimal(TARGET_TRANCHE_SELL_MAX_QTY_FP, MIN_PROFITABLE_ORDER_QTY_FP)
    )
    if original_guard.get("allowed") or prior_recovery_packet:
        reason = "original_order_fee_safe" if original_guard.get("allowed") else "prior_2c_recovery_packet_residual"
        bucket["sell_residual_preserved_last_ts"] = now_ts()
        bucket["sell_residual_preserved_reason"] = reason
        bucket["sell_residual_preserved_order_id"] = str(active_order.get("order_id") or "")
        bucket["sell_residual_preserved_remaining_fp"] = contracts_str(current_remaining)
        bucket["sell_residual_preserved_original_qty_fp"] = contracts_str(original_qty)
        return True, reason
    return False, "; ".join(original_guard.get("reasons", []))[:300] or "original_order_fee_guard_failed"


def sell_first_should_defer_analytics(positions, primary_by_key: dict, writes_allowed: bool) -> bool:
    if not (SELL_FIRST_PRIORITY_ENABLED and SELL_FIRST_DEFER_ANALYTICS_WHEN_POSITIONS and writes_allowed):
        return False
    active_keys = set()
    for p in positions or []:
        if not isinstance(p, dict):
            continue
        ticker = str(p.get("ticker") or "").strip()
        if not ticker:
            continue
        pos = parse_decimal(p.get("position_fp", "0"), "0")
        if abs(pos) <= 0:
            continue
        side = infer_side_from_position(ticker, pos)
        if side in {"yes", "no"}:
            active_keys.add(market_key(ticker, side))
    if not active_keys:
        return False
    if not SELL_FIRST_DEFER_ONLY_UNCOVERED:
        return True
    covered = {k for k, o in (primary_by_key or {}).items() if k in active_keys and isinstance(o, dict) and o.get("order_id")}
    return bool(active_keys - covered)


def maybe_log_sell_first_defer(positions, primary_by_key: dict, context: str = "cycle") -> None:
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if now - int(meta.get("sell_first_last_log_ts", 0) or 0) < max(1, SELL_FIRST_LOG_EVERY_SECONDS):
        return
    pos_count = sum(1 for p in (positions or []) if isinstance(p, dict) and abs(parse_decimal(p.get("position_fp", "0"), "0")) > 0)
    managed_count = len([1 for o in (primary_by_key or {}).values() if isinstance(o, dict) and o.get("order_id")])
    meta["sell_first_last_log_ts"] = now
    meta["sell_first_defer_count"] = int(meta.get("sell_first_defer_count", 0) or 0) + 1
    LOGGER.warning("SellFirstPriority deferring heavy analytics/discovery until after sell management | context=%s | positions=%s | managed_orders=%s", context, pos_count, managed_count)


def write_sell_path_doctor_report(positions=None, primary_by_key: dict = None, writes_allowed: bool = True, context: str = "cycle", deferred_analytics: bool = False) -> dict:
    if not SELL_PATH_DOCTOR_ENABLED:
        return {}
    now = now_ts()
    rows = []
    current_residual_keys = set()
    historical_residual_count = 0
    active_count = 0
    unmanaged_count = 0
    for p in positions or []:
        if not isinstance(p, dict):
            continue
        ticker = str(p.get("ticker") or "").strip()
        if not ticker:
            continue
        pos = parse_decimal(p.get("position_fp", "0"), "0").quantize(Decimal("0.00"))
        if abs(pos) <= 0:
            continue
        side = infer_side_from_position(ticker, pos) or ""
        key = market_key(ticker, side) if side else ticker
        active = (primary_by_key or {}).get(key) if side else None
        has_order = bool(isinstance(active, dict) and active.get("order_id"))
        active_count += 1
        if not has_order:
            unmanaged_count += 1
        bucket = STATE.setdefault("markets", {}).get(key, {}) if side else {}
        rows.append({
            "ticker": ticker,
            "side": side,
            "position_fp": contracts_str(pos),
            "source": p.get("_source", "rest"),
            "ws_hint_age_seconds": p.get("_ws_hint_age_seconds", ""),
            "has_managed_sell": has_order,
            "active_order_id": active.get("order_id", "") if isinstance(active, dict) else "",
            "bucket_active_order_id": bucket.get("active_order_id", "") if isinstance(bucket, dict) else "",
            "last_error": str(bucket.get("last_error", ""))[:180] if isinstance(bucket, dict) else "",
            "cooldown_until_ct": central_time_iso_from_ts(int(bucket.get("cooldown_until_ts", 0) or 0)) if isinstance(bucket, dict) and int(bucket.get("cooldown_until_ts", 0) or 0) else "",
        })
    meta = STATE.setdefault("meta", {})
    payload = {
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "build_id": BUILD_ID,
        "instance": INSTANCE_NAME,
        "context": context,
        "writes_allowed": bool(writes_allowed),
        "deferred_analytics_for_sell_first": bool(deferred_analytics),
        "active_position_count": active_count,
        "unmanaged_position_count": unmanaged_count,
        "managed_sell_count": len([1 for o in (primary_by_key or {}).values() if isinstance(o, dict) and o.get("order_id")]),
        "ws_position_hint_count": len(meta.get("ws_recent_position_hints", {}) if isinstance(meta.get("ws_recent_position_hints", {}), dict) else {}),
        "ws_position_fallback_last_added_count": int(meta.get("ws_position_sell_fallback_last_added_count", 0) or 0),
        "last_loop_wait_reason": meta.get("last_loop_wait_reason", ""),
        "policy": "sell placement runs before heavy analytics/discovery when live inventory lacks covered managed 2c exits",
        "rows": rows[:100],
    }
    try:
        atomic_write_json(SELL_PATH_DOCTOR_LATEST_JSON_PATH, payload)
        lines = [
            "Kalshi 15m 2c Sell Bot - Sell Path Doctor",
            "===========================================",
            f"Generated CT : {payload['snapshot_ct']}",
            f"Build ID     : {BUILD_ID}",
            f"Context      : {context}",
            f"Writes OK    : {writes_allowed}",
            f"Sell-first   : deferred_analytics={deferred_analytics}",
            f"Positions    : active={active_count} unmanaged={unmanaged_count} managed_sells={payload['managed_sell_count']}",
            f"WS hints     : stored={payload['ws_position_hint_count']} last_added={payload['ws_position_fallback_last_added_count']}",
            "",
            "Rows:",
        ]
        for row in rows[:40]:
            lines.append(f"- {row.get('ticker')}|{row.get('side')} pos={row.get('position_fp')} source={row.get('source')} managed={row.get('has_managed_sell')} order={row.get('active_order_id')} err={row.get('last_error')}")
        os.makedirs(os.path.dirname(SELL_PATH_DOCTOR_LATEST_TXT_PATH) or ".", exist_ok=True)
        with open(SELL_PATH_DOCTOR_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception as e:
        try:
            LOGGER.debug("Sell Path Doctor write failed: %s", e)
        except Exception:
            pass
    meta["last_sell_path_doctor"] = {k: v for k, v in payload.items() if k != "rows"}
    return payload


def write_sell_latency_rescue_report(payload: dict) -> dict:
    payload = dict(payload or {})
    payload.setdefault("snapshot_ts", now_ts())
    payload.setdefault("snapshot_ct", central_time_iso_from_ts(int(payload.get("snapshot_ts", now_ts()) or now_ts())))
    payload.setdefault("build_id", BUILD_ID)
    payload.setdefault("instance", INSTANCE_NAME)
    try:
        atomic_write_json(SELL_RESCUE_LATEST_JSON_PATH, payload)
        lines = [
            "Kalshi 15m 2c Sell Bot - Sell Latency Rescue",
            "================================================",
            f"Generated CT : {payload.get('snapshot_ct')}",
            f"Build ID     : {BUILD_ID}",
            f"Context      : {payload.get('context', '')}",
            f"Prework ran  : {payload.get('prework_ran')}",
            f"Refreshed    : {payload.get('refreshed')}",
            f"Private drain: first={payload.get('private_drained_first', 0)} second={payload.get('private_drained_second', 0)}",
            f"Positions    : before={payload.get('positions_before', 0)} after={payload.get('positions_after', 0)} active_after={payload.get('active_positions_after', 0)}",
            f"Managed sells: before={payload.get('managed_before', 0)} after={payload.get('managed_after', 0)}",
            f"Reason       : {payload.get('reason', '')}",
            "",
            "Policy       : private fill/order/position events are drained and positions/orders refreshed immediately before the sell loop.",
        ]
        os.makedirs(os.path.dirname(SELL_RESCUE_LATEST_TXT_PATH) or ".", exist_ok=True)
        with open(SELL_RESCUE_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
    except Exception as e:
        try:
            LOGGER.debug("Sell latency rescue report failed: %s", e)
        except Exception:
            pass
    STATE.setdefault("meta", {})["last_sell_latency_rescue"] = {k: v for k, v in payload.items() if k != "rows"}
    try:
        if PRIVATE_STREAM_SLA_ENABLED:
            write_private_stream_sla_report(force=True, context="sell_latency_rescue")
    except Exception as e:
        try:
            LOGGER.debug("Private Stream SLA update after sell latency rescue failed: %s", e)
        except Exception:
            pass
    return payload


def _active_position_count(positions) -> int:
    count = 0
    for p in positions or []:
        if isinstance(p, dict) and abs(parse_decimal(p.get("position_fp", "0"), "0")) > 0:
            count += 1
    return count


def refresh_sell_inputs_after_prework(positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, writes_allowed: bool, prework_ran: bool, context: str = "pre_sell"):
    """Return fresh sell-loop inputs after analytics/export work.

    Latest support bundles showed buy fills arriving through the authenticated stream
    after the initial REST position read, while heavy reports/discovery continued.
    This helper gives private WS events and a fresh REST position/order read one more
    chance immediately before live sell management. JSON state remains the source of
    truth; this only refreshes local loop inputs.
    """
    if not SELL_RESCUE_AFTER_PREWORK_ENABLED:
        return positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, 0, 0
    meta = STATE.setdefault("meta", {})
    try:
        with WS_EVENT_LOCK:
            private_depth_before = len(WS_PRIVATE_EVENT_QUEUE)
            public_depth_before = len(WS_EVENT_QUEUE)
    except Exception:
        private_depth_before = 0
        public_depth_before = 0
    positions_before = len(positions or [])
    active_before = _active_position_count(positions)
    managed_before = len([1 for o in (primary_by_key or {}).values() if isinstance(o, dict) and o.get("order_id")])
    private_drained_first = drain_ws_events(live_resting_orders=resting_orders, private_only=True)
    should_refresh = bool(private_drained_first or private_depth_before or (prework_ran and SELL_RESCUE_FORCE_POSITION_REFRESH_AFTER_PREWORK))
    reason_bits = []
    if private_depth_before:
        reason_bits.append(f"private_queue_before_{private_depth_before}")
    if private_drained_first:
        reason_bits.append(f"private_drained_{private_drained_first}")
    if prework_ran and SELL_RESCUE_FORCE_POSITION_REFRESH_AFTER_PREWORK:
        reason_bits.append("forced_after_pre_sell_prework")
    if not should_refresh:
        return positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, private_drained_first, 0

    fresh_positions = positions
    fresh_orders = resting_orders
    private_drained_second = 0
    fills_processed = 0
    try:
        fresh_positions = get_all_positions()
        fresh_orders = get_all_resting_orders()
        register_live_managed_orders(fresh_orders)
        private_drained_second = drain_ws_events(live_resting_orders=fresh_orders, private_only=True)
        fresh_positions = augment_positions_with_ws_hints(fresh_positions, context="sell_rescue_after_prework")
        # Force a fill sync so buy fills seen after the first REST read update buckets
        # before the sell loop sizes target orders.
        fills_processed = sync_recent_fills(live_resting_orders=fresh_orders, force=True)
        grouped = build_managed_order_map(fresh_orders)
        if writes_allowed:
            fresh_primary = cleanup_duplicate_managed_orders(grouped)
        else:
            fresh_primary = select_primary_managed_orders(grouped)
        adopt_primary_managed_orders(fresh_primary)
        tickers = sorted({p.get("ticker") for p in fresh_positions if isinstance(p, dict) and p.get("ticker")})
        fresh_queue = get_queue_positions([o.get("ticker") for o in fresh_primary.values() if isinstance(o, dict) and o.get("ticker")], list(fresh_primary.values()))
        if CANDLESTICK_SIGNAL_ENABLED and tickers:
            refresh_candlestick_signals(tickers)
        need_books = bool(tickers) and SELL_RESCUE_REFRESH_ORDERBOOKS and BATCH_ORDERBOOK_ENABLED and (IOC_ENABLED or ORDERBOOK_SIGNAL_ENABLED or DEAD_MARKET_ESCAPE_ENABLED or SELL_LIVENESS_ENABLED or SELL_QUEUE_EXIT_OPTIMIZER_ENABLED)
        fresh_books = get_multiple_orderbooks(tickers) if need_books else {}
        active_after = _active_position_count(fresh_positions)
        managed_after = len([1 for o in fresh_primary.values() if isinstance(o, dict) and o.get("order_id")])
        meta["sell_rescue_after_prework_count"] = int(meta.get("sell_rescue_after_prework_count", 0) or 0) + 1
        meta["sell_rescue_after_prework_last_ts"] = now_ts()
        meta["sell_rescue_after_prework_last_active_positions"] = active_after
        payload = {
            "context": context,
            "prework_ran": bool(prework_ran),
            "refreshed": True,
            "private_queue_depth_before": private_depth_before,
            "public_queue_depth_before": public_depth_before,
            "private_drained_first": private_drained_first,
            "private_drained_second": private_drained_second,
            "fills_processed": fills_processed,
            "positions_before": positions_before,
            "active_positions_before": active_before,
            "positions_after": len(fresh_positions or []),
            "active_positions_after": active_after,
            "managed_before": managed_before,
            "managed_after": managed_after,
            "reason": ";".join(reason_bits) or "pre_sell_refresh",
        }
        write_sell_latency_rescue_report(payload)
        return fresh_positions, fresh_orders, fresh_primary, fresh_queue, fresh_books, (private_drained_first + private_drained_second), fills_processed
    except Exception as e:
        meta["sell_rescue_after_prework_error"] = str(e)[:300]
        LOGGER.warning("SellLatencyRescue refresh failed; continuing with existing sell inputs | error=%s", e)
        write_sell_latency_rescue_report({
            "context": context,
            "prework_ran": bool(prework_ran),
            "refreshed": False,
            "private_queue_depth_before": private_depth_before,
            "public_queue_depth_before": public_depth_before,
            "private_drained_first": private_drained_first,
            "positions_before": positions_before,
            "active_positions_before": active_before,
            "managed_before": managed_before,
            "reason": f"refresh_failed:{str(e)[:120]}",
        })
        return positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, private_drained_first, 0



def _startup_reconcile_fast_text(payload: dict) -> str:
    lines = [
        "Kalshi 15m Sell Bot - Startup Reconcile Fast Path",
        "==================================================",
        f"Build ID     : {payload.get('build_id', '')}",
        f"Generated CT : {payload.get('snapshot_ct', '')}",
        f"Enabled      : {payload.get('enabled')}",
        f"Band         : {payload.get('band')}",
        f"Elapsed      : {payload.get('elapsed_seconds')}s",
        "",
        "Policy:",
        "- sell-first fast path keeps live order price/size/fee gates unchanged",
        "- first run_once still loads balance, positions, resting orders, fills, and order-group state before sell management",
        "- noncritical startup analytics/reports are deferred behind first sell-management readiness",
        "",
        "Core checks:",
        *(f"- {item}" for item in (payload.get("core_checks") or [])),
        "",
    ]
    return "\n".join(lines)


def write_startup_reconcile_fast_path_report(start_ts: int, core_checks: list, error: str = "") -> dict:
    now = now_ts()
    payload = {
        "build_id": BUILD_ID,
        "instance": INSTANCE_NAME,
        "enabled": bool(STARTUP_RECONCILE_SELL_FIRST_FAST_MODE),
        "band": "fast_sell_first_ready" if not error else "fast_sell_first_error",
        "policy": "backend-only; no price, size, fee, or order-gate changes; first run_once performs fresh live sell inputs before writes",
        "snapshot_ts": now,
        "snapshot_ct": central_time_iso_from_ts(now),
        "elapsed_seconds": max(0, now - int(start_ts or now)),
        "core_checks": core_checks or [],
        "error": str(error or "")[:300],
        "safe_behavior": {
            "does_not_place_orders": True,
            "does_not_change_order_size_or_price": True,
            "does_not_override_fee_guard": True,
            "defers_noncritical_startup_reports_only": True,
            "run_once_still_refreshes_sell_inputs": True,
        },
    }
    try:
        atomic_write_json(STARTUP_RECONCILE_FAST_JSON_PATH, payload)
        os.makedirs(os.path.dirname(STARTUP_RECONCILE_FAST_TXT_PATH) or ".", exist_ok=True)
        tmp = f"{STARTUP_RECONCILE_FAST_TXT_PATH}.tmp"
        with open(tmp, "w", encoding="utf-8") as fh:
            fh.write(_startup_reconcile_fast_text(payload))
        atomic_replace_with_retry(tmp, STARTUP_RECONCILE_FAST_TXT_PATH, context="startup_reconcile_fast_txt")
    except Exception as e:
        LOGGER.debug("Startup reconcile fast-path report write failed: %s", e)
    try:
        STATE.setdefault("meta", {})["last_startup_reconcile_fast_path"] = payload
        STATE.setdefault("meta", {})["last_startup_reconcile_fast_path_ts"] = payload.get("snapshot_ts", now)
    except Exception:
        pass
    return payload


def startup_reconcile_fast_sell_first():
    start = now_ts()
    core_checks = []
    LOGGER.info("Startup reconciliation fast path enabled | policy=sell_first | reports=%s", STARTUP_RECONCILE_FAST_JSON_PATH)
    try:
        # Keep only lightweight live-readiness checks here.  Auth, endpoint costs,
        # account limits, order-group startup verification, and websocket launch
        # have already run in main(); run_once() immediately refreshes live sell
        # inputs before any order writes.
        try:
            refresh_user_data_timestamp(force=True)
            core_checks.append("user_data_timestamp_refreshed")
        except Exception as e:
            core_checks.append(f"user_data_timestamp_refresh_skipped:{type(e).__name__}")
            LOGGER.debug("Startup fast path user-data timestamp refresh skipped: %s", e)
        try:
            if ORDER_GROUP_STATUS_SYNC_ON_START and ORDER_GROUP_ENABLED:
                sync_order_group_status(force=True, reason="startup_fast_sell_first")
                core_checks.append("order_group_status_synced")
            elif ORDER_GROUP_ENABLED:
                core_checks.append("order_group_enabled_verified_by_startup_tripwire")
            else:
                core_checks.append("order_group_disabled")
        except Exception as e:
            core_checks.append(f"order_group_status_sync_skipped:{type(e).__name__}")
            LOGGER.debug("Startup fast path order-group status sync skipped: %s", e)
        meta = STATE.setdefault("meta", {})
        meta["last_startup_ts"] = now_ts()
        meta["last_heartbeat_ts"] = now_ts()
        meta["startup_reconcile_fast_sell_first_enabled"] = True
        meta["startup_reconcile_fast_sell_first_ts"] = now_ts()
        meta["startup_reconcile_fast_sell_first_policy"] = "first run_once refreshes balance/positions/orders/fills before sell writes"
        core_checks.append("first_run_once_will_refresh_balance_positions_orders_fills")
        payload = write_startup_reconcile_fast_path_report(start, core_checks)
        maybe_save_state(STATE, critical=False, reason="startup_reconcile_fast_sell_first")
        LOGGER.info("Startup reconciliation fast path complete | elapsed=%ss | core_checks=%s", payload.get("elapsed_seconds"), ",".join(core_checks))
        return payload
    except Exception as e:
        write_startup_reconcile_fast_path_report(start, core_checks, error=f"{type(e).__name__}:{e}")
        raise

def startup_reconcile():
    if STARTUP_RECONCILE_SELL_FIRST_FAST_MODE:
        return startup_reconcile_fast_sell_first()
    LOGGER.info("Startup reconciliation beginning...")
    previous_balance = STATE.setdefault("meta", {}).get("last_known_balance_cents")
    maybe_refresh_endpoint_costs(force=True)
    maybe_refresh_series_fee_changes(force=True)
    get_exchange_status(force=True)
    refresh_user_data_timestamp(force=True)
    if ORDER_GROUP_STATUS_SYNC_ON_START:
        sync_order_group_status(force=True, reason="startup")
    balance = get_balance()
    try:
        write_balance_precision_ledger(balance, context="startup_reconcile", force=True)
    except Exception as e:
        LOGGER.debug("Startup balance precision ledger skipped: %s", e)
    live_balance = balance.get("balance")
    compare_and_log("balance_cents", previous_balance, live_balance)

    positions = get_all_positions()
    positions = augment_positions_with_ws_hints(positions, context="startup_reconcile")
    try:
        startup_active_qty = sum((abs(parse_decimal((p or {}).get("position_fp", (p or {}).get("position", "0")), "0")) for p in positions or [] if isinstance(p, dict)), Decimal("0"))
        STATE.setdefault("meta", {})["startup_position_load_ts"] = now_ts()
        STATE.setdefault("meta", {})["startup_position_row_count"] = len(positions or [])
        STATE.setdefault("meta", {})["startup_active_position_count"] = len([p for p in positions or [] if isinstance(p, dict) and abs(parse_decimal((p or {}).get("position_fp", (p or {}).get("position", "0")), "0")) > 0])
        STATE.setdefault("meta", {})["startup_active_position_qty_fp"] = qty_str(startup_active_qty)
    except Exception:
        pass
    if CANDLESTICK_SIGNAL_ENABLED:
        refresh_candlestick_signals([p.get("ticker") for p in positions if p.get("ticker")], force=True)
    resting_orders = get_all_resting_orders()
    try:
        STATE.setdefault("meta", {})["startup_order_load_ts"] = now_ts()
        STATE.setdefault("meta", {})["startup_resting_order_count"] = len(resting_orders or [])
    except Exception:
        pass
    register_live_managed_orders(resting_orders)
    drained_ws_count = 0
    fills_processed = sync_recent_fills(live_resting_orders=resting_orders, force=True)
    seed_recovery_fill_purity_from_ledger(force=True)
    if SETTLEMENT_SYNC_DEFER_UNTIL_AFTER_SELL:
        settlements_processed = 0
        STATE.setdefault("meta", {})["startup_settlement_sync_deferred_until_after_sell"] = True
        STATE.setdefault("meta", {})["startup_settlement_sync_deferred_ts"] = now_ts()
        LOGGER.info("Startup settlement sync deferred until after first sell-management pass | policy=sell_first")
    else:
        settlements_processed = sync_recent_settlements(force=True)
        write_settlement_integrity_snapshot(force=True)
    grouped = build_managed_order_map(resting_orders)
    startup_writes_allowed = exchange_writes_allowed() and user_data_writes_allowed(force=True)
    if startup_writes_allowed:
        primary_by_key = cleanup_duplicate_managed_orders(grouped)
    else:
        primary_by_key = select_primary_managed_orders(grouped)
    adopt_primary_managed_orders(primary_by_key)
    try:
        STATE.setdefault("meta", {})["startup_managed_sell_count"] = len([o for o in primary_by_key.values() if isinstance(o, dict) and o.get("order_id")])
        STATE.setdefault("meta", {})["startup_primary_order_map_ts"] = now_ts()
    except Exception:
        pass
    write_hedge_compliance_sla_report(positions, primary_by_key, context="startup_reconcile_preflight", force=True, mutate=False)
    write_order_fill_visibility_drilldown_report(positions, primary_by_key, context="startup_reconcile_preflight", force=True)
    write_hedge_fill_lifecycle_timeline_report(positions, primary_by_key, context="startup_reconcile_preflight", force=True)

    live_resting_by_id = {o.get("order_id"): o for o in primary_by_key.values() if o.get("order_id")}
    for bucket in STATE.setdefault("markets", {}).values():
        if isinstance(bucket, dict):
            sync_tracked_order_fill(bucket, live_resting_by_id)

    active_position_keys = set()
    for p in positions:
        ticker = p.get("ticker")
        if not ticker:
            continue
        side = infer_side_from_position(ticker, p.get("position_fp", "0.00"))
        if side is None:
            LOGGER.debug("Skipping position with no inferable side: ticker=%s fp=%s", ticker, p.get("position_fp", "0.00"))
            continue
        key = market_key(ticker, side)
        active_position_keys.add(key)
        bucket = get_bucket(ticker, side)
        position_qty = abs(parse_decimal(p.get("position_fp", "0.00"), "0")).quantize(Decimal("0.00"))
        active_order = primary_by_key.get(key)
        if maybe_recheck_terminal_market(ticker, bucket):
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, bucket, position_qty)
            continue
        if precheck_terminal_on_disappeared_order(ticker, bucket, active_order_present=bool(active_order)):
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, bucket, position_qty)
            continue
        market_info = get_market_status_info_for_sell(ticker, context="startup_reconcile")
        status = str(market_info.get("status", "")).lower()
        if (not market_info.get("exists", True)) or status in {"closed", "settled", "determined", "not_found"}:
            mark_market_terminal(ticker, f"status:{status or 'not_found'}")
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, get_bucket(ticker, side), position_qty)
        else:
            clear_market_terminal(ticker)
            refresh_market_snapshot(ticker, side, position_qty, active_order)

    if startup_writes_allowed:
        cleanup_orphans(primary_by_key, active_position_keys)
    else:
        LOGGER.warning("Startup reconciliation skipped duplicate/orphan cancel writes because exchange/user-data freshness guard is blocking writes")
    for key, bucket in STATE.setdefault("markets", {}).items():
        if key in active_position_keys or key.endswith("|_meta"):
            continue
        compare_and_log(f"{key} position", bucket.get("last_known_position_fp", "0.00"), "0.00")
        compare_and_log(f"{key} open_orders", bucket.get("last_known_open_orders", []), [])
        bucket["last_known_position_fp"] = "0.00"
        bucket["last_known_open_orders"] = []

    STATE["meta"]["last_startup_ts"] = now_ts()
    STATE["meta"]["last_heartbeat_ts"] = now_ts()
    STATE["meta"]["last_known_balance_cents"] = live_balance
    prune_state()
    startup_pnl_context = maybe_write_pnl_attribution(force=True)
    maybe_write_buy_decision_feedback(pnl_context=startup_pnl_context, force=True)
    write_recovery_cycle_audit(force=True)
    write_recovery_timing_audit(force=True)
    write_recovery_scorecard(force=True)
    write_recovery_packet_ledger(force=True)
    write_recovery_fill_purity(force=True)
    write_recovery_repeat_leaderboard(force=True)
    maybe_write_quality_ledgers(resting_orders=resting_orders, positions=positions, force=True)
    write_recovery_cycle_audit(force=True)
    write_recovery_timing_audit(force=True)
    write_recovery_scorecard(force=True)
    write_recovery_packet_ledger(force=True)
    write_recovery_fill_purity(force=True)
    write_recovery_repeat_leaderboard(force=True)
    write_live_launch_sentinel_report(context="startup_reconcile_complete", positions=positions, primary_by_key=primary_by_key, force=True, mutate=True)
    write_api_429_burst_circuit_report(context="startup_reconcile_complete", force=True, mutate=True)
    maybe_save_state(STATE, critical=bool(fills_processed or settlements_processed or drained_ws_count), reason="startup_reconcile_complete")
    maybe_log_pending_terminal_close_summaries()

    managed_count = len([o for o in primary_by_key.values() if o.get("order_id")])
    startup_ts = int(STATE.setdefault("meta", {}).get("last_startup_ts", 0) or 0)
    terminal_count = len([
        1 for key, bucket in STATE.setdefault("markets", {}).items()
        if not key.endswith("|_meta")
        and isinstance(bucket, dict)
        and bucket.get("market_terminal", False)
        and int(bucket.get("terminal_ts", 0) or 0) >= startup_ts
    ])
    LOGGER.info(
        "Startup summary | positions=%s | managed_orders=%s | terminal_markets=%s | effective_fraction=%s",
        len(active_position_keys),
        managed_count,
        terminal_count,
        target_fraction(),
    )
    LOGGER.info("Startup reconciliation complete.")


def ensure_target_order(ticker: str, side: str, desired_remaining: Decimal, active_order, bucket: dict, queue_positions_by_order: dict, orderbook_cache=None, exit_price: Decimal = None, fee_profile: dict = None, position_qty: Decimal = None, target_total: Decimal = None):
    market_info = get_market_status_info_for_sell(ticker, context="ensure_target_order")
    status = str(market_info.get("status", "")).lower()
    if bucket.get("market_terminal", False) or (not market_info.get("exists", True)) or status in {"closed", "settled", "determined", "not_found"}:
        mark_market_terminal(ticker, f"status:{status or 'not_found'}")
        return

    fee_profile = fee_profile or get_fee_profile_for_ticker(ticker, market_info)
    exit_price = snap_exit_price_to_market_tick(ticker, side, parse_decimal(exit_price if exit_price is not None else SELL_PRICE, str(SELL_PRICE)), market_info=market_info)
    position_qty_for_guard = parse_decimal(position_qty if position_qty is not None else bucket.get("last_known_position_fp", "0"), "0").quantize(Decimal("0.00"))
    target_total_for_guard = parse_decimal(target_total if target_total is not None else (parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0") + parse_decimal(desired_remaining, "0")), "0").quantize(Decimal("0.00"))

    def _sell_fee_guard(qty, is_taker: bool, context: str):
        guard = sell_order_fee_guard_state(
            ticker, side, qty, is_taker=is_taker, profile=fee_profile, exit_price=exit_price,
            bucket=bucket, position_qty=position_qty_for_guard, target_total=target_total_for_guard,
        )
        if guard.get("remainder_after_recovery_rescue"):
            LOGGER.warning(
                "RemainderAfterRecovery guard active | context=%s | ticker=%s | side=%s | qty=%s | cum_filled=%s | base_target=%s | group_net_cents=%s | incremental_net_cents=%s",
                context, ticker, side, qty_str(parse_decimal(qty, "0")), guard.get("cum_filled_fp"), guard.get("base_target_total_fp"),
                money_str((guard.get("group_estimate") or {}).get("net_cents", Decimal("0"))),
                money_str((guard.get("estimate") or {}).get("net_cents", Decimal("0"))),
            )
        return guard

    if desired_remaining < MIN_ORDER_QTY_FP:
        if active_order and active_order.get("order_id"):
            LOGGER.info("Cancel managed order because remaining target is below minimum | %s | %s | desired=%s | min=%s", ticker, active_order["order_id"], qty_str(desired_remaining), qty_str(MIN_ORDER_QTY_FP))
            if not DRY_RUN:
                cancel_order(active_order["order_id"], order=active_order)
        bucket["active_order_id"] = None
        bucket["active_order_accounted_fill_fp"] = "0.00"
        reset_error_streak(bucket)
        return

    if active_order and active_order.get("order_id") and HEDGE_2C_ONLY_MODE:
        compliant, hedge_reason = active_order_hedge_compliant(active_order, side, exit_price)
        if not compliant:
            LOGGER.warning(
                "HedgeOrderGuard replacing non-compliant active managed sell | ticker=%s | side=%s | order_id=%s | reason=%s",
                ticker, side, active_order.get("order_id"), hedge_reason,
            )
            write_hedge_order_guard_report(
                "active_order_replaced", ticker=ticker, side=side, qty=desired_remaining, exit_price=exit_price,
                api_version=order_api_version_from_order(active_order),
                body={
                    "side": active_order.get("book_side") or active_order.get("v2_side") or active_order.get("order_side") or active_order.get("side"),
                    "price": active_order.get("price") or active_order.get("yes_price_dollars") or active_order.get("no_price_dollars"),
                    "client_order_id": active_order.get("client_order_id", ""),
                },
                reason=hedge_reason,
                context="active_order_compliance",
            )
            if not DRY_RUN:
                cancel_order(active_order["order_id"], order=active_order)
            bucket["active_order_id"] = None
            # Preserve already-accounted fills; only clear the resting order pointer.
            bucket["active_order_accounted_fill_fp"] = contracts_str(parse_decimal(active_order.get("fill_count_fp", bucket.get("active_order_accounted_fill_fp", "0.00")), "0"))
            active_order = None

    # Do not create, increase, or keep a too-small order if order-level math cannot clear fees.
    resting_guard = _sell_fee_guard(desired_remaining, is_taker=False, context="resting-target")
    if FEE_GUARD_ENABLED and not resting_guard["allowed"]:
        log_fee_guard(bucket, resting_guard, "resting-target")
        record_sell_placement_event(
            "blocked", ticker, side, desired_remaining, "good_till_canceled", True,
            exit_price=exit_price, api_version=ORDER_API_VERSION, context="fee_guard_resting_target",
            error="FeeGuard BLOCK: " + "; ".join(resting_guard.get("reasons", [])),
            note="desired 2c recovery order blocked before placement",
        )
        if active_order and active_order.get("order_id"):
            current_remaining = parse_decimal(active_order.get("remaining_count_fp", "0.00"), "0")
            current_guard = _sell_fee_guard(current_remaining, is_taker=False, context="current-residual")
            if not current_guard["allowed"]:
                preserve_residual, preserve_reason = should_preserve_partial_fill_residual_order(ticker, side, active_order, bucket, fee_profile, exit_price)
                if preserve_residual:
                    LOGGER.warning(
                        "Preserving partial-fill residual managed sell instead of canceling naked inventory | ticker=%s | order_id=%s | remaining=%s | reason=%s",
                        ticker, active_order["order_id"], qty_str(current_remaining), preserve_reason,
                    )
                    record_sell_placement_event(
                        "preserved", ticker, side, current_remaining, "good_till_canceled", True,
                        exit_price=exit_price, api_version=ORDER_API_VERSION, context="partial_fill_residual_preserve",
                        order=active_order, error="FeeGuard current residual blocked but original recovery order was already live",
                        note=preserve_reason,
                    )
                    reset_error_streak(bucket)
                    return
                LOGGER.info("Cancel managed order because fee guard blocks current remaining | ticker=%s | order_id=%s | remaining=%s", ticker, active_order["order_id"], qty_str(current_remaining))
                if not DRY_RUN:
                    cancel_order(active_order["order_id"], order=active_order)
                bucket["active_order_id"] = None
                bucket["active_order_accounted_fill_fp"] = "0.00"
        return
    else:
        log_fee_guard(bucket, resting_guard, "resting-target")

    try:
        queue_exit_filled = maybe_take_sell_queue_profitable_bid(
            ticker=ticker,
            side=side,
            qty=desired_remaining,
            active_order=active_order,
            bucket=bucket,
            orderbook_cache=orderbook_cache or {},
            exit_price=exit_price,
            fee_profile=fee_profile,
            market_info=market_info,
            queue_positions_by_order=queue_positions_by_order or {},
        )
        if queue_exit_filled > 0:
            desired_remaining = max_decimal(Decimal("0"), desired_remaining - queue_exit_filled).quantize(Decimal("0.00"))
            active_order = None
            if desired_remaining < MIN_ORDER_QTY_FP:
                bucket["active_order_id"] = None
                bucket["active_order_accounted_fill_fp"] = "0.00"
                reset_error_streak(bucket)
                return
        elif active_order and not bucket.get("active_order_id"):
            active_order = None
    except Exception as e:
        LOGGER.warning("SellQueueExit profitable bid check/order failed for %s: %s", ticker, e)

    try:
        urgent_filled = maybe_take_urgent_profitable_bid(
            ticker=ticker,
            side=side,
            qty=desired_remaining,
            active_order=active_order,
            bucket=bucket,
            orderbook_cache=orderbook_cache or {},
            exit_price=exit_price,
            fee_profile=fee_profile,
            market_info=market_info,
        )
        if urgent_filled > 0:
            desired_remaining = max_decimal(Decimal("0"), desired_remaining - urgent_filled).quantize(Decimal("0.00"))
            active_order = None
            if desired_remaining < MIN_ORDER_QTY_FP:
                bucket["active_order_id"] = None
                bucket["active_order_accounted_fill_fp"] = "0.00"
                reset_error_streak(bucket)
                return
        elif active_order and not bucket.get("active_order_id"):
            active_order = None
    except Exception as e:
        LOGGER.warning("Urgent bid exit check/order failed for %s: %s", ticker, e)

    if active_order:
        maybe_log_queue_position(ticker, bucket, active_order, queue_positions_by_order)
        current_remaining = parse_decimal(active_order.get("remaining_count_fp", "0.00"), "0")
        current_fill = parse_decimal(active_order.get("fill_count_fp", "0.00"), "0")
        current_price = order_exit_price(active_order, side)
        order_id = active_order.get("order_id")
        client_order_id = active_order.get("client_order_id", "")
        if desired_remaining <= current_remaining:
            bucket.pop("queue_gap_since_ts", None)
            bucket["queue_gap_age_seconds"] = 0
        if current_remaining == desired_remaining and price_str(current_price) == price_str(exit_price):
            reset_error_streak(bucket)
            return
        if desired_remaining < current_remaining:
            sched = smart_amend_scheduler_decision(ticker, side, order_id, current_remaining, desired_remaining, current_price, exit_price, active_order=active_order, bucket=bucket, market_info=market_info, mutation="decrease", context="sell_repair_decrease")
            if not sched.get("execute", True):
                LOGGER.info("Smart Amend Scheduler deferred decrease | ticker=%s | order_id=%s | reason=%s", ticker, order_id, sched.get("reason"))
                reset_error_streak(bucket)
                return
            LOGGER.info("Decrease managed order | ticker=%s | order_id=%s | old_remaining=%s | new_remaining=%s", ticker, order_id, qty_str(current_remaining), qty_str(desired_remaining))
            if DRY_RUN:
                order = active_order
            elif active_order_is_v2(active_order) or (ORDER_API_VERSION == "v2" and not ORDER_API_LEGACY_FALLBACK):
                if price_str(current_price) == price_str(exit_price):
                    LOGGER.info("V2 decrease remaining | ticker=%s | order_id=%s", ticker, order_id)
                    try:
                        order = decrease_order_v2_to(order_id, desired_remaining, active_order=active_order, ticker=ticker, side=side, exit_price=exit_price)
                    except MutationOutcomeUnresolvedError as decrease_error:
                        LOGGER.error("V2 decrease outcome ambiguous; preserving current order and deferring repair | ticker=%s | order_id=%s | mutation_id=%s | error=%s", ticker, order_id, decrease_error.mutation_id, decrease_error)
                        record_mutation_outcome("decrease", "repair_deferred_fail_closed", decrease_error.mutation_id, ticker=ticker, side=side, order_id=order_id, desired_remaining_fp=qty_str(desired_remaining))
                        return
                    except Exception as decrease_error:
                        LOGGER.warning("V2 decrease failed definitively; falling back to amend/recreate | ticker=%s | order_id=%s | error=%s", ticker, order_id, decrease_error)
                        order = amend_or_recreate_v2_order(order_id, client_order_id, ticker, side, current_fill + desired_remaining, desired_remaining, exit_price, bucket)
                else:
                    LOGGER.info("V2 amend/decrease with price change | ticker=%s | order_id=%s", ticker, order_id)
                    order = amend_or_recreate_v2_order(order_id, client_order_id, ticker, side, current_fill + desired_remaining, desired_remaining, exit_price, bucket)
            else:
                order = decrease_order_to(order_id, desired_remaining)
            cache_managed_order_after_write(bucket, order, ticker, side, qty=desired_remaining, exit_price=exit_price, api_version=order_api_version_from_order(order), context="ensure_target_order_decrease")
            reset_error_streak(bucket)
            return
        if desired_remaining > current_remaining and PRESERVE_QUEUE_ON_INCREASE and price_str(current_price) == price_str(exit_price):
            repair_due, gap_age, coverage_pct, gap_reason = queue_gap_repair_due(bucket, desired_remaining, current_remaining)
            gap_qty = max_decimal(Decimal("0"), desired_remaining - current_remaining).quantize(Decimal("0.00"))
            if not repair_due:
                LOGGER.info(
                    "Preserve queue priority; leaving managed order unchanged temporarily | ticker=%s | order_id=%s | current_remaining=%s | desired_remaining=%s | gap=%s | coverage_pct=%s | gap_age=%ss | reason=%s",
                    ticker, order_id, qty_str(current_remaining), qty_str(desired_remaining), qty_str(gap_qty), cents4_str(coverage_pct), gap_age, gap_reason,
                )
                record_sell_coverage_event(
                    ticker, side,
                    position_qty=bucket.get("last_known_position_fp", "0.00"),
                    target_total=desired_remaining + parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0"),
                    desired_remaining=desired_remaining,
                    active_order=active_order,
                    bucket=bucket,
                    queue_positions_by_order=queue_positions_by_order,
                    exit_price=exit_price,
                    context="preserve_queue_gap",
                    note=f"{gap_reason}; preserving old queue before queue-gap repair",
                )
                reset_error_streak(bucket)
                return
            LOGGER.warning(
                "QueueGapRepair will amend upward after persistent undercoverage | ticker=%s | order_id=%s | current_remaining=%s | desired_remaining=%s | gap=%s | coverage_pct=%s | gap_age=%ss | reason=%s",
                ticker, order_id, qty_str(current_remaining), qty_str(desired_remaining), qty_str(gap_qty), cents4_str(coverage_pct), gap_age, gap_reason,
            )
            record_sell_coverage_event(
                ticker, side,
                position_qty=bucket.get("last_known_position_fp", "0.00"),
                target_total=desired_remaining + parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0"),
                desired_remaining=desired_remaining,
                active_order=active_order,
                bucket=bucket,
                queue_positions_by_order=queue_positions_by_order,
                exit_price=exit_price,
                context="queue_gap_repair_due",
                note=f"{gap_reason}; amending upward to restore target coverage",
            )
        new_max_fillable = current_fill + desired_remaining
        sched = smart_amend_scheduler_decision(ticker, side, order_id, current_remaining, desired_remaining, current_price, exit_price, active_order=active_order, bucket=bucket, market_info=market_info, mutation="amend", context="sell_repair_amend")
        if not sched.get("execute", True):
            LOGGER.info("Smart Amend Scheduler deferred amend | ticker=%s | order_id=%s | old_remaining=%s | desired_remaining=%s | reason=%s", ticker, order_id, qty_str(current_remaining), qty_str(desired_remaining), sched.get("reason"))
            reset_error_streak(bucket)
            return
        LOGGER.info("Amend managed order | ticker=%s | order_id=%s | old_remaining=%s | new_remaining=%s | new_price=%s", ticker, order_id, qty_str(current_remaining), qty_str(desired_remaining), price_str(exit_price))
        if DRY_RUN:
            order = active_order
        elif active_order_is_v2(active_order) or (ORDER_API_VERSION == "v2" and not ORDER_API_LEGACY_FALLBACK):
            LOGGER.info("V2 amend managed order | ticker=%s | order_id=%s", ticker, order_id)
            order = amend_or_recreate_v2_order(order_id, client_order_id, ticker, side, new_max_fillable, desired_remaining, exit_price, bucket)
        else:
            order = amend_order_count(order_id, client_order_id, ticker, side, new_max_fillable, exit_price=exit_price)
        cache_managed_order_after_write(bucket, order, ticker, side, qty=desired_remaining, exit_price=exit_price, api_version=order_api_version_from_order(order), context="ensure_target_order_amend")
        reset_error_streak(bucket)
        return

    remaining_to_place = desired_remaining
    if IOC_ENABLED and remaining_to_place > 0:
        try:
            if market_quality_blocks_taker(bucket):
                LOGGER.info("MarketQuality blocked taker-at-target | ticker=%s | score=%s | min_score=%s", ticker, bucket.get("market_quality_score"), MARKET_QUALITY_MIN_SCORE_FOR_TAKER)
                available, best_bid = Decimal("0"), None
            else:
                orderbook = (orderbook_cache or {}).get(ticker) or get_public_orderbook(ticker)
                available, best_bid = same_side_bid_liquidity(orderbook, side, exit_price)
            if available > 0:
                ioc_qty = min_decimal(remaining_to_place, available)
                ioc_guard = _sell_fee_guard(ioc_qty, is_taker=True, context="taker-at-target")
                if FEE_GUARD_ENABLED and not ioc_guard["allowed"]:
                    log_fee_guard(bucket, ioc_guard, "taker-at-target")
                else:
                    log_fee_guard(bucket, ioc_guard, "taker-at-target")
                    LOGGER.info("Taker-at-target | tif=%s | ticker=%s | side=%s | qty=%s | target=%s | best_bid=%s | visible_liquidity=%s",
                                TAKER_EXIT_TIF, ticker, side, qty_str(ioc_qty), price_str(exit_price), price_str(best_bid or Decimal("0")), qty_str(available))
                    if DRY_RUN:
                        filled_now = Decimal("0")
                    else:
                        ioc_resp = create_order_with_compat(ticker=ticker, side=side, qty=ioc_qty, tif=TAKER_EXIT_TIF, post_only=False, exit_price=exit_price)
                        register_managed_order(bucket, ioc_resp.get("order", {}))
                        filled_now = parse_decimal(ioc_resp.get("order", {}).get("fill_count_fp", "0.00"), "0")
                    if filled_now > 0:
                        cum = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0")
                        bucket["cum_filled_fp"] = contracts_str(cum + filled_now)
                        remaining_to_place = max_decimal(Decimal("0"), desired_remaining - filled_now)
                        LOGGER.info("Taker exit filled | ticker=%s | filled=%s | remaining_to_rest=%s", ticker, qty_str(filled_now), qty_str(remaining_to_place))
        except Exception as e:
            msg = str(e).lower()
            if "market closed" in msg or "market_not_found" in msg or "market terminal" in msg:
                mark_market_terminal(ticker, "ioc-terminal")
                LOGGER.info("Retiring terminal market after IOC check | %s", ticker)
                return
            LOGGER.warning("Taker-at-target check/order failed for %s: %s", ticker, e)

    if remaining_to_place < MIN_ORDER_QTY_FP:
        bucket["active_order_id"] = None
        bucket["active_order_accounted_fill_fp"] = "0.00"
        reset_error_streak(bucket)
        return

    if market_quality_blocks_new_resting(bucket):
        if SELL_PATH_WATCHDOG_BYPASS_MARKET_QUALITY_BLOCKS and (sell_path_watchdog_bucket_due(bucket) or not active_order):
            LOGGER.warning(
                "SellPathWatchdog bypassing MarketQuality block for protective 2c sell | ticker=%s | score=%s | min_score=%s | reasons=%s",
                ticker, bucket.get("market_quality_score"), MARKET_QUALITY_MIN_SCORE_FOR_NEW_RESTING, bucket.get("market_quality_reasons", ""),
            )
        else:
            LOGGER.warning("MarketQuality blocked new resting sell | ticker=%s | score=%s | min_score=%s | reasons=%s", ticker, bucket.get("market_quality_score"), MARKET_QUALITY_MIN_SCORE_FOR_NEW_RESTING, bucket.get("market_quality_reasons", ""))
            return

    place_guard = _sell_fee_guard(remaining_to_place, is_taker=False, context="place-resting")
    if FEE_GUARD_ENABLED and not place_guard["allowed"]:
        log_fee_guard(bucket, place_guard, "place-resting")
        record_sell_placement_event(
            "blocked", ticker, side, remaining_to_place, "good_till_canceled", True,
            exit_price=exit_price, api_version=ORDER_API_VERSION, context="fee_guard_place_resting",
            error="FeeGuard BLOCK: " + "; ".join(place_guard.get("reasons", [])),
            note="2c resting sell blocked before placement",
        )
        return
    else:
        log_fee_guard(bucket, place_guard, "place-resting")

    LOGGER.info("Place managed resting sell | ticker=%s | side=%s | qty=%s | price=%s", ticker, side, qty_str(remaining_to_place), price_str(exit_price))
    if DRY_RUN:
        bucket["active_order_id"] = "DRY_RUN_ORDER"
        bucket["active_order_accounted_fill_fp"] = "0.00"
    elif can_batch_create_v2_order("good_till_canceled", True):
        enqueue_batch_create_v2(ticker=ticker, side=side, qty=remaining_to_place, tif="good_till_canceled", post_only=True, exit_price=exit_price, bucket=bucket)
    else:
        try:
            resp = create_order_with_compat(ticker=ticker, side=side, qty=remaining_to_place, tif="good_till_canceled", post_only=True, exit_price=exit_price)
            order = cache_managed_order_after_write(bucket, resp.get("order", {}), ticker, side, qty=remaining_to_place, exit_price=exit_price, api_version=str(resp.get("order", {}).get("_api_version", "")), context="ensure_target_order_place_resting")
            LOGGER.info("Managed 2c hedge sell accepted | ticker=%s | side=%s | order_id=%s | remaining=%s | price=%s", ticker, side, order.get("order_id"), order.get("remaining_count_fp"), price_str(exit_price))
        except Exception as place_error:
            if not (POST_ONLY_CROSS_FALLBACK_ENABLED and post_only_cross_error(place_error)):
                raise

            fallback_guard = dict(_sell_fee_guard(remaining_to_place, is_taker=True, context="post-only-cross-fallback") or {})
            fallback_est = fallback_guard.get("estimate") or {}
            fallback_total_fees_cents = max(
                Decimal("0"),
                (
                    parse_decimal(fallback_est.get("exit_fee_dollars", "0"), "0")
                    + parse_decimal(fallback_est.get("entry_fee_dollars", "0"), "0")
                ) * Decimal("100"),
            )
            fallback_net_cents = parse_decimal(fallback_est.get("net_cents", "0"), "0")
            fallback_ratio_ok = (
                fallback_total_fees_cents <= 0
                or fallback_net_cents >= fallback_total_fees_cents * POST_ONLY_CROSS_FALLBACK_MIN_NET_TO_TOTAL_FEES_RATIO
            )
            fallback_reasons = list(fallback_guard.get("reasons", []))
            if not fallback_ratio_ok:
                fallback_reasons.append(
                    f"post_only_cross_fallback net_to_total_fees_ratio below {money_str(POST_ONLY_CROSS_FALLBACK_MIN_NET_TO_TOTAL_FEES_RATIO)}x "
                    f"(net_cents={money_str(fallback_net_cents)}, fees_cents={money_str(fallback_total_fees_cents)})"
                )
            fallback_allowed = bool(fallback_guard.get("allowed")) and fallback_ratio_ok
            if POST_ONLY_CROSS_FALLBACK_REQUIRE_FEE_GUARD and not fallback_allowed:
                fallback_guard["allowed"] = False
                fallback_guard["reasons"] = fallback_reasons
                fallback_guard["post_only_cross_fallback_total_modeled_fees_cents"] = fallback_total_fees_cents
                fallback_guard["post_only_cross_fallback_fee_ratio_ok"] = fallback_ratio_ok
                log_fee_guard(bucket, fallback_guard, "post-only-cross-fallback")
                bucket["last_post_only_cross_fallback_status"] = "blocked_fee_guard"
                bucket["last_post_only_cross_fallback_ts"] = now_ts()
                bucket["last_post_only_cross_fallback_reason"] = "; ".join(fallback_reasons)[:500]
                record_sell_placement_event(
                    "blocked", ticker, side, remaining_to_place, POST_ONLY_CROSS_FALLBACK_TIF, False,
                    exit_price=exit_price, api_version=ORDER_API_VERSION, context="post_only_cross_fallback_fee_guard",
                    error="FeeGuard BLOCK: " + "; ".join(fallback_reasons),
                    note="post-only order crossed; same-price non-post-only fallback withheld because all-taker economics did not clear",
                )
                LOGGER.warning(
                    "PostOnlyCross fallback blocked by FeeGuard | ticker=%s | side=%s | qty=%s | price=%s | net_cents=%s | modeled_fees_cents=%s | required_ratio=%sx | reasons=%s",
                    ticker, side, qty_str(remaining_to_place), price_str(exit_price), money_str(fallback_net_cents), money_str(fallback_total_fees_cents),
                    money_str(POST_ONLY_CROSS_FALLBACK_MIN_NET_TO_TOTAL_FEES_RATIO), "; ".join(fallback_reasons),
                )
                reset_error_streak(bucket)
                return

            fallback_guard["allowed"] = True
            fallback_guard["reasons"] = fallback_reasons
            fallback_guard["post_only_cross_fallback_total_modeled_fees_cents"] = fallback_total_fees_cents
            fallback_guard["post_only_cross_fallback_fee_ratio_ok"] = fallback_ratio_ok
            log_fee_guard(bucket, fallback_guard, "post-only-cross-fallback")
            LOGGER.warning(
                "PostOnlyCross retrying same exact 2c sell without post_only | tif=%s | ticker=%s | side=%s | qty=%s | net_cents=%s | modeled_fees_cents=%s",
                POST_ONLY_CROSS_FALLBACK_TIF, ticker, side, qty_str(remaining_to_place), money_str(fallback_net_cents), money_str(fallback_total_fees_cents),
            )
            record_sell_placement_event(
                "retry", ticker, side, remaining_to_place, POST_ONLY_CROSS_FALLBACK_TIF, False,
                exit_price=exit_price, api_version=ORDER_API_VERSION, context="post_only_cross_fallback",
                error=place_error, note="same exact 2c fallback after post-only cross; all-taker FeeGuard passed",
            )
            fallback_resp = create_order_with_compat(
                ticker=ticker, side=side, qty=remaining_to_place,
                tif=POST_ONLY_CROSS_FALLBACK_TIF, post_only=False, exit_price=exit_price,
            )
            fallback_order = cache_managed_order_after_write(
                bucket, fallback_resp.get("order", {}), ticker, side,
                qty=remaining_to_place, exit_price=exit_price,
                api_version=str(fallback_resp.get("order", {}).get("_api_version", "")),
                context="ensure_target_order_post_only_cross_fallback",
            )
            fallback_filled = parse_decimal(fallback_order.get("fill_count_fp", fallback_order.get("fill_count", "0.00")), "0")
            if fallback_filled > 0:
                cum = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0")
                bucket["cum_filled_fp"] = contracts_str(cum + fallback_filled)
            bucket["last_post_only_cross_fallback_status"] = "accepted"
            bucket["last_post_only_cross_fallback_ts"] = now_ts()
            bucket["last_post_only_cross_fallback_fill_fp"] = contracts_str(fallback_filled)
            bucket["last_post_only_cross_fallback_remaining_fp"] = qty_str(parse_decimal(fallback_order.get("remaining_count_fp", "0.00"), "0"))
            LOGGER.info(
                "PostOnlyCross 2c fallback accepted | ticker=%s | side=%s | order_id=%s | filled=%s | remaining=%s | price=%s",
                ticker, side, fallback_order.get("order_id"), qty_str(fallback_filled), fallback_order.get("remaining_count_fp"), price_str(exit_price),
            )
    reset_error_streak(bucket)


def run_once():
    maybe_check_network_transition(force=False, context="run_once_start")
    balance = get_balance()
    try:
        write_balance_precision_ledger(balance, context="run_once", force=False)
    except Exception as e:
        LOGGER.debug("Cycle balance precision ledger skipped: %s", e)
    current_balance_cents = balance.get("balance")
    STATE["meta"]["last_known_balance_cents"] = current_balance_cents
    STATE["meta"]["last_known_balance_dollars"] = balance.get("balance_dollars", "")
    maybe_refresh_endpoint_costs()
    maybe_refresh_series_fee_changes()
    if ORDER_GROUP_ENABLED:
        sync_order_group_status(force=False, reason="cycle")
    get_exchange_status()
    positions = get_all_positions()
    try:
        _meta = STATE.setdefault("meta", {})
        _meta["startup_position_load_ts"] = now_ts()
        _active_positions = 0
        _active_qty = Decimal("0")
        for _p in positions or []:
            if not isinstance(_p, dict):
                continue
            _qty = abs(parse_decimal(_p.get("position_fp", _p.get("position", "0")), "0"))
            if _qty > 0:
                _active_positions += 1
                _active_qty += _qty
        _meta["startup_position_row_count"] = len(positions or [])
        _meta["startup_active_position_count"] = _active_positions
        _meta["startup_active_position_qty_fp"] = qty_str(_active_qty)
    except Exception:
        pass
    resting_orders = get_all_resting_orders()
    try:
        STATE.setdefault("meta", {})["startup_order_load_ts"] = now_ts()
        STATE.setdefault("meta", {})["startup_resting_order_count"] = len(resting_orders or [])
    except Exception:
        pass
    register_live_managed_orders(resting_orders)
    drained_ws_count = drain_ws_events(live_resting_orders=resting_orders)
    positions = augment_positions_with_ws_hints(positions, context="run_once_post_ws_drain")
    fills_processed = sync_recent_fills(live_resting_orders=resting_orders)
    defer_settlement_sync_until_after_sell = bool(SETTLEMENT_SYNC_DEFER_UNTIL_AFTER_SELL)
    settlements_processed = 0
    if defer_settlement_sync_until_after_sell:
        STATE.setdefault("meta", {})["last_deferred_pre_sell_settlement_sync_ts"] = now_ts()
    else:
        settlements_processed = sync_recent_settlements()
        write_settlement_integrity_snapshot()
    grouped = build_managed_order_map(resting_orders)
    writes_allowed = exchange_writes_allowed() and user_data_writes_allowed()
    if writes_allowed:
        primary_by_key = cleanup_duplicate_managed_orders(grouped)
    else:
        primary_by_key = select_primary_managed_orders(grouped)
    adopt_primary_managed_orders(primary_by_key)
    live_resting_by_id = {o.get("order_id"): o for o in primary_by_key.values() if o.get("order_id")}
    first_cycle_sell_path = not bool(STATE.setdefault("meta", {}).get("live_startup_sla_first_sell_complete"))
    sell_first_startup_defer = bool(SELL_FIRST_PRIORITY_ENABLED and SELL_FIRST_DEFER_ANALYTICS_ON_FIRST_CYCLE and first_cycle_sell_path)
    if sell_first_startup_defer:
        LOGGER.info("SellFirstPriority skipping pre-sell hedge compliance report on first cycle; post-sell report will refresh after hedge management")
    else:
        write_hedge_compliance_sla_report(positions, primary_by_key, context="run_once_pre_sell", force=True, mutate=False)
    queue_positions_by_order = get_queue_positions([o.get("ticker") for o in primary_by_key.values() if o.get("ticker")], list(primary_by_key.values()))
    position_tickers_for_books = sorted({p.get("ticker") for p in positions if p.get("ticker")})
    if CANDLESTICK_SIGNAL_ENABLED and position_tickers_for_books:
        refresh_candlestick_signals(position_tickers_for_books)
    need_orderbook_cache = bool(position_tickers_for_books) and BATCH_ORDERBOOK_ENABLED and (IOC_ENABLED or ORDERBOOK_SIGNAL_ENABLED or DEAD_MARKET_ESCAPE_ENABLED or SELL_LIVENESS_ENABLED or SELL_QUEUE_EXIT_OPTIMIZER_ENABLED)
    orderbook_cache = get_multiple_orderbooks(position_tickers_for_books) if need_orderbook_cache else {}
    startup_ts = int(STATE.setdefault("meta", {}).get("last_startup_ts", 0) or 0)
    terminal_count = len([
        1 for key, bucket in STATE.setdefault("markets", {}).items()
        if not key.endswith("|_meta")
        and isinstance(bucket, dict)
        and bucket.get("market_terminal", False)
        and int(bucket.get("terminal_ts", 0) or 0) >= startup_ts
    ])
    maybe_log_cycle_heartbeat(
        positions_count=len(positions),
        managed_orders_count=len(live_resting_by_id),
        terminal_count=terminal_count,
        balance_cents=current_balance_cents,
    )
    write_daily_ledger_snapshot(
        positions_count=len(positions),
        managed_orders_count=len(live_resting_by_id),
        terminal_count=terminal_count,
        balance_cents=current_balance_cents,
        resting_orders=resting_orders,
    )
    for bucket in STATE.setdefault("markets", {}).values():
        if isinstance(bucket, dict):
            sync_tracked_order_fill(bucket, live_resting_by_id)

    sell_watchdog_pre = write_sell_path_watchdog_report(positions, primary_by_key, writes_allowed=writes_allowed, context="run_once_pre_sell", update_missing_since=True)
    sell_watchdog_active = bool((sell_watchdog_pre or {}).get("triggered_uncovered_count", 0))
    sell_first_position_defer = sell_first_should_defer_analytics(positions, primary_by_key, writes_allowed)
    sell_first_deferred_analytics = sell_first_position_defer or sell_watchdog_active or sell_first_startup_defer
    pre_sell_work_ran = False
    if sell_first_deferred_analytics:
        defer_context = "run_once_first_cycle" if sell_first_startup_defer else ("run_once_pre_sell_watchdog" if sell_watchdog_active else "run_once_pre_sell")
        STATE.setdefault("meta", {})["sell_first_last_defer_context"] = defer_context
        maybe_log_sell_first_defer(positions, primary_by_key, context=defer_context)
    else:
        pre_sell_work_ran = True
        cycle_pnl_context = maybe_write_pnl_attribution()
        maybe_write_buy_decision_feedback(pnl_context=cycle_pnl_context)
        maybe_write_buy_action_execution_audit()
        write_recovery_cycle_audit()
        write_recovery_timing_audit()
        write_recovery_scorecard()
        write_recovery_packet_ledger()
        write_recovery_fill_purity()
        write_recovery_repeat_leaderboard()
        write_realized_recovery_quality_circuit(context="run_once")
        write_asset_realized_roi_ledger(context="run_once")
        write_asset_roi_recovery_ladder(context="run_once")
        write_asset_exposure_governor(context="run_once")
        write_live_profit_safety_dashboard()
        maybe_write_quality_ledgers(resting_orders=resting_orders, positions=positions)
        write_sell_liveness_audit(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="pre_write_cycle")
    if sell_first_deferred_analytics:
        LOGGER.info("SellFirstPriority deferring pre-sell queue-exit optimizer report until after first sell-management pass")
    else:
        write_sell_queue_exit_optimizer_report(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="pre_sell_cycle")
    write_sell_path_doctor_report(positions, primary_by_key, writes_allowed=writes_allowed, context="pre_write_cycle", deferred_analytics=sell_first_deferred_analytics)

    positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, late_ws_drained, late_fills_processed = refresh_sell_inputs_after_prework(
        positions, resting_orders, primary_by_key, queue_positions_by_order, orderbook_cache, writes_allowed=writes_allowed, prework_ran=pre_sell_work_ran, context="run_once_before_sell_loop"
    )
    drained_ws_count += int(late_ws_drained or 0)
    fills_processed += int(late_fills_processed or 0)
    live_resting_by_id = {o.get("order_id"): o for o in primary_by_key.values() if isinstance(o, dict) and o.get("order_id")}

    _startup_meta = STATE.setdefault("meta", {})
    _startup_events = _startup_meta.get("live_startup_sla_events", {})
    if not isinstance(_startup_events, dict):
        _startup_events = {}
        _startup_meta["live_startup_sla_events"] = _startup_events
    if (not _startup_meta.get("live_startup_sla_first_sell_begin")) or ("first_sell_management_begin" not in _startup_events):
        _startup_meta["live_startup_sla_first_sell_begin"] = now_ts()
        write_live_startup_sla_report("first_sell_management_begin", "sell-management branch reached", force=True, extra={"writes_allowed": writes_allowed, "positions": len(positions), "managed_orders": len(primary_by_key)})

    if not writes_allowed:
        LOGGER.warning("Skipping live order writes this cycle because exchange status or user-data freshness guard is blocking writes")
        write_recovery_cycle_audit()
        write_recovery_timing_audit()
        write_recovery_scorecard()
        write_recovery_packet_ledger()
        write_recovery_fill_purity()
        write_private_stream_sla_report(force=False, context="cycle_writes_blocked")
        write_residual_sell_tuner_report(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="cycle_writes_blocked", force=False)
        write_queue_position_backfill_learner_report(positions, primary_by_key, queue_positions_by_order, context="cycle_writes_blocked", force=False)
        write_active_sell_coverage_autopruner_report(positions, primary_by_key, queue_positions_by_order, context="cycle_writes_blocked", force=False, mutate=True)
        prune_state()
        STATE["meta"]["last_heartbeat_ts"] = now_ts()
        maybe_save_state(STATE, critical=bool(fills_processed or settlements_processed or drained_ws_count), reason="cycle_writes_blocked")
        if not STATE.setdefault("meta", {}).get("live_startup_sla_first_sell_complete"):
            STATE.setdefault("meta", {})["live_startup_sla_first_sell_complete"] = now_ts()
            write_live_startup_sla_report("first_sell_management_complete", "sell-management branch completed with writes blocked", force=True)
        if LOCK_GUARD:
            LOCK_GUARD.write_metadata()
        return

    active_position_keys = set()
    for p in positions:
        ticker = p.get("ticker")
        position_fp = p.get("position_fp", "0.00")
        if not ticker:
            continue
        side = infer_side_from_position(ticker, position_fp)
        if side is None:
            LOGGER.debug("Skipping position with no inferable side: ticker=%s fp=%s", ticker, position_fp)
            continue
        key = market_key(ticker, side)
        active_position_keys.add(key)
        bucket = get_bucket(ticker, side)
        position_qty = abs(parse_decimal(position_fp, "0")).quantize(Decimal("0.00"))
        active_order = primary_by_key.get(key)
        try:
            note_post_fill_position_seen(ticker, side, position_qty, source=p.get("_source", "rest_position"))
        except Exception:
            pass

        if maybe_recheck_terminal_market(ticker, bucket):
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, bucket, position_qty)
            continue

        if precheck_terminal_on_disappeared_order(ticker, bucket, active_order_present=bool(active_order)):
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, bucket, position_qty)
            continue

        market_info = get_market_status_info_for_sell(ticker, context="run_once")
        status = str(market_info.get("status", "")).lower()
        if (not market_info.get("exists", True)) or status in {"closed", "settled", "determined", "not_found"}:
            if not bucket.get("market_terminal", False):
                LOGGER.info("Retiring terminal market | ticker=%s | status=%s", ticker, status or "not_found")
            mark_market_terminal(ticker, f"status:{status or 'not_found'}")
            refresh_market_snapshot(ticker, side, position_qty, None, suppress_logs=True)
            maybe_log_terminal_close_summary(ticker, bucket, position_qty)
            continue
        else:
            if bucket.get("market_terminal", False):
                clear_market_terminal(ticker)

        refresh_market_snapshot(ticker, side, position_qty, active_order)
        if ORDERBOOK_SIGNAL_ENABLED and side in {"yes", "no"}:
            try:
                orderbook_for_signal = (orderbook_cache or {}).get(ticker) or get_public_orderbook(ticker)
                attach_orderbook_signal_to_bucket(ticker, side, bucket, orderbook_for_signal, SELL_PRICE, market_info=market_info)
            except Exception as e:
                LOGGER.debug("Orderbook signal refresh failed | ticker=%s | error=%s", ticker, e)
        live_orders_serialized = bucket.get("last_known_open_orders", [])

        if now_ts() < int(bucket.get("cooldown_until_ts", 0) or 0):
            continue

        if in_post_fill_settle_window(bucket) and not active_order and not sell_path_watchdog_bucket_due(bucket):
            continue

        if "insufficient_balance" in str(bucket.get("last_error", "")).lower() and not should_retry_after_insufficient_balance(
            bucket, position_qty, current_balance_cents, live_orders_serialized
        ):
            continue

        update_market_quality(ticker, side, bucket, active_order=active_order, queue_positions_by_order=queue_positions_by_order, market_info=market_info)
        fee_profile = get_fee_profile_for_ticker(ticker, market_info)
        base_target_total = compute_target_total_qty(position_qty, bucket, exit_price=SELL_PRICE)
        cum_filled = parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0")
        base_desired_remaining = max_decimal(Decimal("0"), min_decimal(position_qty, base_target_total - cum_filled)).quantize(Decimal("0.00"))
        exit_price = dynamic_exit_price_for_bucket(ticker, side, bucket, max_decimal(position_qty, base_desired_remaining), fee_profile, is_taker=False, market_info=market_info)
        exit_price = maybe_residual_ladder_exit_price(ticker, side, bucket, position_qty, active_order, fee_profile, exit_price, market_info=market_info)
        target_total = compute_target_total_qty(position_qty, bucket, exit_price=exit_price)
        desired_remaining = max_decimal(Decimal("0"), min_decimal(position_qty, target_total - cum_filled)).quantize(Decimal("0.00"))
        desired_remaining = apply_market_quality_target(ticker, bucket, desired_remaining, position_qty, target_total=target_total)
        desired_remaining, target_total, full_coverage_reason = maybe_expand_target_to_full_position_coverage(
            ticker, side, desired_remaining, position_qty, target_total, bucket, fee_profile, exit_price, active_order=active_order
        )
        if full_coverage_reason:
            record_sell_coverage_event(
                ticker, side,
                position_qty=position_qty,
                target_total=target_total,
                desired_remaining=desired_remaining,
                active_order=active_order,
                bucket=bucket,
                queue_positions_by_order=queue_positions_by_order,
                exit_price=exit_price,
                context="full_position_2c_coverage",
                note=full_coverage_reason,
            )
        desired_remaining, target_total, residual_promote_reason = maybe_promote_residual_target_to_fee_safe(
            ticker, side, desired_remaining, position_qty, target_total, bucket, fee_profile, exit_price, active_order=active_order
        )
        if residual_promote_reason:
            record_sell_coverage_event(
                ticker, side,
                position_qty=position_qty,
                target_total=target_total,
                desired_remaining=desired_remaining,
                active_order=active_order,
                bucket=bucket,
                queue_positions_by_order=queue_positions_by_order,
                exit_price=exit_price,
                context="partial_fill_residual_promote",
                note=residual_promote_reason,
            )
        desired_remaining, target_total, full_fee_promote_reason = maybe_promote_fee_blocked_target_to_full_position(
            ticker, side, desired_remaining, position_qty, target_total, bucket, fee_profile, exit_price, active_order=active_order
        )
        if full_fee_promote_reason:
            record_sell_coverage_event(
                ticker, side,
                position_qty=position_qty,
                target_total=target_total,
                desired_remaining=desired_remaining,
                active_order=active_order,
                bucket=bucket,
                queue_positions_by_order=queue_positions_by_order,
                exit_price=exit_price,
                context="fee_safe_full_position_escalation",
                note=full_fee_promote_reason,
            )
        if HEDGE_2C_ONLY_MODE:
            strict_target_total = hedge_target_total_qty(position_qty, bucket)
            if HEDGE_BLOCK_OVER_TARGET_SELL_QTY and target_total > strict_target_total:
                LOGGER.warning("HedgeOrderGuard clamped target_total back to 40%% | ticker=%s | side=%s | old_target=%s | strict_target=%s", ticker, side, qty_str(target_total), qty_str(strict_target_total))
            target_total = strict_target_total
            desired_remaining = max_decimal(Decimal("0"), min_decimal(position_qty, target_total - parse_decimal(bucket.get("cum_filled_fp", "0.00"), "0"))).quantize(Decimal("0.00"))
            exit_price = HEDGE_EXIT_PRICE
        maybe_log_market_summary(ticker, bucket, position_qty, target_total, desired_remaining, active_order, queue_positions_by_order, exit_price=exit_price)
        record_sell_coverage_event(
            ticker, side,
            position_qty=position_qty,
            target_total=target_total,
            desired_remaining=desired_remaining,
            active_order=active_order,
            bucket=bucket,
            queue_positions_by_order=queue_positions_by_order,
            exit_price=exit_price,
            context="pre_ensure_target_order",
        )

        try:
            ensure_target_order(ticker, side, desired_remaining, active_order, bucket, queue_positions_by_order, orderbook_cache=orderbook_cache, exit_price=exit_price, fee_profile=fee_profile, position_qty=position_qty, target_total=target_total)
        except Exception as e:
            message = str(e)
            bucket["last_error"] = message
            lower = message.lower()
            if "market closed" in lower or "market_not_found" in lower or "market terminal" in lower:
                mark_market_terminal(ticker, "order-terminal")
                maybe_log_terminal_close_summary(ticker, bucket, position_qty)
                LOGGER.info("Retiring terminal market after order failure | ticker=%s | error=%s", ticker, message)
            elif "insufficient_balance" in lower:
                note_insufficient_balance_state(bucket, position_qty, current_balance_cents, live_orders_serialized)
                cooldown, streak = apply_short_balance_cooldown(bucket)
                LOGGER.error("Sell blocked for %s due to insufficient_balance; retrying in %ss when state changes or cooldown expires (streak=%s)", ticker, cooldown, streak)
            else:
                LOGGER.exception("Process failed | ticker=%s | position=%s | %s", ticker, position_fp, e)

    flush_batch_create_v2_queue()
    if not STATE.setdefault("meta", {}).get("live_startup_sla_first_sell_complete"):
        STATE.setdefault("meta", {})["live_startup_sla_first_sell_complete"] = now_ts()
        write_live_startup_sla_report("first_sell_management_complete", "sell-management branch completed", force=True, extra={"positions": len(positions), "active_position_keys": len(active_position_keys)})
    maybe_post_write_sell_verify(positions)
    primary_by_key = merge_synthetic_orders_for_positions(positions, primary_by_key, context="run_once_after_sell_writes")
    if defer_settlement_sync_until_after_sell:
        try:
            post_sell_settlements = sync_recent_settlements()
            settlements_processed += int(post_sell_settlements or 0)
            write_settlement_integrity_snapshot()
            if post_sell_settlements:
                LOGGER.info("Deferred settlement sync completed after sell-management pass | rows=%s", post_sell_settlements)
        except Exception as e:
            LOGGER.warning("Deferred post-sell settlement sync failed; continuing live loop | error=%s", e)
    write_post_fill_sell_sla_report(positions, primary_by_key, context="run_once_post_sell", force=True, mutate=True)
    write_residual_sell_tuner_report(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="run_once_post_sell", force=False)
    write_queue_position_backfill_learner_report(positions, primary_by_key, queue_positions_by_order, context="run_once_post_sell", force=False)
    write_active_sell_coverage_autopruner_report(positions, primary_by_key, queue_positions_by_order, context="run_once_post_sell", force=False, mutate=True)
    write_sell_path_watchdog_report(positions, primary_by_key, writes_allowed=writes_allowed, context="run_once_post_sell", update_missing_since=True)
    write_startup_to_sell_autorepair_dashboard(context="run_once_post_sell", positions=positions, primary_by_key=primary_by_key, force=True, mutate=True)
    write_live_launch_sentinel_report(context="run_once_post_sell", positions=positions, primary_by_key=primary_by_key, force=True, mutate=True)
    write_api_429_burst_circuit_report(context="run_once_post_sell", force=True, mutate=True)
    write_hedge_compliance_sla_report(positions, primary_by_key, context="run_once_post_sell", force=True, mutate=False)
    write_order_fill_visibility_drilldown_report(positions, primary_by_key, context="run_once_post_sell", force=True)
    write_hedge_fill_lifecycle_timeline_report(positions, primary_by_key, context="run_once_post_sell", force=True)
    write_current_build_freshness_gate_report(context="run_once_post_sell", force=True, mutate=True)
    if sell_first_deferred_analytics:
        cycle_pnl_context = maybe_write_pnl_attribution()
        maybe_write_buy_decision_feedback(pnl_context=cycle_pnl_context)
        maybe_write_buy_action_execution_audit()
        maybe_write_quality_ledgers(resting_orders=resting_orders, positions=positions)
        write_sell_liveness_audit(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="post_sell_deferred")
        write_sell_queue_exit_optimizer_report(positions, primary_by_key, queue_positions_by_order, orderbook_cache, context="post_sell_deferred")
        write_sell_path_doctor_report(positions, primary_by_key, writes_allowed=writes_allowed, context="post_sell_deferred", deferred_analytics=True)
    write_recovery_cycle_audit()
    write_recovery_timing_audit()
    write_recovery_scorecard()
    write_recovery_packet_ledger()
    write_recovery_fill_purity()
    write_recovery_repeat_leaderboard()
    write_realized_recovery_quality_circuit(context="run_once")
    write_asset_realized_roi_ledger(context="run_once")
    write_asset_roi_recovery_ladder(context="run_once")
    write_asset_exposure_governor(context="run_once")
    write_live_profit_safety_dashboard()
    cleanup_orphans(primary_by_key, active_position_keys)
    prune_state()
    STATE["meta"]["last_heartbeat_ts"] = now_ts()
    write_smart_amend_scheduler_report(force=False, context="cycle")
    write_lifecycle_capital_ladder_report(force=False, context="cycle")
    write_outcome_regime_rehab_report(force=False, context="cycle")
    write_macro_regime_advisory_report(force=False, context="cycle")
    write_state_io_doctor_snapshot(force=False, context="cycle")
    write_current_build_freshness_gate_report(context="cycle", force=False, mutate=True)
    write_startup_to_sell_autorepair_dashboard(context="cycle", force=False, mutate=True)
    write_live_launch_sentinel_report(context="cycle", positions=positions, primary_by_key=primary_by_key, force=False, mutate=True)
    write_api_429_burst_circuit_report(context="cycle", force=False, mutate=True)
    write_private_stream_sla_report(force=False, context="cycle")
    write_queue_position_backfill_learner_report(positions, primary_by_key, queue_positions_by_order, context="cycle", force=False)
    write_active_sell_coverage_autopruner_report(positions, primary_by_key, queue_positions_by_order, context="cycle", force=False, mutate=True)
    maybe_save_state(STATE, critical=bool(fills_processed or settlements_processed or drained_ws_count), reason="cycle_complete")
    maybe_log_pending_terminal_close_summaries()
    if LOCK_GUARD:
        LOCK_GUARD.write_metadata()




