def asset_for_ticker(ticker: str = "", series: str = "") -> str:
    raw = str(ticker or series or "").upper().strip()
    if not raw:
        return "UNKNOWN"
    token = ""
    if raw.startswith("KX") and "15M" in raw:
        token = raw[2:raw.index("15M")]
    elif raw.startswith("KX"):
        token = raw[2:].split("-", 1)[0]
    else:
        token = raw.split("-", 1)[0]
    token = "".join(ch for ch in token if ch.isalnum())
    known = {"BTC", "ETH", "SOL", "DOGE", "BNB", "XRP", "HYPE"}
    if token in known:
        return token
    if token.endswith("D") and token[:-1] in known:
        return token[:-1]
    for symbol in sorted(known, key=len, reverse=True):
        if symbol in token:
            return symbol
    return token or "UNKNOWN"


