def _asset_position_qty_from_state(asset: str) -> Decimal:
    qty = Decimal("0")
    for key, bucket in list(STATE.setdefault("markets", {}).items()):
        if not isinstance(bucket, dict):
            continue
        ticker = str(bucket.get("ticker") or str(key).split("|", 1)[0] or "")
        series = str(bucket.get("series_ticker") or "")
        if asset_for_ticker(ticker, series) != asset:
            continue
        if str(bucket.get("market_terminal", "0")).lower() in {"1", "true", "yes"}:
            continue
        live_pos = abs(parse_decimal(bucket.get("last_known_position_fp", "0"), "0"))
        qty += live_pos
    return qty.quantize(Decimal("0.00"), rounding=ROUND_FLOOR)


