def central_datetime_from_ts(ts: int):
    try:
        from zoneinfo import ZoneInfo
        return datetime.fromtimestamp(int(ts), tz=timezone.utc).astimezone(ZoneInfo("America/Chicago"))
    except Exception:
        dt_utc = datetime.fromtimestamp(int(ts), tz=timezone.utc)
        year = dt_utc.year
        dst_start_day = _nth_weekday_of_month(year, 3, 6, 2)
        dst_end_day = _nth_weekday_of_month(year, 11, 6, 1)
        dst_start_utc = datetime(year, 3, dst_start_day, 8, 0, tzinfo=timezone.utc)
        dst_end_utc = datetime(year, 11, dst_end_day, 7, 0, tzinfo=timezone.utc)
        offset = -5 if dst_start_utc <= dt_utc < dst_end_utc else -6
        label = "CDT" if offset == -5 else "CST"
        return dt_utc.astimezone(timezone(timedelta(hours=offset), label))


def ct_hour_session_for_ts(ts: int) -> tuple:
    dt = central_datetime_from_ts(int(ts or now_ts()))
    hour = int(dt.hour)
    hour_bucket = f"{hour:02d}:00-{((hour + 1) % 24):02d}:00"
    if 0 <= hour < 6:
        session = "overnight"
    elif 6 <= hour < 11:
        session = "morning"
    elif 11 <= hour < 16:
        session = "midday"
    elif 16 <= hour < 21:
        session = "evening"
    else:
        session = "late_evening"
    return hour_bucket, session


def _asset_session_empty_agg(asset: str, hour_bucket: str, session: str) -> dict:
    return {
        "asset_symbol": asset or "UNKNOWN",
        "ct_hour_bucket": hour_bucket or "unknown",
        "ct_session": session or "unknown",
        "after_fee_net_dollars": Decimal("0"),
        "capital_basis_dollars": Decimal("0"),
        "evidence_contracts_fp": Decimal("0"),
        "fill_contracts_fp": Decimal("0"),
        "settlement_contracts_fp": Decimal("0"),
        "fill_net_dollars": Decimal("0"),
        "settlement_net_dollars": Decimal("0"),
        "bad_count": 0,
        "sample_tickers": [],
    }


def _asset_session_add(aggs: dict, asset: str, hour_bucket: str, session: str, ticker: str, qty: Decimal, net: Decimal, basis: Decimal, source: str, bad: bool):
    if not asset:
        asset = "UNKNOWN"
    key = (asset, hour_bucket or "unknown", session or "unknown")
    agg = aggs.setdefault(key, _asset_session_empty_agg(asset, hour_bucket, session))
    qty = max_decimal(Decimal("0"), parse_decimal(qty, "0"))
    net = parse_decimal(net, "0")
    basis = max_decimal(Decimal("0"), parse_decimal(basis, "0"))
    agg["after_fee_net_dollars"] += net
    agg["capital_basis_dollars"] += basis
    agg["evidence_contracts_fp"] += qty
    if source == "fill":
        agg["fill_contracts_fp"] += qty
        agg["fill_net_dollars"] += net
    elif source == "settlement":
        agg["settlement_contracts_fp"] += qty
        agg["settlement_net_dollars"] += net
    if bad:
        agg["bad_count"] += 1
    if ticker and ticker not in agg["sample_tickers"]:
        agg["sample_tickers"].append(ticker)
        agg["sample_tickers"] = agg["sample_tickers"][:10]


def _asset_session_row_from_agg(agg: dict, now: int) -> dict:
    qty = parse_decimal(agg.get("evidence_contracts_fp", "0"), "0")
    net = parse_decimal(agg.get("after_fee_net_dollars", "0"), "0")
    basis = parse_decimal(agg.get("capital_basis_dollars", "0"), "0")
    bad = int(agg.get("bad_count", 0) or 0)
    net_pc = (net / max_decimal(qty, Decimal("1")) * Decimal("100")).quantize(Decimal("0.0001")) if qty > 0 else Decimal("0")
    roi_pct = (net / basis * Decimal("100")).quantize(Decimal("0.0001")) if basis > 0 else Decimal("0")
    if qty < ASSET_SESSION_PERFORMANCE_MIN_EVIDENCE_CONTRACTS_FP:
        band, action, mult, cap, block, reason = "insufficient_evidence", "no_session_adjustment_until_min_evidence", Decimal("1.00"), "aggressive", "0", f"evidence_{qty_str(qty)}_below_{qty_str(ASSET_SESSION_PERFORMANCE_MIN_EVIDENCE_CONTRACTS_FP)}"
    elif net_pc <= ASSET_SESSION_PERFORMANCE_SEVERE_MAX_PC_CENTS or (net < 0 and bad > 0):
        band, action, mult, cap, block = "severe_loss", "pilot_shrink_new_buys_for_asset_hour", ASSET_SESSION_PERFORMANCE_SEVERE_MULTIPLIER, "pilot", "1" if ASSET_SESSION_PERFORMANCE_BLOCK_SEVERE else "0"
        reason = f"net_pc_{cents4_str(net_pc)}_net_{money6_str(net)}_bad_{bad}"
    elif net_pc <= ASSET_SESSION_PERFORMANCE_CAUTION_MAX_PC_CENTS or net < 0:
        band, action, mult, cap, block = "caution_weak", "shrink_or_downgrade_new_buys_for_asset_hour", ASSET_SESSION_PERFORMANCE_CAUTION_MULTIPLIER, "normal", "0"
        reason = f"net_pc_{cents4_str(net_pc)}_net_{money6_str(net)}"
    elif net_pc >= ASSET_SESSION_PERFORMANCE_STRONG_MIN_PC_CENTS and net > 0:
        band, action, mult, cap, block = "strong_positive", "allow_asset_hour_toward_base_cap", ASSET_SESSION_PERFORMANCE_STRONG_MULTIPLIER, "aggressive", "0"
        reason = f"net_pc_{cents4_str(net_pc)}_net_{money6_str(net)}"
    else:
        band, action, mult, cap, block, reason = "neutral", "no_session_adjustment", Decimal("1.00"), "aggressive", "0", f"net_pc_{cents4_str(net_pc)}"
    mult = min(max_decimal(Decimal("0"), mult), ASSET_SESSION_PERFORMANCE_MAX_FINAL_SIZE_MULTIPLIER).quantize(Decimal("0.0001"))
    return {
        "snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID,
        "asset_symbol": agg.get("asset_symbol", "UNKNOWN"), "ct_hour_bucket": agg.get("ct_hour_bucket", "unknown"), "ct_session": agg.get("ct_session", "unknown"),
        "session_band": band, "session_action": action, "size_multiplier": str(mult), "level_cap": cap, "candidate_block": block,
        "after_fee_net_dollars": money6_str(net), "capital_basis_dollars": money6_str(basis), "roi_on_basis_pct": cents4_str(roi_pct), "net_per_contract_cents": cents4_str(net_pc),
        "evidence_contracts_fp": qty_str(qty), "fill_contracts_fp": qty_str(agg.get("fill_contracts_fp", Decimal("0"))), "settlement_contracts_fp": qty_str(agg.get("settlement_contracts_fp", Decimal("0"))),
        "fill_net_dollars": money6_str(agg.get("fill_net_dollars", Decimal("0"))), "settlement_net_dollars": money6_str(agg.get("settlement_net_dollars", Decimal("0"))),
        "bad_count": bad, "sample_tickers": ",".join(agg.get("sample_tickers", [])[:10]), "reason": reason,
    }


def build_asset_session_performance_payload(context: str = "snapshot") -> dict:
    now = now_ts()
    if not ASSET_SESSION_PERFORMANCE_LEDGER_ENABLED:
        return {"snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID, "enabled": False, "row_count": 0, "rows": [], "rows_by_asset_hour": {}, "rows_by_asset_session": {}}
    lookback_seconds = int(max_decimal(Decimal("0"), ASSET_SESSION_PERFORMANCE_LOOKBACK_DAYS) * Decimal("86400"))
    cutoff = now - lookback_seconds if lookback_seconds > 0 else 0
    aggs = {}
    for row in _read_csv_rows(FILL_LEDGER_CSV_PATH, max_rows=75000):
        ts = unix_ts_from_any(row.get("fill_ts") or row.get("processed_ts"), default=0)
        if not ts or (cutoff and ts < cutoff):
            continue
        ticker = str(row.get("ticker", "")).strip()
        asset = asset_for_ticker(ticker, row.get("series_ticker", ""))
        hour_bucket, session = ct_hour_session_for_ts(ts)
        qty = parse_decimal(row.get("count_fp", "0"), "0")
        net = parse_decimal(row.get("net_dollars", "0"), "0")
        basis = parse_decimal(row.get("basis_dollars", "0"), "0")
        if basis <= 0:
            basis = qty * BUY_PRICE
        notes = str(row.get("notes", "")).lower()
        bad = (net < 0) or ("below_min_net" in notes) or ("bad" in notes)
        _asset_session_add(aggs, asset, hour_bucket, session, ticker, qty, net, basis, "fill", bad)
    settlement_rows = _read_csv_rows(SETTLEMENT_LEDGER_CSV_PATH, max_rows=75000)
    if SETTLEMENT_DEDUPE_FOR_DAILY_GOAL and settlement_rows:
        settlement_rows, _dupes = settlement_deduped_rows(settlement_rows)
    for row in settlement_rows:
        ts = unix_ts_from_any(row.get("settled_ts") or row.get("processed_ts"), default=0)
        if not ts or (cutoff and ts < cutoff):
            continue
        ticker = str(row.get("ticker", "")).strip()
        asset = asset_for_ticker(ticker, row.get("series_ticker", row.get("event_ticker", "")))
        hour_bucket, session = ct_hour_session_for_ts(ts)
        qty = parse_decimal(row.get("count_fp", "0"), "0")
        net = parse_decimal(row.get("settlement_net_dollars", "0"), "0")
        basis = parse_decimal(row.get("basis_dollars", "0"), "0")
        if basis <= 0:
            basis = qty * BUY_PRICE
        bad = str(row.get("bad_settlement", "0")).lower() in {"1", "true", "yes"} or net < 0
        _asset_session_add(aggs, asset, hour_bucket, session, ticker, qty, net, basis, "settlement", bad)
    rows = [_asset_session_row_from_agg(agg, now) for agg in aggs.values()]
    rows.sort(key=lambda r: (r.get("asset_symbol", ""), r.get("ct_hour_bucket", ""), parse_decimal(r.get("net_per_contract_cents", "0"), "0")))
    rows_by_asset_hour = {f"{r.get('asset_symbol','UNKNOWN')}|{r.get('ct_hour_bucket','unknown')}": r for r in rows}
    session_aggs = {}
    for row in rows:
        key = (row.get("asset_symbol", "UNKNOWN"), row.get("ct_session", "unknown"))
        agg = session_aggs.setdefault(key, _asset_session_empty_agg(key[0], "session", key[1]))
        agg["after_fee_net_dollars"] += parse_decimal(row.get("after_fee_net_dollars", "0"), "0")
        agg["capital_basis_dollars"] += parse_decimal(row.get("capital_basis_dollars", "0"), "0")
        agg["evidence_contracts_fp"] += parse_decimal(row.get("evidence_contracts_fp", "0"), "0")
        agg["fill_contracts_fp"] += parse_decimal(row.get("fill_contracts_fp", "0"), "0")
        agg["settlement_contracts_fp"] += parse_decimal(row.get("settlement_contracts_fp", "0"), "0")
        agg["fill_net_dollars"] += parse_decimal(row.get("fill_net_dollars", "0"), "0")
        agg["settlement_net_dollars"] += parse_decimal(row.get("settlement_net_dollars", "0"), "0")
        agg["bad_count"] += int(row.get("bad_count", 0) or 0)
        for t in str(row.get("sample_tickers", "")).split(","):
            if t and t not in agg["sample_tickers"]:
                agg["sample_tickers"].append(t)
                agg["sample_tickers"] = agg["sample_tickers"][:10]
    session_rows = []
    for agg in session_aggs.values():
        r = _asset_session_row_from_agg(agg, now)
        r["ct_hour_bucket"] = "session"
        session_rows.append(r)
    rows_by_asset_session = {f"{r.get('asset_symbol','UNKNOWN')}|{r.get('ct_session','unknown')}": r for r in session_rows}
    band_counts = {}
    current_hour, current_session = ct_hour_session_for_ts(now)
    current_rows = []
    for asset in sorted({r.get("asset_symbol", "UNKNOWN") for r in rows}):
        ctx = rows_by_asset_hour.get(f"{asset}|{current_hour}") or rows_by_asset_session.get(f"{asset}|{current_session}")
        if ctx:
            current_rows.append(ctx)
    for r in rows:
        band_counts[r.get("session_band", "unknown")] = band_counts.get(r.get("session_band", "unknown"), 0) + 1
    return {
        "snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID,
        "enabled": True, "context": context, "lookback_days": str(ASSET_SESSION_PERFORMANCE_LOOKBACK_DAYS),
        "current_ct_hour_bucket": current_hour, "current_ct_session": current_session, "row_count": len(rows),
        "band_counts": band_counts, "current_context_count": len(current_rows), "current_asset_count": len(current_rows),
        "current_severe_asset_count": sum(1 for r in current_rows if str(r.get("session_band", "")).lower() == "severe_loss"),
        "current_caution_asset_count": sum(1 for r in current_rows if str(r.get("session_band", "")).lower() == "caution_weak"),
        "settings": {
            "interval_seconds": ASSET_SESSION_PERFORMANCE_INTERVAL_SECONDS,
            "min_evidence_contracts_fp": str(ASSET_SESSION_PERFORMANCE_MIN_EVIDENCE_CONTRACTS_FP),
            "strong_min_pc_cents": str(ASSET_SESSION_PERFORMANCE_STRONG_MIN_PC_CENTS),
            "caution_max_pc_cents": str(ASSET_SESSION_PERFORMANCE_CAUTION_MAX_PC_CENTS),
            "severe_max_pc_cents": str(ASSET_SESSION_PERFORMANCE_SEVERE_MAX_PC_CENTS),
            "block_severe": bool(ASSET_SESSION_PERFORMANCE_BLOCK_SEVERE),
            "sell_recovery_unblocked": True,
        },
        "rows_by_asset_hour": rows_by_asset_hour, "rows_by_asset_session": rows_by_asset_session,
        "current_rows": current_rows, "rows": rows,
    }


def write_asset_session_performance_ledger(force: bool = False, context: str = "periodic") -> dict:
    if not ASSET_SESSION_PERFORMANCE_LEDGER_ENABLED:
        return {"enabled": False, "rows": [], "rows_by_asset_hour": {}, "rows_by_asset_session": {}}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_asset_session_performance_ts", 0) or 0) < max(15, ASSET_SESSION_PERFORMANCE_INTERVAL_SECONDS):
        return meta.get("last_asset_session_performance", {}) or {}
    payload = build_asset_session_performance_payload(context=context)
    meta["last_asset_session_performance_ts"] = now
    meta["last_asset_session_performance"] = payload
    rows = payload.get("rows", []) or []
    atomic_write_json(ASSET_SESSION_PERFORMANCE_LATEST_JSON_PATH, payload)
    atomic_write_csv(ASSET_SESSION_PERFORMANCE_LATEST_CSV_PATH, ASSET_SESSION_PERFORMANCE_FIELDS, rows or [{k: "" for k in ASSET_SESSION_PERFORMANCE_FIELDS}])
    for row in rows:
        append_csv_row(ASSET_SESSION_PERFORMANCE_HISTORY_CSV_PATH, ASSET_SESSION_PERFORMANCE_FIELDS, row)
    lines = [
        "Kalshi 15m 2c Sell Bot - Asset Session Performance",
        "=======================================================",
        f"Generated CT : {central_time_iso_from_ts(payload.get('snapshot_ts', now))}",
        f"Build ID     : {BUILD_ID}",
        f"Current CT   : hour={payload.get('current_ct_hour_bucket')} session={payload.get('current_ct_session')}",
        f"Rows         : {payload.get('row_count', 0)} / bands={payload.get('band_counts', {})}",
        "Policy       : buy-size/time-of-day overlay only; sell/recovery remains unblocked",
        "",
    ]
    for row in payload.get("current_rows", [])[:12]:
        lines.append(f"{row.get('asset_symbol')} {row.get('ct_hour_bucket')} {row.get('ct_session')}: band={row.get('session_band')} mult={row.get('size_multiplier')} net={row.get('after_fee_net_dollars')} pc={row.get('net_per_contract_cents')} qty={row.get('evidence_contracts_fp')} reason={row.get('reason')}")
    os.makedirs(os.path.dirname(ASSET_SESSION_PERFORMANCE_LATEST_TXT_PATH) or ".", exist_ok=True)
    with open(ASSET_SESSION_PERFORMANCE_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
        f.write("\n".join(lines))
    return payload


def _session_outcome_review_rows(session_payload: dict, now: int) -> list:
    if not isinstance(session_payload, dict):
        return []
    top_n = max(1, int(ASSET_SESSION_OUTCOME_REVIEW_TOP_N or 8))
    rows = [dict(r) for r in (session_payload.get("rows", []) or []) if isinstance(r, dict)]
    current_rows = [dict(r) for r in (session_payload.get("current_rows", []) or []) if isinstance(r, dict)]
    session_rows = [dict(r) for r in (session_payload.get("rows_by_asset_session", {}) or {}).values() if isinstance(r, dict)] if isinstance(session_payload.get("rows_by_asset_session", {}), dict) else []

    def score(row):
        return parse_decimal(row.get("net_per_contract_cents", "0"), "0")

    def wrap(scope: str, rank: int, row: dict, recommended_use: str) -> dict:
        return {
            "snapshot_ts": now,
            "utc_day": utc_day_from_ts(now),
            "instance": INSTANCE_NAME,
            "build_id": BUILD_ID,
            "scope": scope,
            "rank": rank,
            "asset_symbol": row.get("asset_symbol", "UNKNOWN"),
            "ct_hour_bucket": row.get("ct_hour_bucket", ""),
            "ct_session": row.get("ct_session", ""),
            "session_band": row.get("session_band", ""),
            "after_fee_net_dollars": row.get("after_fee_net_dollars", ""),
            "net_per_contract_cents": row.get("net_per_contract_cents", ""),
            "roi_on_basis_pct": row.get("roi_on_basis_pct", ""),
            "evidence_contracts_fp": row.get("evidence_contracts_fp", ""),
            "bad_count": row.get("bad_count", ""),
            "recommended_use": recommended_use,
            "reason": row.get("reason", ""),
            "sample_tickers": row.get("sample_tickers", ""),
        }

    out = []
    current_worst = sorted(current_rows, key=score)[:top_n]
    current_best = sorted(current_rows, key=score, reverse=True)[:top_n]
    global_worst = sorted(rows, key=score)[:top_n]
    global_best = sorted(rows, key=score, reverse=True)[:top_n]
    session_worst = sorted(session_rows, key=score)[:top_n]
    session_best = sorted(session_rows, key=score, reverse=True)[:top_n]
    for scope, selected, use in [
        ("current_hour_worst", current_worst, "shrink_or_pilot_weak_current_asset_hour"),
        ("current_hour_best", current_best, "prefer_when_all_core_gates_pass"),
        ("all_hours_worst", global_worst, "avoid_or_pilot_until_2c_recovery_improves"),
        ("all_hours_best", global_best, "ranking_boost_only_after_core_gates_pass"),
        ("session_worst", session_worst, "avoid_or_pilot_weak_session"),
        ("session_best", session_best, "session_ranking_boost_after_core_gates_pass"),
    ]:
        for idx, row in enumerate(selected, 1):
            out.append(wrap(scope, idx, row, use))
    return out


def build_session_outcome_review_payload(context: str = "snapshot") -> dict:
    now = now_ts()
    if not ASSET_SESSION_OUTCOME_REVIEW_ENABLED:
        return {"snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID, "enabled": False, "rows": []}
    meta = STATE.setdefault("meta", {})
    session_payload = meta.get("last_asset_session_performance", {}) if isinstance(meta.get("last_asset_session_performance", {}), dict) else {}
    if not session_payload or now - int(session_payload.get("snapshot_ts", 0) or 0) > max(30, ASSET_SESSION_PERFORMANCE_INTERVAL_SECONDS * 2):
        session_payload = write_asset_session_performance_ledger(force=True, context="session_outcome_review")
    rows = _session_outcome_review_rows(session_payload, now)
    current_worst = [r for r in rows if r.get("scope") == "current_hour_worst"]
    current_best = [r for r in rows if r.get("scope") == "current_hour_best"]
    current_severe = [r for r in current_worst if str(r.get("session_band", "")).lower() == "severe_loss"]
    payload = {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "enabled": True,
        "context": context,
        "current_ct_hour_bucket": session_payload.get("current_ct_hour_bucket", ""),
        "current_ct_session": session_payload.get("current_ct_session", ""),
        "top_n": max(1, int(ASSET_SESSION_OUTCOME_REVIEW_TOP_N or 8)),
        "current_severe_count": len(current_severe),
        "current_best_count": len(current_best),
        "row_count": len(rows),
        "policy": "review_panel_only; shapes operator review and dashboard; sell/recovery unblocked",
        "recommended_operator_note": "Prefer current-hour/session winners only after strict 2c, fee, recovery, L2, metadata, and API gates pass; weak current-hour assets should stay pilot-sized.",
        "rows": rows,
        "current_worst_rows": current_worst,
        "current_best_rows": current_best,
    }
    meta["last_session_outcome_review"] = payload
    return payload


def write_session_outcome_review_panel(force: bool = False, context: str = "periodic") -> dict:
    if not ASSET_SESSION_OUTCOME_REVIEW_ENABLED:
        return {"enabled": False, "rows": []}
    payload = build_session_outcome_review_payload(context=context)
    rows = payload.get("rows", []) or []
    atomic_write_json(ASSET_SESSION_OUTCOME_REVIEW_LATEST_JSON_PATH, payload)
    atomic_write_csv(ASSET_SESSION_OUTCOME_REVIEW_LATEST_CSV_PATH, ASSET_SESSION_OUTCOME_REVIEW_FIELDS, rows or [{k: "" for k in ASSET_SESSION_OUTCOME_REVIEW_FIELDS}])
    lines = [
        "Kalshi 15m 2c Sell Bot - Session Outcome Review",
        "==================================================",
        f"Generated CT : {central_time_iso_from_ts(payload.get('snapshot_ts', now_ts()))}",
        f"Build ID     : {BUILD_ID}",
        f"Current CT   : hour={payload.get('current_ct_hour_bucket')} session={payload.get('current_ct_session')}",
        f"Rows         : {payload.get('row_count', 0)} / current severe={payload.get('current_severe_count', 0)}",
        "Policy       : review/ranking panel only; sell/recovery remains unblocked",
        "",
        "Current-hour weakest:",
    ]
    for row in payload.get("current_worst_rows", [])[:max(1, int(ASSET_SESSION_OUTCOME_REVIEW_TOP_N or 8))]:
        lines.append(f"- {row.get('asset_symbol')} {row.get('ct_hour_bucket')} {row.get('ct_session')}: band={row.get('session_band')} pc={row.get('net_per_contract_cents')} net={row.get('after_fee_net_dollars')} qty={row.get('evidence_contracts_fp')} use={row.get('recommended_use')}")
    lines.append("")
    lines.append("Current-hour strongest:")
    for row in payload.get("current_best_rows", [])[:max(1, int(ASSET_SESSION_OUTCOME_REVIEW_TOP_N or 8))]:
        lines.append(f"- {row.get('asset_symbol')} {row.get('ct_hour_bucket')} {row.get('ct_session')}: band={row.get('session_band')} pc={row.get('net_per_contract_cents')} net={row.get('after_fee_net_dollars')} qty={row.get('evidence_contracts_fp')} use={row.get('recommended_use')}")
    os.makedirs(os.path.dirname(ASSET_SESSION_OUTCOME_REVIEW_LATEST_TXT_PATH) or ".", exist_ok=True)
    with open(ASSET_SESSION_OUTCOME_REVIEW_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
        f.write("\n".join(lines))
    return payload


def asset_session_context_for_candidate(ticker: str, series: str = "") -> dict:
    if not ASSET_SESSION_PERFORMANCE_LEDGER_ENABLED:
        return {}
    asset = asset_for_ticker(ticker, series)
    if not asset:
        return {}
    meta = STATE.setdefault("meta", {})
    snap = meta.get("last_asset_session_performance", {}) if isinstance(meta.get("last_asset_session_performance", {}), dict) else {}
    if (not snap) or now_ts() - int(snap.get("snapshot_ts", 0) or 0) > max(30, ASSET_SESSION_PERFORMANCE_INTERVAL_SECONDS * 2):
        snap = write_asset_session_performance_ledger(force=True, context="candidate")
    hour_bucket, session = ct_hour_session_for_ts(now_ts())
    rows_by_hour = snap.get("rows_by_asset_hour", {}) if isinstance(snap, dict) else {}
    rows_by_session = snap.get("rows_by_asset_session", {}) if isinstance(snap, dict) else {}
    ctx = rows_by_hour.get(f"{asset}|{hour_bucket}") if isinstance(rows_by_hour, dict) else None
    if ctx:
        out = dict(ctx); out["context_source"] = "hour"; return out
    ctx = rows_by_session.get(f"{asset}|{session}") if isinstance(rows_by_session, dict) else None
    if ctx:
        out = dict(ctx); out["context_source"] = "session"; out["ct_hour_bucket"] = hour_bucket; return out
    return {"asset_symbol": asset, "ct_hour_bucket": hour_bucket, "ct_session": session, "session_band": "insufficient_evidence", "session_action": "no_session_history_for_current_block", "size_multiplier": "1.0000", "level_cap": "aggressive", "candidate_block": "0", "reason": "no_current_hour_or_session_history"}


def apply_asset_session_level_cap(level: str, level_reason: str, ctx: dict) -> tuple:
    if not ASSET_SESSION_PERFORMANCE_LEDGER_ENABLED or not ctx:
        return level, level_reason
    band = str(ctx.get("session_band", "")).lower()
    level_cap = str(ctx.get("level_cap", "")).lower()
    asset = ctx.get("asset_symbol", "UNKNOWN")
    if str(ctx.get("candidate_block", "0")).lower() in {"1", "true", "yes"}:
        return "deny", f"{level_reason};asset_session_performance_block({asset}:{band}:{ctx.get('ct_hour_bucket','')})"
    if level in {"aggressive", "normal"} and level_cap == "pilot" and ASSET_SESSION_PERFORMANCE_PILOT_ON_SEVERE:
        return "pilot", f"{level_reason};asset_session_performance_pilot_only({asset}:{band}:{ctx.get('ct_hour_bucket','')})"
    if level == "aggressive" and level_cap in {"normal", "pilot"} and ASSET_SESSION_PERFORMANCE_DOWNGRADE_AGGRESSIVE:
        return "normal", f"{level_reason};asset_session_performance_downgrade_aggressive({asset}:{band}:{ctx.get('ct_hour_bucket','')})"
    return level, level_reason


def apply_asset_session_caps(qty_cap: Decimal, cost_cap: Decimal, ctx: dict) -> tuple:
    if not ASSET_SESSION_PERFORMANCE_LEDGER_ENABLED or not ctx:
        return qty_cap, cost_cap
    mult = max_decimal(Decimal("0"), parse_decimal(ctx.get("size_multiplier", "1"), "1"))
    if mult >= Decimal("1"):
        return qty_cap, cost_cap
    return (
        (qty_cap * mult).quantize(Decimal("0.00"), rounding=ROUND_FLOOR),
        (cost_cap * mult).quantize(Decimal("0.000001"), rounding=ROUND_FLOOR),
    )

