def _csv_timestamp(row: dict) -> int:
    for key in ("snapshot_ts", "ts", "created_ts", "updated_ts", "source_snapshot_ts", "event_ts", "processed_ts", "fill_ts", "settled_ts"):
        val = row.get(key) if isinstance(row, dict) else None
        try:
            if val not in (None, ""):
                return int(float(str(val)))
        except Exception:
            continue
    return 0


