        "bad_fill_count", "queue_zero_checks", "queue_stagnation_checks", "queue_eta_band", "queue_eta_seconds",
        "queue_velocity_fp_per_min", "urgent_exit_attempts", "urgent_exit_filled_fp", "last_urgent_exit_price",
        "seconds_to_close", "same_side_best_bid_dollars", "same_side_best_bid_size_fp", "book_best_bid_dollars",
        "book_best_bid_size_fp", "book_depth_at_exit_fp", "book_depth_near_exit_fp", "book_level_count",
