def _markout_group_key(scope: str, asset: str, series: str, hour: str = "", session: str = "") -> str:
    return f"{scope}|{asset or 'UNKNOWN'}|{series or ''}|{hour or ''}|{session or ''}"


def _markout_blank_group(scope: str, asset: str, series: str, hour: str = "", session: str = "") -> dict:
    return {
        "scope": scope, "asset_symbol": asset or "UNKNOWN", "series_ticker": series or "", "ct_hour_bucket": hour or "", "ct_session": session or "",
        "event_count": 0, "unique_tickers": set(), "planned_qty_fp": Decimal("0"), "planned_cost_dollars": Decimal("0"),
        "markouts_by_horizon": {}, "adverse_markout_count": 0, "favorable_markout_count": 0,
        "clean_2c_exit_count": 0, "fast_exit_count": 0, "slow_or_no_exit_count": 0, "exit_seconds": [], "sample_tickers": [],
    }


def _markout_touch_group(groups: dict, scope: str, asset: str, series: str, hour: str = "", session: str = "") -> dict:
    key = _markout_group_key(scope, asset, series, hour, session)
    if key not in groups:
        groups[key] = _markout_blank_group(scope, asset, series, hour, session)
    return groups[key]


def _markout_add_sample(group: dict, ticker: str):
    ticker = str(ticker or "").strip()
    if ticker:
        group["unique_tickers"].add(ticker)
    if ticker and ticker not in group["sample_tickers"] and len(group["sample_tickers"]) < 12:
        group["sample_tickers"].append(ticker)


def _markout_scopes(ticker: str, series: str, ts: int):
    asset = asset_for_ticker(ticker, series)
    hour, session = ct_hour_session_for_ts(ts or now_ts())
    scopes = [("asset", asset, "", "", ""), ("asset_hour", asset, "", hour, session)]
    if series:
        scopes.extend([("series", asset, series, "", ""), ("series_hour", asset, series, hour, session)])
    return scopes


def _markout_series_from_row(row: dict, ticker: str = "") -> str:
    series = str((row or {}).get("series_ticker") or (row or {}).get("series") or "").strip()
    if series:
        return series
    ticker = str(ticker or (row or {}).get("ticker") or "").strip()
    if ticker:
        parts = ticker.split("-")
        if parts:
            return parts[0]
    return ""


def _markout_price_from_snapshot(row: dict) -> Decimal:
    if not isinstance(row, dict):
        return Decimal("0")
    # Prefer true same-side mid/micro/weighted values when available, then fall
    # back to same-side/best-bid fields. We deliberately avoid target/active
    # order prices because those are our intended order prices, not a market mark.
    for key in (
        "orderbook_mid_price_dollars", "orderbook_microprice_dollars", "orderbook_vamp_price_dollars",
        "orderbook_weighted_depth_price_dollars", "book_best_bid_dollars", "same_side_best_bid_dollars",
        "orderbook_snapshot_best_bid_dollars", "book_best_bid", "best_bid_dollars", "best_bid",
    ):
        val = row.get(key)
        if val not in (None, ""):
            price = parse_decimal(val, "0")
            if price > 0:
                return price
    return Decimal("0")


def _markout_collect_rows(export_dirs=None, support_zips=None) -> tuple:
    roots = []
    for root in (export_dirs or [EXPORT_DIR]):
        if root and os.path.isdir(root) and root not in roots:
            roots.append(root)
    temp_root = None
    extracted = []
    zip_paths = _support_zip_candidates(support_zips)
    try:
        if zip_paths:
            temp_root = tempfile.mkdtemp(prefix="kalshi15m_markout_")
            for zp in zip_paths:
                try:
                    root = _extract_support_zip_to_temp(zp, temp_root)
                    extracted.append(root)
                    roots.append(root)
                except Exception as e:
                    LOGGER.debug("Markout support bundle skipped | zip=%s | error=%s", zp, e)
        rows_by_kind = {"plan": [], "fill": [], "snapshot": []}
        for root in roots:
            if not root or not os.path.isdir(root):
                continue
            for dirpath, _dirs, files in os.walk(root):
                for name in files:
                    low = name.lower()
                    if not low.endswith(".csv"):
                        continue
                    path = os.path.join(dirpath, name)
                    if "buy_action_plan" in low:
                        rows_by_kind["plan"].extend(_read_csv_rows_safe(path, 50000))
                    elif "fill_ledger" in low:
                        rows_by_kind["fill"].extend(_read_csv_rows_safe(path, 50000))
                    elif any(k in low for k in ("market_quality", "market_discovery", "exit_readiness", "sell_liveness", "recovery_timing")):
                        rows_by_kind["snapshot"].extend(_read_csv_rows_safe(path, 50000))
        meta = {"roots": roots, "support_zips": zip_paths, "extracted_roots": extracted, "temp_root": temp_root}
        return rows_by_kind, meta
    finally:
        if temp_root:
            shutil.rmtree(temp_root, ignore_errors=True)


def _markout_event_from_plan(row: dict) -> dict:
    ticker = str((row or {}).get("ticker") or "").strip()
    side = str((row or {}).get("side") or "").lower().strip()
    if not ticker or side not in {"yes", "no"}:
        return {}
    ts = _csv_timestamp(row)
    entry_price = parse_decimal((row or {}).get("buy_price_dollars", (row or {}).get("v2_order_price_dollars", "0")), "0")
    qty = parse_decimal((row or {}).get("buy_qty_fp", (row or {}).get("v2_order_count_fp", "0")), "0")
    if entry_price <= 0 or qty <= 0:
        return {}
    target_price = parse_decimal((row or {}).get("sell_target_price_dollars", (row or {}).get("target_sell_price_dollars", TARGET_2C_PRICE)), str(TARGET_2C_PRICE))
    return {
        "ticker": ticker, "side": side, "series_ticker": _markout_series_from_row(row, ticker), "ts": ts,
        "entry_price": entry_price, "target_price": target_price, "qty_fp": qty,
        "cost_dollars": parse_decimal((row or {}).get("buy_cost_dollars", "0"), "0"), "source": "buy_action_plan",
    }


def _markout_event_from_buy_fill(row: dict) -> dict:
    action = str((row or {}).get("action") or "").lower().strip()
    if action and action != "buy":
        return {}
    ticker = str((row or {}).get("ticker") or "").strip()
    side = str((row or {}).get("side") or "").lower().strip()
    if not ticker or side not in {"yes", "no"}:
        return {}
    qty = parse_decimal((row or {}).get("count_fp", "0"), "0")
    entry_price = parse_decimal((row or {}).get("price_dollars", "0"), "0")
    ts = _csv_timestamp(row)
    if qty <= 0 or entry_price <= 0 or ts <= 0:
        return {}
    return {
        "ticker": ticker, "side": side, "series_ticker": _markout_series_from_row(row, ticker), "ts": ts,
        "entry_price": entry_price, "target_price": TARGET_2C_PRICE, "qty_fp": qty,
        "cost_dollars": (qty * entry_price).quantize(Decimal("0.000001")), "source": "buy_fill",
    }


def _markout_snapshot_key(row: dict) -> str:
    ticker = str((row or {}).get("ticker") or "").strip()
    side = str((row or {}).get("side") or "").lower().strip()
    if not ticker or side not in {"yes", "no"}:
        return ""
    return f"{ticker}|{side}"


def _markout_build_snapshot_index(rows: list) -> dict:
    idx = {}
    for row in rows or []:
        key = _markout_snapshot_key(row)
        if not key:
            continue
        ts = _csv_timestamp(row)
        price = _markout_price_from_snapshot(row)
        if ts <= 0 or price <= 0:
            continue
        idx.setdefault(key, []).append((ts, price))
    for key in list(idx.keys()):
        seen = set()
        out = []
        for ts, price in sorted(idx[key], key=lambda x: (x[0], x[1])):
            pair = (int(ts), str(price))
            if pair in seen:
                continue
            seen.add(pair)
            out.append((int(ts), price))
        idx[key] = out
    return idx


def _markout_build_sell_fill_index(rows: list) -> dict:
    idx = {}
    for row in rows or []:
        action = str((row or {}).get("action") or "").lower().strip()
        if action and action != "sell":
            continue
        ticker = str((row or {}).get("ticker") or "").strip()
        side = str((row or {}).get("side") or "").lower().strip()
        if not ticker or side not in {"yes", "no"}:
            continue
        ts = _csv_timestamp(row)
        price = parse_decimal((row or {}).get("price_dollars", "0"), "0")
        qty = parse_decimal((row or {}).get("count_fp", "0"), "0")
        net = parse_decimal((row or {}).get("net_dollars", "0"), "0")
        if ts <= 0 or price <= 0 or qty <= 0:
            continue
        idx.setdefault(f"{ticker}|{side}", []).append({"ts": ts, "price": price, "qty_fp": qty, "net_dollars": net})
    for key in list(idx.keys()):
        idx[key].sort(key=lambda r: int(r.get("ts", 0) or 0))
    return idx


def _markout_nearest_price_for_event(key: str, ts: int, snapshot_index: dict) -> Decimal:
    """Return the closest usable same-side book mark near an observed recovery row."""
    rows = snapshot_index.get(key, []) if isinstance(snapshot_index, dict) else []
    if not rows:
        return Decimal("0")
    grace = max(30, int(MARKOUT_EXIT_SPEED_SNAPSHOT_GRACE_SECONDS or 0))
    best_price = Decimal("0")
    best_dist = None
    for snap_ts, price in rows:
        dist = abs(int(snap_ts) - int(ts or 0))
        if dist > grace:
            continue
        if best_dist is None or dist < best_dist:
            best_dist = dist
            best_price = parse_decimal(price, "0")
    return best_price if best_price > 0 else Decimal("0")


def _markout_event_from_recovery_observation(row: dict, snapshot_index: dict) -> dict:
    """Fallback event builder for old support bundles that lacked buy plans/fills.

    Older uploads sometimes only have sell-liveness/recovery ledgers. When no
    explicit entry rows exist, we still learn useful exit-speed and rough markout
    behavior by treating the first observed positive-position row for a ticker as
    a recovery-observation event. The live bot prefers real buy-action/buy-fill
    rows when available.
    """
    if not isinstance(row, dict):
        return {}
    ticker = str(row.get("ticker") or "").strip()
    side = str(row.get("side") or "").lower().strip()
    if not ticker or side not in {"yes", "no"}:
        return {}
    ts = _csv_timestamp(row)
    if ts <= 0:
        return {}
    qty = max([
        parse_decimal(row.get("position_fp", "0"), "0"),
        parse_decimal(row.get("target_total_fp", "0"), "0"),
        parse_decimal(row.get("desired_remaining_fp", "0"), "0"),
        parse_decimal(row.get("active_remaining_fp", "0"), "0"),
        parse_decimal(row.get("sell_filled_fp", "0"), "0"),
        parse_decimal(row.get("realized_sell_fill_qty_fp", "0"), "0"),
    ] or [Decimal("0")])
    status = str(row.get("recovery_status") or row.get("status") or row.get("packet_status") or "").lower()
    if qty <= 0 and "recovered" not in status:
        return {}
    key = f"{ticker}|{side}"
    entry_price = _markout_price_from_snapshot(row)
    if entry_price <= 0:
        entry_price = _markout_nearest_price_for_event(key, ts, snapshot_index)
    if entry_price <= 0:
        # Last-resort support-bundle fallback. This keeps exit-speed evidence
        # alive but naturally produces no strong markout boost without snapshots.
        entry_price = Decimal("0.0100")
    target_price = parse_decimal(row.get("target_price_dollars", TARGET_2C_PRICE), str(TARGET_2C_PRICE))
    target_total = parse_decimal(row.get("target_total_fp", "0"), "0")
    sell_filled = parse_decimal(row.get("sell_filled_fp", row.get("realized_sell_fill_qty_fp", "0")), "0")
    clean_exit_ts = 0
    if "recovered" in status or (target_total > 0 and sell_filled >= target_total):
        clean_exit_ts = ts
    return {
        "ticker": ticker,
        "side": side,
        "series_ticker": _markout_series_from_row(row, ticker),
        "ts": ts,
        "entry_price": entry_price,
        "target_price": target_price,
        "qty_fp": qty if qty > 0 else Decimal("1.00"),
        "cost_dollars": (max_decimal(qty, Decimal("1.00")) * entry_price).quantize(Decimal("0.000001")),
        "source": "recovery_observation",
        "clean_exit_ts": clean_exit_ts,
    }


def _markout_first_snapshot_after(snapshots: list, target_ts: int):
    grace = max(0, int(MARKOUT_EXIT_SPEED_SNAPSHOT_GRACE_SECONDS or 0))
    best = None
    for ts, price in snapshots or []:
        if ts < target_ts:
            continue
        if grace and ts > target_ts + grace:
            break
        best = (ts, price)
        break
    return best


def _markout_first_clean_exit_after(sell_fills: list, event_ts: int, target_price: Decimal):
    target = parse_decimal(target_price, str(TARGET_2C_PRICE))
    for fill in sell_fills or []:
        ts = int(fill.get("ts", 0) or 0)
        if ts < event_ts:
            continue
        if parse_decimal(fill.get("price", "0"), "0") + Decimal("0.00005") >= target:
            return fill
    return None


def _markout_add_event_to_groups(groups: dict, event: dict, snapshot_index: dict, sell_fill_index: dict, now: int, lookback_seconds: int):
    if not event:
        return
    ts = int(event.get("ts", 0) or 0)
    if ts <= 0:
        ts = now
    if lookback_seconds > 0 and ts < now - lookback_seconds:
        return
    ticker = str(event.get("ticker") or "")
    side = str(event.get("side") or "").lower()
    series = str(event.get("series_ticker") or "")
    key = f"{ticker}|{side}"
    entry_price = parse_decimal(event.get("entry_price", "0"), "0")
    qty = parse_decimal(event.get("qty_fp", "0"), "0")
    cost = parse_decimal(event.get("cost_dollars", "0"), "0")
    if cost <= 0 and qty > 0 and entry_price > 0:
        cost = (qty * entry_price).quantize(Decimal("0.000001"))
    snapshots = snapshot_index.get(key, [])
    sell_fills = sell_fill_index.get(key, [])
    markouts = {}
    for horizon in MARKOUT_EXIT_SPEED_HORIZONS_SECONDS:
        snap = _markout_first_snapshot_after(snapshots, ts + int(horizon))
        if not snap:
            continue
        _snap_ts, future_price = snap
        markouts[int(horizon)] = ((parse_decimal(future_price, "0") - entry_price) * Decimal("100")).quantize(Decimal("0.0001"))
    clean_exit = None
    clean_exit_ts = int(event.get("clean_exit_ts", 0) or 0)
    if clean_exit_ts >= ts and clean_exit_ts > 0:
        clean_exit = {"ts": clean_exit_ts, "price": event.get("target_price", TARGET_2C_PRICE), "qty_fp": event.get("qty_fp", "0")}
    if not clean_exit:
        clean_exit = _markout_first_clean_exit_after(sell_fills, ts, event.get("target_price", TARGET_2C_PRICE))
    exit_seconds = None
    if clean_exit:
        exit_seconds = max(0, int(clean_exit.get("ts", 0) or 0) - ts)
    primary_horizon = 30 if 30 in MARKOUT_EXIT_SPEED_HORIZONS_SECONDS else sorted(MARKOUT_EXIT_SPEED_HORIZONS_SECONDS)[min(len(MARKOUT_EXIT_SPEED_HORIZONS_SECONDS) - 1, 0)]
    primary_markout = markouts.get(primary_horizon)
    if primary_markout is None and markouts:
        primary_markout = markouts[sorted(markouts.keys())[-1]]
    for scope, asset, scoped_series, hour, session in _markout_scopes(ticker, series, ts):
        g = _markout_touch_group(groups, scope, asset, scoped_series, hour, session)
        g["event_count"] += 1
        g["planned_qty_fp"] += max_decimal(Decimal("0"), qty)
        g["planned_cost_dollars"] += max_decimal(Decimal("0"), cost)
        for horizon, val in markouts.items():
            g.setdefault("markouts_by_horizon", {}).setdefault(int(horizon), []).append(val)
        if primary_markout is not None:
            if primary_markout <= MARKOUT_EXIT_SPEED_CAUTION_MARKOUT_30S_CENTS:
                g["adverse_markout_count"] += 1
            elif primary_markout >= MARKOUT_EXIT_SPEED_STRONG_MARKOUT_30S_CENTS:
                g["favorable_markout_count"] += 1
        if clean_exit:
            g["clean_2c_exit_count"] += 1
            g["exit_seconds"].append(Decimal(str(exit_seconds)))
            if exit_seconds <= MARKOUT_EXIT_SPEED_FAST_EXIT_SECONDS:
                g["fast_exit_count"] += 1
            elif exit_seconds >= MARKOUT_EXIT_SPEED_SLOW_EXIT_SECONDS:
                g["slow_or_no_exit_count"] += 1
        else:
            # A no-exit event is a useful warning only after the slow-exit horizon
            # has elapsed; otherwise the event may simply be too new.
            if now - ts >= MARKOUT_EXIT_SPEED_SLOW_EXIT_SECONDS:
                g["slow_or_no_exit_count"] += 1
        _markout_add_sample(g, ticker)


def _markout_average(values, default: Decimal = Decimal("0")) -> Decimal:
    vals = [parse_decimal(v, "0") for v in values or []]
    if not vals:
        return default
    return (sum(vals, Decimal("0")) / Decimal(len(vals))).quantize(Decimal("0.0001"))


def _markout_median(values, default: Decimal = Decimal("0")) -> Decimal:
    vals = sorted(parse_decimal(v, "0") for v in values or [])
    if not vals:
        return default
    n = len(vals)
    if n % 2:
        return vals[n // 2].quantize(Decimal("0.0001"))
    return ((vals[n // 2 - 1] + vals[n // 2]) / Decimal("2")).quantize(Decimal("0.0001"))


def _markout_finalize_group(group: dict, now: int) -> dict:
    events = int(group.get("event_count", 0) or 0)
    unique_count = len(group.get("unique_tickers", set()) or set())
    horizons = list(MARKOUT_EXIT_SPEED_HORIZONS_SECONDS)
    horizon_avgs = {}
    horizon_counts = {}
    for h in horizons:
        vals = (group.get("markouts_by_horizon", {}) or {}).get(int(h), [])
        horizon_counts[int(h)] = len(vals)
        horizon_avgs[int(h)] = _markout_average(vals, Decimal("0"))
    primary_h = 30 if 30 in horizon_avgs else (horizons[-1] if horizons else 30)
    primary_count = horizon_counts.get(primary_h, 0)
    avg_primary = horizon_avgs.get(primary_h, Decimal("0"))
    adverse = int(group.get("adverse_markout_count", 0) or 0)
    favorable = int(group.get("favorable_markout_count", 0) or 0)
    clean = int(group.get("clean_2c_exit_count", 0) or 0)
    fast = int(group.get("fast_exit_count", 0) or 0)
    slow_no = int(group.get("slow_or_no_exit_count", 0) or 0)
    adverse_rate = (Decimal(adverse) / Decimal(max(1, primary_count)) * Decimal("100")).quantize(Decimal("0.0001")) if primary_count else Decimal("0")
    favorable_rate = (Decimal(favorable) / Decimal(max(1, primary_count)) * Decimal("100")).quantize(Decimal("0.0001")) if primary_count else Decimal("0")
    clean_rate = (Decimal(clean) / Decimal(max(1, events)) * Decimal("100")).quantize(Decimal("0.0001")) if events else Decimal("0")
    fast_rate = (Decimal(fast) / Decimal(max(1, events)) * Decimal("100")).quantize(Decimal("0.0001")) if events else Decimal("0")
    slow_no_rate = (Decimal(slow_no) / Decimal(max(1, events)) * Decimal("100")).quantize(Decimal("0.0001")) if events else Decimal("0")
    enough = events >= MARKOUT_EXIT_SPEED_MIN_EVENTS and unique_count >= MARKOUT_EXIT_SPEED_MIN_UNIQUE_TICKERS
    reasons = []
    if not enough:
        band, action, mult, cap, block = "insufficient_evidence", "observe_only", Decimal("1.00"), "aggressive", "0"
        reasons.append(f"events={events};unique_tickers={unique_count};primary_samples={primary_count}")
    elif adverse_rate >= MARKOUT_EXIT_SPEED_SEVERE_ADVERSE_RATE_PCT or avg_primary <= MARKOUT_EXIT_SPEED_SEVERE_MARKOUT_30S_CENTS:
        band, action, mult, cap, block = "severe", "pilot_or_block_negative_markouts", MARKOUT_EXIT_SPEED_SEVERE_SIZE_MULTIPLIER, "pilot", "1" if MARKOUT_EXIT_SPEED_REJECT_SEVERE else "0"
        reasons.append(f"severe_markout_avg={cents4_str(avg_primary)}c;adverse_rate={cents4_str(adverse_rate)}pct")
    elif slow_no_rate >= MARKOUT_EXIT_SPEED_SEVERE_ADVERSE_RATE_PCT:
        band, action, mult, cap, block = "severe", "pilot_or_block_slow_exits", MARKOUT_EXIT_SPEED_SEVERE_SIZE_MULTIPLIER, "pilot", "1" if MARKOUT_EXIT_SPEED_REJECT_SEVERE else "0"
        reasons.append(f"severe_slow_or_no_exit_rate={cents4_str(slow_no_rate)}pct")
    elif avg_primary <= MARKOUT_EXIT_SPEED_CAUTION_MARKOUT_30S_CENTS or slow_no_rate >= MARKOUT_EXIT_SPEED_CAUTION_SLOW_OR_NO_EXIT_RATE_PCT:
        band, action, mult, cap, block = "caution", "downsize_negative_or_slow_markouts", MARKOUT_EXIT_SPEED_CAUTION_SIZE_MULTIPLIER, "normal", "0"
        reasons.append(f"caution_markout_avg={cents4_str(avg_primary)}c;slow_no_exit={cents4_str(slow_no_rate)}pct")
    elif avg_primary >= MARKOUT_EXIT_SPEED_STRONG_MARKOUT_30S_CENTS and fast_rate >= MARKOUT_EXIT_SPEED_STRONG_FAST_EXIT_RATE_PCT and adverse_rate < MARKOUT_EXIT_SPEED_SEVERE_ADVERSE_RATE_PCT:
        band, action, mult, cap, block = "strong", "boost_positive_markout_fast_exits", MARKOUT_EXIT_SPEED_STRONG_SIZE_MULTIPLIER, "aggressive", "0"
        reasons.append(f"strong_markout_avg={cents4_str(avg_primary)}c;fast_exit={cents4_str(fast_rate)}pct")
    else:
        band, action, mult, cap, block = "neutral", "keep_base_markout_risk", Decimal("1.00"), "aggressive", "0"
        reasons.append(f"neutral_markout_avg={cents4_str(avg_primary)}c;fast={cents4_str(fast_rate)}pct;slow_no={cents4_str(slow_no_rate)}pct")
    mult = min_decimal(MARKOUT_EXIT_SPEED_MAX_SIZE_MULTIPLIER, max_decimal(Decimal("0"), mult)).quantize(Decimal("0.0001"))
    def h_count(h): return horizon_counts.get(h, 0)
    def h_avg(h): return cents4_str(horizon_avgs.get(h, Decimal("0")))
    return {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "scope": group.get("scope", ""),
        "asset_symbol": group.get("asset_symbol", "UNKNOWN"),
        "series_ticker": group.get("series_ticker", ""),
        "ct_hour_bucket": group.get("ct_hour_bucket", ""),
        "ct_session": group.get("ct_session", ""),
        "markout_band": band,
        "candidate_action": action,
        "size_multiplier": cents4_str(mult),
        "level_cap": cap,
        "candidate_block": block,
        "event_count": events,
        "unique_ticker_count": unique_count,
        "planned_qty_fp": qty_str(parse_decimal(group.get("planned_qty_fp", "0"), "0")),
        "planned_cost_dollars": money6_str(parse_decimal(group.get("planned_cost_dollars", "0"), "0")),
        "markout_sample_count_1s": h_count(1),
        "avg_markout_1s_cents": h_avg(1),
        "markout_sample_count_5s": h_count(5),
        "avg_markout_5s_cents": h_avg(5),
        "markout_sample_count_30s": h_count(30),
        "avg_markout_30s_cents": h_avg(30),
        "markout_sample_count_120s": h_count(120),
        "avg_markout_120s_cents": h_avg(120),
        "adverse_markout_count": adverse,
        "favorable_markout_count": favorable,
        "adverse_markout_rate_pct": cents4_str(adverse_rate),
        "favorable_markout_rate_pct": cents4_str(favorable_rate),
        "clean_2c_exit_count": clean,
        "fast_exit_count": fast,
        "slow_or_no_exit_count": slow_no,
        "clean_2c_exit_rate_pct": cents4_str(clean_rate),
        "fast_exit_rate_pct": cents4_str(fast_rate),
        "slow_or_no_exit_rate_pct": cents4_str(slow_no_rate),
        "avg_exit_seconds": cents4_str(_markout_average(group.get("exit_seconds"), Decimal("0"))),
        "median_exit_seconds": cents4_str(_markout_median(group.get("exit_seconds"), Decimal("0"))),
        "sample_tickers": ",".join(group.get("sample_tickers", [])[:12]),
        "reason": ";".join(reasons)[:240],
    }


def build_markout_exit_speed_payload(export_dirs=None, support_zips=None, force: bool = False, context: str = "periodic") -> dict:
    now = now_ts()
    if not MARKOUT_EXIT_SPEED_LEARNER_ENABLED:
        return {"snapshot_ts": now, "utc_day": utc_day_from_ts(now), "instance": INSTANCE_NAME, "build_id": BUILD_ID, "enabled": False, "rows": []}
    lookback_seconds = int(max_decimal(Decimal("0"), MARKOUT_EXIT_SPEED_LOOKBACK_DAYS) * Decimal("86400"))
    rows_by_kind, source_meta = _markout_collect_rows(export_dirs=export_dirs, support_zips=support_zips)
    snapshot_index = _markout_build_snapshot_index(rows_by_kind.get("snapshot", []))
    sell_fill_index = _markout_build_sell_fill_index(rows_by_kind.get("fill", []))
    groups = {}
    seen_events = set()
    for row in rows_by_kind.get("plan", []):
        event = _markout_event_from_plan(row)
        if not event:
            continue
        eid = (event.get("ticker"), event.get("side"), int(event.get("ts", 0) or 0), str(event.get("qty_fp")), str(event.get("entry_price")))
        if eid in seen_events:
            continue
        seen_events.add(eid)
        _markout_add_event_to_groups(groups, event, snapshot_index, sell_fill_index, now, lookback_seconds)
    for row in rows_by_kind.get("fill", []):
        event = _markout_event_from_buy_fill(row)
        if not event:
            continue
        eid = (event.get("ticker"), event.get("side"), int(event.get("ts", 0) or 0), str(event.get("qty_fp")), str(event.get("entry_price")), "fill")
        if eid in seen_events:
            continue
        seen_events.add(eid)
        _markout_add_event_to_groups(groups, event, snapshot_index, sell_fill_index, now, lookback_seconds)
    observation_event_count = 0
    if not seen_events:
        observed_keys = set()
        for row in sorted(rows_by_kind.get("snapshot", []), key=lambda r: _csv_timestamp(r)):
            event = _markout_event_from_recovery_observation(row, snapshot_index)
            if not event:
                continue
            obs_key = (event.get("ticker"), event.get("side"))
            if obs_key in observed_keys:
                continue
            observed_keys.add(obs_key)
            observation_event_count += 1
            seen_events.add((event.get("ticker"), event.get("side"), int(event.get("ts", 0) or 0), "recovery_observation"))
            _markout_add_event_to_groups(groups, event, snapshot_index, sell_fill_index, now, lookback_seconds)
    rows = [_markout_finalize_group(group, now) for group in groups.values()]
    rows.sort(key=lambda r: (r.get("scope", ""), r.get("markout_band", ""), parse_decimal(r.get("avg_markout_30s_cents", "0"), "0")), reverse=True)
    by_series = {r.get("series_ticker", ""): r for r in rows if r.get("scope") == "series" and r.get("series_ticker")}
    by_asset = {r.get("asset_symbol", "UNKNOWN"): r for r in rows if r.get("scope") == "asset"}
    by_asset_hour = {f"{r.get('asset_symbol','UNKNOWN')}|{r.get('ct_hour_bucket','')}": r for r in rows if r.get("scope") == "asset_hour"}
    by_series_hour = {f"{r.get('series_ticker','')}|{r.get('ct_hour_bucket','')}": r for r in rows if r.get("scope") == "series_hour" and r.get("series_ticker")}
    band_counts = {}
    for r in rows:
        band_counts[r.get("markout_band", "unknown")] = band_counts.get(r.get("markout_band", "unknown"), 0) + 1
    return {
        "snapshot_ts": now,
        "utc_day": utc_day_from_ts(now),
        "instance": INSTANCE_NAME,
        "build_id": BUILD_ID,
        "enabled": True,
        "context": context,
        "row_count": len(rows),
        "band_counts": band_counts,
        "source_counts": {**{k: len(v) for k, v in rows_by_kind.items()}, "observation_events": observation_event_count, "entry_events": len(seen_events)},
        "sources": {"roots": source_meta.get("roots", []), "support_zips": source_meta.get("support_zips", [])},
        "settings": {
            "lookback_days": str(MARKOUT_EXIT_SPEED_LOOKBACK_DAYS),
            "horizons_seconds": list(MARKOUT_EXIT_SPEED_HORIZONS_SECONDS),
            "snapshot_grace_seconds": MARKOUT_EXIT_SPEED_SNAPSHOT_GRACE_SECONDS,
            "fast_exit_seconds": MARKOUT_EXIT_SPEED_FAST_EXIT_SECONDS,
            "slow_exit_seconds": MARKOUT_EXIT_SPEED_SLOW_EXIT_SECONDS,
            "max_size_multiplier": str(MARKOUT_EXIT_SPEED_MAX_SIZE_MULTIPLIER),
            "apply_to_action_plan": bool(MARKOUT_EXIT_SPEED_APPLY_TO_ACTION_PLAN),
        },
        "rows_by_series": by_series,
        "rows_by_asset": by_asset,
        "rows_by_asset_hour": by_asset_hour,
        "rows_by_series_hour": by_series_hour,
        "rows": rows,
    }


def write_markout_exit_speed_learner(force: bool = False, context: str = "periodic", export_dirs=None, support_zips=None) -> dict:
    if not MARKOUT_EXIT_SPEED_LEARNER_ENABLED:
        return {"enabled": False, "rows": []}
    meta = STATE.setdefault("meta", {})
    now = now_ts()
    if not force and now - int(meta.get("last_markout_exit_speed_ts", 0) or 0) < max(15, MARKOUT_EXIT_SPEED_INTERVAL_SECONDS):
        return meta.get("last_markout_exit_speed", {}) or {}
    payload = build_markout_exit_speed_payload(export_dirs=export_dirs, support_zips=support_zips, force=force, context=context)
    meta["last_markout_exit_speed_ts"] = now
    meta["last_markout_exit_speed"] = payload
    rows = payload.get("rows", []) or []
    atomic_write_json(MARKOUT_EXIT_SPEED_LATEST_JSON_PATH, payload)
    atomic_write_csv(MARKOUT_EXIT_SPEED_LATEST_CSV_PATH, MARKOUT_EXIT_SPEED_FIELDS, [{k: r.get(k, "") for k in MARKOUT_EXIT_SPEED_FIELDS} for r in rows] or [{k: "" for k in MARKOUT_EXIT_SPEED_FIELDS}])
    lines = [
        "Kalshi 15m 2c Sell Bot - Markout + Exit-Speed Learner",
        "======================================================",
        f"Generated CT : {central_time_iso_from_ts(payload.get('snapshot_ts', now))}",
        f"Build ID     : {BUILD_ID}",
        f"Rows         : {payload.get('row_count', 0)}",
        f"Band counts  : {payload.get('band_counts', {})}",
        f"Sources      : plans={payload.get('source_counts', {}).get('plan', 0)} fills={payload.get('source_counts', {}).get('fill', 0)} snapshots={payload.get('source_counts', {}).get('snapshot', 0)} observed_events={payload.get('source_counts', {}).get('observation_events', 0)} support_zips={len(payload.get('sources', {}).get('support_zips', []))}",
        "Policy       : risk-heavy size is boosted only where short-horizon marks and 2c exit speed are clean; strict 2c fee/net gates remain mandatory.",
        "",
    ]
    for row in rows[:20]:
        lines.append(f"{row.get('scope')} {row.get('asset_symbol')} {row.get('series_ticker')} {row.get('ct_hour_bucket')}: band={row.get('markout_band')} mult={row.get('size_multiplier')} m30={row.get('avg_markout_30s_cents')}c fast={row.get('fast_exit_rate_pct')}pct slow_no={row.get('slow_or_no_exit_rate_pct')}pct reason={row.get('reason')}")
    os.makedirs(os.path.dirname(MARKOUT_EXIT_SPEED_LATEST_TXT_PATH) or ".", exist_ok=True)
    with open(MARKOUT_EXIT_SPEED_LATEST_TXT_PATH, "w", encoding="utf-8") as f:
        f.write("\n".join(lines))
    return payload


def markout_exit_speed_context_for_candidate(ticker: str, series: str = "") -> dict:
    if not MARKOUT_EXIT_SPEED_LEARNER_ENABLED or not MARKOUT_EXIT_SPEED_APPLY_TO_ACTION_PLAN:
        return {}
    asset = asset_for_ticker(ticker, series)
    hour, _session = ct_hour_session_for_ts(now_ts())
    meta = STATE.setdefault("meta", {})
    snap = meta.get("last_markout_exit_speed", {}) if isinstance(meta.get("last_markout_exit_speed", {}), dict) else {}
    if (not snap) or now_ts() - int(snap.get("snapshot_ts", 0) or 0) > max(30, MARKOUT_EXIT_SPEED_INTERVAL_SECONDS * 2):
        snap = write_markout_exit_speed_learner(force=True, context="candidate")
    if not isinstance(snap, dict):
        return {}
    for idx_name, key, source in [
        ("rows_by_series_hour", f"{series}|{hour}", "series_hour"),
        ("rows_by_series", series, "series"),
        ("rows_by_asset_hour", f"{asset}|{hour}", "asset_hour"),
        ("rows_by_asset", asset, "asset"),
    ]:
        idx = snap.get(idx_name, {}) if isinstance(snap.get(idx_name, {}), dict) else {}
        row = idx.get(key)
        if row:
            out = dict(row)
            out["context_source"] = source
            return out
    return {"asset_symbol": asset, "series_ticker": series, "ct_hour_bucket": hour, "markout_band": "no_history", "size_multiplier": "1.0000", "level_cap": "aggressive", "candidate_block": "0", "context_source": "none", "reason": "no_markout_exit_speed_history"}


def apply_markout_exit_speed_level_cap(level: str, level_reason: str, ctx: dict) -> tuple:
    if not MARKOUT_EXIT_SPEED_LEARNER_ENABLED or not MARKOUT_EXIT_SPEED_APPLY_TO_ACTION_PLAN or not ctx:
        return level, level_reason
    band = str(ctx.get("markout_band", "")).lower()
    cap = str(ctx.get("level_cap", "")).lower()
    if str(ctx.get("candidate_block", "0")).lower() in {"1", "true", "yes"} and MARKOUT_EXIT_SPEED_REJECT_SEVERE:
        return "deny", f"{level_reason};markout_exit_speed_block({ctx.get('context_source','')}:{band})"
    if level in {"aggressive", "normal"} and cap == "pilot" and MARKOUT_EXIT_SPEED_PILOT_ON_SEVERE:
        return "pilot", f"{level_reason};markout_exit_speed_pilot_only({ctx.get('context_source','')}:{band})"
    if level == "aggressive" and cap in {"normal", "pilot"} and MARKOUT_EXIT_SPEED_DOWNGRADE_ON_CAUTION:
        return "normal", f"{level_reason};markout_exit_speed_downgrade_aggressive({ctx.get('context_source','')}:{band})"
    return level, level_reason


